class ToolTip:
    def __init__(self, widget, text, delay_ms=500):
        self.widget = widget
        self.text = text
        self.delay_ms = delay_ms
        self.after_id = None
        self.window = None
        widget.bind("<Enter>", self.schedule, add="+")
        widget.bind("<Leave>", self.hide, add="+")
        widget.bind("<ButtonPress>", self.hide, add="+")

    def schedule(self, event=None):
        self.cancel()
        self.after_id = self.widget.after(self.delay_ms, self.show)

    def cancel(self):
        if self.after_id:
            try:
                self.widget.after_cancel(self.after_id)
            except Exception:
                pass
            self.after_id = None

    def show(self):
        text = str(self.text or "")
        if self.window or not text:
            return
        margin = 12
        x = self.widget.winfo_rootx() + 20
        y = self.widget.winfo_rooty() + self.widget.winfo_height() + 8
        screen_width = self.widget.winfo_screenwidth()
        screen_height = self.widget.winfo_screenheight()
        available_right = max(180, screen_width - x - margin)
        wraplength = max(180, min(520, available_right - 24))
        self.window = tk.Toplevel(self.widget)
        self.window.wm_overrideredirect(True)
        self.window.configure(bg=GRAPHITE_BORDER)
        label = tk.Label(
            self.window,
            text=text,
            justify="left",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            relief="flat",
            borderwidth=0,
            padx=8,
            pady=5,
            font=("Segoe UI", 9),
            wraplength=wraplength,
        )
        label.pack(ipadx=1, ipady=1)
        self.window.update_idletasks()
        width = self.window.winfo_reqwidth()
        height = self.window.winfo_reqheight()
        if x + width + margin > screen_width:
            x = max(margin, screen_width - width - margin)
            wraplength = max(180, min(520, screen_width - x - margin - 24))
            label.configure(wraplength=wraplength)
            self.window.update_idletasks()
            width = self.window.winfo_reqwidth()
            height = self.window.winfo_reqheight()
        if y + height + margin > screen_height:
            y = self.widget.winfo_rooty() - height - 8
        y = max(margin, min(y, screen_height - height - margin))
        self.window.wm_geometry(f"+{x}+{y}")

    def hide(self, event=None):
        self.cancel()
        if self.window:
            self.window.destroy()
            self.window = None


def add_tooltip(widget, text):
    return ToolTip(widget, text) if text else None


def app_data_dir() -> Path:
    base = os.environ.get("APPDATA") or str(Path.home())
    path = Path(base) / "RaG Economy Manager"
    path.mkdir(parents=True, exist_ok=True)
    return path


def settings_path() -> Path:
    return app_data_dir() / "settings.json"


def source_backup_dir() -> Path:
    path = app_data_dir() / "backups"
    path.mkdir(parents=True, exist_ok=True)
    return path


def source_backup_manifest_path() -> Path:
    return source_backup_dir() / "manifest.json"


def safe_backup_name(source_path: str | os.PathLike[str]) -> str:
    source = Path(source_path)
    digest = hashlib.sha1(os.path.normcase(os.path.abspath(source)).encode("utf-8")).hexdigest()[:12]
    safe_stem = re.sub(r"[^A-Za-z0-9_.-]+", "_", source.name).strip("._") or "source"
    return f"{digest}_{safe_stem}.bak"


def looks_like_empty_types_xml(text: str) -> bool:
    compact = re.sub(r"\s+", "", text or "")
    return compact in {
        '<?xmlversion="1.0"encoding="UTF-8"standalone="yes"?><types/>',
        '<?xmlversion="1.0"encoding="UTF-8"?><types/>',
        "<types/>",
    }


def load_settings() -> dict:
    path = settings_path()
    if not path.is_file():
        return {}
    try:
        with path.open("r", encoding="utf-8") as file:
            data = json.load(file)
        return data if isinstance(data, dict) else {}
    except (OSError, json.JSONDecodeError):
        return {}


def save_settings(data: dict) -> None:
    try:
        with settings_path().open("w", encoding="utf-8") as file:
            json.dump(data, file, indent=2)
    except OSError:
        pass


def resource_path(relative_path: str) -> str:
    base_path = getattr(sys, "_MEIPASS", os.path.abspath(os.path.dirname(__file__)))
    return os.path.join(base_path, relative_path)


def configure_windows_taskbar_icon():
    if os.name != "nt":
        return
    try:
        ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID("RaG.RaGEconomyManager")
    except Exception:
        pass


def apply_app_icon(window):
    icon_path = resource_path(APP_ICON_FILE)
    if not os.path.isfile(icon_path):
        return
    try:
        window.iconbitmap(icon_path)
        return
    except Exception:
        pass
    try:
        image = tk.PhotoImage(file=icon_path)
        window.iconphoto(True, image)
        window._rag_icon_ref = image
    except Exception:
        pass


def center_window(window, parent=None):
    window.update_idletasks()
    width = max(window.winfo_width(), window.winfo_reqwidth())
    height = max(window.winfo_height(), window.winfo_reqheight())
    if parent is not None and parent.winfo_viewable():
        x = parent.winfo_rootx() + max(0, (parent.winfo_width() - width) // 2)
        y = parent.winfo_rooty() + max(0, (parent.winfo_height() - height) // 2)
    else:
        x = (window.winfo_screenwidth() - width) // 2
        y = (window.winfo_screenheight() - height) // 2
    x = max(0, x)
    y = max(0, y)
    window.geometry(f"+{x}+{y}")


def is_safe_window_geometry(value):
    if not value or not isinstance(value, str):
        return False
    parts = value.split("+", 1)[0].split("x", 1)
    if len(parts) != 2:
        return False
    try:
        return int(parts[0]) >= 1000 and int(parts[1]) >= 700
    except ValueError:
        return False


def parse_sort_int(value):
    value = str(value).strip()
    if not value:
        return None
    try:
        return int(value)
    except ValueError:
        return None


def format_download_size(size):
    try:
        size = float(size)
    except Exception:
        return "0 B"
    units = ["B", "KB", "MB", "GB"]
    index = 0
    while size >= 1024 and index < len(units) - 1:
        size /= 1024
        index += 1
    if index == 0:
        return f"{int(size)} {units[index]}"
    return f"{size:.1f} {units[index]}"


def map_canvas_to_world(canvas_x, canvas_y, offset_x, offset_y, zoom, base_width, base_height, map_width, map_height):
    if zoom <= 0 or min(base_width, base_height, map_width, map_height) <= 0:
        return None
    image_x = (canvas_x - offset_x) / zoom
    image_y = (canvas_y - offset_y) / zoom
    if image_x < 0 or image_y < 0 or image_x > base_width or image_y > base_height:
        return None
    return image_x / base_width * map_width, (base_height - image_y) / base_height * map_height


def map_world_size_from_info(map_info, default=15360.0):
    for key in ("world_size", "worldSize", "worldsize", "world", "size"):
        if key not in map_info:
            continue
        try:
            value = float(map_info.get(key))
        except (TypeError, ValueError):
            continue
        if value > 0:
            return value
    return float(default)


def map_info_has_world_size(map_info):
    if not isinstance(map_info, dict):
        return False
    for key in ("world_size", "worldSize", "worldsize", "world", "size"):
        if key in map_info:
            try:
                return float(map_info.get(key)) > 0
            except (TypeError, ValueError):
                return False
    return False


def known_map_world_size(map_key, map_info=None):
    candidates = [str(map_key or "").casefold()]
    if isinstance(map_info, dict):
        candidates.extend(str(alias or "").casefold() for alias in map_info.get("aliases", []) if str(alias or "").strip())
        folder = str(map_info.get("folder", "") or "").casefold()
        if folder:
            candidates.append(folder)
    for candidate in candidates:
        if candidate in DEFAULT_MAP_WORLD_SIZES:
            return DEFAULT_MAP_WORLD_SIZES[candidate]
    return None


def format_event_coordinate(value):
    number = float(value)
    if abs(number) < 0.0000005:
        number = 0.0
    return f"{number:.6f}".rstrip("0").rstrip(".")


class ProgressWindow(tk.Toplevel):
    def __init__(self, parent, title, message, maximum=100):
        super().__init__(parent)
        self.parent = parent
        self.title(title)
        self.configure(bg=GRAPHITE_BG)
        self.resizable(False, False)
        self.transient(parent)
        apply_app_icon(self)
        frame = ttk.Frame(self, padding=16)
        frame.pack(fill="both", expand=True)
        frame.columnconfigure(0, weight=1)
        self.message_var = tk.StringVar(value=message)
        self.detail_var = tk.StringVar(value="")
        ttk.Label(frame, textvariable=self.message_var, style="FieldName.TLabel", wraplength=420, justify="left").grid(row=0, column=0, sticky="w", pady=(0, 10))
        self.progress = ttk.Progressbar(frame, mode="determinate", maximum=maximum)
        self.progress.grid(row=1, column=0, sticky="ew")
        ttk.Label(frame, textvariable=self.detail_var, style="FieldMuted.TLabel", wraplength=420, justify="left").grid(row=2, column=0, sticky="w", pady=(8, 0))
        self.grab_set()
        self.protocol("WM_DELETE_WINDOW", lambda: None)
        self.after(20, lambda: center_window(self, parent))

    def update_progress(self, value=None, maximum=None, message=None, detail=None):
        if maximum is not None:
            self.progress.configure(maximum=maximum)
        if value is not None:
            self.progress.configure(value=value)
        if message is not None:
            self.message_var.set(message)
        if detail is not None:
            self.detail_var.set(detail)
        self.update_idletasks()


