    def attach_button_hover(self, button, normal_bg, hover_bg, pressed_bg=None):
        pressed_bg = pressed_bg or hover_bg

        def on_enter(event=None):
            if str(button.cget("state")) != "disabled":
                button.configure(bg=hover_bg, activebackground=pressed_bg)

        def on_leave(event=None):
            button.configure(bg=normal_bg, activebackground=pressed_bg)

        button.bind("<Enter>", on_enter, add="+")
        button.bind("<Leave>", on_leave, add="+")

    def make_button(self, parent, text, command, primary=False, variant="", large=False, tooltip="", width=None):
        if primary and not variant:
            variant = "primary"
        if variant in {"analysis", "action"}:
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_PREFLIGHT, "#ffffff", GRAPHITE_PREFLIGHT_ACTIVE, GRAPHITE_PREFLIGHT_HOVER, "bold"
        elif variant == "add":
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_ADD, "#ffffff", GRAPHITE_ADD_ACTIVE, GRAPHITE_ADD_HOVER, "bold"
        elif variant in {"save", "apply", "write"}:
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_SAVE, "#ffffff", GRAPHITE_SAVE_ACTIVE, GRAPHITE_SAVE_HOVER, "bold"
        elif variant == "report":
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_REPORT, "#ffffff", GRAPHITE_REPORT_ACTIVE, GRAPHITE_REPORT_HOVER, "bold"
        elif variant in {"danger", "delete"}:
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_DANGER, "#ffffff", GRAPHITE_DANGER_ACTIVE, GRAPHITE_DANGER_HOVER, "bold"
        elif variant == "primary":
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_PREFLIGHT, "#ffffff", GRAPHITE_PREFLIGHT_ACTIVE, GRAPHITE_PREFLIGHT_HOVER, "bold"
        else:
            bg, fg, active_bg, hover_bg, weight = GRAPHITE_CARD_SOFT, GRAPHITE_TEXT, GRAPHITE_BORDER, GRAPHITE_BORDER, "normal"
        button = tk.Button(
            parent,
            text=text,
            command=command,
            bg=bg,
            fg=fg,
            activebackground=active_bg,
            activeforeground="#ffffff" if fg == "#ffffff" else GRAPHITE_TEXT,
            relief="flat",
            borderwidth=0,
            padx=14 if large else 9,
            pady=8 if large else 5,
            font=("Segoe UI", 10 if large else 9, weight),
            cursor="hand2",
        )
        if width:
            button.configure(width=width)
        button.pack(side="left", padx=(0, 8))
        self.attach_button_hover(button, bg, hover_bg, active_bg)
        add_tooltip(button, tooltip)
        return button

    def make_header_button(self, parent, text, command):
        button = tk.Button(parent, text=text, command=command, bg=GRAPHITE_CARD_SOFT, fg=GRAPHITE_TEXT, activebackground=GRAPHITE_BORDER, activeforeground=GRAPHITE_TEXT, relief="flat", borderwidth=0, padx=12, pady=6, font=("Segoe UI", 9), cursor="hand2")
        button.pack(side="right", padx=(0, 8))
        self.attach_button_hover(button, GRAPHITE_CARD_SOFT, GRAPHITE_BORDER, GRAPHITE_BORDER)
        return button

    def make_info_button(self, parent, module_id, pack_side="right"):
        button = tk.Button(
            parent,
            text="?",
            command=lambda: self.open_module_info_window(module_id),
            bg=GRAPHITE_INFO,
            fg="#ffffff",
            activebackground=GRAPHITE_INFO_ACTIVE,
            activeforeground="#ffffff",
            relief="flat",
            borderwidth=0,
            width=3,
            padx=6,
            pady=4,
            font=("Segoe UI", 9, "bold"),
            cursor="hand2",
        )
        button.pack(side=pack_side, padx=(0, 8))
        self.attach_button_hover(button, GRAPHITE_INFO, GRAPHITE_INFO_HOVER, GRAPHITE_INFO_ACTIVE)
        add_tooltip(button, "Open module help and field explanations.")
        return button

    def open_module_info_window(self, module_id):
        info = MODULE_INFO.get(module_id)
        if not info:
            info = {
                "title": "Help",
                "subtitle": "No help content is available for this module yet.",
                "sections": [("Overview", ["No help text available for this module yet."])],
            }
        elif isinstance(info, tuple):
            title, paragraphs = info
            info = {"title": title, "subtitle": "", "sections": [("Overview", paragraphs)]}
        title = info.get("title", "Help")
        subtitle = info.get("subtitle", "")
        sections = info.get("sections", [])
        window = tk.Toplevel(self)
        window.title(f"{title} Help")
        window.geometry("760x620")
        window.minsize(560, 420)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)

        shell = tk.Frame(window, bg=GRAPHITE_BG, padx=18, pady=18)
        shell.pack(fill="both", expand=True)
        shell.rowconfigure(1, weight=1)
        shell.columnconfigure(0, weight=1)

        header = tk.Frame(shell, bg=GRAPHITE_HEADER, padx=18, pady=14)
        header.grid(row=0, column=0, sticky="ew", pady=(0, 12))
        header.columnconfigure(0, weight=1)
        tk.Label(header, text=title, bg=GRAPHITE_HEADER, fg=GRAPHITE_TEXT, font=("Segoe UI", 17, "bold")).grid(row=0, column=0, sticky="w")
        if subtitle:
            tk.Label(header, text=subtitle, bg=GRAPHITE_HEADER, fg=GRAPHITE_MUTED, font=("Segoe UI", 10), wraplength=660, justify="left").grid(row=1, column=0, sticky="w", pady=(5, 0))

        body_shell = tk.Frame(shell, bg=GRAPHITE_CARD, highlightthickness=1, highlightbackground=GRAPHITE_BORDER_SOFT)
        body_shell.grid(row=1, column=0, sticky="nsew")
        body_shell.rowconfigure(0, weight=1)
        body_shell.columnconfigure(0, weight=1)

        canvas = tk.Canvas(body_shell, bg=GRAPHITE_CARD, highlightthickness=0, borderwidth=0)
        canvas.grid(row=0, column=0, sticky="nsew")
        scroll = ttk.Scrollbar(body_shell, command=canvas.yview)
        scroll.grid(row=0, column=1, sticky="ns")
        canvas.configure(yscrollcommand=scroll.set)

        content = tk.Frame(canvas, bg=GRAPHITE_CARD, padx=18, pady=16)
        content_id = canvas.create_window((0, 0), window=content, anchor="nw")
        wrapped_labels = []

        def refresh_scroll_region(event=None):
            canvas.configure(scrollregion=canvas.bbox("all"))

        def fit_content_width(event=None):
            available_width = max(1, canvas.winfo_width())
            canvas.itemconfigure(content_id, width=available_width)
            wrap_width = max(260, available_width - 100)
            for label in wrapped_labels:
                label.configure(wraplength=wrap_width)

        content.bind("<Configure>", refresh_scroll_region)
        canvas.bind("<Configure>", fit_content_width)

        def on_mousewheel(event):
            canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        canvas.bind("<MouseWheel>", on_mousewheel)
        content.bind("<MouseWheel>", on_mousewheel)

        for index, (section_title, bullets) in enumerate(sections):
            section = tk.Frame(content, bg=GRAPHITE_CARD_SOFT, padx=14, pady=12, highlightthickness=1, highlightbackground=GRAPHITE_BORDER_SOFT)
            section.pack(fill="x", expand=True, pady=(0 if index == 0 else 12, 0))
            tk.Label(section, text=section_title, bg=GRAPHITE_CARD_SOFT, fg=GRAPHITE_TEXT, font=("Segoe UI", 12, "bold")).pack(anchor="w", pady=(0, 8))
            for bullet in bullets:
                row = tk.Frame(section, bg=GRAPHITE_CARD_SOFT)
                row.pack(fill="x", anchor="w", pady=2)
                row.columnconfigure(1, weight=1)
                tk.Label(row, text="-", bg=GRAPHITE_CARD_SOFT, fg=GRAPHITE_INFO_HOVER, font=("Segoe UI", 12, "bold"), width=2, anchor="w").grid(row=0, column=0, sticky="nw", padx=(0, 8))
                bullet_label = tk.Label(row, text=str(bullet), bg=GRAPHITE_CARD_SOFT, fg=GRAPHITE_MUTED, font=("Segoe UI", 10), wraplength=560, justify="left", anchor="w")
                bullet_label.grid(row=0, column=1, sticky="ew")
                wrapped_labels.append(bullet_label)

        actions = tk.Frame(shell, bg=GRAPHITE_BG)
        actions.grid(row=2, column=0, sticky="e", pady=(12, 0))
        self.make_button(actions, "Close", window.destroy, primary=True)
        window.after(20, lambda: center_window(window))

    def add_labeled_tooltip(self, label, tooltip):
        add_tooltip(label, tooltip)
        return label

    def build_module_sidebar(self, parent):
        modules = [
            ("dashboard", "Dashboard", "Mission overview and health checks."),
            ("types", "Types", "types.xml entries and economy editing."),
            ("spawnabletypes", "Spawnabletypes", "cfgspawnabletypes.xml cargo, attachments, presets, and references."),
            ("randompresets", "Randompresets", "cfgrandompresets.xml cargo and attachment presets."),
            ("definitions", "Definitions", "cfglimitsdefinition.xml categories, usages, values, and tags."),
            ("economy_core", "Economy Core", "cfgeconomycore.xml managed class roots, global settings, and extra economy XML files."),
            ("events", "Events", "events.xml and event spawn tooling."),
            ("environment", "Environment", "cfgenvironment.xml territory registrations, populations, agents, and limits."),
            ("territories", "Territories", "Territory and areaflags tooling."),
            ("ce_zones", "CE Zones", "Usage flags, tier zones, water, and CE Tool map layers."),
            ("mapgroupproto", "Mapgroupproto", "Loot prototype groups, containers, filters, and points."),
            ("weather", "Weather", "cfgweather.xml weather presets and live ranges."),
            ("configs", "Configs", "JSON, CFG, and gameplay configuration files."),
            ("profiles", "Profiles", "Optional server profiles folder configs."),
            ("logs", "Logs Analyzer", "Analyze DayZ RPT, ADM, script, crash, console, and minidump files."),
            ("tools", "Tools", "Bulk replacement, compare, cleanup, and reports."),
        ]
        parent.columnconfigure(0, weight=1)
        ttk.Label(parent, text="Modules", style="FieldName.TLabel").grid(row=0, column=0, sticky="w", padx=10, pady=(10, 8))
        for row, (module_id, label, tooltip) in enumerate(modules, start=1):
            button = tk.Button(
                parent,
                text=label,
                command=lambda target=module_id: self.switch_module(target),
                bg=GRAPHITE_CARD_SOFT,
                fg=GRAPHITE_TEXT,
                activebackground=GRAPHITE_BORDER,
                activeforeground=GRAPHITE_TEXT,
                relief="flat",
                borderwidth=0,
                anchor="w",
                padx=12,
                pady=9,
                font=("Segoe UI", 10, "bold" if module_id == self.active_module else "normal"),
                cursor="hand2",
            )
            button.grid(row=row, column=0, sticky="ew", padx=8, pady=(0, 6))
            button.bind("<Enter>", lambda event, target=module_id, widget=button: self.on_module_button_enter(target, widget), add="+")
            button.bind("<Leave>", lambda event, target=module_id, widget=button: self.on_module_button_leave(target, widget), add="+")
            add_tooltip(button, tooltip)
            self.module_buttons[module_id] = button

    def on_module_button_enter(self, module_id, button):
        if module_id == self.active_module:
            button.configure(bg=GRAPHITE_ACCENT, activebackground=GRAPHITE_ACCENT)
        else:
            button.configure(bg=GRAPHITE_BORDER, activebackground=GRAPHITE_BORDER)

    def on_module_button_leave(self, module_id, button):
        if module_id == self.active_module:
            button.configure(bg=GRAPHITE_ACCENT_DARK, activebackground=GRAPHITE_ACCENT)
        else:
            button.configure(bg=GRAPHITE_CARD_SOFT, activebackground=GRAPHITE_BORDER)

    def mark_module_views_stale(self, *module_ids):
        self.stale_module_views.update(module_ids)

    def refresh_active_module_view(self):
        module_id = self.active_module
        if module_id == "dashboard":
            self.refresh_dashboard()
        elif module_id == "types":
            self.refresh_table()
        elif module_id == "spawnabletypes":
            self.refresh_spawnable_table()
        elif module_id == "randompresets":
            self.refresh_random_preset_table()
        elif module_id == "definitions":
            self.refresh_definition_lists()
        elif module_id == "economy_core":
            self.refresh_economycore_view()
        elif module_id == "events":
            self.refresh_event_table()
        elif module_id == "environment":
            self.refresh_environment_view()
        elif module_id == "territories":
            self.refresh_territory_table()
        elif module_id == "ce_zones":
            self.refresh_ce_zones_layers()
            self.draw_ce_zones_map()
        elif module_id == "mapgroupproto":
            self.refresh_mapgroupproto_view()
        elif module_id == "weather":
            self.refresh_weather_preview()
        elif module_id == "configs":
            self.refresh_config_list()
        elif module_id == "profiles":
            self.refresh_profile_config_list()
        self.stale_module_views.discard(module_id)

    def build_placeholder_module(self, module_id, title, body):
        page = ttk.Frame(self.module_content)
        page.grid(row=0, column=0, sticky="nsew")
        page.columnconfigure(0, weight=1)
        page.rowconfigure(0, weight=1)
        panel = ttk.LabelFrame(page, text=title, padding=18)
        panel.grid(row=0, column=0, sticky="nsew")
        panel.columnconfigure(0, weight=1)
        ttk.Label(panel, text=body, style="FieldMuted.TLabel", wraplength=760, justify="left").grid(row=0, column=0, sticky="nw")
        self.module_pages[module_id] = page

    def build_configs_module(self):
        page = ttk.Frame(self.module_content)
        page.grid(row=0, column=0, sticky="nsew")
        page.columnconfigure(0, weight=0, minsize=300)
        page.columnconfigure(1, weight=1)
        page.rowconfigure(1, weight=1)
        self.module_pages["configs"] = page

        header = ttk.LabelFrame(page, text="Config files", padding=10)
        header.grid(row=0, column=0, columnspan=2, sticky="ew", pady=(0, 10))
        header.columnconfigure(1, weight=1)
        ttk.Label(header, textvariable=self.config_path_var, style="FieldMuted.TLabel").grid(row=0, column=0, sticky="w")
        actions = ttk.Frame(header, style="Card.TFrame")
        actions.grid(row=0, column=1, sticky="e")
        self.make_info_button(actions, "configs")
