    def choose_log_analyzer_files(self):
        paths = filedialog.askopenfilenames(
            title="Choose DayZ session log/crash files",
            filetypes=[
                ("DayZ session files", "*.rpt *.adm *.log *.txt *.mdmp"),
                ("Log files", "*.rpt *.adm *.log *.txt"),
                ("Minidumps", "*.mdmp"),
                ("All files", "*.*"),
            ],
            initialdir=self.saved_settings.get("last_dir", str(Path.home())),
        )
        if not paths:
            return
        added = self.add_log_analyzer_paths(paths)
        self.saved_settings["last_dir"] = os.path.dirname(paths[-1])
        save_settings(self.saved_settings)
        self.refresh_log_analyzer_files()
        self.log_analyzer_status_var.set(f"{len(self.log_analyzer_paths)} session file(s) available. Added {added}. Select file(s), then scan.")

    def choose_log_analyzer_folder(self):
        folder = filedialog.askdirectory(
            title="Choose DayZ log/crash folder",
            initialdir=self.saved_settings.get("last_dir", str(Path.home())),
        )
        if not folder:
            return
        root = Path(folder)
        paths = self.discover_log_analyzer_files(root)
        if not paths:
            messagebox.showwarning(APP_TITLE, "No supported DayZ log/crash files were found in that folder.", parent=self)
            return
        root_key = self.normalized_path(root)
        if root_key not in {self.normalized_path(path) for path in self.log_analyzer_roots}:
            self.log_analyzer_roots.append(str(root))
        added = self.add_log_analyzer_paths(paths)
        self.saved_settings["last_dir"] = str(root)
        save_settings(self.saved_settings)
        self.refresh_log_analyzer_files()
        self.log_analyzer_status_var.set(f"{len(self.log_analyzer_paths)} session file(s) available. Added {added} from {root.name}. Select file(s), then scan.")

    def is_supported_log_analyzer_file(self, path):
        if is_ignored_storage_path(path):
            return False
        source = Path(path)
        return source.is_file() and source.suffix.lower() in {".rpt", ".adm", ".log", ".txt", ".mdmp"}

    def discover_log_analyzer_files(self, root):
        try:
            return sorted(
                (str(path) for path in iter_files_ignoring_storage(root) if self.is_supported_log_analyzer_file(path)),
                key=lambda value: value.casefold(),
            )
        except OSError:
            return []

    def add_log_analyzer_paths(self, paths):
        existing_keys = {self.normalized_path(path) for path in self.log_analyzer_paths}
        added = 0
        for path in paths:
            if not self.is_supported_log_analyzer_file(path):
                continue
            key = self.normalized_path(path)
            if key not in existing_keys:
                self.log_analyzer_paths.append(str(path))
                existing_keys.add(key)
                added += 1
        self.log_analyzer_paths.sort(key=lambda value: value.casefold())
        return added

    def log_analyzer_root_for_path(self, path):
        path_obj = Path(path)
        for root in self.log_analyzer_roots:
            root_obj = Path(root)
            try:
                path_obj.resolve().relative_to(root_obj.resolve())
                return root_obj
            except (OSError, ValueError):
                continue
        return None

    def log_analyzer_relative_parts(self, path):
        root = self.log_analyzer_root_for_path(path)
        if root is None:
            return (Path(path).name,)
        try:
            return Path(path).resolve().relative_to(root.resolve()).parts
        except (OSError, ValueError):
            return (Path(path).name,)

    def refresh_log_analyzer_files(self):
        if self.log_analyzer_tree is None:
            return
        self.log_analyzer_tree.delete(*self.log_analyzer_tree.get_children())
        self.log_analyzer_iids = {}
        root_iids: dict[str, str] = {}
        folder_iids: dict[tuple[str, tuple[str, ...]], str] = {}
        root_counts: dict[str, int] = {}
        for path in self.log_analyzer_paths:
            root = self.log_analyzer_root_for_path(path)
            root_key = self.normalized_path(root) if root is not None else "__added_files__"
            root_counts[root_key] = root_counts.get(root_key, 0) + 1

        sorted_roots = []
        for root in self.log_analyzer_roots:
            key = self.normalized_path(root)
            if key in root_counts:
                sorted_roots.append((key, Path(root).name or str(root), str(root)))
        if root_counts.get("__added_files__", 0):
            sorted_roots.append(("__added_files__", "Added files", ""))

        for root_index, (root_key, label, root_path) in enumerate(sorted_roots):
            iid = f"log-root-{root_index}"
            count = root_counts.get(root_key, 0)
            self.log_analyzer_tree.insert("", "end", iid=iid, text=f"{label} ({count})", open=True, values=("", "", "", root_path))
            root_iids[root_key] = iid

        for index, path in enumerate(self.log_analyzer_paths):
            source = Path(path)
            try:
                stat = source.stat()
                size = f"{stat.st_size:,}"
                modified = datetime.fromtimestamp(stat.st_mtime).strftime("%Y-%m-%d %H:%M")
            except OSError:
                size = "-"
                modified = "-"
            root = self.log_analyzer_root_for_path(path)
            root_key = self.normalized_path(root) if root is not None else "__added_files__"
            current_parent = root_iids.get(root_key)
            if current_parent is None:
                current_parent = self.log_analyzer_tree.insert("", "end", text="Added files", open=True)
                root_iids[root_key] = current_parent
            parts = self.log_analyzer_relative_parts(path)
            folder_parts = tuple(parts[:-1])
            for depth in range(1, len(folder_parts) + 1):
                folder_key = (root_key, folder_parts[:depth])
                folder_iid = folder_iids.get(folder_key)
                if folder_iid is None:
                    folder_iid = f"log-folder-{len(folder_iids)}"
                    self.log_analyzer_tree.insert(current_parent, "end", iid=folder_iid, text=folder_parts[depth - 1], open=True, values=("", "", "", ""))
                    folder_iids[folder_key] = folder_iid
                current_parent = folder_iid
            iid = f"log-file-{index}"
            self.log_analyzer_iids[iid] = path
            self.log_analyzer_tree.insert(
                current_parent,
                "end",
                iid=iid,
                text=source.name,
                values=(dayz_text_file_kind(source), size, modified, str(source)),
            )

    def selected_log_analyzer_paths(self):
        if self.log_analyzer_tree is None:
            return []
        selected_paths = []

        def collect_file_paths(iid):
            if iid in self.log_analyzer_iids:
                selected_paths.append(self.log_analyzer_iids[iid])
                return
            for child_iid in self.log_analyzer_tree.get_children(iid):
                collect_file_paths(child_iid)

        for iid in self.log_analyzer_tree.selection():
            collect_file_paths(iid)
        seen = set()
        unique_paths = []
        for path in selected_paths:
            key = self.normalized_path(path)
            if key not in seen:
                seen.add(key)
                unique_paths.append(path)
        return unique_paths

    def on_log_analyzer_selection_changed(self, _event=None):
        selected = self.selected_log_analyzer_paths()
        if selected:
            self.log_analyzer_status_var.set(f"{len(selected)} selected file(s). Scan selected only analyzes those files.")

    def remove_selected_log_analyzer_files(self):
        selected = set(self.selected_log_analyzer_paths())
        if not selected:
            messagebox.showwarning(APP_TITLE, "Select one or more session files to remove.", parent=self)
            return
        selected_keys = {self.normalized_path(path) for path in selected}
        self.log_analyzer_paths = [path for path in self.log_analyzer_paths if self.normalized_path(path) not in selected_keys]
        self.refresh_log_analyzer_files()
        self.log_analyzer_status_var.set(f"{len(self.log_analyzer_paths)} session file(s) selected.")

    def clear_log_analyzer_files(self):
        self.log_analyzer_paths = []
        self.log_analyzer_roots = []
        self.log_analyzer_last_report = ""
        self.refresh_log_analyzer_files()
        self.set_log_analyzer_report("Add DayZ session files or a folder, select one or more files in the tree, then click Scan selected.\n\nSupported: .RPT, .ADM, .log, .txt, .mdmp\n\nDeep selected dump uses Windows Debugging Tools when cdb.exe is installed.\n")
        self.log_analyzer_status_var.set("Add RPT, ADM, script/crash/server logs, or MDMP files from one server session.")

    def open_selected_log_analyzer_folder(self):
        selected = self.selected_log_analyzer_paths()
        if not selected:
            messagebox.showwarning(APP_TITLE, "Select a session file first.", parent=self)
            return
        try:
            os.startfile(str(Path(selected[0]).parent))
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not open folder:\n{exc}", parent=self)

    def set_log_analyzer_report(self, report):
        self.log_analyzer_last_report = report
        if self.log_analyzer_report_text is None:
            return
        self.log_analyzer_report_text.configure(state="normal")
        self.log_analyzer_report_text.delete("1.0", "end")
        self.log_analyzer_report_text.insert("1.0", report)
        self.log_analyzer_report_text.configure(state="disabled")

    def scan_log_analyzer_files(self):
        selected = self.selected_log_analyzer_paths()
        if not selected:
            messagebox.showwarning(APP_TITLE, "Select one or more session files first. Scan only runs on selected files.", parent=self)
            return
        analysis = analyze_dayz_session_logs(selected)
        report = analysis.to_text()
        self.set_log_analyzer_report(report)
        counts = analysis.counts_by_severity()
        if counts["error"]:
            status = "error"
            label = f"Log analysis found {counts['error']} error(s), {counts['warning']} warning(s)."
        elif counts["warning"]:
            status = "warning"
            label = f"Log analysis found {counts['warning']} warning(s)."
        else:
            status = "success"
            label = "Log analysis complete; no obvious critical signatures found."
        self.log_analyzer_status_var.set(label)
        self.log(label, status)
        self.set_status(label, status)

    def deep_analyze_log_minidumps(self):
        dumps = [path for path in self.selected_log_analyzer_paths() if Path(path).suffix.lower() == ".mdmp"]
        if not dumps:
            messagebox.showwarning(APP_TITLE, "Select one or more .mdmp files first. Deep analysis only runs on selected minidumps.", parent=self)
            return
        cdb_path = find_windows_cdb()
        if not cdb_path:
            messagebox.showerror(
                APP_TITLE,
                "Windows Debugging Tools cdb.exe was not found.\n\nInstall Windows Debugging Tools, or add cdb.exe to PATH.",
                parent=self,
            )
            return
        symbol_dir = app_data_dir() / "symbols"
        progress = ProgressWindow(self, "Deep Minidump Analysis", "Running Windows Debugging Tools...", maximum=max(len(dumps), 1))
        results = []
        errors = []

        def worker():
            for index, dump_path in enumerate(dumps, start=1):
                self.after(0, lambda value=index - 1, path=dump_path: progress.update_progress(value=value, detail=f"Analyzing {Path(path).name}"))
                try:
                    result = run_dayz_minidump_debugger(
                        dump_path,
                        cdb_path=cdb_path,
                        symbol_dir=symbol_dir,
                        image_paths=[Path(dump_path).parent],
                        timeout=180,
                    )
                    results.append(result)
                except Exception as exc:
                    errors.append(f"{Path(dump_path).name}: {exc}")
            self.after(0, finish)

        def finish():
            try:
                progress.update_progress(value=len(dumps), detail="Done")
                progress.destroy()
            except tk.TclError:
                pass
            report = create_dayz_debugger_report(results)
            if errors:
                report += "\nDebugger runner errors:\n" + "\n".join(f"- {error}" for error in errors) + "\n"
            self.set_log_analyzer_report(report)
            failed = [result for result in results if not result.success]
            if failed or errors:
                label = f"Deep minidump analysis finished with {len(failed) + len(errors)} issue(s)."
                status = "warning"
            else:
                label = f"Deep minidump analysis complete for {len(results)} dump(s)."
                status = "success"
            self.log_analyzer_status_var.set(label)
            self.log(label, status)
            self.set_status(label, status)

        threading.Thread(target=worker, daemon=True).start()

    def copy_log_analyzer_report(self):
        if not self.log_analyzer_last_report:
            messagebox.showinfo(APP_TITLE, "No log analysis report to copy.", parent=self)
            return
        self.clipboard_clear()
        self.clipboard_append(self.log_analyzer_last_report)
        self.log("Copied log analysis report to clipboard.", "success")

    def export_log_analyzer_report(self):
        if not self.log_analyzer_last_report:
            messagebox.showinfo(APP_TITLE, "No log analysis report to export.", parent=self)
            return
        output_path = filedialog.asksaveasfilename(
            title="Save log analysis report",
            initialdir=self.saved_settings.get("last_dir", str(Path.home())),
            initialfile="DayZ_log_crash_analysis.txt",
            defaultextension=".txt",
            filetypes=[("Text files", "*.txt"), ("All files", "*.*")],
        )
        if not output_path:
            return
        try:
            Path(output_path).write_text(self.log_analyzer_last_report, encoding="utf-8")
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not write report:\n{exc}", parent=self)
            return
        self.saved_settings["last_dir"] = os.path.dirname(output_path)
        save_settings(self.saved_settings)
        self.log(f"Wrote log analysis report: {output_path}", "success")
        self.set_status("Log analysis report saved", "success")

