    def ce_registration_file_type_for_path(self, path):
        if is_ignored_storage_path(path):
            return ""
        try:
            root = ET.parse(path).getroot()
        except (OSError, ET.ParseError):
            return ""
        return {
            "types": "types",
            "spawnabletypes": "spawnabletypes",
            "randompresets": "randompresets",
        }.get(str(root.tag).strip().casefold(), "")

    def discover_unregistered_ce_files(self):
        if self.mission_workspace is None:
            return [], None
        root = Path(self.mission_workspace.root_path)
        economycore_path = root / "cfgeconomycore.xml"
        content = economycore_path.read_text(encoding="utf-8") if economycore_path.is_file() else '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<economycore>\n</economycore>\n'
        try:
            economycore_root = self.parse_economycore_root_from_text(content)
        except (ET.ParseError, ValueError):
            return [], f"cfgeconomycore.xml cannot be updated safely. Fix its root XML first:\n{economycore_path}"
        candidates = []
        for folder in self.economycore_folder_choices(economycore_root):
            folder_path = root / Path(*PurePosixPath(folder).parts)
            if is_ignored_storage_path(folder_path):
                continue
            if not folder_path.is_dir():
                continue
            for path in sorted(folder_path.glob("*.xml"), key=lambda item: item.name.casefold()):
                if not path.is_file():
                    continue
                file_type = self.ce_registration_file_type_for_path(path)
                if not file_type:
                    continue
                filename = path.name
                try:
                    _updated, added = update_cfgeconomycore_file_refs_text(content, folder, [filename], file_type)
                except ValueError:
                    return [], f"cfgeconomycore.xml cannot be updated safely. Fix its root XML first:\n{economycore_path}"
                if added:
                    candidates.append(
                        {
                            "path": str(path),
                            "folder": folder,
                            "filename": filename,
                            "file_type": file_type,
                        }
                    )
        return candidates, None

    def choose_ce_registration_candidates(self, candidates, economycore_path):
        selected_keys = {index for index in range(len(candidates))}
        result = {"selected": None}
        window = tk.Toplevel(self)
        window.title("Fix CE Registrations")
        window.geometry("980x520")
        window.minsize(860, 420)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)

        shell = ttk.Frame(window, padding=14)
        shell.pack(fill="both", expand=True)
        shell.columnconfigure(0, weight=1)
        shell.rowconfigure(2, weight=1)

        ttk.Label(
            shell,
            text="Choose which missing cfgeconomycore.xml registrations to create.",
            style="SectionTitle.TLabel",
        ).grid(row=0, column=0, sticky="w", pady=(0, 6))
        note = "Existing cfgeconomycore.xml will be backed up before writing."
        if not Path(economycore_path).is_file():
            note = "cfgeconomycore.xml does not exist yet. It will be created."
        ttk.Label(
            shell,
            text=note,
            style="FieldMuted.TLabel",
            wraplength=920,
            justify="left",
        ).grid(row=1, column=0, sticky="w", pady=(0, 10))

        columns = ("include", "type", "folder", "file", "path")
        tree = ttk.Treeview(shell, columns=columns, show="headings", selectmode="extended", style="Economy.Treeview")
        tree.grid(row=2, column=0, sticky="nsew")
        tree.heading("include", text="Use")
        tree.heading("type", text="Type")
        tree.heading("folder", text="CE folder")
        tree.heading("file", text="File")
        tree.heading("path", text="Source path")
        tree.column("include", width=60, minwidth=50, anchor="center", stretch=False)
        tree.column("type", width=120, minwidth=110, anchor="w", stretch=False)
        tree.column("folder", width=180, minwidth=140, anchor="w", stretch=False)
        tree.column("file", width=240, minwidth=160, anchor="w", stretch=True)
        tree.column("path", width=320, minwidth=200, anchor="w", stretch=True)
        y_scroll = ttk.Scrollbar(shell, command=tree.yview)
        y_scroll.grid(row=2, column=1, sticky="ns")
        x_scroll = ttk.Scrollbar(shell, command=tree.xview, orient="horizontal")
        x_scroll.grid(row=3, column=0, sticky="ew")
        tree.configure(yscrollcommand=y_scroll.set, xscrollcommand=x_scroll.set)

        def row_values(index):
            candidate = candidates[index]
            mark = "Yes" if index in selected_keys else "No"
            return (
                mark,
                candidate["file_type"],
                candidate["folder"],
                candidate["filename"],
                candidate["path"],
            )

        for index, candidate in enumerate(candidates):
            tree.insert("", "end", iid=str(index), values=row_values(index))

        status_var = tk.StringVar()

        def refresh_status():
            count = len(selected_keys)
            status_var.set(f"{count} of {len(candidates)} registration(s) selected.")
            for index in range(len(candidates)):
                iid = str(index)
                if tree.exists(iid):
                    tree.item(iid, values=row_values(index))

        def selected_indices():
            result_indices = []
            for iid in tree.selection():
                try:
                    result_indices.append(int(iid))
                except ValueError:
                    continue
            return result_indices

        def toggle_selected():
            indices = selected_indices()
            if not indices:
                return
            all_selected = all(index in selected_keys for index in indices)
            for index in indices:
                if all_selected:
                    selected_keys.discard(index)
                else:
                    selected_keys.add(index)
            refresh_status()

        def select_all():
            selected_keys.update(range(len(candidates)))
            refresh_status()

        def select_none():
            selected_keys.clear()
            refresh_status()

        def accept():
            if not selected_keys:
                messagebox.showwarning(APP_TITLE, "Select at least one registration to create.", parent=window)
                return
            result["selected"] = [candidates[index] for index in sorted(selected_keys)]
            window.destroy()

        def cancel():
            result["selected"] = None
            window.destroy()

        tree.bind("<Double-Button-1>", lambda _event: toggle_selected())
        tree.bind("<space>", lambda _event: toggle_selected())
        footer = ttk.Frame(shell)
        footer.grid(row=4, column=0, columnspan=2, sticky="ew", pady=(12, 0))
        footer.columnconfigure(0, weight=1)
        ttk.Label(footer, textvariable=status_var, style="FieldMuted.TLabel").grid(row=0, column=0, sticky="w")
        actions = ttk.Frame(footer)
        actions.grid(row=0, column=1, sticky="e")
        self.make_button(actions, "Select all", select_all, variant="action")
        self.make_button(actions, "Select none", select_none)
        self.make_button(actions, "Create selected registrations", accept, variant="save")
        self.make_button(actions, "Cancel", cancel)
        window.bind("<Escape>", lambda _event: cancel())
        window.bind("<Return>", lambda _event: accept())
        refresh_status()
        first = tree.get_children()
        if first:
            tree.selection_set(first[0])
            tree.focus(first[0])
        window.after(20, lambda: center_window(window, self))
        window.grab_set()
        self.wait_window(window)
        return result["selected"]

    def write_ce_registration_candidates(self, economycore_path, candidates):
        content = economycore_path.read_text(encoding="utf-8") if economycore_path.is_file() else '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<economycore>\n</economycore>\n'
        updated = content
        added_total = 0
        for candidate in candidates:
            updated, added = update_cfgeconomycore_file_refs_text(
                updated,
                candidate["folder"],
                [candidate["filename"]],
                candidate["file_type"],
            )
            added_total += len(added)
        if added_total <= 0 or updated == content:
            return 0
        economycore_path.parent.mkdir(parents=True, exist_ok=True)
        self.ensure_source_writable(economycore_path)
        if economycore_path.is_file():
            self.create_pre_save_backup(economycore_path)
        economycore_path.write_text(updated, encoding="utf-8")
        return added_total

    def fix_ce_registrations_interactive(self):
        if self.mission_workspace is None:
            messagebox.showwarning(APP_TITLE, "Open a mission folder before fixing CE registrations.")
            return False
        root = Path(self.mission_workspace.root_path)
        economycore_path = root / "cfgeconomycore.xml"
        candidates, error = self.discover_unregistered_ce_files()
        if error:
            messagebox.showerror(APP_TITLE, error)
            return False
        if not candidates:
            messagebox.showinfo(APP_TITLE, "No unregistered split Types, Spawnabletypes, or Randompresets XML files were found.")
            return False

        selected_candidates = self.choose_ce_registration_candidates(candidates, economycore_path)
        if selected_candidates is None:
            return False
        if not selected_candidates:
            messagebox.showinfo(APP_TITLE, "No CE registrations selected.")
            return False

        try:
            added_total = self.write_ce_registration_candidates(economycore_path, selected_candidates)
            if added_total <= 0:
                messagebox.showinfo(APP_TITLE, "cfgeconomycore.xml already contains those registrations.")
                return False
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not update cfgeconomycore.xml:\n{exc}")
            return False
        except ValueError as exc:
            messagebox.showerror(APP_TITLE, f"Could not update cfgeconomycore.xml:\n{exc}")
            return False

        self.log(f"Registered {added_total} CE file(s) in cfgeconomycore.xml.", "success")
        self.set_status("CE registrations fixed", "success")
        self.open_mission_folder(str(root))
        return True

    def official_ce_cache_dir(self):
        path = app_data_dir() / "official_ce"
        path.mkdir(parents=True, exist_ok=True)
        return path

    def official_ce_archive_path(self):
        return self.official_ce_cache_dir() / "DayZ-Central-Economy-master.zip"

    def download_official_ce_archive(self, force=False):
        archive_path = self.official_ce_archive_path()
        if archive_path.is_file() and not force:
            return archive_path
        progress = ProgressWindow(self, "Official DayZ CE", "Downloading official DayZ Central Economy sources...", maximum=100)
        temp_path = archive_path.with_suffix(".zip.download")
        try:
            request = urllib.request.Request(OFFICIAL_CE_ZIP_URL, headers={"User-Agent": APP_TITLE})
            with urllib.request.urlopen(request, timeout=120) as response:
                total = int(response.headers.get("Content-Length") or 0)
                downloaded = 0
                temp_path.parent.mkdir(parents=True, exist_ok=True)
                with temp_path.open("wb") as file:
                    while True:
                        chunk = response.read(1024 * 256)
                        if not chunk:
                            break
                        file.write(chunk)
                        downloaded += len(chunk)
                        if total:
                            progress.update_progress(
                                min(100, int(downloaded / total * 100)),
                                100,
                                detail=f"{format_download_size(downloaded)} / {format_download_size(total)}",
                            )
                        else:
                            progress.update_progress(0, 100, detail=format_download_size(downloaded))
            temp_path.replace(archive_path)
            progress.update_progress(100, 100, detail=f"Downloaded {format_download_size(archive_path.stat().st_size)}")
            self.log(f"Downloaded official DayZ CE sources: {archive_path}", "success")
            return archive_path
        except (OSError, urllib.error.URLError, TimeoutError) as exc:
            try:
                temp_path.unlink(missing_ok=True)
            except OSError:
                pass
            raise OSError(f"Could not download official DayZ CE sources from GitHub:\n{exc}") from exc
        finally:
            if progress.winfo_exists():
                progress.destroy()

    def official_mission_templates_in_archive(self, archive_path):
        templates = set()
        with zipfile.ZipFile(archive_path) as archive:
            for info in archive.infolist():
                parts = PurePosixPath(info.filename).parts
                if len(parts) < 2:
                    continue
                candidate = parts[1]
                if candidate.casefold().startswith("dayzoffline."):
                    templates.add(candidate)
        ordered = [template for template in OFFICIAL_MISSION_TEMPLATES if template in templates]
        ordered.extend(sorted(templates - set(ordered), key=str.casefold))
        return ordered

    def extract_official_mission_template(self, archive_path, template_name, output_path):
        if is_ignored_storage_path(archive_path) or is_ignored_storage_path(output_path):
            raise OSError("Access blocked: storage_1 is always ignored.")
        target = Path(output_path)
        if target.exists() and not target.is_dir():
            raise OSError(f"Output path exists and is not a folder:\n{target}")
        if target.exists() and any(target.iterdir()):
            raise OSError(f"Output folder is not empty:\n{target}\n\nChoose a new or empty folder.")
        target.mkdir(parents=True, exist_ok=True)
        template_key = str(template_name).casefold()
        extracted = 0
        with zipfile.ZipFile(archive_path) as archive:
            for info in archive.infolist():
                if info.is_dir():
                    continue
                parts = PurePosixPath(info.filename).parts
                if len(parts) < 3 or parts[1].casefold() != template_key:
                    continue
                relative_parts = parts[2:]
                if not relative_parts:
                    continue
                destination = target.joinpath(*relative_parts)
                destination.parent.mkdir(parents=True, exist_ok=True)
                with archive.open(info) as source, destination.open("wb") as dest:
                    shutil.copyfileobj(source, dest)
                extracted += 1
        if extracted <= 0:
            raise OSError(f"Template {template_name!r} was not found inside official DayZ CE archive.")
        return extracted

    def open_official_mission_creator(self):
        window = tk.Toplevel(self)
        window.title("Create Official DayZ Mission")
        window.geometry("760x420")
        window.minsize(700, 380)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)

        template_var = tk.StringVar(value=OFFICIAL_MISSION_TEMPLATES[0])
        output_parent_var = tk.StringVar(value=self.saved_settings.get("last_mission_create_dir", str(Path.home())))
        folder_name_var = tk.StringVar(value=OFFICIAL_MISSION_TEMPLATES[0])
        status_var = tk.StringVar(value="Downloads official Bohemia DayZ CE sources from GitHub, then copies one mission template.")

        shell = ttk.Frame(window, padding=14)
        shell.pack(fill="both", expand=True)
        shell.columnconfigure(1, weight=1)

        ttk.Label(shell, text="Template", style="FieldName.TLabel").grid(row=0, column=0, sticky="w", padx=(0, 10), pady=(0, 8))
        template_combo = ttk.Combobox(shell, textvariable=template_var, values=OFFICIAL_MISSION_TEMPLATES, state="readonly", style="TCombobox")
        template_combo.grid(row=0, column=1, sticky="ew", pady=(0, 8))
        self.bind_combobox_open_on_click(template_combo)

        ttk.Label(shell, text="Output parent", style="FieldName.TLabel").grid(row=1, column=0, sticky="w", padx=(0, 10), pady=(0, 8))
        ttk.Entry(shell, textvariable=output_parent_var).grid(row=1, column=1, sticky="ew", pady=(0, 8))

        def browse_parent():
            folder = filedialog.askdirectory(title="Choose where to create mission folder", initialdir=output_parent_var.get() or str(Path.home()), parent=window)
            if folder:
                output_parent_var.set(folder)

        browse_button = ttk.Frame(shell, style="Card.TFrame")
        browse_button.grid(row=1, column=2, sticky="e", padx=(8, 0), pady=(0, 8))
        self.make_button(browse_button, "Browse", browse_parent)

        ttk.Label(shell, text="Mission folder", style="FieldName.TLabel").grid(row=2, column=0, sticky="w", padx=(0, 10), pady=(0, 8))
        ttk.Entry(shell, textvariable=folder_name_var).grid(row=2, column=1, sticky="ew", pady=(0, 8))

        info = tk.Text(
            shell,
            height=7,
            wrap="word",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            relief="flat",
            borderwidth=0,
            highlightthickness=1,
            highlightbackground=GRAPHITE_BORDER,
            font=("Segoe UI", 9),
        )
        info.grid(row=3, column=0, columnspan=3, sticky="ew", pady=(6, 10))
        info.insert(
            "1.0",
            f"Source: {OFFICIAL_CE_REPO_URL}\n"
            "Creates a fresh mission folder from official DayZ Central Economy files.\n"
            "Existing non-empty output folders are blocked. License: ADPL-SA, DayZ/Arma use only, non-commercial, share-alike.",
        )
        info.configure(state="disabled")

        ttk.Label(shell, textvariable=status_var, style="FieldMuted.TLabel", wraplength=680, justify="left").grid(row=4, column=0, columnspan=3, sticky="ew", pady=(0, 10))

        def sync_folder_name(_event=None):
            if not folder_name_var.get().strip() or folder_name_var.get().strip() in OFFICIAL_MISSION_TEMPLATES:
                folder_name_var.set(template_var.get())

        template_combo.bind("<<ComboboxSelected>>", sync_folder_name, add="+")

        def refresh_templates():
            try:
                archive_path = self.download_official_ce_archive(force=True)
                templates = self.official_mission_templates_in_archive(archive_path)
            except OSError as exc:
                messagebox.showerror(APP_TITLE, str(exc), parent=window)
                return
            if templates:
                template_combo.configure(values=templates)
                if template_var.get() not in templates:
                    template_var.set(templates[0])
                    folder_name_var.set(templates[0])
                status_var.set(f"Official sources updated. {len(templates)} mission template(s) found.")

        def create_mission():
            template = template_var.get().strip()
            parent = Path(output_parent_var.get().strip())
            folder_name = folder_name_var.get().strip() or template
            if not template:
                messagebox.showwarning(APP_TITLE, "Choose a mission template.", parent=window)
                return
            if not parent:
                messagebox.showwarning(APP_TITLE, "Choose an output parent folder.", parent=window)
                return
            if any(char in folder_name for char in '<>:"/\\|?*'):
                messagebox.showerror(APP_TITLE, "Mission folder name contains invalid Windows filename characters.", parent=window)
                return
            target = parent / folder_name
            try:
                archive_path = self.download_official_ce_archive(force=False)
                extracted = self.extract_official_mission_template(archive_path, template, target)
            except OSError as exc:
                messagebox.showerror(APP_TITLE, f"Mission creation failed:\n{exc}", parent=window)
                return
            self.saved_settings["last_mission_create_dir"] = str(parent)
            save_settings(self.saved_settings)
            self.log(f"Created official DayZ mission from {template}: {target} ({extracted} file(s))", "success")
            status_var.set(f"Created {target}")
            if messagebox.askyesno(APP_TITLE, f"Mission created:\n{target}\n\nOpen it now?", parent=window):
                window.destroy()
                self.open_mission_folder(str(target))

        actions = ttk.Frame(shell)
        actions.grid(row=5, column=0, columnspan=3, sticky="e")
        self.make_button(actions, "Update sources", refresh_templates, variant="action")
        self.make_button(actions, "Create mission", create_mission, variant="save")
        self.make_button(actions, "Close", window.destroy)
        window.bind("<Escape>", lambda _event: window.destroy())
        window.after(20, lambda: center_window(window, self))

