    def add_tool_row(self, parent, row, spec):
        button_frame = ttk.Frame(parent, style="Card.TFrame")
        button_frame.grid(row=row, column=0, sticky="nw", padx=(0, 14), pady=7)
        button = self.make_button(
            button_frame,
            spec["label"],
            spec["command"],
            primary=bool(spec.get("primary")),
            variant="" if spec.get("primary") else "analysis",
            large=True,
            tooltip=spec.get("tooltip", ""),
            width=20,
        )

        body = ttk.Frame(parent, style="Card.TFrame")
        body.grid(row=row, column=1, sticky="ew", pady=7)
        body.columnconfigure(0, weight=1)
        ttk.Label(
            body,
            text=spec["description"],
            style="FieldMuted.TLabel",
            wraplength=760,
            justify="left",
        ).grid(row=0, column=0, sticky="w")
        badge_frame = tk.Frame(body, bg=GRAPHITE_CARD)
        badge_frame.grid(row=1, column=0, sticky="w", pady=(5, 0))
        for badge in spec.get("badges", ()):
            color = self.tool_badge_color(badge)
            label = tk.Label(
                badge_frame,
                text=badge,
                bg=color,
                fg="#ffffff",
                relief="flat",
                borderwidth=0,
                padx=8,
                pady=2,
                font=("Segoe UI", 8, "bold"),
            )
            label.pack(side="left", padx=(0, 6))
        search_text = " ".join([spec["label"], spec["description"], " ".join(spec.get("badges", ()))])
        self.tool_rows.append((button_frame, body, search_text.casefold(), button))

    def tool_badge_color(self, badge):
        badge_key = str(badge).casefold()
        if "write" in badge_key or "overwrite" in badge_key:
            return GRAPHITE_ERROR_DARK
        if "backup" in badge_key:
            return GRAPHITE_BUILDING
        if "preview" in badge_key or "read only" in badge_key or "export" in badge_key:
            return GRAPHITE_PREFLIGHT
        if "dirty" in badge_key:
            return GRAPHITE_WARNING
        return GRAPHITE_CARD_SOFT

    def refresh_tool_rows(self):
        query = self.tool_search_var.get().strip().casefold() if hasattr(self, "tool_search_var") else ""
        for button_frame, body, search_text, _button in getattr(self, "tool_rows", []):
            visible = not query or query in search_text
            if visible:
                button_frame.grid()
                body.grid()
            else:
                button_frame.grid_remove()
                body.grid_remove()

