    def open_ce_zones_project(self):
        if self.ce_zones_dirty_layers and not messagebox.askyesno(APP_TITLE, "Discard unsaved CE Zone layer edits and open another project?"):
            return
        initialdir = ""
        if self.mission_workspace is not None:
            initialdir = self.mission_workspace.root_path
        path = filedialog.askopenfilename(
            title="Open DayZ CE Tool project",
            initialdir=initialdir,
            filetypes=[("DayZ CE Tool project", "*.xml"), ("All files", "*.*")],
        )
        if not path:
            return
        self.load_ce_zones_project(path)

    def load_ce_zones_project(self, path):
        if is_ignored_storage_path(path):
            messagebox.showwarning(APP_TITLE, "storage_1 is always ignored and cannot be opened.")
            return
        project = parse_ce_zones_project(path)
        self.ce_zones_project = project
        self.ce_zones_path = path
        self.ce_zones_cache = {}
        self.ce_zones_dirty_layers = set()
        self.ce_zones_original_masks = {}
        self.ce_zones_undo_stack = []
        self.ce_zones_redo_stack = []
        self.ce_zones_current_paint_action = None
        self.ce_zones_imported_areaflags = None
        self.ce_zones_imported_areaflags_path = ""
        self.ce_zones_layer_vars = {layer.name: tk.BooleanVar(value=layer.visible) for layer in project.layers}
        warning_count = len([issue for issue in project.issues if issue.severity != "error"])
        error_count = len([issue for issue in project.issues if issue.severity == "error"])
        self.ce_zones_summary_var.set(
            f"{Path(path).name}: {len(project.layers)} layer(s), {len(project.usages)} usage flag(s), {len(project.values)} value tier(s)."
        )
        if self.ce_zones_project_map_image_path():
            self.ce_zones_map_source_var.set("CE project map")
        else:
            self.ce_zones_map_source_var.set("Tool selected map")
        if error_count:
            self.ce_zones_status_var.set(f"Loaded with {error_count} error(s) and {warning_count} warning(s).")
        elif warning_count:
            self.ce_zones_status_var.set(f"Loaded with {warning_count} warning(s). Missing layer images will not render.")
        else:
            self.ce_zones_status_var.set("CE Zones project loaded.")
        self.refresh_ce_zones_layers()
        self.invalidate_ce_zones_map(reset_view=True)
        self.draw_ce_zones_map()
        for issue in project.issues[:8]:
            self.log(f"CE Zones: {issue.message}", issue.severity)

    def ce_zones_candidate_names(self):
        names = []
        if self.selected_map_key:
            names.append(self.selected_map_key)
        if self.mission_workspace is not None:
            root_name = Path(self.mission_workspace.root_path).name.casefold()
            names.extend([root_name, root_name.split(".", 1)[-1] if "." in root_name else root_name])
        names.extend(["chernarusplus", "enoch", "livonia", "sakhal"])
        clean = []
        for name in names:
            key = re.sub(r"[^a-z0-9]+", "", str(name or "").casefold())
            if key and key not in clean:
                clean.append(key)
        return clean

    def find_ce_zones_project_near_workspace(self):
        if self.mission_workspace is None:
            return ""
        root = Path(self.mission_workspace.root_path).resolve()
        names = self.ce_zones_candidate_names()
        bases = [root, root.parent, root.parent.parent]
        candidates = []
        for base in bases:
            for ce_dir in (base / "CETool", base / "CE Tool", base / "CE Files"):
                if not ce_dir.exists():
                    continue
                for name in names:
                    candidates.extend([
                        ce_dir / name / f"{name}.xml",
                        ce_dir / name.capitalize() / f"{name}.xml",
                        ce_dir / name.upper() / f"{name}.xml",
                    ])
                try:
                    for xml_path in iter_files_ignoring_storage(ce_dir):
                        if xml_path.suffix.casefold() != ".xml":
                            continue
                        key = re.sub(r"[^a-z0-9]+", "", xml_path.stem.casefold())
                        if key in names and (xml_path.parent / "layers").is_dir():
                            candidates.append(xml_path)
                except OSError:
                    pass
        for candidate in candidates:
            if candidate.is_file():
                return str(candidate)
        return ""

    def auto_load_ce_zones_project(self, force=False):
        if self.ce_zones_dirty_layers:
            return
        if self.ce_zones_project is not None and not force:
            return
        path = self.find_ce_zones_project_near_workspace()
        if not path:
            return
        self.load_ce_zones_project(path)
        self.log(f"Auto-detected CE Zones project: {path}", "success")

    def ce_zone_layer_iid(self, layer_name):
        return "ce-zone-layer-" + hashlib.md5(str(layer_name).encode("utf-8", errors="ignore")).hexdigest()

    def ce_zone_group_iid(self, group_name):
        return "ce-zone-group-" + hashlib.md5(str(group_name).encode("utf-8", errors="ignore")).hexdigest()

    def refresh_ce_zones_layers(self):
        tree = self.ce_zones_layer_tree
        if tree is None:
            return
        tree.delete(*tree.get_children())
        self.ce_zones_layer_iids = {}
        project = self.ce_zones_project
        if project is None:
            return
        for group_name, layers in project.layer_groups().items():
            if not layers:
                continue
            group_iid = self.ce_zone_group_iid(group_name)
            tree.insert("", "end", iid=group_iid, text=group_name, values=("", f"{len(layers)}"), open=group_name in {"Value tiers", "Usage paint"})
            for layer in layers:
                variable = self.ce_zones_layer_vars.setdefault(layer.name, tk.BooleanVar(value=layer.visible))
                state = "Shown" if variable.get() else "Hidden"
                flags = self.ce_zone_layer_flags_text(layer)
                iid = self.ce_zone_layer_iid(layer.name)
                dirty = "* " if layer.name in self.ce_zones_dirty_layers else ""
                tree.insert(group_iid, "end", iid=iid, text=f"{dirty}{layer.display_name()}", values=(state, flags), tags=("ce-visible",) if variable.get() else ("ce-hidden",))
                self.ce_zones_layer_iids[iid] = layer.name

    def ce_zone_layer_flags_text(self, layer):
        if layer.value_flags:
            return f"value {layer.value_flags}"
        if layer.usage_flags:
            return f"usage {layer.usage_flags}"
        return ""

    def selected_ce_zone_layer(self):
        tree = self.ce_zones_layer_tree
        project = self.ce_zones_project
        if tree is None or project is None:
            return None
        selected = tree.selection()
        if not selected:
            return None
        name = self.ce_zones_layer_iids.get(selected[0])
        if not name:
            return None
        for layer in project.layers:
            if layer.name == name:
                return layer
        return None

    def ce_zone_layer_relation(self, layer):
        if layer is None:
            return "", ""
        if layer.kind == "value":
            return "value", layer.display_name()
        if layer.kind in {"usage_paint", "usage_default"}:
            value = layer.display_name()
            if value and value.casefold() != "all":
                return "usage", value
        return "", ""

    def open_ce_zone_matching_types(self):
        layer = self.selected_ce_zone_layer()
        if layer is None:
            messagebox.showwarning(APP_TITLE, "Select a CE Zone layer first.")
            return
        kind, value = self.ce_zone_layer_relation(layer)
        if not kind or not value:
            messagebox.showinfo(APP_TITLE, f"{layer.display_name()} is a reference layer, not a Types relation.")
            return
        usages = self.entries_using_definition(kind, value)
        self.log(f"CE Zones: {layer.name} -> {len(usages)} type entr{'y' if len(usages) == 1 else 'ies'} using {kind} {value}.", "success" if usages else "muted")
        self.apply_usage_filter(kind, value, usages)

    def on_ce_zones_layer_click(self, event=None):
        tree = self.ce_zones_layer_tree
        if tree is None:
            return
        iid = tree.identify_row(event.y) if event is not None else (tree.selection()[0] if tree.selection() else "")
        layer_name = self.ce_zones_layer_iids.get(iid)
        if not layer_name:
            return
        variable = self.ce_zones_layer_vars.get(layer_name)
        if variable is None:
            return
        column = tree.identify_column(event.x) if event is not None else ""
        if column in {"#0", "#1", "#2"}:
            variable.set(not variable.get())
        self.update_ce_zones_layer_row(iid, layer_name)
        self.show_ce_zones_layer_details(layer_name)
        self.invalidate_ce_zones_map()
        self.draw_ce_zones_map()

    def update_ce_zones_layer_row(self, iid, layer_name):
        tree = self.ce_zones_layer_tree
        if tree is None or not tree.exists(iid):
            return
        visible = self.ce_zones_layer_vars.get(layer_name) is not None and self.ce_zones_layer_vars[layer_name].get()
        values = list(tree.item(iid, "values"))
        if values:
            values[0] = "Shown" if visible else "Hidden"
        layer = self.ce_zones_layer_by_name(layer_name)
        text = layer.display_name() if layer is not None else layer_name
        if layer_name in self.ce_zones_dirty_layers:
            text = f"* {text}"
        tree.item(iid, text=text, values=values, tags=("ce-visible",) if visible else ("ce-hidden",))

    def show_ce_zones_layer_details(self, layer_name):
        project = self.ce_zones_project
        if project is None or self.ce_zones_detail_text is None:
            return
        layer = next((item for item in project.layers if item.name == layer_name), None)
        if layer is None:
            return
        text = [
            f"Name: {layer.name}",
            f"Kind: {layer.kind}",
            f"Usage flags: {layer.usage_flags}",
            f"Value flags: {layer.value_flags}",
            f"Visible by default: {'yes' if layer.visible else 'no'}",
            f"Image: {layer.image_path}",
        ]
        self.ce_zones_detail_text.configure(state="normal")
        self.ce_zones_detail_text.delete("1.0", "end")
        self.ce_zones_detail_text.insert("1.0", "\n".join(text))
        self.ce_zones_detail_text.configure(state="disabled")

    def select_ce_zones_layer_target(self, layer_name="", source_path=""):
        self.switch_module("ce_zones")
        project = self.ce_zones_project
        if project is None:
            return False
        name_key = str(layer_name or "").casefold()
        source_key = self.normalized_path(source_path) if source_path else ""
        for layer in project.layers:
            layer_names = {layer.name.casefold(), layer.display_name().casefold()}
            layer_source_key = self.normalized_path(layer.image_path) if layer.image_path else ""
            if name_key and name_key not in layer_names:
                continue
            if source_key and layer_source_key != source_key and self.normalized_path(project.source_path) != source_key:
                continue
            iid = self.ce_zone_layer_iid(layer.name)
            if self.ce_zones_layer_tree is not None and self.ce_zones_layer_tree.exists(iid):
                parent = self.ce_zones_layer_tree.parent(iid)
                if parent:
                    self.ce_zones_layer_tree.item(parent, open=True)
                self.ce_zones_layer_tree.selection_set(iid)
                self.ce_zones_layer_tree.see(iid)
            self.show_ce_zones_layer_details(layer.name)
            return True
        if source_key and self.normalized_path(project.source_path) == source_key:
            return True
        return False

    def select_ce_zones_source_path(self, source_path):
        self.switch_module("ce_zones")
        project = self.ce_zones_project
        if project is None:
            return False
        source_key = self.normalized_path(source_path)
        if self.normalized_path(project.source_path) == source_key:
            return True
        for layer in project.layers:
            if layer.image_path and self.normalized_path(layer.image_path) == source_key:
                return self.select_ce_zones_layer_target(layer.name, source_path=source_path)
        return False

    def ce_zones_project_map_image_path(self):
        project = self.ce_zones_project
        if project is None:
            return ""
        if project.map_file:
            candidate = Path(project.source_path).resolve().parent / project.map_file
            if is_ignored_storage_path(candidate):
                return ""
            if candidate.is_file():
                return str(candidate)
        return ""

    def ce_zones_tool_map_image_path(self):
        if self.selected_map_key:
            map_path, _label, _source = self.resolve_map_image(self.selected_map_key)
            return map_path
        return ""

    def ce_zones_current_map_path(self):
        source = self.ce_zones_map_source_var.get()
        if source == "Tool selected map":
            return self.ce_zones_tool_map_image_path()
        project_path = self.ce_zones_project_map_image_path()
        if project_path:
            return project_path
        return self.ce_zones_tool_map_image_path()

    def ce_zones_file_info(self, path):
        if not path:
            return "none"
        if is_ignored_storage_path(path):
            return "ignored"
        path_obj = Path(path)
        if not path_obj.is_file():
            return f"{path_obj.name}: missing"
        size = path_obj.stat().st_size
        if size >= 1024 * 1024:
            size_text = f"{size / (1024 * 1024):.1f} MB"
        else:
            size_text = f"{max(1, size // 1024)} KB"
        resolution = "unknown"
        if PIL_AVAILABLE:
            try:
                with Image.open(path_obj) as image:
                    resolution = f"{image.width}x{image.height}"
            except Exception:
                resolution = "unreadable"
        return f"{path_obj.name}: {resolution}, {size_text}"

    def update_ce_zones_map_info(self):
        project_path = self.ce_zones_project_map_image_path()
        tool_path = self.ce_zones_tool_map_image_path()
        selected = self.ce_zones_map_source_var.get()
        self.ce_zones_map_info_var.set(
            f"Using {selected}. CE: {self.ce_zones_file_info(project_path)} | Tool: {self.ce_zones_file_info(tool_path)}"
        )

    def invalidate_ce_zones_map(self, reset_view=False):
        self.ce_zones_cache.pop("composite", None)
        self.ce_zones_cache.pop("composite_key", None)
        if reset_view:
            self.ce_zones_map_state.update({"zoom": 0.0, "offset_x": 0.0, "offset_y": 0.0, "panning": False})

    def on_ce_zones_map_source_changed(self, event=None):
        self.invalidate_ce_zones_map(reset_view=True)
        self.draw_ce_zones_map()

    def on_ce_zones_opacity_changed(self, _value=None):
        if self.ce_zones_opacity_after_id:
            self.after_cancel(self.ce_zones_opacity_after_id)
        self.ce_zones_opacity_after_id = self.after(120, self.apply_ce_zones_opacity_change)

    def apply_ce_zones_opacity_change(self):
        self.ce_zones_opacity_after_id = None
        self.invalidate_ce_zones_map()
        self.draw_ce_zones_map()

    def on_ce_zones_brush_size_changed(self, _value=None):
        self.clear_ce_zones_brush_preview()

    def ce_zones_layer_color(self, layer):
        value = int(layer.color or 0)
        return ((value >> 16) & 255, (value >> 8) & 255, value & 255)

    def ce_zones_visible_layers(self):
        project = self.ce_zones_project
        if project is None:
            return []
        return [layer for layer in project.layers if self.ce_zones_layer_vars.get(layer.name) is not None and self.ce_zones_layer_vars[layer.name].get()]

    def load_ce_zones_layer_mask(self, layer):
        cache_key = ("mask", layer.image_path)
        if cache_key in self.ce_zones_cache:
            return self.ce_zones_cache[cache_key]
        if not PIL_AVAILABLE or not layer.image_path or is_ignored_storage_path(layer.image_path) or not Path(layer.image_path).is_file():
            return None
        try:
            if Path(layer.image_path).suffix.casefold() == ".tga":
                width, height, pixels, top_origin = decode_tga_grayscale(Path(layer.image_path).read_bytes())
                mask = Image.frombytes("L", (width, height), pixels)
                if not top_origin:
                    mask = mask.transpose(Image.Transpose.FLIP_TOP_BOTTOM)
            else:
                mask = Image.open(layer.image_path).convert("L")
        except Exception as exc:
            self.log(f"Could not load CE Zone layer {layer.name}: {exc}", "warning")
            return None
        self.ce_zones_cache[cache_key] = mask
        return mask

    def selected_ce_zones_edit_layer(self):
        layer = self.selected_ce_zone_layer()
        if layer is None:
            messagebox.showwarning(APP_TITLE, "Select one CE Zone layer first.")
            return None
        if layer.kind not in {"value", "usage_paint", "usage_default", "water", "keypoint", "attractors", "other"}:
            messagebox.showwarning(APP_TITLE, "This layer cannot be edited.")
            return None
        return layer

    def ce_zones_canvas_to_mask_xy(self, event):
        bounds = self.ce_zones_cache.get("last_render_bounds")
        project = self.ce_zones_project
        if not bounds or project is None:
            return None
        x0, y0, render_w, render_h, image_w, image_h = bounds
        if event.x < x0 or event.y < y0 or event.x > x0 + render_w or event.y > y0 + render_h:
            return None
        px = int((event.x - x0) / max(render_w, 1) * image_w)
        py = int((event.y - y0) / max(render_h, 1) * image_h)
        return min(image_w - 1, max(0, px)), min(image_h - 1, max(0, py))

    def ce_zones_brush_size(self):
        try:
            return max(1, min(1024, int(float(self.ce_zones_brush_size_var.get()))))
        except (TypeError, ValueError):
            return 96

    def mark_ce_zones_layer_dirty(self, layer, mask, original_pixels=None):
        if layer.name not in self.ce_zones_original_masks:
            self.ce_zones_original_masks[layer.name] = original_pixels if original_pixels is not None else mask.tobytes()
        already_dirty = layer.name in self.ce_zones_dirty_layers
        self.ce_zones_dirty_layers.add(layer.name)
        self.update_ce_zones_layer_row(self.ce_zone_layer_iid(layer.name), layer.name)
        if not already_dirty:
            self.update_ce_zones_dirty_status()

    def ce_zones_layer_by_name(self, layer_name):
        project = self.ce_zones_project
        if project is None:
            return None
        return next((layer for layer in project.layers if layer.name == layer_name), None)

    def set_ce_zones_layer_mask_bytes(self, layer_name, size, pixels, original_pixels=None):
        layer = self.ce_zones_layer_by_name(layer_name)
        if layer is None:
            return False
        mask = Image.frombytes("L", size, pixels)
        self.ce_zones_cache[("mask", layer.image_path)] = mask
        original = original_pixels if original_pixels is not None else self.ce_zones_original_masks.get(layer.name)
        if original is not None and pixels == original:
            self.ce_zones_dirty_layers.discard(layer.name)
            self.ce_zones_original_masks.pop(layer.name, None)
            self.update_ce_zones_layer_row(self.ce_zone_layer_iid(layer.name), layer.name)
        else:
            self.mark_ce_zones_layer_dirty(layer, mask, original_pixels=original)
        self.invalidate_ce_zones_map()
        self.update_ce_zones_dirty_status()
        self.draw_ce_zones_map()
        return True

    def push_ce_zones_paint_action(self):
        action = self.ce_zones_current_paint_action
        self.ce_zones_current_paint_action = None
        if not action:
            return
        layer = self.ce_zones_layer_by_name(action["layer_name"])
        if layer is None:
            return
        mask = self.load_ce_zones_layer_mask(layer)
        if mask is None:
            return
        after_pixels = mask.tobytes()
        if after_pixels == action["before"]:
            return
        action["after"] = after_pixels
        self.ce_zones_undo_stack.append(action)
        self.ce_zones_redo_stack.clear()
        if len(self.ce_zones_undo_stack) > 100:
            self.ce_zones_undo_stack.pop(0)

    def undo_ce_zones_paint(self):
        if not self.ce_zones_undo_stack:
            self.ce_zones_status_var.set("No CE Zones paint action to undo.")
            return
        action = self.ce_zones_undo_stack.pop()
        if self.set_ce_zones_layer_mask_bytes(action["layer_name"], action["size"], action["before"], original_pixels=action["before"]):
            self.ce_zones_redo_stack.append(action)
            self.ce_zones_status_var.set(f"Undid paint stroke on {action['display_name']}.")

    def redo_ce_zones_paint(self):
        if not self.ce_zones_redo_stack:
            self.ce_zones_status_var.set("No CE Zones paint action to redo.")
            return
        action = self.ce_zones_redo_stack.pop()
        if self.set_ce_zones_layer_mask_bytes(action["layer_name"], action["size"], action["after"], original_pixels=action["before"]):
            self.ce_zones_undo_stack.append(action)
            self.ce_zones_status_var.set(f"Redid paint stroke on {action['display_name']}.")

    def update_ce_zones_dirty_status(self):
        if self.ce_zones_dirty_layers:
            self.ce_zones_status_var.set(f"{len(self.ce_zones_dirty_layers)} edited CE layer(s). Save layer writes selected mask.")
            self.workspace_validation_stale = True
        else:
            self.ce_zones_status_var.set("No unsaved CE layer edits.")
        self.refresh_dashboard()

    def draw_ce_zones_paint_preview(self, event, layer):
        canvas = self.ce_zones_canvas
        bounds = self.ce_zones_cache.get("last_render_bounds")
        if canvas is None or not bounds:
            return
        _x0, _y0, render_w, _render_h, image_w, _image_h = bounds
        width = max(3, int((self.ce_zones_brush_size() / max(image_w, 1)) * render_w))
        mode = self.ce_zones_edit_mode_var.get()
        previous = self.ce_zones_last_paint_canvas_xy or (event.x, event.y)
        if mode == "Erase":
            item = canvas.create_line(
                previous[0],
                previous[1],
                event.x,
                event.y,
                fill="#f0d0d0",
                width=max(2, width // 3),
                capstyle=tk.ROUND,
                smooth=True,
            )
        else:
            color = "#%02x%02x%02x" % self.ce_zones_layer_color(layer)
            item = canvas.create_line(
                previous[0],
                previous[1],
                event.x,
                event.y,
                fill=color,
                width=width,
                capstyle=tk.ROUND,
                smooth=True,
            )
        self.ce_zones_last_paint_canvas_xy = (event.x, event.y)
        self.ce_zones_paint_preview_items.append(item)

    def clear_ce_zones_paint_preview(self):
        canvas = self.ce_zones_canvas
        if canvas is None:
            return
        for item in self.ce_zones_paint_preview_items:
            canvas.delete(item)
        self.ce_zones_paint_preview_items = []

    def draw_ce_zones_brush_preview(self, event):
        canvas = self.ce_zones_canvas
        bounds = self.ce_zones_cache.get("last_render_bounds")
        if canvas is None or not bounds:
            return
        mode = self.ce_zones_edit_mode_var.get()
        if mode not in {"Paint", "Erase"} or self.ce_zones_painting or self.ce_zones_canvas_to_mask_xy(event) is None:
            self.clear_ce_zones_brush_preview()
            return
        _x0, _y0, render_w, _render_h, image_w, _image_h = bounds
        radius = max(2, int((self.ce_zones_brush_size() / max(image_w, 1)) * render_w / 2))
        layer = self.selected_ce_zone_layer()
        color = "#f0d0d0" if mode == "Erase" or layer is None else "#%02x%02x%02x" % self.ce_zones_layer_color(layer)
        box = (event.x - radius, event.y - radius, event.x + radius, event.y + radius)
        if self.ce_zones_brush_preview_item is None:
            self.ce_zones_brush_preview_item = canvas.create_oval(*box, outline=color, width=2, dash=(4, 3))
        else:
            canvas.coords(self.ce_zones_brush_preview_item, *box)
            canvas.itemconfigure(self.ce_zones_brush_preview_item, outline=color)
        canvas.tag_raise(self.ce_zones_brush_preview_item)

    def clear_ce_zones_brush_preview(self, _event=None):
        canvas = self.ce_zones_canvas
        if canvas is not None and self.ce_zones_brush_preview_item is not None:
            canvas.delete(self.ce_zones_brush_preview_item)
        self.ce_zones_brush_preview_item = None

    def paint_ce_zones_layer_at_event(self, event, layer=None, preview=True):
        mode = self.ce_zones_edit_mode_var.get()
        if mode not in {"Paint", "Erase"}:
            return False
        layer = layer or self.selected_ce_zones_edit_layer()
        if layer is None:
            return False
        coords = self.ce_zones_canvas_to_mask_xy(event)
        if coords is None:
            return False
        mask = self.load_ce_zones_layer_mask(layer)
        project = self.ce_zones_project
        if mask is None and project is not None:
            size = max(1, int(project.layer_size or 4096))
            mask = Image.new("L", (size, size), 0)
            self.ce_zones_cache[("mask", layer.image_path)] = mask
        if mask is None:
            return False
        before_pixels = mask.tobytes()
        if self.ce_zones_current_paint_action is None:
            self.ce_zones_current_paint_action = {
                "layer_name": layer.name,
                "display_name": layer.display_name(),
                "size": mask.size,
                "before": before_pixels,
                "after": before_pixels,
            }
        x, y = coords
        bounds = self.ce_zones_cache.get("last_render_bounds", (0, 0, 0, 0, mask.width, mask.height))
        source_w, source_h = bounds[4], bounds[5]
        if mask.size != (source_w, source_h):
            x = int(x / max(source_w, 1) * mask.width)
            y = int(y / max(source_h, 1) * mask.height)
        radius = self.ce_zones_brush_size() // 2
        draw = ImageDraw.Draw(mask)
        value = 255 if mode == "Paint" else 0
        previous_mask_xy = self.ce_zones_last_paint_mask_xy or (x, y)
        draw.line((previous_mask_xy[0], previous_mask_xy[1], x, y), fill=value, width=max(1, radius * 2))
        draw.ellipse((x - radius, y - radius, x + radius, y + radius), fill=value)
        self.ce_zones_last_paint_mask_xy = (x, y)
        self.mark_ce_zones_layer_dirty(layer, mask, original_pixels=before_pixels)
        if preview:
            self.draw_ce_zones_paint_preview(event, layer)
        return True

    def on_ce_zones_map_press(self, event):
        if self.ce_zones_edit_mode_var.get() in {"Paint", "Erase"}:
            self.clear_ce_zones_brush_preview()
            self.ce_zones_active_paint_layer = self.selected_ce_zones_edit_layer()
            self.ce_zones_last_paint_canvas_xy = (event.x, event.y)
            self.ce_zones_last_paint_mask_xy = None
            self.ce_zones_painting = self.ce_zones_active_paint_layer is not None and self.paint_ce_zones_layer_at_event(event, self.ce_zones_active_paint_layer)
            return
        state = self.ce_zones_map_state
        state["panning"] = True
        state["pan_moved"] = False
        state["last_x"] = event.x
        state["last_y"] = event.y

    def on_ce_zones_map_motion(self, event):
        self.draw_ce_zones_brush_preview(event)

    def on_ce_zones_map_drag(self, event):
        if self.ce_zones_painting:
            self.paint_ce_zones_layer_at_event(event, self.ce_zones_active_paint_layer)
            return
        state = self.ce_zones_map_state
        if state.get("panning"):
            dx = event.x - int(state.get("last_x", event.x))
            dy = event.y - int(state.get("last_y", event.y))
            if dx or dy:
                state["pan_moved"] = True
            state["offset_x"] = float(state.get("offset_x", 0.0)) + dx
            state["offset_y"] = float(state.get("offset_y", 0.0)) + dy
            state["last_x"] = event.x
            state["last_y"] = event.y
            self.draw_ce_zones_map()

    def on_ce_zones_map_release(self, event):
        if self.ce_zones_painting:
            self.ce_zones_painting = False
            self.ce_zones_active_paint_layer = None
            self.ce_zones_last_paint_canvas_xy = None
            self.ce_zones_last_paint_mask_xy = None
            self.clear_ce_zones_paint_preview()
            self.push_ce_zones_paint_action()
            self.invalidate_ce_zones_map()
            self.draw_ce_zones_map()
            self.draw_ce_zones_brush_preview(event)
            return
        if self.ce_zones_map_state.get("panning"):
            moved = bool(self.ce_zones_map_state.get("pan_moved"))
            self.ce_zones_map_state["panning"] = False
            self.ce_zones_map_state["pan_moved"] = False
            if moved:
                return
        self.on_ce_zones_map_click(event)

    def on_ce_zones_map_mousewheel(self, event):
        if not PIL_AVAILABLE or self.ce_zones_project is None:
            return
        composite, _rendered = self.build_ce_zones_composite()
        if composite is None:
            return
        state = self.ce_zones_map_state
        if float(state.get("zoom") or 0.0) <= 0:
            self.draw_ce_zones_map()
        old_zoom = max(float(state.get("zoom") or 1.0), 0.0001)
        factor = 1.15 if event.delta > 0 else 1 / 1.15
        new_zoom = max(0.03, min(20.0, old_zoom * factor))
        if new_zoom == old_zoom:
            return
        state["offset_x"] = event.x - (event.x - float(state.get("offset_x", 0.0))) * (new_zoom / old_zoom)
        state["offset_y"] = event.y - (event.y - float(state.get("offset_y", 0.0))) * (new_zoom / old_zoom)
        state["zoom"] = new_zoom
        self.draw_ce_zones_map()

    def ce_zones_layer_change_report(self, layer, old_pixels, new_pixels):
        changed = sum(1 for old, new in zip(old_pixels, new_pixels) if old != new)
        painted = sum(1 for old, new in zip(old_pixels, new_pixels) if old == 0 and new > 0)
        erased = sum(1 for old, new in zip(old_pixels, new_pixels) if old > 0 and new == 0)
        return "\n".join([
            "RaG Economy Manager CE Zones change report",
            "",
            f"Layer: {layer.name}",
            f"File: {layer.image_path}",
            f"Changed pixels: {changed}",
            f"Painted pixels: {painted}",
            f"Erased pixels: {erased}",
        ])

    def save_selected_ce_zone_layer(self):
        layer = self.selected_ce_zones_edit_layer()
        if layer is None:
            return
        mask = self.load_ce_zones_layer_mask(layer)
        if mask is None:
            messagebox.showwarning(APP_TITLE, "Selected layer has no mask loaded.")
            return
        if layer.name not in self.ce_zones_dirty_layers:
            messagebox.showinfo(APP_TITLE, "Selected CE Zone layer has no unsaved edits.")
            return
        output_path = Path(layer.image_path)
        if is_ignored_storage_path(output_path):
            messagebox.showwarning(APP_TITLE, "storage_1 is always ignored and cannot be saved.")
            return
        old_pixels = self.ce_zones_original_masks.get(layer.name, mask.tobytes())
        try:
            output_path.parent.mkdir(parents=True, exist_ok=True)
            if output_path.is_file():
                self.create_pre_save_backup(output_path)
            output_path.write_bytes(encode_tga_grayscale(mask.width, mask.height, mask.tobytes(), top_origin=True))
            report = self.ce_zones_layer_change_report(layer, old_pixels, mask.tobytes())
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            report_name = re.sub(r"[^A-Za-z0-9_.-]+", "_", layer.name).strip("._") or "ce_zone_layer"
            report_path = self.local_change_report_dir() / f"{timestamp}_{report_name}.ce_zones_change_report.txt"
            report_path.write_text(report, encoding="utf-8")
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not save CE Zone layer:\n{exc}")
            return
        self.ce_zones_dirty_layers.discard(layer.name)
        self.ce_zones_original_masks.pop(layer.name, None)
        self.update_ce_zones_layer_row(self.ce_zone_layer_iid(layer.name), layer.name)
        self.ce_zones_status_var.set(f"Saved {layer.display_name()} and wrote change report.")
        self.log(f"Saved CE Zone layer: {output_path}", "success")

    def export_ce_zones_layer_set(self):
        project = self.ce_zones_project
        if project is None:
            messagebox.showwarning(APP_TITLE, "Open a CE Zones project first.")
            return
        target = filedialog.askdirectory(title="Export CE Zones layer set")
        if not target:
            return
        if is_ignored_storage_path(target):
            messagebox.showwarning(APP_TITLE, "storage_1 is always ignored and cannot be used.")
            return
        target_path = Path(target)
        try:
            target_layers = target_path / "layers"
            target_layers.mkdir(parents=True, exist_ok=True)
            shutil.copy2(project.source_path, target_path / Path(project.source_path).name)
            map_path = Path(project.source_path).resolve().parent / project.map_file if project.map_file else None
            if map_path and not is_ignored_storage_path(map_path) and map_path.is_file():
                shutil.copy2(map_path, target_path / map_path.name)
            copied = 0
            for layer in project.layers:
                source = Path(layer.image_path)
                if source.is_file():
                    shutil.copy2(source, target_layers / source.name)
                    copied += 1
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not export CE Zones layer set:\n{exc}")
            return
        self.log(f"Exported CE Zones layer set to {target_path} ({copied} layer file(s)).", "success")

    def import_ce_zones_layer_set(self):
        if self.ce_zones_dirty_layers and not messagebox.askyesno(APP_TITLE, "Discard unsaved CE Zone layer edits and import another layer set?"):
            return
        folder = filedialog.askdirectory(title="Import CE Zones layer set")
        if not folder:
            return
        if is_ignored_storage_path(folder):
            messagebox.showwarning(APP_TITLE, "storage_1 is always ignored and cannot be opened.")
            return
        root = Path(folder)
        xml_candidates = sorted([path for path in root.glob("*.xml") if (root / "layers").is_dir()])
        if not xml_candidates:
            messagebox.showwarning(APP_TITLE, "No CE Tool XML found in selected folder.")
            return
        self.load_ce_zones_project(str(xml_candidates[0]))

    def ce_zones_composite_key(self):
        visible = tuple(layer.name for layer in self.ce_zones_visible_layers())
        return (self.ce_zones_current_map_path(), int(self.ce_zones_layer_opacity_var.get()), visible)

    def build_ce_zones_composite(self):
        project = self.ce_zones_project
        if project is None or not PIL_AVAILABLE:
            return None, 0
        key = self.ce_zones_composite_key()
        if self.ce_zones_cache.get("composite_key") == key and self.ce_zones_cache.get("composite") is not None:
            return self.ce_zones_cache["composite"], int(self.ce_zones_cache.get("composite_rendered", 0))

        base_size = max(project.layer_size or 0, 1024)
        map_path = self.ce_zones_current_map_path()
        base_stat = None
        if map_path:
            try:
                stat = Path(map_path).stat()
                base_stat = (stat.st_mtime_ns, stat.st_size)
            except OSError:
                base_stat = None
        base_key = ("ce_zones_base", map_path or "", project.layer_size or 0, base_stat)
        base = self.ce_zones_cache.get(base_key)
        if base is None:
            try:
                if map_path:
                    base = Image.open(map_path).convert("RGB")
                else:
                    base = Image.new("RGB", (base_size, base_size), GRAPHITE_FIELD)
            except Exception as exc:
                self.log(f"Could not load CE Zones map image: {exc}", "warning")
                base = Image.new("RGB", (base_size, base_size), GRAPHITE_FIELD)

            if project.layer_size and base.size != (project.layer_size, project.layer_size):
                base = base.resize((project.layer_size, project.layer_size), Image.Resampling.BILINEAR)
            self.ce_zones_cache[base_key] = base

        composite = base.convert("RGBA")
        alpha = max(0, min(100, int(self.ce_zones_layer_opacity_var.get()))) / 100.0
        if alpha <= 0:
            self.ce_zones_cache["composite_key"] = key
            self.ce_zones_cache["composite"] = composite
            self.ce_zones_cache["composite_rendered"] = 0
            return composite, 0

        rendered = 0
        for layer in self.ce_zones_visible_layers():
            mask = self.load_ce_zones_layer_mask(layer)
            if mask is None:
                continue
            if mask.size != composite.size:
                mask = mask.resize(composite.size, Image.Resampling.NEAREST)
            color = self.ce_zones_layer_color(layer)
            binary_mask = mask.point(lambda px: 255 if px > 0 else 0)
            layer_alpha = binary_mask.point(lambda px: int(px * alpha))
            overlay = Image.new("RGBA", composite.size, (*color, 0))
            overlay.putalpha(layer_alpha)
            composite = Image.alpha_composite(composite, overlay)
            rendered += 1

        self.ce_zones_cache["composite_key"] = key
        self.ce_zones_cache["composite"] = composite
        self.ce_zones_cache["composite_rendered"] = rendered
        return composite, rendered

    def reset_ce_zones_map_view(self):
        self.ce_zones_map_state.update({"zoom": 0.0, "offset_x": 0.0, "offset_y": 0.0, "panning": False})
        self.draw_ce_zones_map()

    def clamp_ce_zones_map_view(self, canvas_w, canvas_h, image_w, image_h):
        state = self.ce_zones_map_state
        zoom = max(float(state.get("zoom") or 0.0), 0.0001)
        map_w = image_w * zoom
        map_h = image_h * zoom
        if map_w <= canvas_w:
            state["offset_x"] = (canvas_w - map_w) / 2
        else:
            state["offset_x"] = min(0.0, max(canvas_w - map_w, float(state.get("offset_x", 0.0))))
        if map_h <= canvas_h:
            state["offset_y"] = (canvas_h - map_h) / 2
        else:
            state["offset_y"] = min(0.0, max(canvas_h - map_h, float(state.get("offset_y", 0.0))))

    def on_ce_zones_map_configure(self, event=None):
        if self.active_module != "ce_zones":
            return
        if self.ce_zones_map_state.get("zoom", 0.0) <= 0:
            self.draw_ce_zones_map()

    def draw_ce_zones_map(self):
        canvas = self.ce_zones_canvas
        project = self.ce_zones_project
        if canvas is None:
            return
        canvas.delete("all")
        self.ce_zones_paint_preview_items = []
        self.ce_zones_brush_preview_item = None
        width = max(canvas.winfo_width(), 320)
        height = max(canvas.winfo_height(), 240)
        if project is None:
            canvas.create_text(width / 2, height / 2, text="Open a CE Tool project XML.", fill=GRAPHITE_MUTED, font=("Segoe UI", 12, "bold"))
            return
        if not PIL_AVAILABLE:
            canvas.create_text(width / 2, height / 2, text="Install Pillow to render CE Zone layers.", fill=GRAPHITE_MUTED, font=("Segoe UI", 12, "bold"))
            return

        self.update_ce_zones_map_info()
        composite, rendered = self.build_ce_zones_composite()
        if composite is None:
            return
        image_w, image_h = composite.size
        state = self.ce_zones_map_state
        if float(state.get("zoom") or 0.0) <= 0:
            state["zoom"] = max(0.05, min(width / image_w, height / image_h) * 0.94)
            state["offset_x"] = (width - image_w * state["zoom"]) / 2
            state["offset_y"] = (height - image_h * state["zoom"]) / 2
        self.clamp_ce_zones_map_view(width, height, image_w, image_h)
        zoom = max(float(state["zoom"]), 0.0001)
        left = max(0.0, -state["offset_x"] / zoom)
        top = max(0.0, -state["offset_y"] / zoom)
        right = min(image_w, (width - state["offset_x"]) / zoom)
        bottom = min(image_h, (height - state["offset_y"]) / zoom)
        if right <= left or bottom <= top:
            self.ce_zones_cache["last_render_bounds"] = (state["offset_x"], state["offset_y"], image_w * zoom, image_h * zoom, image_w, image_h)
            return
        crop_box = (int(left), int(top), max(int(right), int(left) + 1), max(int(bottom), int(top) + 1))
        crop = composite.crop(crop_box)
        render_w = max(1, int(crop.width * zoom))
        render_h = max(1, int(crop.height * zoom))
        image = crop.resize((render_w, render_h), Image.Resampling.BILINEAR)
        self.ce_zones_render_image = ImageTk.PhotoImage(image)
        x = state["offset_x"] + crop_box[0] * zoom
        y = state["offset_y"] + crop_box[1] * zoom
        canvas.create_image(x, y, anchor="nw", image=self.ce_zones_render_image)
        full_x = state["offset_x"]
        full_y = state["offset_y"]
        full_w = image_w * zoom
        full_h = image_h * zoom
        canvas.create_rectangle(full_x, full_y, full_x + full_w, full_y + full_h, outline=GRAPHITE_BORDER)
        self.ce_zones_cache["last_render_bounds"] = (full_x, full_y, full_w, full_h, image_w, image_h)
        self.ce_zones_status_var.set(f"Rendered {rendered}/{len(self.ce_zones_visible_layers())} visible layer(s). Zoom {zoom:.2f}x.")

    def on_ce_zones_map_click(self, event):
        project = self.ce_zones_project
        if project is None:
            return
        bounds = self.ce_zones_cache.get("last_render_bounds")
        if not bounds:
            return
        x0, y0, render_w, render_h, image_w, image_h = bounds
        if event.x < x0 or event.y < y0 or event.x > x0 + render_w or event.y > y0 + render_h:
            return
        px = int((event.x - x0) / max(render_w, 1) * image_w)
        py = int((event.y - y0) / max(render_h, 1) * image_h)
        world_size = float(project.world_size or image_w)
        world_x = px / max(image_w, 1) * world_size
        world_z = world_size - (py / max(image_h, 1) * world_size)
        hits = []
        relation_hits = []
        for layer in self.ce_zones_visible_layers():
            mask = self.load_ce_zones_layer_mask(layer)
            if mask is None:
                continue
            sx = min(mask.width - 1, max(0, int(px / max(image_w, 1) * mask.width)))
            sy = min(mask.height - 1, max(0, int(py / max(image_h, 1) * mask.height)))
            if mask.getpixel((sx, sy)) > 0:
                hits.append(layer.display_name())
                kind, value = self.ce_zone_layer_relation(layer)
                if kind and value:
                    count = len(self.entries_using_definition(kind, value))
                    relation_hits.append(f"{kind} {value}: {count} type(s)")
        hit_text = ", ".join(hits[:8]) if hits else "no visible layer"
        if len(hits) > 8:
            hit_text += f" (+{len(hits) - 8})"
        relation_text = "; ".join(relation_hits[:4])
        if len(relation_hits) > 4:
            relation_text += f"; +{len(relation_hits) - 4} more"
        suffix = f" | {relation_text}" if relation_text else ""
        self.ce_zones_status_var.set(f"X {world_x:.1f}, Z {world_z:.1f}: {hit_text}{suffix}")

    def show_all_ce_zones_layers(self):
        for variable in self.ce_zones_layer_vars.values():
            variable.set(True)
        self.refresh_ce_zones_layers()
        self.invalidate_ce_zones_map()
        self.draw_ce_zones_map()

    def hide_all_ce_zones_layers(self):
        for variable in self.ce_zones_layer_vars.values():
            variable.set(False)
        self.refresh_ce_zones_layers()
        self.invalidate_ce_zones_map()
        self.draw_ce_zones_map()

    def default_areaflags_map_path(self):
        if self.ce_zones_project is None:
            return ""
        root = Path(self.ce_zones_project.source_path).resolve().parent
        for candidate in (root / "map" / "areaflags.map", root / "map" / f"{Path(self.ce_zones_project.source_path).stem}.map"):
            if candidate.is_file():
                return str(candidate)
        return ""

    def choose_areaflags_map_path(self, title, save=False):
        initial = self.default_areaflags_map_path()
        options = {
            "title": title,
            "initialdir": str(Path(initial).parent if initial else Path(self.ce_zones_path).parent if self.ce_zones_path else Path.home()),
            "initialfile": Path(initial).name if initial else "areaflags.map",
            "filetypes": [("CE exported map", "*.map"), ("All files", "*.*")],
        }
        if save:
            return filedialog.asksaveasfilename(defaultextension=".map", **options)
        return filedialog.askopenfilename(**options)

    def import_areaflags_map(self):
        if self.ce_zones_project is None:
            messagebox.showwarning(APP_TITLE, "Open a CE Zones project first.")
            return
        if not PIL_AVAILABLE:
            messagebox.showwarning(APP_TITLE, "Install Pillow to import areaflags.map into editable layer masks.")
            return
        path = self.choose_areaflags_map_path("Import exported areaflags.map")
        if not path:
            return
        try:
            area_map = parse_areaflags_map(path)
        except (OSError, ValueError) as exc:
            messagebox.showerror(APP_TITLE, f"Could not read areaflags.map:\n\n{exc}")
            return
        import_usage = messagebox.askyesno(
            APP_TITLE,
            "Import experimental usage flag layers too?\n\n"
            "Value tier layers are verified against the exported map format.\n"
            "Usage paint/default layers from DayZ CE Editor do not always match the exported binary map cleanly, and can look oversized or misplaced.\n\n"
            "Choose No to import only verified value tier layers and preserve usage flags unchanged for export.",
            default=messagebox.NO,
        )
        imported = 0
        skipped = 0
        self.ce_zones_cache = {key: value for key, value in self.ce_zones_cache.items() if not (isinstance(key, tuple) and key[0] == "mask")}
        for layer in self.ce_zones_project.layers:
            pixels = b""
            try:
                if layer.kind == "value" and layer.value_flags:
                    pixels = area_map.value_mask(layer.value_flags)
                elif import_usage and layer.usage_flags:
                    pixels = area_map.usage_mask(layer.usage_flags)
            except ValueError:
                pixels = b""
            if not pixels:
                skipped += 1
                continue
            self.ce_zones_cache[("mask", layer.image_path)] = Image.frombytes("L", (area_map.width, area_map.height), pixels)
            imported += 1
        self.ce_zones_imported_areaflags = area_map
        self.ce_zones_imported_areaflags_path = path
        self.ce_zones_dirty_layers = set()
        self.ce_zones_original_masks = {}
        self.ce_zones_undo_stack = []
        self.ce_zones_redo_stack = []
        self.refresh_ce_zones_layers()
        self.invalidate_ce_zones_map(reset_view=True)
        self.draw_ce_zones_map()
        scope = "value and usage" if import_usage else "verified value"
        self.ce_zones_status_var.set(f"Imported {imported} {scope} layer mask(s) from {Path(path).name}; preserved original usage bits for export.")
        self.log(f"Imported areaflags.map: {path}", "success")

    def export_areaflags_map(self):
        if self.ce_zones_project is None:
            messagebox.showwarning(APP_TITLE, "Open a CE Zones project first.")
            return
        if not PIL_AVAILABLE:
            messagebox.showwarning(APP_TITLE, "Install Pillow to export areaflags.map from layer masks.")
            return
        path = self.choose_areaflags_map_path("Export areaflags.map", save=True)
        if not path:
            return
        project = self.ce_zones_project
        base_map = self.ce_zones_imported_areaflags
        if base_map is None:
            size = int(project.layer_size or 4096)
            world_size = int(project.world_size or size)
            empty = bytes(size * size)
            base_map = AreaFlagsMap("", size, size, world_size, world_size, 32, 0, (empty, empty, empty, empty), empty)
        width, height = base_map.width, base_map.height
        usage_planes = base_map.usage_planes
        value_plane = base_map.value_plane
        written_layers = 0
        for layer in project.layers:
            if not layer.value_flags and not layer.usage_flags:
                continue
            mask = self.load_ce_zones_layer_mask(layer)
            if mask is None:
                continue
            if mask.size != (width, height):
                mask = mask.resize((width, height), Image.Resampling.NEAREST)
            pixels = mask.tobytes()
            if layer.kind == "value" and layer.value_flags:
                value_plane = set_bit_from_mask_on_plane(value_plane, width, height, layer.value_flags, pixels)
                written_layers += 1
            elif layer.usage_flags:
                usage_planes = set_usage_mask_on_planes(usage_planes, width, height, layer.usage_flags, pixels)
                written_layers += 1
        output_map = AreaFlagsMap(str(path), width, height, base_map.world_x, base_map.world_z, base_map.cell_size, base_map.reserved, usage_planes, value_plane)
        if is_ignored_storage_path(path):
            messagebox.showwarning(APP_TITLE, "storage_1 is always ignored and cannot be used.")
            return
        try:
            output_path = Path(path)
            output_path.parent.mkdir(parents=True, exist_ok=True)
            if output_path.is_file():
                self.create_pre_save_backup(output_path)
            output_path.write_bytes(encode_areaflags_map(output_map))
        except (OSError, ValueError) as exc:
            messagebox.showerror(APP_TITLE, f"Could not export areaflags.map:\n\n{exc}")
            return
        self.ce_zones_imported_areaflags = output_map
        self.ce_zones_imported_areaflags_path = str(path)
        self.ce_zones_status_var.set(f"Exported areaflags.map with {written_layers} mapped layer(s).")
        self.log(f"Exported areaflags.map: {path}", "success")

    def show_text_window(self, title, text, width=780, height=520):
        window = tk.Toplevel(self)
        window.title(title)
        window.geometry(f"{width}x{height}")
        window.minsize(560, 360)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)
        frame = ttk.Frame(window, padding=12)
        frame.pack(fill="both", expand=True)
        frame.rowconfigure(0, weight=1)
        frame.columnconfigure(0, weight=1)
        text_widget = tk.Text(
            frame,
            wrap="word",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            insertbackground=GRAPHITE_TEXT,
            relief="flat",
            borderwidth=0,
            highlightthickness=1,
            highlightbackground=GRAPHITE_BORDER,
            highlightcolor=GRAPHITE_ACCENT,
            font=("Segoe UI", 10),
        )
        text_widget.grid(row=0, column=0, sticky="nsew")
        scrollbar = ttk.Scrollbar(frame, command=text_widget.yview)
        scrollbar.grid(row=0, column=1, sticky="ns")
        text_widget.configure(yscrollcommand=scrollbar.set)
        text_widget.insert("1.0", text)
        text_widget.configure(state="disabled")
        actions = ttk.Frame(frame)
        actions.grid(row=1, column=0, columnspan=2, sticky="e", pady=(10, 0))
        self.make_button(actions, "Close", window.destroy)
        window.after(20, lambda: center_window(window))

    def build_weather_module(self):
        page = ttk.Frame(self.module_content)
        page.grid(row=0, column=0, sticky="nsew")
        page.columnconfigure(0, weight=1)
        page.columnconfigure(1, weight=1)
        page.rowconfigure(1, weight=1)
        self.module_pages["weather"] = page

        header = ttk.LabelFrame(page, text="cfgweather.xml", padding=10)
        header.grid(row=0, column=0, columnspan=2, sticky="ew", pady=(0, 10))
        header.columnconfigure(0, weight=1)
        ttk.Label(header, textvariable=self.weather_path_var, style="FieldName.TLabel").grid(row=0, column=0, sticky="w")
        ttk.Label(header, textvariable=self.weather_summary_var, style="FieldMuted.TLabel").grid(row=1, column=0, sticky="w", pady=(4, 0))
        actions = ttk.Frame(header, style="Card.TFrame")
        actions.grid(row=0, column=1, rowspan=2, sticky="e", padx=(12, 0))
        self.make_info_button(actions, "weather")
        self.make_button(actions, "Reload", self.reload_weather_config, tooltip="Reload cfgweather.xml from disk.")
        self.make_button(actions, "Save weather", self.save_weather_config, variant="save", tooltip="Overwrite cfgweather.xml with current weather values.")

        left = ttk.LabelFrame(page, text="Weather values", padding=10)
        left.grid(row=1, column=0, sticky="nsew", padx=(0, 10))
        left.columnconfigure(0, weight=1)
        left.rowconfigure(2, weight=1)

        preset_row = ttk.Frame(left, style="Card.TFrame")
        preset_row.grid(row=0, column=0, sticky="ew", pady=(0, 10))
        season_label = ttk.Label(preset_row, text="Season", style="FieldName.TLabel")
        season_label.pack(side="left", padx=(0, 8))
        add_tooltip(season_label, "Preset season category. Only organizes presets; it does not write season metadata to cfgweather.xml.")
        season_combo = ttk.Combobox(preset_row, textvariable=self.weather_season_var, values=list(WEATHER_PRESET_CATEGORIES.keys()), state="readonly", width=12)
        season_combo.pack(side="left", padx=(0, 8))
        add_tooltip(season_combo, "Choose which seasonal preset group to browse.")
        season_combo.bind("<<ComboboxSelected>>", self.on_weather_season_changed)
        self.bind_combobox_open_on_click(season_combo)
        preset_label = ttk.Label(preset_row, text="Preset", style="FieldName.TLabel")
        preset_label.pack(side="left", padx=(0, 8))
        add_tooltip(preset_label, "Weather preset to apply to editable cfgweather.xml fields.")
        self.weather_preset_combo = ttk.Combobox(preset_row, textvariable=self.weather_preset_var, values=self.weather_preset_names_for_selected_season(), state="readonly", width=18)
        self.weather_preset_combo.pack(side="left", padx=(0, 8))
        add_tooltip(self.weather_preset_combo, "Choose a built-in or custom preset.")
        self.bind_combobox_open_on_click(self.weather_preset_combo)
        self.make_button(preset_row, "Apply preset", self.apply_weather_preset, variant="action", tooltip="Apply selected weather preset to editable fields.")
        self.make_button(preset_row, "Add preset", self.add_weather_custom_preset, variant="add", tooltip="Save the current weather values as a custom preset under the selected season.")
        self.make_button(preset_row, "Delete preset", self.delete_weather_custom_preset, variant="danger", tooltip="Delete the selected custom preset. Built-in presets cannot be deleted.")
        self.make_button(preset_row, "Defaults", self.apply_weather_defaults, tooltip="Reset fields to the selected custom default file, or the official DayZ cfgweather.xml when no custom default is configured.")

        default_row = ttk.Frame(left, style="Card.TFrame")
        default_row.grid(row=1, column=0, sticky="ew", pady=(0, 10))
        ttk.Label(default_row, textvariable=self.weather_default_path_var, style="FieldMuted.TLabel").pack(side="left", fill="x", expand=True)
        self.make_button(default_row, "Set default file", self.choose_weather_default_file, variant="add", tooltip="Choose a cfgweather.xml file to use when applying Defaults or creating a missing weather config.")
        self.make_button(default_row, "Use official", self.clear_weather_default_file, tooltip="Use the built-in official DayZ cfgweather.xml values as the default again.")

        canvas = tk.Canvas(left, bg=GRAPHITE_CARD, highlightthickness=0)
        canvas.grid(row=2, column=0, sticky="nsew")
        scroll = ttk.Scrollbar(left, command=canvas.yview)
        scroll.grid(row=2, column=1, sticky="ns")
        fields = ttk.Frame(canvas, style="Card.TFrame")
        fields_window = canvas.create_window((0, 0), window=fields, anchor="nw")
        canvas.configure(yscrollcommand=scroll.set)
        fields.bind("<Configure>", lambda event: canvas.configure(scrollregion=canvas.bbox("all")))
        canvas.bind("<Configure>", lambda event: canvas.itemconfigure(fields_window, width=event.width))

        current_section = ""
        row = -1
        for key, label, help_text in WEATHER_FIELD_DEFINITIONS:
            section = key.split(".", 1)[0].title()
            if section != current_section:
                current_section = section
                row += 1
                ttk.Label(fields, text=current_section, style="FieldName.TLabel").grid(row=row, column=0, columnspan=3, sticky="w", pady=(10 if row else 0, 4))
            row += 1
            label_widget = ttk.Label(fields, text=label, style="FieldName.TLabel")
            label_widget.grid(row=row, column=0, sticky="w", padx=(0, 8), pady=2)
            add_tooltip(label_widget, help_text)
            entry = ttk.Entry(fields, textvariable=self.weather_vars[key], width=14)
            entry.grid(row=row, column=1, sticky="ew", padx=(0, 8), pady=2)
            add_tooltip(entry, help_text)
            entry.bind("<KeyRelease>", self.on_weather_field_changed)
            self.weather_entry_widgets[key] = entry
            ttk.Label(fields, text=help_text, style="FieldMuted.TLabel", wraplength=360).grid(row=row, column=2, sticky="w", pady=2)
        fields.columnconfigure(2, weight=1)

        right = ttk.LabelFrame(page, text="Preview and notes", padding=10)
        right.grid(row=1, column=1, sticky="nsew")
        right.columnconfigure(0, weight=1)
        right.rowconfigure(1, weight=1)
        notes = (
            "Weather values are normalized 0..1 except times and wind max speed. "
            "Rain is tied to overcast thresholds: if overcast falls outside that range, rain fades out. "
            "Thunder/lightning uses storm density plus overcast threshold."
        )
        ttk.Label(right, text=notes, style="FieldMuted.TLabel", wraplength=620, justify="left").grid(row=0, column=0, sticky="ew", pady=(0, 10))
        self.weather_preview_text = tk.Text(
            right,
            wrap="none",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            insertbackground=GRAPHITE_TEXT,
            selectbackground=GRAPHITE_ACCENT_DARK,
            selectforeground="#ffffff",
            relief="flat",
            borderwidth=0,
            highlightthickness=1,
            highlightbackground=GRAPHITE_BORDER,
            highlightcolor=GRAPHITE_ACCENT,
            font=("Consolas", 9),
        )
        self.weather_preview_text.grid(row=1, column=0, sticky="nsew")
        self.configure_xml_tags(self.weather_preview_text)
        preview_y = ttk.Scrollbar(right, command=self.weather_preview_text.yview)
        preview_y.grid(row=1, column=1, sticky="ns")
        preview_x = ttk.Scrollbar(right, command=self.weather_preview_text.xview, orient="horizontal")
        preview_x.grid(row=2, column=0, sticky="ew")
        self.weather_preview_text.configure(yscrollcommand=preview_y.set, xscrollcommand=preview_x.set, state="disabled")
        self.update_weather_default_path_var()
        self.refresh_weather_preview()

    def weather_preset_names_for_selected_season(self):
        season = self.weather_season_var.get().strip()
        built_in_names = [name for name in WEATHER_PRESET_CATEGORIES.get(season, ()) if name in WEATHER_PRESETS]
        custom_names = sorted(self.weather_custom_presets_for_season(season), key=str.casefold)
        return built_in_names + [name for name in custom_names if name not in built_in_names]

    def on_weather_season_changed(self, _event=None):
        names = self.refresh_weather_preset_combo_values()
        if names and self.weather_preset_var.get() not in names:
            self.weather_preset_var.set(names[0])

    def weather_custom_presets(self):
        presets = self.saved_settings.get("weather_custom_presets", {})
        return presets if isinstance(presets, dict) else {}

    def weather_custom_presets_for_season(self, season):
        presets = self.weather_custom_presets().get(season, {})
        return presets if isinstance(presets, dict) else {}

    def weather_selected_preset_is_custom(self):
        season = self.weather_season_var.get().strip()
        name = self.weather_preset_var.get().strip()
        return bool(name) and name in self.weather_custom_presets_for_season(season)

    def weather_values_for_selected_preset(self, name):
        if name in WEATHER_PRESETS:
            return weather_preset_values(name)
        season = self.weather_season_var.get().strip()
        custom = self.weather_custom_presets_for_season(season).get(name)
        if isinstance(custom, dict):
            values = weather_default_values()
            values.update({key: str(value) for key, value in custom.items() if key in WEATHER_DEFAULT_VALUES})
            return values
        for season_presets in self.weather_custom_presets().values():
            if isinstance(season_presets, dict) and isinstance(season_presets.get(name), dict):
                values = weather_default_values()
                values.update({key: str(value) for key, value in season_presets[name].items() if key in WEATHER_DEFAULT_VALUES})
                return values
        return weather_preset_values(name)

    def refresh_weather_preset_combo_values(self):
        names = self.weather_preset_names_for_selected_season()
        if self.weather_preset_combo is not None:
            self.weather_preset_combo.configure(values=names)
        return names

    def add_weather_custom_preset(self):
        season = self.weather_season_var.get().strip()
        if season not in WEATHER_PRESET_CATEGORIES:
            messagebox.showwarning(APP_TITLE, "Select a season before adding a weather preset.")
            return
        name = simpledialog.askstring(APP_TITLE, f"New {season} weather preset name:", parent=self)
        if name is None:
            return
        name = name.strip()
        if not name:
            messagebox.showwarning(APP_TITLE, "Preset name cannot be empty.")
            return
        if name in WEATHER_PRESETS:
            messagebox.showerror(APP_TITLE, "That name is used by a built-in preset. Choose another name.")
            return
        values = self.weather_values_from_vars()
        errors = [issue for issue in validate_weather_values(values, f"{name}.xml") if issue.severity == "error"]
        if errors:
            preview = "\n".join(f"- {issue.name}: {issue.message}" for issue in errors[:6])
            messagebox.showerror(APP_TITLE, f"Fix weather errors before saving this preset:\n\n{preview}")
            return
        presets = dict(self.weather_custom_presets())
        season_presets = dict(self.weather_custom_presets_for_season(season))
        if name in season_presets and not messagebox.askyesno(APP_TITLE, f"Replace custom preset '{name}' in {season}?"):
            return
        season_presets[name] = {key: values.get(key, "") for key in WEATHER_DEFAULT_VALUES}
        presets[season] = season_presets
        self.saved_settings["weather_custom_presets"] = presets
        save_settings(self.saved_settings)
        self.weather_preset_var.set(name)
        self.refresh_weather_preset_combo_values()
        self.weather_summary_var.set(f"Added custom {season} preset: {name}.")

    def remove_weather_custom_preset_from_settings(self, season, name):
        presets = dict(self.weather_custom_presets())
        season_presets = dict(self.weather_custom_presets_for_season(season))
        if name not in season_presets:
            return False
        season_presets.pop(name, None)
        if season_presets:
            presets[season] = season_presets
        else:
            presets.pop(season, None)
        self.saved_settings["weather_custom_presets"] = presets
        return True

    def delete_weather_custom_preset(self):
        season = self.weather_season_var.get().strip()
        name = self.weather_preset_var.get().strip()
        if not name:
            messagebox.showwarning(APP_TITLE, "Select a custom weather preset to delete.")
            return
        if name in WEATHER_PRESETS or not self.weather_selected_preset_is_custom():
            messagebox.showinfo(APP_TITLE, "Only custom weather presets can be deleted. Built-in presets are protected.")
            return
        if not messagebox.askyesno(APP_TITLE, f"Delete custom {season} preset '{name}'?"):
            return
        self.remove_weather_custom_preset_from_settings(season, name)
        save_settings(self.saved_settings)
        names = self.refresh_weather_preset_combo_values()
        self.weather_preset_var.set(names[0] if names else "")
        self.weather_summary_var.set(f"Deleted custom {season} preset: {name}.")

    def weather_custom_default_path(self):
        path = str(self.saved_settings.get("weather_default_path", "") or "").strip()
        return path if path and Path(path).is_file() else ""

    def weather_default_display_text(self):
        custom_path = self.weather_custom_default_path()
        if custom_path:
            return f"Default: {Path(custom_path).name}"
        return "Default: official DayZ cfgweather.xml"

    def update_weather_default_path_var(self):
        self.weather_default_path_var.set(self.weather_default_display_text())

    def preferred_weather_default_values(self):
        custom_path = self.weather_custom_default_path()
        if not custom_path:
            return weather_default_values(), []
        values, issues = parse_weather_config_file(custom_path)
        hard_errors = [issue for issue in issues if issue.severity == "error"]
        if hard_errors:
            return weather_default_values(), [ValidationIssue("warning", "cfgweather.xml", f"Custom weather default could not be used: {hard_errors[0].message}", custom_path, "Choose another default cfgweather.xml or clear the custom default.")]
        return values, issues

    def choose_weather_default_file(self):
        initialdir = self.saved_settings.get("last_dir", str(Path.home()))
        current = self.weather_custom_default_path()
        if current:
            initialdir = str(Path(current).parent)
        path = filedialog.askopenfilename(
            title="Choose default cfgweather.xml",
            filetypes=[("DayZ weather config", "cfgweather.xml"), ("XML files", "*.xml"), ("All files", "*.*")],
            initialdir=initialdir,
        )
        if not path:
            return
        values, issues = parse_weather_config_file(path)
        errors = [issue for issue in issues if issue.severity == "error"]
        if errors:
            preview = "\n".join(f"- {issue.message}" for issue in errors[:5])
            messagebox.showerror(APP_TITLE, f"This file cannot be used as weather default:\n\n{preview}")
            return
        self.saved_settings["weather_default_path"] = path
        self.saved_settings["last_dir"] = os.path.dirname(path)
        save_settings(self.saved_settings)
        self.update_weather_default_path_var()
        self.weather_summary_var.set(f"Selected custom weather default: {Path(path).name}.")
        if issues:
            self.log(f"Custom weather default has {len(issues)} warning(s). It can still be used.", "warning")

    def clear_weather_default_file(self):
        if "weather_default_path" in self.saved_settings:
            self.saved_settings.pop("weather_default_path", None)
            save_settings(self.saved_settings)
        self.update_weather_default_path_var()
        self.weather_summary_var.set("Using official DayZ cfgweather.xml as default.")

    def weather_source_path_for_workspace(self):
        if self.mission_workspace is None:
            return ""
        return str(Path(self.mission_workspace.root_path) / "cfgweather.xml")

    def load_weather_config(self):
        self.weather_path = self.weather_source_path_for_workspace()
        if not self.weather_path:
            self.weather_values, default_issues = self.preferred_weather_default_values()
            self.original_weather_values = dict(self.weather_values)
            self.weather_path_var.set("No mission folder loaded")
            self.weather_summary_var.set("Open a mission folder to edit cfgweather.xml.")
            self.validation_issues.extend(default_issues)
            self.set_weather_vars(self.weather_values)
            return
        path = Path(self.weather_path)
        if path.is_file():
            values, issues = parse_weather_config_file(path)
            self.weather_values = values
            self.original_weather_values = dict(values)
            self.weather_path_var.set(self.source_display_name(str(path)))
            if issues:
                self.weather_summary_var.set(f"Loaded with {len(issues)} issue(s). Apply preset or fix fields before saving.")
                self.validation_issues.extend(issues)
            else:
                self.weather_summary_var.set("Loaded cfgweather.xml. Edit fields or apply a preset.")
        else:
            values, default_issues = self.preferred_weather_default_values()
            self.weather_values = values
            self.original_weather_values = dict(values)
            self.weather_path_var.set(str(path))
            self.validation_issues.extend(default_issues)
            self.weather_summary_var.set(f"cfgweather.xml does not exist yet. Save weather will create it from {self.weather_default_display_text().removeprefix('Default: ')}.")
        self.set_weather_vars(self.weather_values)

    def set_weather_vars(self, values):
        for key, variable in self.weather_vars.items():
            variable.set(str(values.get(key, WEATHER_DEFAULT_VALUES.get(key, ""))))
        self.refresh_weather_preview()

    def weather_values_from_vars(self):
        return {key: variable.get().strip() for key, variable in self.weather_vars.items()}

    def current_weather_validation_issues(self):
        source_path = self.weather_path or self.weather_source_path_for_workspace()
        return validate_weather_values(self.weather_values_from_vars(), source_path)

    def select_weather_issue_field(self, field_name):
        widget = self.weather_entry_widgets.get(str(field_name or "").strip())
        if widget is None:
            return False
        widget.focus_set()
        widget.selection_range(0, "end")
        widget.icursor("end")
        return True

    def update_weather_validation_summary(self):
        issues = self.current_weather_validation_issues()
        errors = sum(1 for issue in issues if issue.severity == "error")
        warnings = sum(1 for issue in issues if issue.severity == "warning")
        if errors:
            self.weather_summary_var.set(f"Weather has {errors} error(s). Fix red-level issues before saving.")
        elif warnings:
            self.weather_summary_var.set(f"Weather has {warnings} warning(s). Saving is allowed, but review the validation report.")
        elif self.weather_path:
            self.weather_summary_var.set("Weather values look valid.")
        return issues

    def refresh_weather_preview(self):
        if self.weather_preview_text is None:
            return
        values = self.weather_values_from_vars()
        preview = format_weather_config_xml(values)
        self.weather_preview_text.configure(state="normal")
        self.weather_preview_text.delete("1.0", "end")
        self.weather_preview_text.insert("1.0", preview)
        self.apply_xml_highlighting_to_widget(self.weather_preview_text)
        self.weather_preview_text.configure(state="disabled")

    def on_weather_field_changed(self, _event=None):
        self.refresh_weather_preview()
        self.update_weather_validation_summary()
        if self.weather_path:
            self.mark_source_dirty(self.weather_path)

    def apply_weather_preset(self):
        name = self.weather_preset_var.get().strip()
        values = self.weather_values_for_selected_preset(name)
        self.set_weather_vars(values)
        self.weather_summary_var.set(f"Applied {name} preset. Save weather writes cfgweather.xml.")
        if self.weather_path:
            self.mark_source_dirty(self.weather_path)
            self.set_dirty(True)

    def apply_weather_defaults(self):
        values, issues = self.preferred_weather_default_values()
        self.set_weather_vars(values)
        if issues:
            self.validation_issues.extend(issues)
            self.weather_summary_var.set(f"Applied {self.weather_default_display_text().removeprefix('Default: ')} with {len(issues)} warning(s).")
        else:
            self.weather_summary_var.set(f"Applied {self.weather_default_display_text().removeprefix('Default: ')}. Save weather writes cfgweather.xml.")
        if self.weather_path:
            self.mark_source_dirty(self.weather_path)
            self.set_dirty(True)

    def reload_weather_config(self):
        if not self.weather_path:
            self.load_weather_config()
            return
        if self.source_has_changes(self.weather_path) and not messagebox.askyesno(APP_TITLE, "Discard unsaved weather changes and reload cfgweather.xml from disk?"):
            return
        self.load_weather_config()
        self.log("Reloaded weather config.", "success")

    def save_weather_config(self):
        if not self.weather_path:
            self.weather_path = self.weather_source_path_for_workspace()
        if not self.weather_path:
            messagebox.showwarning(APP_TITLE, "Open a mission folder before saving cfgweather.xml.")
            return
        values = self.weather_values_from_vars()
        issues = self.current_weather_validation_issues()
        errors = [issue for issue in issues if issue.severity == "error"]
        warnings = [issue for issue in issues if issue.severity == "warning"]
        if errors:
            preview = "\n".join(f"- {issue.name}: {issue.message}" for issue in errors[:8])
            if len(errors) > 8:
                preview += f"\n- ... {len(errors) - 8} more"
            self.weather_summary_var.set(f"Weather has {len(errors)} error(s). Save blocked.")
            messagebox.showerror(APP_TITLE, f"Fix weather errors before saving cfgweather.xml:\n\n{preview}")
            return
        if warnings:
            self.log(f"Weather validation has {len(warnings)} warning(s). Saved anyway.", "warning")
        try:
            self.create_pre_save_backup(self.weather_path)
            write_weather_config_file(values, self.weather_path)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not save cfgweather.xml:\n{exc}")
            return
        self.weather_values = values
        self.original_weather_values = dict(values)
        self.mark_source_saved(self.weather_path)
        self.recompute_dirty_sources()
        self.weather_path_var.set(self.source_display_name(self.weather_path))
        self.weather_summary_var.set("Saved cfgweather.xml.")
        self.log(f"Saved weather config: {self.weather_path}", "success")
        self.set_status("Weather saved", "success")

    def selected_dashboard_target(self):
        for tree in (self.dashboard_attention_tree, self.dashboard_unsaved_tree, self.dashboard_coverage_tree):
            if tree is None:
                continue
            selected = tree.selection()
            if selected:
                target = self.dashboard_targets.get(selected[0])
                if target is not None:
                    return target
        if self.dashboard_issue_listbox is not None:
            selected = self.dashboard_issue_listbox.curselection()
            if selected:
                return self.dashboard_targets.get(selected[0])
        return None

    def open_dashboard_selection(self):
        target = self.selected_dashboard_target()
        if target is None:
            return
        self.open_dashboard_target(target)

    def open_dashboard_target(self, target):
        opened = False
        kind = target[0]
        line = target[2] if len(target) > 2 and isinstance(target[2], int) else None
        column = target[3] if len(target) > 3 and isinstance(target[3], int) else None
        if kind == "module":
            self.switch_module(target[1])
            opened = True
        elif kind == "source":
            opened = self.select_source_path(target[1], line=line, column=column)
        elif kind == "duplicate":
            opened = self.select_type_entry_by_name(target[1], duplicates=True)
        elif kind == "duplicates":
            self.dashboard_show_duplicates()
            opened = True
        elif kind == "entry":
            opened = self.select_type_entry_by_name(target[1], source_path=target[2] if len(target) > 2 else "")
        elif kind == "event":
            opened = self.select_event_entry_by_name(target[1], source_path=target[2] if len(target) > 2 else "")
        elif kind == "event_source":
            opened = self.select_event_source_path(target[1])
        elif kind == "weather_source":
            self.switch_module("weather")
            opened = self.select_weather_issue_field(target[2]) if len(target) > 2 else True
        elif kind == "spawnable":
            opened = self.select_spawnable_entry_by_name(target[1], source_path=target[2] if len(target) > 2 else "")
        elif kind == "spawnable_source":
            opened = self.select_spawnable_source_path(target[1])
        elif kind == "random_preset":
            opened = self.select_random_preset_entry_by_name(target[1], source_path=target[2] if len(target) > 2 else "")
        elif kind == "random_preset_source":
            opened = self.select_random_preset_source_path(target[1])
        elif kind == "territory_source":
            opened = self.select_territory_source_path(target[1])
        elif kind == "territory_zone":
            opened = self.select_territory_zone_by_name(target[1], source_path=target[2] if len(target) > 2 else "")
        elif kind == "ce_zones_source":
            opened = self.select_ce_zones_source_path(target[1])
        elif kind == "ce_zone_layer":
            opened = self.select_ce_zones_layer_target(target[1], source_path=target[2] if len(target) > 2 else "")
        elif kind == "mapgroupproto_group":
            self.switch_module("mapgroupproto")
            opened = self.select_mapgroupproto_group_by_name(target[1], update_search=True)
        elif kind == "config_source":
            opened = self.select_config_source_path(target[1], line=line, column=column)
        elif kind == "profile_source":
            opened = self.select_profile_config_source_path(target[1], line=line, column=column)
        elif kind == "issues":
            self.dashboard_show_issues()
            opened = True
        if opened:
            self.set_status("Issue target opened", "success")
        else:
            self.set_status("Could not find exact issue target in loaded data", "warning")
        return opened

    def dashboard_focus_attention(self, severity):
        tree = self.dashboard_attention_tree
        if tree is None:
            return
        for parent in tree.get_children():
            for iid in tree.get_children(parent):
                if severity in tree.item(iid, "tags"):
                    tree.item(parent, open=True)
                    tree.selection_set(iid)
                    tree.focus(iid)
                    tree.see(iid)
                    tree.focus_set()
                    return
        if any(issue.severity == severity for issue in self.issues):
            self.open_dashboard_all_issues(severity)
        else:
            self.set_status(f"No {severity} issues", "success")

    def dashboard_focus_unsaved(self):
        tree = self.dashboard_unsaved_tree
        if tree is None:
            return
        rows = tree.get_children()
        if rows and self.dashboard_targets.get(rows[0]) is not None:
            tree.selection_set(rows[0])
            tree.focus(rows[0])
            tree.see(rows[0])
            tree.focus_set()
        else:
            self.set_status("No unsaved sources", "success")

    def dashboard_focus_missing(self):
        tree = self.dashboard_coverage_tree
        if tree is None or not self.dashboard_missing_iids:
            self.set_status("No required files missing", "success")
            return
        iid = self.dashboard_missing_iids[0]
        parent = tree.parent(iid)
        if parent:
            tree.item(parent, open=True)
        tree.selection_set(iid)
        tree.focus(iid)
        tree.see(iid)
        tree.focus_set()

    def open_dashboard_all_issues(self, severity_filter=None):
        issues = [issue for issue in self.issues if severity_filter is None or issue.severity == severity_filter]
        issues = sorted(issues, key=lambda issue: ({"error": 0, "warning": 1, "info": 2}.get(issue.severity, 3), self.issue_module_sort_key(self.issue_module_id(issue)), issue.name.casefold(), issue.message.casefold()))
        if not issues:
            messagebox.showinfo(APP_TITLE, "No issues found.", parent=self)
            return
        window = tk.Toplevel(self)
        window.title(f"{severity_filter.title()} Issues" if severity_filter else "All Workspace Issues")
        window.geometry("1180x680")
        window.minsize(820, 480)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)
        shell = ttk.Frame(window, padding=12)
        shell.pack(fill="both", expand=True)
        shell.columnconfigure(0, weight=1)
        shell.rowconfigure(0, weight=1)
        tree = ttk.Treeview(shell, columns=("severity", "module", "item", "issue", "source"), show="headings", selectmode="browse", style="Economy.Treeview")
        for column, label, width, stretch in (
            ("severity", "Severity", 80, False),
            ("module", "Module", 115, False),
            ("item", "Item", 240, False),
            ("issue", "Issue", 720, False),
            ("source", "Source", 420, False),
        ):
            tree.heading(column, text=label)
            tree.column(column, width=width, anchor="w", stretch=stretch)
        tree.grid(row=0, column=0, sticky="nsew")
        scroll = ttk.Scrollbar(shell, command=tree.yview)
        scroll.grid(row=0, column=1, sticky="ns")
        x_scroll = ttk.Scrollbar(shell, command=tree.xview, orient="horizontal")
        x_scroll.grid(row=1, column=0, sticky="ew")
        tree.configure(yscrollcommand=scroll.set, xscrollcommand=x_scroll.set)
        tree.tag_configure("error", foreground=GRAPHITE_ERROR)
        tree.tag_configure("warning", foreground=GRAPHITE_WARNING)
        tree.tag_configure("info", foreground=GRAPHITE_MUTED)
        targets = {}
        for index, issue in enumerate(issues):
            iid = f"all-issue-{index}"
            source = self.source_display_name(issue.source_path) if issue.source_path else ""
            tree.insert("", "end", iid=iid, values=(issue.severity.title(), self.issue_module_label(issue), issue.name, issue.message, source), tags=(issue.severity,))
            targets[iid] = self.issue_target(issue)

        def open_selected():
            selected = tree.selection()
            if not selected:
                return
            target = targets.get(selected[0])
            if target is not None and self.open_dashboard_target(target):
                window.destroy()

        tree.bind("<Double-Button-1>", lambda _event: open_selected())
        tree.bind("<Return>", lambda _event: open_selected())
        actions = ttk.Frame(shell)
        actions.grid(row=2, column=0, columnspan=2, sticky="e", pady=(10, 0))
        self.make_button(actions, "Open selected", open_selected, variant="action")
        self.make_button(actions, "Close", window.destroy)
        window.after(20, lambda: center_window(window, self))

    def select_source_path(self, source_path, line=None, column=None):
        self.switch_module("types")
        self.selected_source_path = source_path
        self.active_usage_filter = None
        self.usage_filter_var.set("")
        self.filter_var.set("All")
        self.clear_editor()
        self.update_source_listbox()
        found = False
        for index, path in enumerate(self.loaded_paths):
            if self.normalized_path(path) == self.normalized_path(source_path):
                self.source_listbox.selection_clear(0, "end")
                self.source_listbox.selection_set(index)
                self.source_listbox.see(index)
                found = True
                break
        self.refresh_table()
        self.update_summary()
        return found

    def scroll_text_widget_to_line(self, widget, line=None, column=None):
        if widget is None or not line:
            return
        try:
            line_number = max(1, int(line))
            column_number = max(0, int(column) - 1) if column else 0
        except (TypeError, ValueError):
            return
        index = f"{line_number}.{column_number}"
        widget.mark_set("insert", index)
        widget.tag_remove("issue_line", "1.0", "end")
        widget.tag_configure("issue_line", background=GRAPHITE_ACCENT_DARK)
        widget.tag_add("issue_line", f"{line_number}.0", f"{line_number}.end")
        widget.see(index)
        widget.focus_set()

    def select_type_entry_by_name(self, name, source_path="", duplicates=False):
        self.switch_module("types")
        self.selected_source_path = None
        self.active_usage_filter = None
        self.usage_filter_var.set("")
        if hasattr(self, "source_listbox"):
            self.source_listbox.selection_clear(0, "end")
        self.search_var.set("")
        self.filter_var.set("Duplicates" if duplicates else "All")
        target_index = None
        source_key = self.normalized_path(source_path) if source_path else ""
        for index, entry in enumerate(self.entries):
            if entry.name.casefold() != name.casefold():
                continue
            if source_key and self.normalized_path(entry.source_path) != source_key:
                continue
            target_index = index
            break
        self.current_index = target_index
        self.refresh_table()
        if target_index is not None:
            iid = str(target_index)
            if iid in self.tree.get_children():
                self.tree.selection_set(iid)
                self.tree.see(iid)
                self.populate_editor(self.entries[target_index])
        self.update_summary()
        return target_index is not None

    def select_event_entry_by_name(self, name, source_path=""):
        self.switch_module("events")
        source_key = self.normalized_path(source_path) if source_path else ""
        for index, entry in enumerate(self.event_entries):
            if entry.name.casefold() != name.casefold():
                continue
            if source_key and self.normalized_path(entry.source_path) != source_key:
                continue
            self.select_event_entry_by_index(index)
            return True
        return False

    def select_event_source_path(self, source_path):
        self.switch_module("events")
        source_key = self.normalized_path(source_path) if source_path else ""
        if self.event_filter_var.get() != "All":
            self.event_filter_var.set("All")
        self.refresh_event_table()
        for index, entry in enumerate(self.event_entries):
            if self.normalized_path(entry.source_path) == source_key:
                self.select_event_entry_by_index(index)
                return True
        return False

    def select_event_entry_by_index(self, index):
        if index is None or not (0 <= index < len(self.event_entries)):
            return False
        self.switch_module("events")
        self.current_event_index = index
        if self.event_filter_var.get() != "All":
            self.event_filter_var.set("All")
        self.refresh_event_table()
        if self.event_tree is not None:
            iid = f"event-{index}"
            if iid in self.event_tree.get_children():
                self.event_tree.selection_set(iid)
                self.event_tree.see(iid)
        self.populate_event_editor(index)
        return True

    def event_index_for_entry(self, target):
        for index, entry in enumerate(self.event_entries):
            if entry is target:
                return index
        target_key = (
            target.name.casefold(),
            self.normalized_path(target.source_path),
        )
        for index, entry in enumerate(self.event_entries):
            if (
                entry.name.casefold(),
                self.normalized_path(entry.source_path),
            ) == target_key:
                return index
        for index, entry in enumerate(self.event_entries):
            if entry.name.casefold() == target.name.casefold():
                return index
        return None

