            ("Max", "max"), ("Lifetime", "lifetime"),
            ("Restock", "restock"), ("Safe radius", "saferadius"),
            ("Distance radius", "distanceradius"), ("Cleanup radius", "cleanupradius"),
            ("Secondary event", "secondary"), ("Position", "position"),
            ("Limit", "limit"), ("Active", "active"),
