    def parse_mapgroupproto_relation_values(self, text):
        return [part.strip() for part in re.split(r"[,;\n]+", str(text or "")) if part.strip()]

    def current_mapgroupproto_root(self):
        parser = ET.XMLParser(target=ET.TreeBuilder(insert_comments=True))
        return ET.fromstring(self.mapgroupproto_current_text, parser=parser)

    def mapgroupproto_xml_nodes(self, parent, tag, inherited_commented=False):
        records = []
        for node in list(parent):
            if node.tag == tag:
                records.append((node, node, inherited_commented))
                continue
            element = parse_commented_xml_element(node, tag)
            if element is not None:
                records.append((node, element, True))
        return records

    def selected_mapgroupproto_group_xml_record(self, root):
        records = self.mapgroupproto_xml_nodes(root, "group")
        if self.mapgroupproto_selected_index is None or not (0 <= self.mapgroupproto_selected_index < len(records)):
            return None
        return records[self.mapgroupproto_selected_index]

    def render_mapgroupproto_root(self, root):
        ET.indent(root, space="    ")
        body = ET.tostring(root, encoding="unicode", short_empty_elements=True)
        return '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n' + body + "\n"

    def set_mapgroupproto_current_text(self, text, selected_name="", validate=False, preserve_issues=False, removed_issue_name=""):
        old_issues = list(self.mapgroupproto_issues) if preserve_issues else []
        self.mapgroupproto_current_text = text
        if self.mapgroupproto_path:
            self.mark_source_dirty(self.mapgroupproto_path)
        if validate:
            self.validate_mapgroupproto_current_text(show_success=False)
        else:
            self.populate_mapgroupproto_view_fast()
        if preserve_issues:
            removed_key = str(removed_issue_name or "").casefold()
            self.mapgroupproto_issues = [issue for issue in old_issues if not removed_key or str(issue.name).casefold() != removed_key]
            self.populate_mapgroupproto_issues()
        if selected_name:
            self.select_mapgroupproto_group_by_name(selected_name, update_search=True)

    def set_mapgroupproto_relation_children(self, parent, values_by_kind, before_tags):
        children = list(parent)
        for child in children:
            if child.tag in RELATION_FIELDS:
                parent.remove(child)
        insert_at = len(parent)
        for index, child in enumerate(list(parent)):
            if child.tag in before_tags:
                insert_at = index
                break
        offset = 0
        for kind in RELATION_FIELDS:
            for value in values_by_kind.get(kind, ()):
                parent.insert(insert_at + offset, ET.Element(kind, {"name": value}))
                offset += 1

    def apply_mapgroupproto_add_group(self, values):
        group_name = str(values.get("group_name", "")).strip()
        if not group_name:
            raise ValueError("Group name is required.")
        group_lootmax = str(values.get("group_lootmax", "")).strip()
        if group_lootmax and not group_lootmax.isdigit():
            raise ValueError("Group lootmax must be a positive integer.")
        root = self.current_mapgroupproto_root()
        group_element = ET.Element("group", {"name": group_name})
        if group_lootmax:
            group_element.set("lootmax", group_lootmax)
        self.set_mapgroupproto_relation_children(
            group_element,
            {kind: self.parse_mapgroupproto_relation_values(values.get(f"group_{kind}", "")) for kind in RELATION_FIELDS},
            {"container"},
        )
        root.append(group_element)
        self.set_mapgroupproto_current_text(self.render_mapgroupproto_root(root), group_name)
        self.set_status("Mapgroupproto group added", "success")

    def apply_mapgroupproto_add_container(self, values):
        if self.mapgroupproto_selected_index is None:
            raise ValueError("Select a group first.")
        container_name = str(values.get("container_name", "")).strip()
        if not container_name:
            raise ValueError("Container name is required.")
        container_lootmax = str(values.get("container_lootmax", "")).strip()
        if container_lootmax and not container_lootmax.isdigit():
            raise ValueError("Container lootmax must be a positive integer.")
        root = self.current_mapgroupproto_root()
        group_record = self.selected_mapgroupproto_group_xml_record(root)
        if group_record is None:
            raise ValueError("Selected group no longer exists.")
        _group_node, group_element, group_commented = group_record
        if group_commented:
            raise ValueError("Activate the commented group before adding a container.")
        container_element = ET.Element("container", {"name": container_name})
        if container_lootmax:
            container_element.set("lootmax", container_lootmax)
        self.set_mapgroupproto_relation_children(
            container_element,
            {kind: self.parse_mapgroupproto_relation_values(values.get(f"container_{kind}", "")) for kind in RELATION_FIELDS},
            {"point"},
        )
        group_element.append(container_element)
        self.set_mapgroupproto_current_text(self.render_mapgroupproto_root(root), group_element.get("name", ""))
        self.set_status("Mapgroupproto container added", "success")

    def apply_mapgroupproto_selected_edit(self, values):
        if self.mapgroupproto_selected_index is None:
            raise ValueError("Select a group first.")
        selected_group = self.selected_mapgroupproto_group()
        if selected_group is None:
            raise ValueError("Selected group no longer exists.")
        group_name = str(values.get("group_name", "")).strip()
        if not group_name:
            raise ValueError("Group name is required.")
        group_lootmax = str(values.get("group_lootmax", "")).strip()
        if group_lootmax and not group_lootmax.isdigit():
            raise ValueError("Group lootmax must be a positive integer.")
        root = self.current_mapgroupproto_root()
        group_record = self.selected_mapgroupproto_group_xml_record(root)
        if group_record is None:
            raise ValueError("Selected group no longer exists.")
        _group_node, group_element, group_commented = group_record
        if group_commented:
            raise ValueError("Activate the commented group before editing it.")
        group_element.set("name", group_name)
        if group_lootmax:
            group_element.set("lootmax", group_lootmax)
        else:
            group_element.attrib.pop("lootmax", None)
        self.set_mapgroupproto_relation_children(
            group_element,
            {kind: self.parse_mapgroupproto_relation_values(values.get(f"group_{kind}", "")) for kind in RELATION_FIELDS},
            {"container"},
        )

        if self.mapgroupproto_selected_container_index is not None:
            containers = self.mapgroupproto_xml_nodes(group_element, "container")
            if self.mapgroupproto_selected_container_index < len(containers):
                _container_node, container_element, container_commented = containers[self.mapgroupproto_selected_container_index]
                if container_commented:
                    raise ValueError("Activate the commented container before editing it.")
                container_name = str(values.get("container_name", "")).strip()
                if not container_name:
                    raise ValueError("Container name is required.")
                container_lootmax = str(values.get("container_lootmax", "")).strip()
                if container_lootmax and not container_lootmax.isdigit():
                    raise ValueError("Container lootmax must be a positive integer.")
                container_element.set("name", container_name)
                if container_lootmax:
                    container_element.set("lootmax", container_lootmax)
                else:
                    container_element.attrib.pop("lootmax", None)
                self.set_mapgroupproto_relation_children(
                    container_element,
                    {kind: self.parse_mapgroupproto_relation_values(values.get(f"container_{kind}", "")) for kind in RELATION_FIELDS},
                    {"point"},
                )

        if self.mapgroupproto_selected_point_index is not None:
            container_index, point_index = self.mapgroupproto_selected_point_index
            containers = self.mapgroupproto_xml_nodes(group_element, "container")
            if container_index < len(containers):
                _container_node, container_element, container_commented = containers[container_index]
                if container_commented:
                    raise ValueError("Activate the commented container before editing its points.")
                points = self.mapgroupproto_xml_nodes(container_element, "point")
                if point_index < len(points):
                    _point_node, point_element, point_commented = points[point_index]
                    if point_commented:
                        raise ValueError("Activate the commented point before editing it.")
                    point_pos = str(values.get("point_pos", "")).strip()
                    if not point_pos:
                        raise ValueError("Point pos is required.")
                    point_element.set("pos", point_pos)
                    for attr, key in (("range", "point_range"), ("height", "point_height"), ("flags", "point_flags")):
                        value = str(values.get(key, "")).strip()
                        if value:
                            point_element.set(attr, value)
                        else:
                            point_element.attrib.pop(attr, None)

        self.set_mapgroupproto_current_text(self.render_mapgroupproto_root(root), group_name, preserve_issues=True, removed_issue_name=selected_group.name)
        self.set_status("Mapgroupproto edit applied", "success")

    def deactivate_selected_mapgroupproto_group(self, parent=None):
        self.comment_out_selected_mapgroupproto(parent=parent, force_kind="group")

    def comment_mapgroupproto_element(self, parent, element):
        element_text = xml_element_to_text(element)
        children = list(parent)
        child_index = children.index(element)
        parent.remove(element)
        parent.insert(child_index, ET.Comment("\n" + element_text + "\n"))

    def activate_mapgroupproto_comment(self, parent, comment_node, expected_tag):
        element = parse_commented_xml_element(comment_node, expected_tag)
        if element is None:
            raise ValueError(f"Comment does not contain one valid <{expected_tag}> element.")
        child_index = list(parent).index(comment_node)
        parent.remove(comment_node)
        parent.insert(child_index, element)

    def toggle_selected_mapgroupproto_comment(self, parent=None):
        group = self.selected_mapgroupproto_group()
        if group is None:
            messagebox.showwarning(APP_TITLE, "Select a mapgroupproto group first.", parent=parent)
            return
        container = self.selected_mapgroupproto_container(group)
        point = self.selected_mapgroupproto_point(group)
        if group.commented or (container is not None and container.commented) or (point is not None and point.commented):
            self.activate_selected_mapgroupproto(parent=parent)
        else:
            self.comment_out_selected_mapgroupproto(parent=parent)

    def activate_selected_mapgroupproto(self, parent=None):
        group = self.selected_mapgroupproto_group()
        if group is None:
            messagebox.showwarning(APP_TITLE, "Select a commented mapgroupproto entry first.", parent=parent)
            return
        root = self.current_mapgroupproto_root()
        group_record = self.selected_mapgroupproto_group_xml_record(root)
        if group_record is None:
            messagebox.showerror(APP_TITLE, "Selected group no longer exists.", parent=parent)
            return
        group_node, group_element, group_commented = group_record
        target_kind = "group"
        try:
            if group_commented:
                self.activate_mapgroupproto_comment(root, group_node, "group")
            else:
                container = self.selected_mapgroupproto_container(group)
                point = self.selected_mapgroupproto_point(group)
                container_records = self.mapgroupproto_xml_nodes(group_element, "container")
                if container is not None and container.commented and self.mapgroupproto_selected_container_index is not None:
                    if self.mapgroupproto_selected_container_index >= len(container_records):
                        raise ValueError("Selected container no longer exists.")
                    container_node, _container_element, container_commented = container_records[self.mapgroupproto_selected_container_index]
                    if not container_commented:
                        raise ValueError("Selected container is already active.")
                    self.activate_mapgroupproto_comment(group_element, container_node, "container")
                    target_kind = "container"
                elif point is not None and point.commented and self.mapgroupproto_selected_point_index is not None:
                    container_index, point_index = self.mapgroupproto_selected_point_index
                    if container_index >= len(container_records):
                        raise ValueError("Selected container no longer exists.")
                    _container_node, container_element, container_commented = container_records[container_index]
                    if container_commented:
                        raise ValueError("Activate the commented container before activating one of its points.")
                    point_records = self.mapgroupproto_xml_nodes(container_element, "point")
                    if point_index >= len(point_records):
                        raise ValueError("Selected point no longer exists.")
                    point_node, _point_element, point_commented = point_records[point_index]
                    if not point_commented:
                        raise ValueError("Selected point is already active.")
                    self.activate_mapgroupproto_comment(container_element, point_node, "point")
                    target_kind = "point"
                else:
                    raise ValueError("Selected entry is already active.")
        except ValueError as exc:
            messagebox.showerror(APP_TITLE, str(exc), parent=parent)
            return
        self.set_mapgroupproto_current_text(self.render_mapgroupproto_root(root), selected_name=group.name, preserve_issues=True)
        self.set_status(f"Mapgroupproto {target_kind} activated", "success")

    def comment_out_selected_mapgroupproto(self, parent=None, force_kind=""):
        group = self.selected_mapgroupproto_group()
        if group is None or self.mapgroupproto_selected_index is None:
            messagebox.showwarning(APP_TITLE, "Select a mapgroupproto group first.", parent=parent)
            return
        point = self.selected_mapgroupproto_point(group) if force_kind != "group" else None
        container = self.selected_mapgroupproto_container(group) if force_kind not in {"group", "point"} else None
        if point is not None:
            target_kind = "point"
            target_label = point.pos
        elif container is not None:
            target_kind = "container"
            target_label = container.name
        else:
            target_kind = "group"
            target_label = group.name

        if target_kind == "group" and group.placed_count > 0 and not messagebox.askyesno(APP_TITLE, f"{group.name} has {group.placed_count} placed instance(s).\n\nComment it out anyway?", parent=parent):
            return
        if target_kind == "group" and group.placed_count <= 0:
            message = f"Comment out this unplaced prototype group?\n\n{group.name}\n\nDayZ will ignore it; the tool will keep it visible."
        elif target_kind == "container":
            message = f"Comment out selected container?\n\n{group.name} -> {target_label}\n\nDayZ will ignore it; the tool will keep it visible."
        else:
            message = f"Comment out selected point?\n\n{group.name} -> {target_label}\n\nDayZ will ignore it; the tool will keep it visible."
        if not messagebox.askyesno(APP_TITLE, message, parent=parent):
            return
        root = self.current_mapgroupproto_root()
        group_record = self.selected_mapgroupproto_group_xml_record(root)
        if group_record is None:
            messagebox.showerror(APP_TITLE, "Selected group no longer exists.", parent=parent)
            return
        group_node, group_element, group_commented = group_record
        if group_commented:
            messagebox.showwarning(APP_TITLE, "Selected group is already commented out.", parent=parent)
            return
        selected_name = ""
        if target_kind == "point" and self.mapgroupproto_selected_point_index is not None:
            container_index, point_index = self.mapgroupproto_selected_point_index
            containers = self.mapgroupproto_xml_nodes(group_element, "container")
            if container_index >= len(containers):
                messagebox.showerror(APP_TITLE, "Selected container no longer exists.", parent=parent)
                return
            _container_node, container_element, container_commented = containers[container_index]
            if container_commented:
                messagebox.showwarning(APP_TITLE, "Selected container is already commented out.", parent=parent)
                return
            points = self.mapgroupproto_xml_nodes(container_element, "point")
            if point_index >= len(points):
                messagebox.showerror(APP_TITLE, "Selected point no longer exists.", parent=parent)
                return
            point_node, _point_element, point_commented = points[point_index]
            if point_commented:
                messagebox.showwarning(APP_TITLE, "Selected point is already commented out.", parent=parent)
                return
            self.comment_mapgroupproto_element(container_element, point_node)
            selected_name = group.name
        elif target_kind == "container" and self.mapgroupproto_selected_container_index is not None:
            containers = self.mapgroupproto_xml_nodes(group_element, "container")
            if self.mapgroupproto_selected_container_index >= len(containers):
                messagebox.showerror(APP_TITLE, "Selected container no longer exists.", parent=parent)
                return
            container_node, _container_element, container_commented = containers[self.mapgroupproto_selected_container_index]
            if container_commented:
                messagebox.showwarning(APP_TITLE, "Selected container is already commented out.", parent=parent)
                return
            self.comment_mapgroupproto_element(group_element, container_node)
            selected_name = group.name
        else:
            self.comment_mapgroupproto_element(root, group_node)
            selected_name = group.name
        self.set_mapgroupproto_current_text(self.render_mapgroupproto_root(root), selected_name=selected_name, preserve_issues=True, removed_issue_name=group.name)
        self.set_status(f"Mapgroupproto {target_kind} commented out", "warning")

    def delete_selected_mapgroupproto_group(self, parent=None):
        group = self.selected_mapgroupproto_group()
        if group is None or self.mapgroupproto_selected_index is None:
            messagebox.showwarning(APP_TITLE, "Select a mapgroupproto group first.", parent=parent)
            return
        if not messagebox.askyesno(APP_TITLE, f"Delete selected prototype group?\n\n{group.name}\n\nThis removes it from mapgroupproto.xml.", parent=parent):
            return
        root = self.current_mapgroupproto_root()
        group_record = self.selected_mapgroupproto_group_xml_record(root)
        if group_record is None:
            messagebox.showerror(APP_TITLE, "Selected group no longer exists.", parent=parent)
            return
        group_node, _group_element, _group_commented = group_record
        root.remove(group_node)
        self.set_mapgroupproto_current_text(self.render_mapgroupproto_root(root), preserve_issues=True, removed_issue_name=group.name)
        self.set_status("Mapgroupproto group deleted", "warning")

    def reload_mapgroupproto(self):
        if not self.mapgroupproto_path and not self.ensure_mapgroupproto_loaded():
            messagebox.showwarning(APP_TITLE, "No mapgroupproto.xml found in selected mission root.")
            return
        if self.source_has_changes(self.mapgroupproto_path) and not messagebox.askyesno(APP_TITLE, "Discard unsaved mapgroupproto.xml changes and reload from disk?"):
            return
        text = self.read_config_file_text(self.mapgroupproto_path)
        self.mapgroupproto_original_text = text
        self.mapgroupproto_current_text = text
        self.dirty_source_keys_cache.discard(self.mapgroupproto_current_key())
        self.set_mapgroupproto_preview_text("")
        self.validate_mapgroupproto_current_text(show_success=False)

    def save_mapgroupproto(self):
        if not self.mapgroupproto_path:
            messagebox.showwarning(APP_TITLE, "No mapgroupproto.xml loaded.")
            return
        try:
            self.current_mapgroupproto_root()
        except ET.ParseError as exc:
            messagebox.showerror(APP_TITLE, f"mapgroupproto.xml contains invalid XML:\n\n{exc}")
            return
        if not messagebox.askyesno(APP_TITLE, f"This will overwrite:\n{self.mapgroupproto_path}\n\nContinue?"):
            return
        if not self.confirm_source_save_sanity([self.mapgroupproto_path]):
            return
        count = self.save_source_file(self.mapgroupproto_path, allow_suspicious=True)
        self.mark_source_saved(self.mapgroupproto_path)
        self.log(f"Saved mapgroupproto.xml ({count} line(s)): {self.mapgroupproto_path}", "success")
        self.set_status("Mapgroupproto saved", "success")

    def config_file_supported(self, path):
        return is_supported_config_file(path)

    def discover_config_paths(self):
        paths = []
        if self.mission_workspace is not None:
            root = Path(self.mission_workspace.root_path)
            if root.is_dir():
                paths.extend(discover_config_files([root], handled_paths=self.handled_workspace_source_keys(), recursive=False))
                db_root = root / "db"
                if db_root.is_dir():
                    paths.extend(discover_config_files([db_root], recursive=False))
        deduped = []
        seen = set()
        for path in paths:
            key = self.normalized_path(path)
            if key in seen:
                continue
            seen.add(key)
            deduped.append(path)
        return sorted(deduped, key=lambda value: self.config_sort_key(value))

    def discover_profile_config_paths(self):
        if not self.profile_roots:
            return []
        paths = discover_config_files(self.profile_roots, recursive=True)
        deduped = []
        seen = set()
        for path in paths:
            key = self.normalized_path(path)
            if key in seen:
                continue
            seen.add(key)
            deduped.append(path)
        return sorted(deduped, key=lambda value: self.config_sort_key(value))

    def load_config_sources(self, preserve_existing=False):
        discovered = self.discover_config_paths()
        discovered_profiles = self.discover_profile_config_paths()
        existing_configs = [path for path in self.config_paths if Path(path).is_file() and not self.config_path_is_in_profile_roots(path) and not self.is_dedicated_module_source_path(path)]
        self.config_paths = self.dedupe_config_path_list(discovered + existing_configs)
        self.profile_config_paths = self.dedupe_config_path_list(discovered_profiles)
        all_paths = self.config_paths + self.profile_config_paths
        previous_originals = dict(self.config_original_texts)
        previous_current = dict(self.config_current_texts)
        self.config_original_texts = {}
        self.config_current_texts = {}
        for path in all_paths:
            key = self.normalized_path(path)
            if preserve_existing and key in previous_current:
                self.config_original_texts[key] = previous_originals.get(key, previous_current[key])
                self.config_current_texts[key] = previous_current[key]
        seen = {self.normalized_path(path) for path in all_paths}
        if self.selected_config_path and self.normalized_path(self.selected_config_path) not in seen:
            self.selected_config_path = ""
        if self.selected_profile_config_path and self.normalized_path(self.selected_profile_config_path) not in seen:
            self.selected_profile_config_path = ""

    def dedupe_config_path_list(self, paths):
        merged = []
        seen = set()
        for path in paths:
            key = self.normalized_path(path)
            if key in seen:
                continue
            seen.add(key)
            merged.append(path)
        return merged

    def read_config_file_text(self, path):
        if is_ignored_storage_path(path):
            raise OSError("Access blocked: storage_1 is always ignored.")
        try:
            return Path(path).read_text(encoding="utf-8-sig")
        except UnicodeDecodeError:
            return Path(path).read_text(encoding="latin-1")

    def ensure_config_loaded(self, path):
        key = self.normalized_path(path)
        if key in self.config_current_texts:
            return True
        try:
            text = self.read_config_file_text(path)
        except OSError as exc:
            self.log(f"Could not read config file {path}: {exc}", "warning")
            self.set_config_validation_message(f"Could not read config file: {exc}", "error")
            return False
        self.config_original_texts[key] = text
        self.config_current_texts[key] = text
        return True

    def config_source_is_dirty(self, path):
        key = self.normalized_path(path)
        return key in self.config_current_texts and self.config_current_texts.get(key, "") != self.config_original_texts.get(key, "")

    def config_source_label(self, path):
        return Path(path).name

    def config_display_name(self, path):
        category = self.config_category_name(path)
        if self.mission_workspace is not None:
            try:
                relative = Path(path).resolve().relative_to(Path(self.mission_workspace.root_path).resolve())
                return f"{category}\\configs\\{relative}"
            except (OSError, ValueError):
                pass
        for profile_root in self.profile_roots:
            try:
                relative = Path(path).resolve().relative_to(Path(profile_root).resolve())
                return f"{category}\\profiles\\{Path(profile_root).name}\\{relative}"
            except (OSError, ValueError):
                continue
        return f"{category}\\external\\{self.source_display_name(path)}"

    def config_category_name(self, path):
        suffix = Path(path).suffix.casefold()
        if suffix == ".json":
            return "json"
        if suffix == ".xml":
            return "xml"
        if suffix == ".c":
            return "c"
        if suffix == ".cfg":
            return "cfg"
        return "other"

    def config_sort_key(self, path):
        order = {"json": 0, "xml": 1, "c": 2, "cfg": 3, "other": 4}
        category = self.config_category_name(path)
        path_obj = Path(path)
        return (order.get(category, 99), path_obj.name.casefold(), self.config_display_name(path).casefold())

    def config_category_label(self, category):
        return {
            "json": "JSON files",
            "xml": "XML files",
            "c": "C script files",
            "cfg": "CFG files",
            "other": "Other files",
        }.get(category, "Other files")

    def filtered_config_paths(self):
        search = self.config_search_var.get().strip().casefold()
        paths = []
        for path in self.config_paths:
            if self.is_dedicated_module_source_path(path):
                continue
            if Path(path).name.casefold() == MISSION_MAPGROUPPROTO_FILENAME:
                continue
            display = self.config_display_name(path)
            if search and search not in display.casefold():
                continue
            paths.append(path)
        return paths

    def schedule_config_list_refresh(self, event=None):
        if self.config_search_after_id:
            self.after_cancel(self.config_search_after_id)
        self.config_search_after_id = self.after(120, self.refresh_config_list)

    def refresh_config_list(self):
        self.config_search_after_id = None
        if self.config_tree is None:
            return
        selected_key = self.normalized_path(self.selected_config_path) if self.selected_config_path else ""
        self.config_reloading_list = True
        self.config_tree.delete(*self.config_tree.get_children())
        self.config_tree_paths = {}
        paths = self.filtered_config_paths()
        categories = {category: [] for category in ("json", "xml", "c", "cfg", "other")}
        for path in paths:
            categories.setdefault(self.config_category_name(path), []).append(path)
        for category in ("json", "xml", "c", "cfg", "other"):
            category_paths = categories.get(category, [])
            if not category_paths:
                continue
            parent_iid = f"config-category-{category}"
            self.config_tree.insert("", "end", iid=parent_iid, text=f"{self.config_category_label(category)} ({len(category_paths)})", open=True)
            for index, path in enumerate(category_paths):
                dirty = "*" if self.config_source_is_dirty(path) else " "
                iid = f"config-file-{category}-{index}"
                self.config_tree.insert(parent_iid, "end", iid=iid, text=f"{dirty} {self.config_source_label(path)}")
                self.config_tree_paths[iid] = path
        selected_path = ""
        if selected_key and paths:
            for path in paths:
                if self.normalized_path(path) == selected_key:
                    selected_path = path
                    break
        if selected_path:
            selected_iid = next((iid for iid, config_path in self.config_tree_paths.items() if self.normalized_path(config_path) == self.normalized_path(selected_path)), "")
            if selected_iid:
                self.config_tree.selection_set(selected_iid)
                self.config_tree.see(selected_iid)
            self.selected_config_path = selected_path
            self.load_selected_config_into_editor()
        else:
            self.clear_config_editor()
        self.config_reloading_list = False
        self.config_path_var.set(f"{len(self.config_paths)} mission config file(s) found" if self.config_paths else "No mission config files found")

    def refresh_config_tree_rows(self):
        if self.config_tree is None:
            return
        for iid, path in self.config_tree_paths.items():
            dirty = "*" if self.config_source_is_dirty(path) else " "
            self.config_tree.item(iid, text=f"{dirty} {self.config_source_label(path)}")

    def on_config_editor_yscroll(self, scrollbar, first, last):
        scrollbar.set(first, last)
        self.schedule_config_line_number_refresh()

    def schedule_config_line_number_refresh(self, event=None):
        if self.config_line_numbers is None:
            return
        if self.config_line_numbers_after_id:
            self.after_cancel(self.config_line_numbers_after_id)
        self.config_line_numbers_after_id = self.after_idle(self.refresh_config_line_numbers)

    def refresh_config_line_numbers(self):
        self.config_line_numbers_after_id = None
        if self.config_line_numbers is None or self.config_editor_text is None:
            return
        self.refresh_line_numbers_for_widget(self.config_line_numbers, self.config_editor_text)

    def refresh_line_numbers_for_widget(self, canvas, text):
        canvas.delete("all")
        total_lines = max(1, int(text.index("end-1c").split(".", 1)[0]))
        gutter_width = max(44, len(str(total_lines)) * 8 + 18)
        if canvas.winfo_width() != gutter_width:
            canvas.configure(width=gutter_width)
        line_index = text.index("@0,0")
        while True:
            dline = text.dlineinfo(line_index)
            if dline is None:
                break
            y = dline[1]
            line_number = line_index.split(".", 1)[0]
            canvas.create_text(
                gutter_width - 8,
                y,
                anchor="ne",
                text=line_number,
                fill=GRAPHITE_MUTED,
                font=("Consolas", 9),
            )
            line_index = text.index(f"{line_index}+1line")

    def clear_config_editor(self):
        self.selected_config_path = ""
        self.config_status_var.set("No config selected.")
        if self.config_editor_text is not None:
            self.config_editor_text.delete("1.0", "end")
            self.config_editor_text.edit_modified(False)
        self.schedule_config_line_number_refresh()
        self.set_config_validation_message("Select a config file to view or edit it.", "muted")

    def selected_config_key(self):
        return self.normalized_path(self.selected_config_path)

    def load_selected_config_into_editor(self):
        if self.config_editor_text is None or not self.selected_config_path:
            return
        if not self.ensure_config_loaded(self.selected_config_path):
            self.config_editor_text.delete("1.0", "end")
            self.config_editor_text.edit_modified(False)
            return
        key = self.selected_config_key()
        text = self.config_current_texts.get(key, "")
        self.config_editor_text.delete("1.0", "end")
        self.config_editor_text.insert("1.0", text)
        self.config_editor_text.edit_modified(False)
        self.schedule_config_line_number_refresh()
        dirty = " Unsaved changes." if text != self.config_original_texts.get(key, "") else ""
        self.config_status_var.set(f"{self.config_display_name(self.selected_config_path)}.{dirty}")
        self.set_config_validation_message("Click Validate to check this file.", "muted")
        self.schedule_config_highlighting(delay=250)

    def on_config_source_select(self, event=None):
        if self.config_reloading_list or self.config_tree is None:
            return
        selected = self.config_tree.selection()
        if not selected:
            return
        path = self.config_tree_paths.get(selected[0])
        if not path:
            return
        if self.selected_config_path:
            self.capture_config_editor_text()
        self.selected_config_path = path
        self.load_selected_config_into_editor()

    def select_config_source_path(self, path, line=None, column=None):
        self.switch_module("configs")
        target_key = self.normalized_path(path)
        if target_key not in {self.normalized_path(config_path) for config_path in self.config_paths}:
            return False
        self.selected_config_path = path
        self.config_search_var.set("")
        self.refresh_config_list()
        found = False
        if self.config_tree is not None:
            for iid, config_path in self.config_tree_paths.items():
                if self.normalized_path(config_path) == target_key:
                    self.config_tree.selection_set(iid)
                    self.config_tree.see(iid)
                    found = True
                    break
        self.load_selected_config_into_editor()
        self.scroll_text_widget_to_line(self.config_editor_text, line=line, column=column)
        return found

    def capture_config_editor_text(self):
        if self.config_editor_text is None or not self.selected_config_path:
            return
        key = self.selected_config_key()
        if key not in self.config_current_texts:
            return
        self.config_current_texts[key] = self.config_editor_text.get("1.0", "end-1c")

    def on_config_editor_modified(self, event=None):
        if self.config_editor_text is None or not self.config_editor_text.edit_modified():
            return
        self.config_editor_text.edit_modified(False)
        if not self.selected_config_path:
            return
        self.capture_config_editor_text()
        key = self.selected_config_key()
        if self.config_current_texts.get(key, "") != self.config_original_texts.get(key, ""):
            self.mark_source_dirty(self.selected_config_path)
        else:
            self.dirty_source_keys_cache.discard(key)
            self.set_dirty(True)
        self.refresh_config_list_preserve_selection()
        self.schedule_config_line_number_refresh()
        self.schedule_config_highlighting()

    def refresh_config_list_preserve_selection(self):
        if self.config_tree is None or self.config_reloading_list:
            return
        selected_key = self.selected_config_key()
        self.refresh_config_tree_rows()
        for iid, path in self.config_tree_paths.items():
            if self.normalized_path(path) == selected_key:
                self.config_tree.selection_set(iid)
                break

    def filtered_profile_config_paths(self):
        search = self.profile_config_search_var.get().strip().casefold()
        paths = []
        for path in self.profile_config_paths:
            display = self.config_display_name(path)
            if search and search not in display.casefold():
                continue
            paths.append(path)
        return paths

    def schedule_profile_config_list_refresh(self, event=None):
        if self.profile_config_search_after_id:
            self.after_cancel(self.profile_config_search_after_id)
        self.profile_config_search_after_id = self.after(120, self.refresh_profile_config_list)

    def refresh_profile_config_list(self):
        self.profile_config_search_after_id = None
        if self.profile_config_tree is None:
            return
        selected_key = self.normalized_path(self.selected_profile_config_path) if self.selected_profile_config_path else ""
        self.profile_config_reloading_list = True
        self.profile_config_tree.delete(*self.profile_config_tree.get_children())
        self.profile_config_tree_paths = {}
        paths = self.filtered_profile_config_paths()
        self.populate_profile_config_tree(paths)
        selected_path = ""
        if selected_key and paths:
            for path in paths:
                if self.normalized_path(path) == selected_key:
                    selected_path = path
                    break
        if selected_path:
            selected_iid = next((iid for iid, config_path in self.profile_config_tree_paths.items() if self.normalized_path(config_path) == self.normalized_path(selected_path)), "")
            if selected_iid:
                self.profile_config_tree.selection_set(selected_iid)
                self.profile_config_tree.see(selected_iid)
            self.selected_profile_config_path = selected_path
            self.load_selected_profile_config_into_editor()
        else:
            self.clear_profile_config_editor()
        self.profile_config_reloading_list = False
        root_summary = f" from {len(self.profile_roots)} profiles folder(s)" if self.profile_roots else ""
        self.profile_config_path_var.set(f"{len(self.profile_config_paths)} profile config file(s){root_summary}" if self.profile_roots else "No profiles folder attached")

    def profile_root_for_path(self, path):
        path_obj = Path(path)
        for profile_root in self.profile_roots:
            root_obj = Path(profile_root)
            try:
                path_obj.resolve().relative_to(root_obj.resolve())
                return root_obj
            except (OSError, ValueError):
                continue
        return None

    def profile_relative_parts(self, path):
        root = self.profile_root_for_path(path)
        if root is None:
            return (Path(path).name,)
        try:
            return Path(path).resolve().relative_to(root.resolve()).parts
        except (OSError, ValueError):
            return (Path(path).name,)

    def populate_profile_config_tree(self, paths):
        root_iids: dict[str, str] = {}
        folder_iids: dict[tuple[str, tuple[str, ...]], str] = {}
        root_counts: dict[str, int] = {}
        for path in paths:
            root = self.profile_root_for_path(path)
            root_key = self.normalized_path(root) if root is not None else "__external__"
            root_counts[root_key] = root_counts.get(root_key, 0) + 1

        sorted_roots = []
        for profile_root in self.profile_roots:
            key = self.normalized_path(profile_root)
            if key in root_counts:
                sorted_roots.append((key, Path(profile_root).name or str(profile_root), str(profile_root)))
        external_count = root_counts.get("__external__", 0)
        if external_count:
            sorted_roots.append(("__external__", "External profile files", ""))

        for root_index, (root_key, label, _root_path) in enumerate(sorted_roots):
            iid = f"profile-root-{root_index}"
            count = root_counts.get(root_key, 0)
            self.profile_config_tree.insert("", "end", iid=iid, text=f"{label} ({count})", open=True)
            root_iids[root_key] = iid

        for file_index, path in enumerate(paths):
            root = self.profile_root_for_path(path)
            root_key = self.normalized_path(root) if root is not None else "__external__"
            parent_iid = root_iids.get(root_key)
            if parent_iid is None:
                parent_iid = self.profile_config_tree.insert("", "end", text="External profile files", open=True)
                root_iids[root_key] = parent_iid
            parts = self.profile_relative_parts(path)
            folder_parts = tuple(parts[:-1])
            current_parent = parent_iid
            for depth in range(1, len(folder_parts) + 1):
                folder_key = (root_key, folder_parts[:depth])
                folder_iid = folder_iids.get(folder_key)
                if folder_iid is None:
                    folder_iid = f"profile-folder-{len(folder_iids)}"
                    self.profile_config_tree.insert(current_parent, "end", iid=folder_iid, text=folder_parts[depth - 1], open=True)
                    folder_iids[folder_key] = folder_iid
                current_parent = folder_iid
            dirty = "*" if self.config_source_is_dirty(path) else " "
            file_iid = f"profile-config-file-{file_index}"
            self.profile_config_tree.insert(current_parent, "end", iid=file_iid, text=f"{dirty} {Path(path).name}")
            self.profile_config_tree_paths[file_iid] = path

    def refresh_profile_config_tree_rows(self):
        if self.profile_config_tree is None:
            return
        for iid, path in self.profile_config_tree_paths.items():
            dirty = "*" if self.config_source_is_dirty(path) else " "
            self.profile_config_tree.item(iid, text=f"{dirty} {Path(path).name}")

    def on_profile_config_editor_yscroll(self, scrollbar, first, last):
        scrollbar.set(first, last)
        self.schedule_profile_config_line_number_refresh()

    def schedule_profile_config_line_number_refresh(self, event=None):
        if self.profile_config_line_numbers is None:
            return
        if self.profile_config_line_numbers_after_id:
            self.after_cancel(self.profile_config_line_numbers_after_id)
        self.profile_config_line_numbers_after_id = self.after_idle(self.refresh_profile_config_line_numbers)

    def refresh_profile_config_line_numbers(self):
        self.profile_config_line_numbers_after_id = None
        if self.profile_config_line_numbers is None or self.profile_config_editor_text is None:
            return
        self.refresh_line_numbers_for_widget(self.profile_config_line_numbers, self.profile_config_editor_text)

    def clear_profile_config_editor(self):
        self.selected_profile_config_path = ""
        self.profile_config_status_var.set("No profile config selected.")
        if self.profile_config_editor_text is not None:
            self.profile_config_editor_text.delete("1.0", "end")
            self.profile_config_editor_text.edit_modified(False)
        self.schedule_profile_config_line_number_refresh()
        self.set_profile_config_validation_message("Select a profile config file to view or edit it.", "muted")

    def selected_profile_config_key(self):
        return self.normalized_path(self.selected_profile_config_path)

    def load_selected_profile_config_into_editor(self):
        if self.profile_config_editor_text is None or not self.selected_profile_config_path:
            return
        if not self.ensure_config_loaded(self.selected_profile_config_path):
            self.profile_config_editor_text.delete("1.0", "end")
            self.profile_config_editor_text.edit_modified(False)
            return
        key = self.selected_profile_config_key()
        text = self.config_current_texts.get(key, "")
        self.profile_config_editor_text.delete("1.0", "end")
        self.profile_config_editor_text.insert("1.0", text)
        self.profile_config_editor_text.edit_modified(False)
        self.schedule_profile_config_line_number_refresh()
        dirty = " Unsaved changes." if text != self.config_original_texts.get(key, "") else ""
        self.profile_config_status_var.set(f"{self.config_display_name(self.selected_profile_config_path)}.{dirty}")
        self.set_profile_config_validation_message("Click Validate to check this file.", "muted")
        self.schedule_profile_config_highlighting(delay=250)

    def on_profile_config_source_select(self, event=None):
        if self.profile_config_reloading_list or self.profile_config_tree is None:
            return
        selected = self.profile_config_tree.selection()
        if not selected:
            return
        path = self.profile_config_tree_paths.get(selected[0])
        if not path:
            return
        if self.selected_profile_config_path:
            self.capture_profile_config_editor_text()
        self.selected_profile_config_path = path
        self.load_selected_profile_config_into_editor()

    def select_profile_config_source_path(self, path, line=None, column=None):
        self.switch_module("profiles")
        target_key = self.normalized_path(path)
        if target_key not in {self.normalized_path(config_path) for config_path in self.profile_config_paths}:
            return False
        self.selected_profile_config_path = path
        self.profile_config_search_var.set("")
        self.refresh_profile_config_list()
        found = False
        if self.profile_config_tree is not None:
            for iid, config_path in self.profile_config_tree_paths.items():
                if self.normalized_path(config_path) == target_key:
                    self.profile_config_tree.selection_set(iid)
                    self.profile_config_tree.see(iid)
                    found = True
                    break
        self.load_selected_profile_config_into_editor()
        self.scroll_text_widget_to_line(self.profile_config_editor_text, line=line, column=column)
        return found

    def capture_profile_config_editor_text(self):
        if self.profile_config_editor_text is None or not self.selected_profile_config_path:
            return
        key = self.selected_profile_config_key()
        if key not in self.config_current_texts:
            return
        self.config_current_texts[key] = self.profile_config_editor_text.get("1.0", "end-1c")

    def capture_config_editor_text_for_path(self, source_path):
        source_key = self.normalized_path(source_path)
        if self.selected_config_path and source_key == self.selected_config_key():
            self.capture_config_editor_text()
        if self.selected_profile_config_path and source_key == self.selected_profile_config_key():
            self.capture_profile_config_editor_text()

    def on_profile_config_editor_modified(self, event=None):
        if self.profile_config_editor_text is None or not self.profile_config_editor_text.edit_modified():
            return
        self.profile_config_editor_text.edit_modified(False)
        if not self.selected_profile_config_path:
            return
        self.capture_profile_config_editor_text()
        key = self.selected_profile_config_key()
        if self.config_current_texts.get(key, "") != self.config_original_texts.get(key, ""):
            self.mark_source_dirty(self.selected_profile_config_path)
        else:
            self.dirty_source_keys_cache.discard(key)
            self.set_dirty(True)
        self.refresh_profile_config_list_preserve_selection()
        self.schedule_profile_config_line_number_refresh()
        self.schedule_profile_config_highlighting()

    def refresh_profile_config_list_preserve_selection(self):
        if self.profile_config_tree is None or self.profile_config_reloading_list:
            return
        selected_key = self.selected_profile_config_key()
        self.refresh_profile_config_tree_rows()
        for iid, path in self.profile_config_tree_paths.items():
            if self.normalized_path(path) == selected_key:
                self.profile_config_tree.selection_set(iid)
                break

    def set_config_validation_message(self, message, variant="muted"):
        if self.config_validation_text is None:
            return
        self.config_validation_text.configure(state="normal")
        self.config_validation_text.delete("1.0", "end")
        self.config_validation_text.insert("end", message)
        self.config_validation_text.configure(state="disabled")

    def set_profile_config_validation_message(self, message, variant="muted"):
        if self.profile_config_validation_text is None:
            return
        self.profile_config_validation_text.configure(state="normal")
        self.profile_config_validation_text.delete("1.0", "end")
        self.profile_config_validation_text.insert("end", message)
        self.profile_config_validation_text.configure(state="disabled")

    def validate_config_text(self, path, text):
        suffix = Path(path).suffix.casefold()
        if suffix == ".json":
            json.loads(text)
            return "JSON syntax is valid."
        if suffix == ".xml":
            ET.fromstring(text)
            return "XML syntax is valid."
        return "No strict validator is available for this file type. Text can still be edited and saved."

    def validate_selected_config_file(self, show_success=True):
        if not self.selected_config_path:
            self.set_config_validation_message("Select a config file first.", "warning")
            return False
        if not self.ensure_config_loaded(self.selected_config_path):
            return False
        self.capture_config_editor_text()
        try:
            message = self.validate_config_text(self.selected_config_path, self.config_current_texts.get(self.selected_config_key(), ""))
        except (json.JSONDecodeError, ET.ParseError) as exc:
            self.set_config_validation_message(f"Syntax error: {exc}", "error")
            if show_success:
                self.log(f"Config validation failed for {self.selected_config_path}: {exc}", "warning")
            return False
        self.set_config_validation_message(message, "success")
        if show_success:
            self.log(f"Config validation passed: {self.selected_config_path}", "success")
        return True

    def validate_selected_profile_config_file(self, show_success=True):
        if not self.selected_profile_config_path:
            self.set_profile_config_validation_message("Select a profile config file first.", "warning")
            return False
        if not self.ensure_config_loaded(self.selected_profile_config_path):
            return False
        self.capture_profile_config_editor_text()
        try:
            message = self.validate_config_text(self.selected_profile_config_path, self.config_current_texts.get(self.selected_profile_config_key(), ""))
        except (json.JSONDecodeError, ET.ParseError) as exc:
            self.set_profile_config_validation_message(f"Syntax error: {exc}", "error")
            if show_success:
                self.log(f"Profile config validation failed for {self.selected_profile_config_path}: {exc}", "warning")
            return False
        self.set_profile_config_validation_message(message, "success")
        if show_success:
            self.log(f"Profile config validation passed: {self.selected_profile_config_path}", "success")
        return True

    def validate_loaded_config_files(self):
        issues = []
        for path in self.config_paths + self.profile_config_paths:
            key = self.normalized_path(path)
            suffix = Path(path).suffix.casefold()
            if suffix not in {".json", ".xml"}:
                continue
            try:
                text = self.config_current_texts.get(key)
                if text is None:
                    text = self.read_config_file_text(path)
            except OSError as exc:
                issues.append(
                    ValidationIssue(
                        "error",
                        "",
                        f"Could not read config file: {exc}",
                        path,
                        "Make sure the file still exists and can be read.",
                    )
                )
                continue
            if suffix == ".json":
                try:
                    json.loads(text)
                except json.JSONDecodeError as exc:
                    issues.append(
                        ValidationIssue(
                            "error",
                            "",
                            f"JSON syntax error: {exc.msg}",
                            path,
                            "Fix the JSON syntax before saving or using this profiles/config file.",
                            exc.lineno,
                            exc.colno,
                        )
                    )
            elif suffix == ".xml":
                try:
                    ET.fromstring(text)
                except ET.ParseError as exc:
                    line, column = getattr(exc, "position", (None, None))
                    issues.append(
                        ValidationIssue(
                            "error",
                            "",
                            f"XML syntax error: {exc}",
                            path,
                            "Fix the XML syntax before saving or using this config file.",
                            line,
                            column,
                        )
                    )
        return issues

    def choose_config_files(self):
        paths = filedialog.askopenfilenames(
            title="Choose config files",
            filetypes=[("Config files", "*.json *.xml *.c *.cfg"), ("All files", "*.*")],
            initialdir=self.saved_settings.get("last_dir", str(Path.home())),
        )
        if not paths:
            return
        for path in paths:
            if self.normalized_path(path) not in {self.normalized_path(existing) for existing in self.config_paths}:
                self.config_paths.append(path)
        self.saved_settings["last_dir"] = os.path.dirname(paths[-1])
        self.load_config_sources(preserve_existing=True)
        self.refresh_config_list()

    def profiles_folder_initial_dir(self):
        candidates = []
        saved_profiles = self.saved_settings.get("profiles_dir")
        if saved_profiles:
            saved_profiles_path = Path(saved_profiles)
            if saved_profiles_path.is_dir():
                candidates.append(saved_profiles_path.parent)
        if self.mission_workspace is not None:
            mission_root = Path(self.mission_workspace.root_path)
            try:
                mission_root = mission_root.resolve()
            except OSError:
                pass
            if mission_root.name.casefold().startswith("dayzoffline") and mission_root.parent.name.casefold() == "mpmissions":
                candidates.append(mission_root.parent.parent)
            candidates.extend([mission_root.parent, mission_root])
        last_dir = self.saved_settings.get("last_dir")
        if last_dir:
            candidates.append(Path(last_dir))
        candidates.append(Path.home())
        for candidate in candidates:
            try:
                if candidate and Path(candidate).is_dir():
                    return str(candidate)
            except OSError:
                continue
        return str(Path.home())

    def choose_profiles_folder(self):
        path = filedialog.askdirectory(
            title="Choose DayZ server profiles folder",
            initialdir=self.profiles_folder_initial_dir(),
            mustexist=True,
        )
        if not path:
            return
        if self.normalized_path(path) not in {self.normalized_path(existing) for existing in self.profile_roots}:
            self.profile_roots.append(path)
        self.saved_settings["profiles_dir"] = path
        self.saved_settings["last_dir"] = path
        save_settings(self.saved_settings)
        before = len(self.profile_config_paths)
        self.load_config_sources(preserve_existing=True)
        self.refresh_config_list()
        self.refresh_profile_config_list()
        added = max(0, len(self.profile_config_paths) - before)
        self.log(f"Added profiles folder: {path} ({added} new config file(s) found).", "success" if added else "warning")

    def config_path_is_in_profile_roots(self, path):
        for profile_root in self.profile_roots:
            try:
                Path(path).resolve().relative_to(Path(profile_root).resolve())
                return True
            except (OSError, ValueError):
                continue
        return False

    def clear_profiles_folders(self):
        if not self.profile_roots:
            messagebox.showinfo(APP_TITLE, "No profiles folders are attached.")
            return
        removed_roots = len(self.profile_roots)
        removed_keys = {
            self.normalized_path(path)
            for path in self.profile_config_paths
            if self.config_path_is_in_profile_roots(path)
        }
        self.profile_config_paths = []
        for key in removed_keys:
            self.config_original_texts.pop(key, None)
            self.config_current_texts.pop(key, None)
            self.dirty_source_keys_cache.discard(key)
        if self.selected_profile_config_path and self.normalized_path(self.selected_profile_config_path) in removed_keys:
            self.selected_profile_config_path = ""
        self.profile_roots = []
        self.clear_profile_config_editor()
        self.refresh_config_list()
        self.refresh_profile_config_list()
        self.update_summary()
        self.log(f"Removed {removed_roots} profiles folder(s) from Profiles.", "success")

    def reload_selected_config_file(self):
        if not self.selected_config_path:
            messagebox.showwarning(APP_TITLE, "Select a config file first.")
            return
        if self.source_has_changes(self.selected_config_path) and not messagebox.askyesno(APP_TITLE, "Discard unsaved changes and reload this config from disk?"):
            return
        path = self.selected_config_path
        try:
            text = self.read_config_file_text(path)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Reload failed:\n{exc}")
            return
        key = self.normalized_path(path)
        self.config_original_texts[key] = text
        self.config_current_texts[key] = text
        self.dirty_source_keys_cache.discard(key)
        self.set_dirty(True)
        self.load_selected_config_into_editor()
        self.refresh_config_list_preserve_selection()
        self.log(f"Reloaded config: {path}", "success")

    def reload_selected_profile_config_file(self):
        if not self.selected_profile_config_path:
            messagebox.showwarning(APP_TITLE, "Select a profile config file first.")
            return
        if self.source_has_changes(self.selected_profile_config_path) and not messagebox.askyesno(APP_TITLE, "Discard unsaved changes and reload this profile config from disk?"):
            return
        path = self.selected_profile_config_path
        try:
            text = self.read_config_file_text(path)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Reload failed:\n{exc}")
            return
        key = self.normalized_path(path)
        self.config_original_texts[key] = text
        self.config_current_texts[key] = text
        self.dirty_source_keys_cache.discard(key)
        self.set_dirty(True)
        self.load_selected_profile_config_into_editor()
        self.refresh_profile_config_list_preserve_selection()
        self.log(f"Reloaded profile config: {path}", "success")

    def save_selected_config_file(self):
        if not self.selected_config_path:
            messagebox.showwarning(APP_TITLE, "Select a config file first.")
            return
        if self.is_dedicated_module_source_path(self.selected_config_path):
            module = self.source_module_label(self.selected_config_path)
            messagebox.showwarning(APP_TITLE, f"{Path(self.selected_config_path).name} is managed by the {module} module.\n\nOpen {module} and use Save there. Generic Configs save is blocked so raw text edits cannot overwrite module-managed data.")
            return
        if not self.validate_selected_config_file(show_success=False):
            if not messagebox.askyesno(APP_TITLE, "This config has syntax issues.\n\nSave it anyway?"):
                return
        if not messagebox.askyesno(APP_TITLE, f"This will overwrite:\n{self.selected_config_path}\n\nContinue?"):
            return
        if not self.confirm_source_save_sanity([self.selected_config_path]):
            return
        try:
            count = self.save_source_file(self.selected_config_path, allow_suspicious=True)
        except (OSError, ValueError, ET.ParseError) as exc:
            messagebox.showerror(APP_TITLE, f"Save failed:\n{exc}")
            return
        self.mark_source_saved(self.selected_config_path)
        self.refresh_config_list_preserve_selection()
        self.log(f"Saved config file ({count} line(s)): {self.selected_config_path}", "success")
        self.set_status("Config saved", "success")

    def save_selected_profile_config_file(self):
        if not self.selected_profile_config_path:
            messagebox.showwarning(APP_TITLE, "Select a profile config file first.")
            return
        if not self.validate_selected_profile_config_file(show_success=False):
            if not messagebox.askyesno(APP_TITLE, "This profile config has syntax issues.\n\nSave it anyway?"):
                return
        if not messagebox.askyesno(APP_TITLE, f"This will overwrite:\n{self.selected_profile_config_path}\n\nContinue?"):
            return
        if not self.confirm_source_save_sanity([self.selected_profile_config_path]):
            return
        try:
            count = self.save_source_file(self.selected_profile_config_path, allow_suspicious=True)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Save failed:\n{exc}")
            return
        self.mark_source_saved(self.selected_profile_config_path)
        self.refresh_profile_config_list_preserve_selection()
        self.log(f"Saved profile config file ({count} line(s)): {self.selected_profile_config_path}", "success")
        self.set_status("Profile saved", "success")

    def reset_territory_map_view(self):
        state = self.territory_map_state
        state["zoom"] = 1.0
        state["offset_x"] = 0.0
        state["offset_y"] = 0.0
        self.load_embedded_territory_map_image()
        self.fit_territory_map()
        self.draw_territory_map()

    def territory_map_visible_items(self):
        return [
            (index, zone, coord)
            for index, zone in self.visible_territory_zone_items()
            for coord in [self.spawn_position_xy(zone)]
            if coord is not None
        ]

    def load_embedded_territory_map_image(self):
        state = self.territory_map_state
        map_key = self.selected_map_key
        if state.get("map_key") == map_key and (state.get("image") is not None or state.get("tk_image") is not None or not map_key or state.get("missing_map_key") == map_key):
            return
        state.update({"image": None, "tk_image": None, "rendered_image": None, "image_levels": [], "image_backend": "", "base_w": 0.0, "base_h": 0.0, "map_key": map_key, "missing_map_key": ""})
        if not map_key:
            return
        local_path, _image_label, image_source = self.resolve_map_image(map_key)
        if not local_path:
            state["missing_map_key"] = map_key
            if image_source:
                self.log(f"Map image unavailable: {image_source}", "warning")
            return
        if PIL_AVAILABLE:
            try:
                image = Image.open(local_path).convert("RGB")
                state["image"] = image
                state["image_levels"] = self.build_map_image_levels(image)
                state["image_backend"] = "pillow"
                state["base_w"] = float(image.width)
                state["base_h"] = float(image.height)
            except Exception as exc:
                self.log(f"Could not load map image {local_path}: {exc}", "warning")
        else:
            try:
                image = tk.PhotoImage(file=local_path)
                state["tk_image"] = image
                state["image_backend"] = "tk"
                state["base_w"] = float(image.width())
                state["base_h"] = float(image.height())
                if self.territory_map_canvas is not None:
                    self.territory_map_canvas._map_image_ref = image
            except tk.TclError as exc:
                self.log(f"Could not load map image {local_path}: {exc}", "warning")

    def territory_map_base_size(self):
        state = self.territory_map_state
        if state.get("image") is not None or state.get("tk_image") is not None:
            return state.get("base_w") or 900.0, state.get("base_h") or 900.0
        return 900.0, 900.0

    def build_map_image_levels(self, image):
        levels = [(1.0, image)]
        if not PIL_AVAILABLE:
            return levels
        scale = 1.0
        current = image
        while min(current.width, current.height) > 1024:
            next_width = max(1, current.width // 2)
            next_height = max(1, current.height // 2)
            current = current.resize((next_width, next_height), Image.Resampling.BOX)
            scale = min(current.width / image.width, current.height / image.height)
            levels.append((scale, current))
        return levels

    def map_image_level_for_zoom(self, state):
        levels = state.get("image_levels") or []
        if not levels and state.get("image") is not None:
            levels = [(1.0, state["image"])]
        zoom = max(float(state.get("zoom") or 1.0), 0.01)
        chosen = levels[0] if levels else (1.0, None)
        for scale, image in levels:
            if scale >= zoom:
                chosen = (scale, image)
            else:
                break
        return chosen

    def draw_cached_map_image(self, canvas, state, base_w, base_h):
        if state.get("image_backend") == "tk" and state.get("tk_image") is not None:
            canvas.create_image(state["offset_x"], state["offset_y"], image=state["tk_image"], anchor="nw")
            return True
        if state.get("image") is None:
            return False
        canvas_w = max(canvas.winfo_width(), 1)
        canvas_h = max(canvas.winfo_height(), 1)
        left = max(0.0, -state["offset_x"] / state["zoom"])
        top = max(0.0, -state["offset_y"] / state["zoom"])
        right = min(base_w, (canvas_w - state["offset_x"]) / state["zoom"])
        bottom = min(base_h, (canvas_h - state["offset_y"]) / state["zoom"])
        if right <= left or bottom <= top:
            return True
        source_scale, source_image = self.map_image_level_for_zoom(state)
        if source_image is None:
            return False
        source_crop_box = (
            max(0, int(left * source_scale)),
            max(0, int(top * source_scale)),
            min(source_image.width, max(int(right * source_scale), int(left * source_scale) + 1)),
            min(source_image.height, max(int(bottom * source_scale), int(top * source_scale) + 1)),
        )
        crop = source_image.crop(source_crop_box)
        render_scale = state["zoom"] / source_scale
        render_w = max(1, int(crop.width * render_scale))
        render_h = max(1, int(crop.height * render_scale))
        if render_w > 12000 or render_h > 12000:
            return True
        if state.get("render_fast"):
            resample = Image.Resampling.NEAREST if render_scale >= 0.75 else Image.Resampling.BILINEAR
        else:
            resample = Image.Resampling.LANCZOS if render_scale < 1 else Image.Resampling.BICUBIC
        rendered = ImageTk.PhotoImage(crop.resize((render_w, render_h), resample))
        state["rendered_image"] = rendered
        canvas.create_image(
            state["offset_x"] + (source_crop_box[0] / source_scale) * state["zoom"],
            state["offset_y"] + (source_crop_box[1] / source_scale) * state["zoom"],
            image=rendered,
            anchor="nw",
        )
        return True

    def fit_territory_map(self):
        canvas = self.territory_map_canvas
        if canvas is None:
            return
        canvas.update_idletasks()
        width = max(canvas.winfo_width(), 400)
        height = max(canvas.winfo_height(), 400)
        base_w, base_h = self.territory_map_base_size()
        state = self.territory_map_state
        state["zoom"] = 1.0 if state.get("image_backend") == "tk" else max(0.05, min(width / base_w, height / base_h) * 0.94)
        state["offset_x"] = (width - base_w * state["zoom"]) / 2
        state["offset_y"] = (height - base_h * state["zoom"]) / 2

    def territory_world_to_canvas(self, x, z, map_width, map_height):
        base_w, base_h = self.territory_map_base_size()
        state = self.territory_map_state
        px = (x / map_width) * base_w
        py = base_h - (z / map_height) * base_h
        return state["offset_x"] + px * state["zoom"], state["offset_y"] + py * state["zoom"]

    def territory_canvas_to_world(self, canvas_x, canvas_y, map_width, map_height):
        base_w, base_h = self.territory_map_base_size()
        state = self.territory_map_state
        if base_w <= 0 or base_h <= 0 or state["zoom"] <= 0:
            return None
        x = ((canvas_x - state["offset_x"]) / state["zoom"]) / base_w * map_width
        z = (1.0 - ((canvas_y - state["offset_y"]) / state["zoom"]) / base_h) * map_height
        x = max(0.0, min(map_width, x))
        z = max(0.0, min(map_height, z))
        return x, z

    def format_territory_coordinate(self, value):
        clean = f"{value:.2f}".rstrip("0").rstrip(".")
        return clean or "0"

    def format_territory_radius(self, value):
        try:
            radius = float(value)
        except (TypeError, ValueError):
            return ""
        radius = max(0.0, radius)
        return str(int(radius + 0.5))

    def territory_radius_value(self, zone):
        try:
            return float(zone.attributes.get("r", "0") or 0)
        except ValueError:
            return 0.0

    def visible_territory_index_set(self):
        return {index for index, _zone in self.visible_territory_zone_items()}

    def selected_visible_territory_indices(self):
        visible_indices = self.visible_territory_index_set()
        self.selected_territory_indices = {
            index
            for index in self.selected_territory_indices
            if index in visible_indices and 0 <= index < len(self.territory_zones)
        }
        return sorted(self.selected_territory_indices)

    def mark_territory_indices_dirty(self, indices):
        for source_path in {
            self.territory_zones[index].source_path
            for index in indices
            if 0 <= index < len(self.territory_zones)
        }:
            self.mark_source_dirty(source_path)

    def territory_zone_snapshot(self):
        return [zone.clone() for zone in self.territory_zones]

    def territory_group_snapshot(self):
        return [group.clone() for group in self.territory_groups]

    def apply_territory_edit_operation(self, operation, use_new=True):
        if operation.get("type") == "structure":
            self.territory_zones = [zone.clone() for zone in (operation["new"] if use_new else operation["old"])]
            if "new_groups" in operation or "old_groups" in operation:
                self.territory_groups = [
                    group.clone()
                    for group in (operation.get("new_groups", []) if use_new else operation.get("old_groups", []))
                ]
            selected = operation.get("new_selected" if use_new else "old_selected", [])
            self.selected_territory_indices = {
                int(index) for index in selected if 0 <= int(index) < len(self.territory_zones)
            }
            self.current_territory_index = min(self.selected_territory_indices) if self.selected_territory_indices else None
            for source_path in operation.get("source_paths", []):
                self.mark_source_dirty(source_path)
            self.mark_territory_related_event_cache_stale()
            self.schedule_validation_refresh()
            self.refresh_territory_table()
            if self.current_territory_index is not None:
                self.populate_territory_detail(self.current_territory_index)
            else:
                self.clear_territory_detail()
            self.update_summary()
            self.draw_territory_map()
            return True

        if operation.get("type") == "bulk_resize":
            values = operation["new"] if use_new else operation["old"]
            edited_indices = []
            for raw_index, radius in values.items():
                index = int(raw_index)
                if 0 <= index < len(self.territory_zones):
                    self.territory_zones[index].set_attribute("r", radius)
                    edited_indices.append(index)
            if not edited_indices:
                return False
            self.selected_territory_indices = set(edited_indices)
            active_index = operation.get("index")
            if active_index not in self.selected_territory_indices:
                active_index = edited_indices[0]
            self.current_territory_index = active_index
            self.populate_territory_detail(active_index)
            self.mark_territory_indices_dirty(edited_indices)
            self.mark_territory_related_event_cache_stale()
            self.schedule_validation_refresh()
            self.update_summary()
            self.draw_territory_map()
            return True

        index = operation.get("index")
        if index is None or not (0 <= index < len(self.territory_zones)):
            return False
        zone = self.territory_zones[index]
        values = operation["new"] if use_new else operation["old"]
        if operation.get("type") == "move":
            zone.set_attribute("x", values[0])
            zone.set_attribute("z", values[1])
        elif operation.get("type") == "resize":
            zone.set_attribute("r", values)
        else:
            return False
        self.select_territory_zone_index(index)
        self.mark_source_dirty(zone.source_path)
        self.mark_territory_related_event_cache_stale()
        self.schedule_validation_refresh()
        self.update_summary()
        self.draw_territory_map()
        return True

    def push_territory_edit_undo(self, operation_type, index, old_value, new_value):
        if old_value == new_value:
            return
        if operation_type != "bulk_resize" and (index is None or not (0 <= index < len(self.territory_zones))):
            return
        zone = self.territory_zones[index] if index is not None and 0 <= index < len(self.territory_zones) else None
        operation = {
            "type": operation_type,
            "index": index,
            "source_path": zone.source_path if zone is not None else "",
            "name": zone.name if zone is not None else f"{len(new_value)} zones",
            "old": old_value,
            "new": new_value,
        }
        self.territory_undo_stack.append(operation)
        self.territory_redo_stack.clear()

    def push_territory_structure_undo(self, action_name, old_zones, new_zones, source_paths, old_selected, new_selected, old_groups=None, new_groups=None):
        operation = {
            "type": "structure",
            "name": action_name,
            "source_paths": list(source_paths),
            "old": [zone.clone() for zone in old_zones],
            "new": [zone.clone() for zone in new_zones],
            "old_groups": [group.clone() for group in (old_groups if old_groups is not None else self.territory_groups)],
            "new_groups": [group.clone() for group in (new_groups if new_groups is not None else self.territory_groups)],
            "old_selected": list(old_selected),
            "new_selected": list(new_selected),
        }
        self.territory_undo_stack.append(operation)
        self.territory_redo_stack.clear()

    def undo_territory_edit(self):
        if not self.territory_undo_stack:
            self.log("No territory edit to undo.", "muted")
            return
        operation = self.territory_undo_stack.pop()
        if self.apply_territory_edit_operation(operation, use_new=False):
            self.territory_redo_stack.append(operation)
            self.log(f"Undid territory {operation.get('type', 'edit')}: {operation.get('name', '')}.", "success")

    def redo_territory_edit(self):
        if not self.territory_redo_stack:
            self.log("No territory edit to redo.", "muted")
            return
        operation = self.territory_redo_stack.pop()
        if self.apply_territory_edit_operation(operation, use_new=True):
            self.territory_undo_stack.append(operation)
            self.log(f"Redid territory {operation.get('type', 'edit')}: {operation.get('name', '')}.", "success")

    def draw_embedded_territory_map_image(self, base_w, base_h):
        canvas = self.territory_map_canvas
        if canvas is None:
            return
        self.draw_cached_map_image(canvas, self.territory_map_state, base_w, base_h)

    def schedule_territory_map_refine(self, delay_ms=90):
        state = self.territory_map_state
        after_id = state.get("render_refine_after_id")
        if after_id is not None:
            try:
                self.after_cancel(after_id)
            except tk.TclError:
                pass

        def refine():
            state["render_refine_after_id"] = None
            state["render_fast"] = False
            self.draw_territory_map()

        state["render_refine_after_id"] = self.after(delay_ms, refine)

    def schedule_territory_map_draw(self, fast=False):
        state = self.territory_map_state
        if fast:
            state["render_fast"] = True
        if state.get("draw_after_id") is not None:
            return

        def run_draw():
            state["draw_after_id"] = None
            self.draw_territory_map()

        state["draw_after_id"] = self.after(15, run_draw)

    def draw_territory_map_grid(self, base_w, base_h):
        canvas = self.territory_map_canvas
        state = self.territory_map_state
        if canvas is None:
            return
        for step in range(9):
            x = state["offset_x"] + base_w * state["zoom"] * step / 8
            y = state["offset_y"] + base_h * state["zoom"] * step / 8
            canvas.create_line(x, state["offset_y"], x, state["offset_y"] + base_h * state["zoom"], fill=GRAPHITE_BORDER_SOFT)
            canvas.create_line(state["offset_x"], y, state["offset_x"] + base_w * state["zoom"], y, fill=GRAPHITE_BORDER_SOFT)

    def draw_territory_map(self):
        canvas = self.territory_map_canvas
        if canvas is None:
            return
        canvas.delete("all")
        state = self.territory_map_state
        state["drawn_zones"] = []
        state["resize_handles"] = []
        state["selection_rect_item"] = None
        self.load_embedded_territory_map_image()
        visible_items = self.territory_map_visible_items()
        selected_indices = set(self.selected_visible_territory_indices())
        if not self.selected_map_key:
            self.territory_map_status_var.set("Map: not selected")
            canvas.create_text(max(canvas.winfo_width(), 400) / 2, max(canvas.winfo_height(), 300) / 2, text="Choose a map at the top to view territories.", fill=GRAPHITE_MUTED, font=("Segoe UI", 12, "bold"))
            return
        if not visible_items:
            self.territory_map_status_var.set("No plottable zones in visible layers")
        else:
            layer_count = len(self.visible_territory_layer_keys())
            group_label = f"{layer_count} visible layer{'s' if layer_count != 1 else ''}" if layer_count else "No visible layers"
            selected_suffix = f" | {len(selected_indices)} selected" if selected_indices else ""
            self.territory_map_status_var.set(f"{self.map_info_summary()['text']} | {group_label}: {len(visible_items)} plottable zone(s){selected_suffix}")
        zones = [zone for _index, zone, _coord in visible_items]
        map_width, map_height, _map_label = self.mission_map_size(zones, self.selected_map_key)
        base_w, base_h = self.territory_map_base_size()
        map_x1 = state["offset_x"]
        map_y1 = state["offset_y"]
        map_x2 = map_x1 + base_w * state["zoom"]
        map_y2 = map_y1 + base_h * state["zoom"]
        canvas.create_rectangle(map_x1, map_y1, map_x2, map_y2, outline=GRAPHITE_BORDER, fill=GRAPHITE_CARD)
        self.draw_embedded_territory_map_image(base_w, base_h)
        self.draw_territory_map_grid(base_w, base_h)
        label_limit = len(visible_items) <= 120
        for index, zone, (x, z) in visible_items:
            zone_tag = f"territory-zone-{index}"
            handle_tag = f"territory-resize-handle-{index}"
            px, py = self.territory_world_to_canvas(x, z, map_width, map_height)
            try:
                zone_radius = float(zone.attributes.get("r", "0"))
            except ValueError:
                zone_radius = 0.0
            scaled_radius = (zone_radius / map_width) * base_w * state["zoom"] if zone_radius > 0 else 0.0
            selected = index in selected_indices
            active = index == self.current_territory_index
            layer_color = self.territory_zone_color(zone)
            outline = GRAPHITE_ACCENT_HOVER if active else GRAPHITE_PREFLIGHT_ACTIVE if selected else layer_color
            fill = GRAPHITE_ACCENT_HOVER if active else GRAPHITE_PREFLIGHT if selected else layer_color
            width = 3 if active else 2 if selected else 1
            if scaled_radius > 0:
                canvas.create_oval(px - scaled_radius, py - scaled_radius, px + scaled_radius, py + scaled_radius, outline=outline, width=width, tags=(zone_tag,))
            if active:
                handle_offset = max(scaled_radius, 24.0)
                handle_x = px + handle_offset
                handle_y = py
                handle_radius = 7
                canvas.create_line(px, py, handle_x, handle_y, fill=GRAPHITE_ACCENT_HOVER, width=2, tags=(zone_tag, handle_tag))
                canvas.create_rectangle(
                    handle_x - handle_radius,
                    handle_y - handle_radius,
                    handle_x + handle_radius,
                    handle_y + handle_radius,
                    fill=GRAPHITE_ACCENT_HOVER,
                    outline="#ffffff",
                    width=2,
                    tags=(zone_tag, handle_tag),
                )
                state["resize_handles"].append((index, handle_x, handle_y, max(14.0, handle_radius + 6)))
            icon_key = self.territory_zone_icon_key(zone)
            marker_radius = self.draw_map_marker(
                canvas,
                px,
                py,
                icon_key,
                fill,
                active=active,
                selected=selected,
                display_radius=scaled_radius,
                tags=(zone_tag,),
            )
            if active:
                canvas.tag_raise(handle_tag)
            if active or selected or label_limit:
                canvas.create_text(px + 8, py - 8, text=zone.name, fill=GRAPHITE_TEXT, anchor="sw", font=("Segoe UI", 9, "bold" if active or selected else "normal"), tags=(zone_tag,))
            state["drawn_zones"].append((index, px, py, max(8.0, scaled_radius), marker_radius))
        canvas.create_text(map_x1 + 8, map_y1 + 14, text="NW", fill=GRAPHITE_MUTED, anchor="w", font=("Segoe UI", 8, "bold"))
        canvas.create_text(map_x2 - 8, map_y2 - 14, text="SE", fill=GRAPHITE_MUTED, anchor="e", font=("Segoe UI", 8, "bold"))
        if state.get("edit_mode") == "add_zone":
            self.territory_map_status_var.set("Add zone: click the map to place, drag while placing to set radius, Esc cancels.")
        elif state.get("edit_mode") == "duplicate_zone":
            self.territory_map_status_var.set("Duplicate: click the map to place copied zone(s), Esc cancels.")
        selection_rect = state.get("selection_rect")
        if selection_rect:
            x1, y1, x2, y2 = selection_rect
            canvas.create_rectangle(
                min(x1, x2),
                min(y1, y2),
                max(x1, x2),
                max(y1, y2),
                outline=GRAPHITE_ACCENT_HOVER,
                width=2,
                dash=(4, 3),
            )
        preview = state.get("placement_preview")
        if state.get("edit_mode") == "add_zone" and preview:
            preview_x, preview_y, preview_radius = preview
            self.draw_territory_add_preview(preview_x, preview_y, preview_radius)
        elif state.get("edit_mode") == "duplicate_zone" and preview:
            preview_x, preview_y, _preview_radius = preview
            self.draw_territory_duplicate_preview(preview_x, preview_y)
        if state.get("drag_mode") == "resize":
            self.draw_territory_resize_preview()

    def hit_test_territory_map(self, canvas_x, canvas_y):
        hits = []
        for index, px, py, hit_radius, _marker_radius in self.territory_map_state.get("drawn_zones", []):
            distance = ((canvas_x - px) ** 2 + (canvas_y - py) ** 2) ** 0.5
            if distance <= hit_radius:
                hits.append((distance, hit_radius, index))
        if not hits:
            return None
        hits.sort(key=lambda item: (item[0] / max(item[1], 1.0), item[0]))
        return hits[0][2]

    def hit_test_territory_map_marker(self, canvas_x, canvas_y):
        hits = []
        for index, px, py, _hit_radius, marker_radius in self.territory_map_state.get("drawn_zones", []):
            distance = ((canvas_x - px) ** 2 + (canvas_y - py) ** 2) ** 0.5
            marker_hit = max(12.0, marker_radius + 5)
            if distance <= marker_hit:
                hits.append((distance, index))
        if not hits:
            return None
        hits.sort(key=lambda item: item[0])
        return hits[0][1]

    def hit_test_territory_resize_handle(self, canvas_x, canvas_y):
        hits = []
        for index, px, py, hit_radius in self.territory_map_state.get("resize_handles", []):
            distance = ((canvas_x - px) ** 2 + (canvas_y - py) ** 2) ** 0.5
            if distance <= hit_radius:
                hits.append((distance, index))
        if not hits:
            return None
        hits.sort(key=lambda item: item[0])
        return hits[0][1]

    def territory_event_has_control(self, event):
        return bool(getattr(event, "state", 0) & 0x0004)

    def territory_event_has_alt(self, event):
        if os.name == "nt":
            try:
                return bool(ctypes.windll.user32.GetKeyState(0x12) & 0x8000)
            except Exception:
                pass
        return bool(self.territory_alt_down)

    def territory_resize_targets_for_anchor(self, anchor_index):
        selected = self.selected_visible_territory_indices()
        if anchor_index in selected:
            return selected
        return [anchor_index]

    def select_territory_zones_in_rect(self, rect):
        if not rect:
            return
        x1, y1, x2, y2 = rect
        left, right = sorted((x1, x2))
        top, bottom = sorted((y1, y2))
        selected = [
            index
            for index, px, py, _hit_radius, _marker_radius in self.territory_map_state.get("drawn_zones", [])
            if left <= px <= right and top <= py <= bottom
        ]
        self.selected_territory_indices = set(selected)
        if selected:
            self.current_territory_index = selected[0]
            self.set_active_territory_group_for_zone(self.territory_zones[selected[0]])
            self.populate_territory_detail(selected[0])
            self.log(f"Selected {len(selected)} territory zone(s).", "success")
        else:
            self.clear_territory_detail()
            self.log("No territory zones inside selection.", "muted")
        self.draw_territory_map()
        self.update_territory_group_tree_tags()

    def center_selected_territory_on_map(self):
        index = self.current_territory_index
        if index is None or not (0 <= index < len(self.territory_zones)) or self.territory_map_canvas is None:
            return
        coord = self.spawn_position_xy(self.territory_zones[index])
        if coord is None:
            return
        visible_items = self.territory_map_visible_items()
        zones = [zone for _index, zone, _coord in visible_items]
        map_width, map_height, _map_label = self.mission_map_size(zones, self.selected_map_key)
        self.territory_map_canvas.update_idletasks()
        width = max(self.territory_map_canvas.winfo_width(), 400)
        height = max(self.territory_map_canvas.winfo_height(), 400)
        base_w, base_h = self.territory_map_base_size()
        x, z = coord
        px = (x / map_width) * base_w
        py = base_h - (z / map_height) * base_h
        state = self.territory_map_state
        state["offset_x"] = width / 2 - px * state["zoom"]
        state["offset_y"] = height / 2 - py * state["zoom"]
        self.draw_territory_map()

    def on_territory_map_configure(self, event=None):
        if self.active_module != "territories":
            return
        state = self.territory_map_state
        if state["zoom"] == 1.0 and state["offset_x"] == 0.0 and state["offset_y"] == 0.0:
            self.fit_territory_map()
        self.schedule_territory_map_draw(fast=True)

    def on_territory_map_mousewheel(self, event):
        state = self.territory_map_state
        if state.get("image_backend") == "tk":
            self.log("Install Pillow from requirements.txt to enable smooth map image zoom.", "warning")
            return
        old_zoom = state["zoom"]
        factor = 1.12 if event.delta > 0 else 1 / 1.12
        new_zoom = max(0.05, min(12.0, old_zoom * factor))
        if new_zoom == old_zoom:
            return
        state["offset_x"] = event.x - (event.x - state["offset_x"]) * (new_zoom / old_zoom)
        state["offset_y"] = event.y - (event.y - state["offset_y"]) * (new_zoom / old_zoom)
        state["zoom"] = new_zoom
        self.schedule_territory_map_draw(fast=True)
        self.schedule_territory_map_refine()

    def on_territory_map_drag_start(self, event):
        if self.territory_map_canvas is not None:
            self.territory_map_canvas.focus_set()
        state = self.territory_map_state
        state["press_x"] = event.x
        state["press_y"] = event.y
        state["drag_x"] = event.x
        state["drag_y"] = event.y
        state["dragged"] = False
        state["move_dirty"] = False
        state["resize_dirty"] = False
        state["pending_ctrl_toggle_index"] = None
        state["resize_indices"] = []
        state["resize_originals"] = {}
        state["resize_anchor_original"] = 0.0
        state["resize_preview_indices"] = []
        state["selection_rect"] = None
        ctrl_down = self.territory_event_has_control(event)
        alt_down = self.territory_event_has_alt(event)
        resize_index = self.hit_test_territory_resize_handle(event.x, event.y)
        marker_index = self.hit_test_territory_map_marker(event.x, event.y) if resize_index is None else None
        if alt_down:
            state["drag_mode"] = "pan"
            state["move_index"] = None
            state["move_original"] = None
            state["resize_index"] = None
            state["resize_original"] = None
            state["resize_indices"] = []
            state["resize_originals"] = {}
            state["resize_anchor_original"] = 0.0
        elif state.get("edit_mode") == "add_zone":
            state["drag_mode"] = "place_add"
            state["placement_preview"] = (event.x, event.y, self.territory_add_radius_value())
            self.draw_territory_add_preview(event.x, event.y)
            return
        elif state.get("edit_mode") == "duplicate_zone":
            state["drag_mode"] = "place_duplicate"
            state["placement_preview"] = (event.x, event.y, 0.0)
            self.draw_territory_duplicate_preview(event.x, event.y)
            return
        elif ctrl_down and marker_index is not None:
            resize_index = marker_index
            state["pending_ctrl_toggle_index"] = marker_index
            resize_indices = self.territory_resize_targets_for_anchor(marker_index)
            if marker_index not in self.selected_territory_indices:
                self.current_territory_index = marker_index
                self.populate_territory_detail(marker_index)
            state["drag_mode"] = "resize"
            state["resize_index"] = resize_index
            state["resize_indices"] = resize_indices
            state["resize_preview_indices"] = list(resize_indices)
            state["resize_originals"] = {index: self.territory_zones[index].attributes.get("r", "") for index in resize_indices}
            state["resize_original"] = self.territory_zones[resize_index].attributes.get("r", "")
            state["resize_anchor_original"] = self.territory_radius_value(self.territory_zones[resize_index])
        elif resize_index is not None:
            resize_indices = self.territory_resize_targets_for_anchor(resize_index)
            self.select_territory_zone_index(resize_index, preserve_selection=resize_index in self.selected_territory_indices)
            state["drag_mode"] = "resize"
            state["resize_index"] = resize_index
            state["resize_indices"] = resize_indices
            state["resize_preview_indices"] = list(resize_indices)
            state["resize_originals"] = {index: self.territory_zones[index].attributes.get("r", "") for index in resize_indices}
            zone = self.territory_zones[resize_index]
            state["resize_original"] = zone.attributes.get("r", "")
            state["resize_anchor_original"] = self.territory_radius_value(zone)
        elif marker_index is not None:
            self.select_territory_zone_index(marker_index)
            state["drag_mode"] = "move"
            state["move_index"] = marker_index
            zone = self.territory_zones[marker_index]
            state["move_original"] = (zone.attributes.get("x", ""), zone.attributes.get("z", ""))
        else:
            state["drag_mode"] = "select"
            state["move_index"] = None
            state["move_original"] = None
            state["resize_index"] = None
            state["resize_original"] = None
            state["resize_indices"] = []
            state["resize_originals"] = {}
            state["resize_anchor_original"] = 0.0
            state["selection_rect"] = (event.x, event.y, event.x, event.y)

    def on_territory_map_drag_move(self, event):
        state = self.territory_map_state
        dx = event.x - state["drag_x"]
        dy = event.y - state["drag_y"]
        if abs(event.x - state["press_x"]) > 3 or abs(event.y - state["press_y"]) > 3:
            state["dragged"] = True
        if state.get("drag_mode") == "place_add":
            radius = self.territory_add_radius_value()
            if state.get("dragged"):
                radius = self.territory_canvas_radius_to_world(state["press_x"], state["press_y"], event.x, event.y) or radius
                self.territory_add_radius_var.set(self.format_territory_radius(radius))
            state["placement_preview"] = (state["press_x"], state["press_y"], radius)
            self.draw_territory_add_preview(state["press_x"], state["press_y"], radius)
            state["drag_x"] = event.x
            state["drag_y"] = event.y
            return
        if state.get("drag_mode") == "place_duplicate":
            state["placement_preview"] = (event.x, event.y, 0.0)
            self.draw_territory_duplicate_preview(event.x, event.y)
            state["drag_x"] = event.x
            state["drag_y"] = event.y
            return
        if state.get("drag_mode") == "resize" and state.get("resize_index") is not None:
            resize_index = state["resize_index"]
            if 0 <= resize_index < len(self.territory_zones):
                visible_items = self.territory_map_visible_items()
                zones = [zone for _index, zone, _coord in visible_items]
                map_width, map_height, _map_label = self.mission_map_size(zones, self.selected_map_key)
                coord = self.territory_canvas_to_world(event.x, event.y, map_width, map_height)
                center = self.spawn_position_xy(self.territory_zones[resize_index])
                if coord is not None and center is not None:
                    x, z = coord
                    center_x, center_z = center
                    radius = ((x - center_x) ** 2 + (z - center_z) ** 2) ** 0.5
                    delta = radius - float(state.get("resize_anchor_original") or 0.0)
                    for target_index in state.get("resize_indices") or [resize_index]:
                        if 0 <= target_index < len(self.territory_zones):
                            zone = self.territory_zones[target_index]
                            original_radius = 0.0
                            try:
                                original_radius = float((state.get("resize_originals") or {}).get(target_index, zone.attributes.get("r", "0")) or 0)
                            except ValueError:
                                original_radius = 0.0
                            zone.set_attribute("r", self.format_territory_radius(original_radius + delta))
                    if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
                        self.territory_editor_vars["r"].set(self.territory_zones[self.current_territory_index].attributes.get("r", ""))
                    state["resize_dirty"] = True
                    state["resize_preview_indices"] = list(state.get("resize_indices") or [resize_index])
                    self.draw_territory_resize_preview()
            state["drag_x"] = event.x
            state["drag_y"] = event.y
            return
        elif state.get("drag_mode") == "move" and state.get("move_index") is not None:
            move_index = state["move_index"]
            if 0 <= move_index < len(self.territory_zones):
                visible_items = self.territory_map_visible_items()
                zones = [zone for _index, zone, _coord in visible_items]
                map_width, map_height, _map_label = self.mission_map_size(zones, self.selected_map_key)
                coord = self.territory_canvas_to_world(event.x, event.y, map_width, map_height)
                if coord is not None:
                    x, z = coord
                    zone = self.territory_zones[move_index]
                    zone.set_attribute("x", self.format_territory_coordinate(x))
                    zone.set_attribute("z", self.format_territory_coordinate(z))
                    self.territory_editor_vars["x"].set(zone.attributes.get("x", ""))
                    self.territory_editor_vars["z"].set(zone.attributes.get("z", ""))
                    state["move_dirty"] = True
                    new_px, new_py = self.territory_world_to_canvas(x, z, map_width, map_height)
                    drawn_zones = list(state.get("drawn_zones", []))
                    for drawn_index, drawn_zone in enumerate(drawn_zones):
                        index, old_px, old_py, hit_radius, marker_radius = drawn_zone
                        if index != move_index:
                            continue
                        move_dx = new_px - old_px
                        move_dy = new_py - old_py
                        self.territory_map_canvas.move(f"territory-zone-{move_index}", move_dx, move_dy)
                        drawn_zones[drawn_index] = (index, new_px, new_py, hit_radius, marker_radius)
                        state["drawn_zones"] = drawn_zones
                        state["resize_handles"] = [
                            (index, handle_x + move_dx, handle_y + move_dy, handle_radius) if index == move_index else (index, handle_x, handle_y, handle_radius)
                            for index, handle_x, handle_y, handle_radius in state.get("resize_handles", [])
                        ]
                        break
            state["drag_x"] = event.x
            state["drag_y"] = event.y
            return
        elif state.get("drag_mode") == "select":
            state["selection_rect"] = (state["press_x"], state["press_y"], event.x, event.y)
            item = state.get("selection_rect_item")
            if item is None:
                item = self.territory_map_canvas.create_rectangle(
                    state["press_x"],
                    state["press_y"],
                    event.x,
                    event.y,
                    outline=GRAPHITE_ACCENT_HOVER,
                    width=2,
                    dash=(4, 3),
                )
                state["selection_rect_item"] = item
            else:
                self.territory_map_canvas.coords(item, state["press_x"], state["press_y"], event.x, event.y)
            state["drag_x"] = event.x
            state["drag_y"] = event.y
            return
        elif state.get("drag_mode") == "pan":
            state["offset_x"] += dx
            state["offset_y"] += dy
            if self.territory_map_canvas is not None:
                self.territory_map_canvas.move("all", dx, dy)
                state["drawn_zones"] = [
                    (index, px + dx, py + dy, hit_radius, marker_radius)
                    for index, px, py, hit_radius, marker_radius in state.get("drawn_zones", [])
                ]
                state["resize_handles"] = [
                    (index, px + dx, py + dy, hit_radius)
                    for index, px, py, hit_radius in state.get("resize_handles", [])
                ]
            state["drag_x"] = event.x
            state["drag_y"] = event.y
            return
        if state.get("drag_mode") in {"pan", "move", "resize"}:
            state["render_fast"] = True
        state["drag_x"] = event.x
        state["drag_y"] = event.y
        self.schedule_territory_map_draw(fast=state.get("drag_mode") in {"pan", "move", "resize"})
        if state.get("drag_mode") in {"pan", "move", "resize"}:
            self.schedule_territory_map_refine()

    def on_territory_map_click_release(self, event):
        state = self.territory_map_state
        if state.get("drag_mode") == "place_add":
            preview = state.get("placement_preview") or (event.x, event.y, self.territory_add_radius_value())
            center_x, center_y, radius = preview
            self.place_territory_zone_at_canvas(center_x, center_y, radius)
            state["drag_mode"] = "idle"
            state["placement_preview"] = None
            state["dragged"] = False
            self.clear_territory_placement_preview()
            return
        if state.get("drag_mode") == "place_duplicate":
            self.place_duplicate_territory_zones_at_canvas(event.x, event.y)
            state["drag_mode"] = "idle"
            state["placement_preview"] = None
            state["dragged"] = False
            self.clear_territory_placement_preview()
            return
        if state.get("drag_mode") == "resize" and state.get("resize_dirty") and state.get("resize_index") is not None:
            resize_index = state["resize_index"]
            if 0 <= resize_index < len(self.territory_zones):
                zone = self.territory_zones[resize_index]
                resize_indices = [index for index in state.get("resize_indices", []) if 0 <= index < len(self.territory_zones)]
                old_values = {index: (state.get("resize_originals") or {}).get(index, "") for index in resize_indices}
                new_values = {index: self.territory_zones[index].attributes.get("r", "") for index in resize_indices}
                if len(resize_indices) > 1:
                    self.selected_territory_indices = set(resize_indices)
                    if old_values != new_values:
                        self.push_territory_edit_undo("bulk_resize", resize_index, old_values, new_values)
                        self.mark_territory_indices_dirty(resize_indices)
                else:
                    old_radius = state.get("resize_original") or ""
                    new_radius = zone.attributes.get("r", "")
                    self.selected_territory_indices = {resize_index}
                    if old_radius != new_radius:
                        self.push_territory_edit_undo("resize", resize_index, old_radius, new_radius)
                        self.mark_source_dirty(zone.source_path)
                if old_values != new_values:
                    self.mark_territory_related_event_cache_stale()
                    self.schedule_validation_refresh()
                self.populate_territory_detail(resize_index)
                self.update_summary()
                if len(resize_indices) > 1 and old_values != new_values:
                    self.log(f"Resized {len(resize_indices)} territory zones.", "success")
                elif len(resize_indices) <= 1 and old_values != new_values:
                    self.log(f"Resized territory zone {zone.name} to r={zone.attributes.get('r', '')}.", "success")
        elif state.get("drag_mode") == "move" and state.get("move_dirty") and state.get("move_index") is not None:
            move_index = state["move_index"]
            if 0 <= move_index < len(self.territory_zones):
                zone = self.territory_zones[move_index]
                old_coords = state.get("move_original") or ("", "")
                new_coords = (zone.attributes.get("x", ""), zone.attributes.get("z", ""))
                self.push_territory_edit_undo("move", move_index, old_coords, new_coords)
                self.mark_source_dirty(zone.source_path)
                self.mark_territory_related_event_cache_stale()
                self.schedule_validation_refresh()
                self.populate_territory_detail(move_index)
                self.update_summary()
                self.log(f"Moved territory zone {zone.name} to x={zone.attributes.get('x', '')}, z={zone.attributes.get('z', '')}.", "success")
        elif state.get("drag_mode") == "select" and state.get("dragged"):
            self.select_territory_zones_in_rect(state.get("selection_rect"))
        state["drag_mode"] = "idle"
        state["move_index"] = None
        state["move_original"] = None
        state["resize_index"] = None
        state["resize_original"] = None
        state["resize_indices"] = []
        state["resize_originals"] = {}
        state["resize_anchor_original"] = 0.0
        state["resize_preview_indices"] = []
        self.clear_territory_resize_preview()
        state["selection_rect"] = None
        state["selection_rect_item"] = None
        state["render_fast"] = False
        if state.get("dragged"):
            state["pending_ctrl_toggle_index"] = None
            self.draw_territory_map()
            return
        toggle_index = state.get("pending_ctrl_toggle_index")
        state["pending_ctrl_toggle_index"] = None
        if toggle_index is not None:
            self.toggle_territory_zone_selection(toggle_index)
            return
        index = self.hit_test_territory_map(event.x, event.y)
        if index is not None:
            self.select_territory_zone_index(index)
        else:
            self.clear_territory_selection(announce=False)

    def territory_group_name(self, path):
        stem = Path(path).stem
        clean = re.sub(r"_?territories$", "", stem, flags=re.IGNORECASE)
        clean = clean.replace("_", " ").replace("-", " ").strip()
        if not clean:
            clean = stem
        return " ".join(part.capitalize() for part in clean.split())

    def territory_type_name(self, path):
        return self.territory_group_name(path)

    def territory_zone_group_key(self, zone):
        return f"{self.normalized_path(zone.source_path)}::{int(getattr(zone, 'group_index', 0) or 0)}"

    def territory_group_key_for(self, source_path, group_index=0):
        return f"{self.normalized_path(source_path)}::{int(group_index or 0)}"

    def territory_group_key_source(self, group_key):
        raw = str(group_key or "")
        if "::" not in raw:
            return raw
        source_key = raw.rsplit("::", 1)[0]
        for path in self.territory_source_paths():
            if self.normalized_path(path) == source_key:
                return path
        for zone in self.territory_zones:
            if self.normalized_path(zone.source_path) == source_key:
                return zone.source_path
        return source_key

    def territory_group_key_index(self, group_key):
        raw = str(group_key or "")
        if "::" not in raw:
            return 0
        try:
            return int(raw.rsplit("::", 1)[1])
        except ValueError:
            return 0

    def territory_group_display_name(self, zone):
        type_name = self.territory_type_name(zone.source_path)
        group_name = getattr(zone, "group_name", "") or f"Group {int(getattr(zone, 'group_index', 0) or 0) + 1}"
        if group_name == type_name:
            return type_name
        return f"{type_name} / {group_name}"

    def territory_group_records(self):
        records = {}
        for group in self.__dict__.get("territory_groups", []):
            key = self.territory_group_key_for(group.source_path, group.group_index)
            type_name = self.territory_type_name(group.source_path)
            group_name = group.display_name()
            records[key] = {
                "key": key,
                "path": group.source_path,
                "group_index": int(group.group_index or 0),
                "name": f"{type_name} / {group_name}",
                "total": 0,
                "active": 0,
                "attributes": dict(group.attributes or {}),
            }
        for zone in self.territory_zones:
            key = self.territory_zone_group_key(zone)
            if key not in records:
                records[key] = {
                    "key": key,
                    "path": zone.source_path,
                    "group_index": int(getattr(zone, "group_index", 0) or 0),
                    "name": self.territory_group_display_name(zone),
                    "total": 0,
                    "active": 0,
                    "attributes": dict(getattr(zone, "group_attributes", {}) or {}),
                }
            records[key]["total"] += 1
            if self.territory_zone_is_active(zone):
                records[key]["active"] += 1
        for path in self.territory_source_paths():
            if any(self.normalized_path(record["path"]) == self.normalized_path(path) for record in records.values()):
                continue
            key = self.territory_group_key_for(path, 0)
            records[key] = {
                "key": key,
                "path": path,
                "group_index": 0,
                "name": f"{self.territory_type_name(path)} / Group 1",
                "total": 0,
                "active": 0,
                "attributes": {},
            }
        return records

    def update_territory_type_filter_values(self):
        if not hasattr(self, "territory_type_combo"):
            return
        current = self.territory_type_filter_var.get() or "All types"
        display_paths = {}
        for path in self.territory_source_paths():
            display_paths[self.territory_type_name(path)] = path
        values = ["All types"] + sorted(display_paths, key=str.casefold)
        self.territory_type_filter_paths = display_paths
        self.territory_type_combo.configure(values=values)
        if current not in values:
            self.territory_type_filter_var.set(values[1] if len(values) > 1 else "All types")

    def selected_territory_type_path(self):
        variable = self.__dict__.get("territory_type_filter_var")
        type_filter = variable.get() if variable is not None else "All types"
        if not type_filter or type_filter == "All types":
            return ""
        return self.__dict__.get("territory_type_filter_paths", {}).get(type_filter, "")

    def custom_territory_file_name(self, name):
        clean = re.sub(r"[^A-Za-z0-9_ -]+", "", str(name or "").strip())
        clean = re.sub(r"[\s-]+", "_", clean).strip("_").lower()
        if not clean:
            return ""
        if clean.endswith("_territories"):
            clean = clean[: -len("_territories")]
        return f"{clean}_territories.xml"

    def custom_territory_source_path_for_name(self, name):
        if self.mission_workspace is None:
            return ""
        file_name = self.custom_territory_file_name(name)
        if not file_name:
            return ""
        return str(Path(self.mission_workspace.root_path) / "env" / file_name)

    def custom_territory_settings_key(self):
        if self.mission_workspace is None:
            return ""
        return self.normalized_path(self.mission_workspace.root_path)

    def saved_custom_territory_source_paths(self):
        key = self.custom_territory_settings_key()
        if not key:
            return []
        stored = self.saved_settings.get("custom_territory_sources", {})
        values = stored.get(key, []) if isinstance(stored, dict) else []
        root = Path(self.mission_workspace.root_path)
        paths = []
        iterable = values if isinstance(values, list) else []
        for value in iterable:
            path = Path(str(value))
            paths.append(str(path if path.is_absolute() else root / path))
        return paths

    def saved_custom_territory_source_keys(self):
        territory_keys = {self.normalized_path(path) for path in self.territory_source_paths()}
        return {
            self.normalized_path(path)
            for path in self.saved_custom_territory_source_paths()
            if self.normalized_path(path) in territory_keys
        }

    def remember_custom_territory_source_path(self, source_path):
        key = self.custom_territory_settings_key()
        if not key:
            return
        stored = self.saved_settings.setdefault("custom_territory_sources", {})
        paths = list(stored.get(key, [])) if isinstance(stored.get(key, []), list) else []
        root = Path(self.mission_workspace.root_path)
        try:
            value = str(Path(source_path).resolve().relative_to(root.resolve()))
        except (OSError, ValueError):
            value = str(source_path)
        if value not in paths:
            paths.append(value)
        stored[key] = paths
        save_settings(self.saved_settings)

    def forget_custom_territory_source_path(self, source_path):
        key = self.custom_territory_settings_key()
        if not key:
            return
        stored = self.saved_settings.get("custom_territory_sources", {})
        paths = list(stored.get(key, [])) if isinstance(stored, dict) and isinstance(stored.get(key, []), list) else []
        root = Path(self.mission_workspace.root_path)
        candidates = {str(source_path)}
        try:
            candidates.add(str(Path(source_path).resolve().relative_to(root.resolve())))
        except (OSError, ValueError):
            pass
        kept = [path for path in paths if path not in candidates]
        if isinstance(stored, dict):
            if kept:
                stored[key] = kept
            else:
                stored.pop(key, None)
            save_settings(self.saved_settings)

    def is_custom_territory_source_path(self, path):
        return self.normalized_path(path) in getattr(self, "custom_territory_source_keys", set())

    def add_territory_source_path(self, source_path):
        if self.mission_workspace is None:
            return False
        source_key = self.normalized_path(source_path)
        paths = list(getattr(self.mission_workspace, "territory_paths", []))
        if any(self.normalized_path(path) == source_key for path in paths):
            return False
        paths.append(source_path)
        self.mission_workspace.territory_paths = paths
        return True

    def remove_territory_source_path(self, source_path):
        if self.mission_workspace is None:
            return
        source_key = self.normalized_path(source_path)
        self.mission_workspace.territory_paths = [
            path for path in getattr(self.mission_workspace, "territory_paths", [])
            if self.normalized_path(path) != source_key
        ]

    def territory_layer_color(self, path):
        palette = [
            GRAPHITE_SUCCESS,
            GRAPHITE_WARNING,
            GRAPHITE_PREFLIGHT_HOVER,
            GRAPHITE_ACCENT_HOVER,
            "#70b7d8",
            "#a6c36f",
            "#c68fd3",
            "#d18b65",
            "#8ec8aa",
            "#d0c06e",
        ]
        key = str(path or "")
        digest = hashlib.md5(key.encode("utf-8", errors="ignore")).hexdigest()
        return palette[int(digest[:8], 16) % len(palette)]

    def territory_group_color_hex(self, attributes, fallback_key=""):
        value = str((attributes or {}).get("color", "")).strip()
        try:
            number = int(value, 0)
            rgb = number & 0xFFFFFF
            return f"#{rgb:06x}"
        except ValueError:
            pass
        return self.territory_layer_color(fallback_key)

    def territory_zone_color(self, zone):
        return self.territory_group_color_hex(getattr(zone, "group_attributes", {}), self.territory_zone_group_key(zone))

    def territory_color_to_ce_value(self, hex_color):
        value = str(hex_color or "").strip().lstrip("#")
        if len(value) != 6:
            return ""
        try:
            rgb = int(value, 16)
        except ValueError:
            return ""
        return str((255 << 24) | rgb)

    def map_marker_icon_key_for_text(self, text):
        normalized = re.sub(r"[^a-z0-9]+", "", str(text or "").casefold())
        if not normalized:
            return ""
        for icon_key, needles in MAP_MARKER_ICON_RULES:
            for needle in needles:
                if re.sub(r"[^a-z0-9]+", "", needle.casefold()) in normalized:
                    return icon_key
        return ""

    def territory_zone_icon_key(self, zone):
        override = self.territory_icon_override(zone.source_path)
        if override:
            return override
        return self.map_marker_icon_key_for_text(
            " ".join([zone.name, self.territory_group_name(zone.source_path), os.path.basename(zone.source_path)])
        )

    def territory_icon_override(self, source_path):
        stored = self.saved_settings.get("territory_icons", {})
        if not isinstance(stored, dict):
            return ""
        icon_key = str(stored.get(self.normalized_path(source_path), "") or "").strip().casefold()
        valid_keys = {key for _label, key in MAP_MARKER_ICON_OPTIONS}
        return icon_key if icon_key in valid_keys else ""

    def selected_territory_icon_source_path(self):
        group_key = self.current_territory_group_key or self.selected_territory_group_key()
        if group_key:
            return self.territory_group_key_source(group_key)
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            return self.territory_zones[self.current_territory_index].source_path
        return ""

    def update_territory_icon_control(self):
        combo = self.territory_icon_combo
        if combo is None:
            return
        source_path = self.selected_territory_icon_source_path()
        if not source_path:
            self.territory_icon_var.set("Auto")
            combo.configure(state="disabled")
            return
        icon_key = self.territory_icon_override(source_path)
        self.territory_icon_var.set(MAP_MARKER_ICON_LABELS.get(icon_key, "Auto"))
        combo.configure(state="readonly")

    def on_territory_icon_changed(self, event=None):
        source_path = self.selected_territory_icon_source_path()
        if not source_path:
            self.update_territory_icon_control()
            return
        label = self.territory_icon_var.get()
        icon_key = MAP_MARKER_ICON_KEYS.get(label, "")
        stored = self.saved_settings.setdefault("territory_icons", {})
        if not isinstance(stored, dict):
            stored = {}
            self.saved_settings["territory_icons"] = stored
        source_key = self.normalized_path(source_path)
        if icon_key:
            stored[source_key] = icon_key
        else:
            stored.pop(source_key, None)
            if not stored:
                self.saved_settings.pop("territory_icons", None)
        save_settings(self.saved_settings)
        self.draw_territory_map()
        self.log(f"Territory icon set to {label} for {self.source_display_name(source_path)}.", "success")

    def event_location_icon_key(self, event_entry, position=None):
        parts = [getattr(event_entry, "name", "")]
        if position is not None:
            parts.extend([getattr(position, "name", ""), getattr(position, "source_path", "")])
        return self.map_marker_icon_key_for_text(" ".join(str(part) for part in parts))

    def parse_hex_color(self, color, fallback=(255, 255, 255)):
        value = str(color or "").strip().lstrip("#")
        if len(value) != 6:
            return fallback
        try:
            return tuple(int(value[index:index + 2], 16) for index in (0, 2, 4))
        except ValueError:
            return fallback

    def map_marker_icon_image(self, icon_key, size=22, foreground="#ffffff"):
        if not PIL_AVAILABLE or not icon_key:
            return None
        file_name = MAP_MARKER_ICON_FILES.get(icon_key)
        if not file_name:
            return None
        cache_key = (icon_key, int(size), str(foreground))
        cached = self.map_marker_icon_cache.get(cache_key)
        if cached is not None:
            return cached
        path = resource_path(file_name)
        if not os.path.isfile(path):
            return None
        try:
            image = Image.open(path).convert("RGBA").resize((int(size), int(size)), Image.Resampling.LANCZOS)
        except OSError:
            return None
        fg_r, fg_g, fg_b = self.parse_hex_color(foreground)
        pixels = []
        pixels_data = image.get_flattened_data() if hasattr(image, "get_flattened_data") else image.getdata()
        for r, g, b, a in pixels_data:
            luma = (r * 0.299) + (g * 0.587) + (b * 0.114)
            alpha = int(max(0, min(255, 255 - luma)) * (a / 255))
            pixels.append((fg_r, fg_g, fg_b, alpha))
        image.putdata(pixels)
        rendered = ImageTk.PhotoImage(image)
        self.map_marker_icon_cache[cache_key] = rendered
        return rendered

    def draw_map_marker(self, canvas, px, py, icon_key, fill, outline="#ffffff", active=False, selected=False, display_radius=0.0, tags=()):
        try:
            scaled_radius = float(display_radius or 0.0)
        except (TypeError, ValueError):
            scaled_radius = 0.0
        if icon_key == "none":
            return max(3.0, scaled_radius)
        if icon_key and scaled_radius >= 4.0:
            icon_size = max(8, min(512, int(round(scaled_radius * 2))))
            icon = self.map_marker_icon_image(icon_key, icon_size, fill)
            if icon is not None:
                canvas.create_image(px, py, image=icon, tags=tags)
                return max(scaled_radius, icon_size / 2)
        icon_size = 22 if active else 20 if selected else 17
        icon = self.map_marker_icon_image(icon_key, icon_size, "#ffffff")
        if icon is None:
            marker_radius = 7 if active else 6 if selected else 5
            canvas.create_oval(px - marker_radius, py - marker_radius, px + marker_radius, py + marker_radius, fill=fill, outline=outline, tags=tags)
            return marker_radius
        radius = (icon_size / 2) + (5 if active else 4)
        canvas.create_oval(px - radius, py - radius, px + radius, py + radius, fill=fill, outline=outline, width=2 if active or selected else 1, tags=tags)
        canvas.create_image(px, py, image=icon, tags=tags)
        return radius

    def territory_layer_entries(self):
        records = self.territory_group_records()
        selected_type_path = self.selected_territory_type_path()
        selected_type_key = self.normalized_path(selected_type_path) if selected_type_path else ""
        entries = []
        for record in records.values():
            if selected_type_key and self.normalized_path(record["path"]) != selected_type_key:
                continue
            if not self.territory_show_inactive_var.get() and not record["active"] and not self.is_custom_territory_source_path(record["path"]):
                continue
            entries.append(
                {
                    "key": record["key"],
                    "path": record["path"],
                    "display": record["name"].split(" / ", 1)[1] if selected_type_key and " / " in record["name"] else record["name"],
                    "total": record["total"],
                    "active": record["active"],
                    "color": self.territory_group_color_hex(record.get("attributes", {}), record["key"]),
                }
            )
        return sorted(entries, key=lambda item: (self.normalized_path(item["path"]), self.territory_group_key_index(item["key"]), item["display"].casefold()))

    def select_territory_group_from_list(self, group_key):
        if not group_key:
            return
        self.current_territory_group_key = group_key
        self.set_territory_group_filter_for_key(group_key)
        for key, variable in self.territory_layer_vars.items():
            variable.set(key == group_key)
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()

    def toggle_territory_group_expanded(self, group_key):
        if not group_key:
            return "break"
        if group_key in self.territory_expanded_group_keys:
            self.territory_expanded_group_keys.discard(group_key)
        else:
            self.territory_expanded_group_keys.add(group_key)
        self.refresh_territory_layers()
        return "break"

    def territory_group_zone_items(self, group_key):
        items = []
        for index, zone in enumerate(self.territory_zones):
            if self.territory_zone_group_key(zone) != group_key:
                continue
            if not self.territory_show_inactive_var.get() and not self.territory_zone_is_active(zone):
                continue
            items.append((index, zone))
        return sorted(
            items,
            key=lambda item: (
                item[1].name.casefold(),
                self.float_sort_value(item[1].attributes.get("x", "")),
                self.float_sort_value(item[1].attributes.get("z", "")),
                item[0],
            ),
        )

    def territory_group_iid(self, group_key):
        digest = hashlib.md5(str(group_key or "").encode("utf-8", errors="ignore")).hexdigest()
        return f"territory-group-{digest}"

    def float_sort_value(self, value):
        try:
            return float(value)
        except (TypeError, ValueError):
            return 0.0

    def select_territory_zone_from_group_list(self, index):
        if not (0 <= index < len(self.territory_zones)):
            return "break"
        zone = self.territory_zones[index]
        self.set_active_territory_group_for_zone(zone)
        self.current_territory_index = index
        self.selected_territory_indices = {index}
        self.populate_territory_detail(index)
        self.schedule_territory_map_draw(fast=True)
        self.update_territory_group_tree_tags()
        return "break"

    def toggle_territory_zone_from_group_list(self, index):
        if not (0 <= index < len(self.territory_zones)):
            return "break"
        zone = self.territory_zones[index]
        self.ensure_territory_layer_visible(self.territory_zone_group_key(zone))
        if index in self.selected_territory_indices:
            self.selected_territory_indices.remove(index)
            if self.current_territory_index == index:
                self.current_territory_index = next(iter(sorted(self.selected_territory_indices)), None)
        else:
            self.selected_territory_indices.add(index)
            self.current_territory_index = index
        if self.current_territory_index is None:
            self.clear_territory_detail()
        else:
            self.populate_territory_detail(self.current_territory_index)
        self.schedule_territory_map_draw(fast=True)
        self.update_territory_group_tree_tags()
        return "break"

    def toggle_territory_group_from_group_list(self, group_key):
        variable = self.territory_layer_vars.get(group_key)
        if variable is None:
            return
        variable.set(not variable.get())
        if variable.get():
            self.current_territory_group_key = group_key
            self.set_territory_group_filter_for_key(group_key)
        elif group_key == self.current_territory_group_key or group_key == self.selected_territory_group_key():
            self.current_territory_group_key = ""
            self.territory_group_filter_var.set("All groups")
            self.sync_territory_source_filter_to_group()
        self.clear_territory_selection(announce=False)
        self.update_territory_group_tree_visibility_label(group_key)
        self.schedule_territory_map_draw(fast=True)
        self.update_territory_group_tree_tags()

    def update_territory_group_tree_visibility_label(self, group_key):
        tree = self.territory_group_tree
        if tree is None:
            return
        iid = self.territory_group_iid(group_key)
        if not tree.exists(iid):
            return
        values = list(tree.item(iid, "values"))
        if values:
            values[0] = self.territory_group_status_label(group_key)
            tree.item(iid, values=values)
        self.update_territory_group_tree_tags()

    def territory_group_status_label(self, group_key):
        if group_key == self.current_territory_group_key:
            return "Current"
        variable = self.territory_layer_vars.get(group_key)
        return "Shown" if variable is not None and variable.get() else "Hidden"

    def territory_group_display_label(self, display, group_key):
        return display

    def territory_zone_status_label(self, index):
        if index == self.current_territory_index:
            return "Current"
        return "Selected" if index in self.selected_territory_indices else ""

    def territory_zone_display_label(self, zone, index):
        return zone.name

    def update_territory_group_tree_tags(self):
        tree = self.territory_group_tree
        if tree is None:
            return
        for iid, (kind, value) in list(self.territory_group_tree_items.items()):
            if not tree.exists(iid):
                continue
            if kind == "group":
                visible = self.territory_layer_vars.get(value) is not None and self.territory_layer_vars[value].get()
                tags = ("group-current",) if value == self.current_territory_group_key else (("group-visible",) if visible else ("group-hidden",))
                values = list(tree.item(iid, "values"))
                if values:
                    values[0] = self.territory_group_status_label(value)
                tree.item(iid, values=values, tags=tags)
            elif kind == "zone":
                index = int(value)
                selected = index in self.selected_territory_indices
                current = index == self.current_territory_index
                tags = ("zone-current",) if current else (("zone-selected",) if selected else ("zone-muted",))
                values = list(tree.item(iid, "values"))
                if values:
                    values[0] = self.territory_zone_status_label(index)
                if 0 <= index < len(self.territory_zones):
                    tree.item(iid, text=self.territory_zone_display_label(self.territory_zones[index], index), values=values, tags=tags)
                else:
                    tree.item(iid, values=values, tags=tags)

    def update_territory_group_tree_selection(self):
        tree = self.territory_group_tree
        if tree is None:
            return
        if self.current_territory_index is not None:
            iid = f"territory-zone-row-{self.current_territory_index}"
            if tree.exists(iid):
                self.updating_territory_group_tree_selection = True
                try:
                    tree.selection_set(iid)
                    tree.see(iid)
                finally:
                    self.updating_territory_group_tree_selection = False
                return
        group_key = self.selected_territory_group_key()
        if not group_key:
            group_key = self.current_territory_group_key
        if group_key:
            iid = self.territory_group_iid(group_key)
            if tree.exists(iid):
                self.updating_territory_group_tree_selection = True
                try:
                    tree.selection_set(iid)
                    tree.see(iid)
                finally:
                    self.updating_territory_group_tree_selection = False

    def on_territory_group_tree_open(self, event=None):
        tree = self.territory_group_tree
        if tree is None:
            return
        iid = tree.focus()
        kind, value = self.territory_group_tree_items.get(iid, ("", None))
        if kind == "group":
            self.territory_expanded_group_keys.add(value)
            self.populate_territory_group_tree_children(value)

    def on_territory_group_tree_close(self, event=None):
        tree = self.territory_group_tree
        if tree is None:
            return
        iid = tree.focus()
        kind, value = self.territory_group_tree_items.get(iid, ("", None))
        if kind == "group":
            self.territory_expanded_group_keys.discard(value)
            for child in tree.get_children(iid):
                tree.delete(child)
                self.territory_group_tree_items.pop(child, None)
            if self.territory_group_tree_items.get(iid):
                dummy_iid = f"{iid}-dummy"
                tree.insert(iid, "end", iid=dummy_iid, text="Loading...", values=("", ""))
                self.territory_group_tree_items[dummy_iid] = ("dummy", value)

    def on_territory_group_tree_select(self, event=None):
        if self.refreshing_territory_layers or self.updating_territory_group_tree_selection or self.handling_territory_group_tree_select:
            return
        tree = self.territory_group_tree
        if tree is None:
            return
        selected = tree.selection()
        if not selected:
            return
        kind, value = self.territory_group_tree_items.get(selected[0], ("", None))
        self.handling_territory_group_tree_select = True
        try:
            if kind == "group":
                self.set_territory_group_filter_for_key(value)
                self.current_territory_group_key = value
                for key, variable in self.territory_layer_vars.items():
                    variable.set(key == value)
                self.clear_territory_selection(announce=False)
                self.update_territory_icon_control()
                self.schedule_territory_map_draw(fast=True)
                return
            if kind == "zone":
                self.select_territory_zone_from_group_list(value)
        finally:
            self.handling_territory_group_tree_select = False

    def on_territory_group_tree_click(self, event):
        tree = self.territory_group_tree
        if tree is None:
            return
        iid = tree.identify_row(event.y)
        column = tree.identify_column(event.x)
        kind, value = self.territory_group_tree_items.get(iid, ("", None))
        if kind == "group" and column == "#1":
            variable = self.territory_layer_vars.get(value)
            if variable is not None:
                variable.set(not variable.get())
                self.update_territory_group_tree_visibility_label(value)
                self.on_territory_layer_toggled(value)
            return "break"

    def on_territory_group_tree_release(self, event):
        if self.refreshing_territory_layers or self.handling_territory_group_tree_select:
            return
        tree = self.territory_group_tree
        if tree is None:
            return
        iid = tree.identify_row(event.y)
        if not iid:
            return
        # The visibility column is handled on Button-1 so the checkbox feel stays immediate.
        if tree.identify_column(event.x) == "#1":
            return
        kind, value = self.territory_group_tree_items.get(iid, ("", None))
        ctrl_down = self.territory_event_has_control(event)
        self.handling_territory_group_tree_select = True
        try:
            if kind == "group":
                if ctrl_down:
                    self.toggle_territory_group_from_group_list(value)
                    return
                self.current_territory_group_key = value
                self.set_territory_group_filter_for_key(value)
                for key, variable in self.territory_layer_vars.items():
                    variable.set(key == value)
                self.clear_territory_selection(announce=False)
                self.update_territory_icon_control()
                self.schedule_territory_map_draw(fast=True)
                return
            if kind == "zone":
                if ctrl_down:
                    self.toggle_territory_zone_from_group_list(value)
                else:
                    self.select_territory_zone_from_group_list(value)
        finally:
            self.handling_territory_group_tree_select = False

    def toggle_territory_groups_panel(self):
        collapsed = not self.territory_groups_collapsed_var.get()
        self.territory_groups_collapsed_var.set(collapsed)
        if self.territory_group_list_shell is not None:
            if collapsed:
                self.territory_group_list_shell.grid_remove()
            else:
                self.territory_group_list_shell.grid()
        if self.territory_groups_toggle_button is not None:
            self.territory_groups_toggle_button.configure(text="Expand" if collapsed else "Collapse")

    def visible_territory_layer_keys(self):
        if not self.territory_layer_vars:
            group_key = self.selected_territory_group_key()
            return {group_key} if group_key else set()
        return {key for key, variable in self.territory_layer_vars.items() if variable.get()}

    def set_territory_group_filter_for_path(self, path):
        target_key = self.normalized_path(path)
        for display, group_key in self.territory_group_filter_paths.items():
            if self.normalized_path(self.territory_group_key_source(group_key)) == target_key:
                self.territory_group_filter_var.set(display)
                self.sync_territory_source_filter_to_group()
                return True
        return False

    def set_territory_group_filter_for_key(self, target_key):
        for display, group_key in self.territory_group_filter_paths.items():
            if group_key == target_key:
                self.territory_group_filter_var.set(display)
                self.sync_territory_source_filter_to_group()
                return True
        return False

    def ensure_territory_layer_visible(self, path):
        raw = str(path or "")
        if "::" in raw:
            keys = [raw]
        else:
            source_key = self.normalized_path(path)
            keys = [key for key in self.territory_layer_vars if key.rsplit("::", 1)[0] == source_key]
        for key in keys:
            variable = self.territory_layer_vars.get(key)
            if variable is not None:
                variable.set(True)

    def set_active_territory_group_for_source(self, source_path):
        if self.set_territory_group_filter_for_path(source_path):
            self.sync_territory_source_filter_to_group()
            self.current_territory_group_key = self.selected_territory_group_key()
        self.ensure_territory_layer_visible(source_path)

    def set_active_territory_group_for_zone(self, zone):
        group_key = self.territory_zone_group_key(zone)
        self.current_territory_group_key = group_key
        if self.set_territory_group_filter_for_key(group_key):
            self.sync_territory_source_filter_to_group()
        self.ensure_territory_layer_visible(group_key)
        self.update_territory_icon_control()

    def refresh_territory_layers(self):
        tree = self.territory_group_tree
        if tree is None:
            return
        entries = self.territory_layer_entries()
        valid_keys = {entry["key"] for entry in entries}
        self.territory_expanded_group_keys.intersection_update(valid_keys)
        for key in list(self.territory_layer_vars):
            if key not in valid_keys:
                self.territory_layer_vars.pop(key, None)
        had_vars = bool(self.territory_layer_vars)
        selected_group_key = self.current_territory_group_key or self.selected_territory_group_key()
        self.refreshing_territory_layers = True
        try:
            for entry in entries:
                key = entry["key"]
                if key not in self.territory_layer_vars:
                    default_visible = (not had_vars and key == selected_group_key) or (not had_vars and not selected_group_key and entry == entries[0])
                    self.territory_layer_vars[key] = tk.BooleanVar(value=default_visible)
            tree.delete(*tree.get_children())
            self.territory_group_tree_items = {}
            for entry in entries:
                self.add_territory_layer_row(entry)
            self.update_territory_group_tree_selection()
            self.update_territory_group_tree_tags()
            if self.territory_group_list_shell is not None:
                if self.territory_groups_collapsed_var.get():
                    self.territory_group_list_shell.grid_remove()
                else:
                    self.territory_group_list_shell.grid()
            if self.territory_groups_toggle_button is not None:
                self.territory_groups_toggle_button.configure(text="Expand" if self.territory_groups_collapsed_var.get() else "Collapse")
            self.update_territory_icon_control()
        finally:
            self.refreshing_territory_layers = False

    def add_territory_layer_row(self, entry):
        tree = self.territory_group_tree
        if tree is None:
            return
        expanded = entry["key"] in self.territory_expanded_group_keys
        variable = self.territory_layer_vars[entry["key"]]
        visible_label = self.territory_group_status_label(entry["key"])
        iid = self.territory_group_iid(entry["key"])
        group_tags = ("group-current",) if entry["key"] == self.current_territory_group_key else (("group-visible",) if variable.get() else ("group-hidden",))
        tree.insert(
            "",
            "end",
            iid=iid,
            text=self.territory_group_display_label(entry["display"], entry["key"]),
            values=(visible_label, f"{entry['active']}/{entry['total']}"),
            open=expanded,
            tags=group_tags,
        )
        self.territory_group_tree_items[iid] = ("group", entry["key"])
        if expanded:
            self.populate_territory_group_tree_children(entry["key"])
        elif entry["total"]:
            dummy_iid = f"{iid}-dummy"
            tree.insert(iid, "end", iid=dummy_iid, text="Loading...", values=("", ""))
            self.territory_group_tree_items[dummy_iid] = ("dummy", entry["key"])

    def populate_territory_group_tree_children(self, group_key):
        tree = self.territory_group_tree
        if tree is None:
            return
        parent_iid = self.territory_group_iid(group_key)
        if not tree.exists(parent_iid):
            return
        for child in tree.get_children(parent_iid):
            tree.delete(child)
            self.territory_group_tree_items.pop(child, None)
        for index, zone in self.territory_group_zone_items(group_key):
            self.add_territory_zone_child_row(index, zone, parent_iid)

    def add_territory_zone_child_row(self, index, zone, parent_iid=None):
        tree = self.territory_group_tree
        if tree is None:
            return
        coord = zone.coordinate_preview()
        parent_iid = parent_iid or self.territory_group_iid(self.territory_zone_group_key(zone))
        iid = f"territory-zone-row-{index}"
        tags = ("zone-current",) if index == self.current_territory_index else (("zone-selected",) if index in self.selected_territory_indices else ("zone-muted",))
        tree.insert(
            parent_iid,
            "end",
            iid=iid,
            text=self.territory_zone_display_label(zone, index),
            values=(self.territory_zone_status_label(index), coord),
            tags=tags,
        )
        self.territory_group_tree_items[iid] = ("zone", index)

    def on_territory_layer_toggled(self, group_key):
        if self.refreshing_territory_layers:
            return
        if self.territory_layer_vars.get(group_key) is not None and self.territory_layer_vars[group_key].get():
            self.current_territory_group_key = group_key
            self.set_territory_group_filter_for_key(group_key)
        elif group_key == self.current_territory_group_key or group_key == self.selected_territory_group_key():
            self.current_territory_group_key = ""
            self.territory_group_filter_var.set("All groups")
            self.sync_territory_source_filter_to_group()
        self.clear_territory_selection(announce=False)
        self.schedule_territory_map_draw(fast=True)

    def show_only_selected_territory_layer(self):
        group_path = self.selected_territory_group_path()
        group_key = self.selected_territory_group_key()
        if not group_key:
            messagebox.showwarning(APP_TITLE, "Choose a territory group first.")
            return
        for key, variable in self.territory_layer_vars.items():
            variable.set(key == group_key)
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()

    def show_all_territory_layers(self):
        for variable in self.territory_layer_vars.values():
            variable.set(True)
        self.refresh_territory_table()

    def hide_all_territory_layers(self):
        for variable in self.territory_layer_vars.values():
            variable.set(False)
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()

    def update_territory_group_filter_values(self):
        self.update_territory_type_filter_values()
        current = self.territory_group_filter_var.get() or "All groups"
        selected_type_path = self.selected_territory_type_path()
        selected_type_key = self.normalized_path(selected_type_path) if selected_type_path else ""
        records = self.territory_group_records()
        display_paths = {}
        display_sources = {}
        for record in records.values():
            if selected_type_key and self.normalized_path(record["path"]) != selected_type_key:
                continue
            if not self.territory_show_inactive_var.get() and not record["active"] and not self.is_custom_territory_source_path(record["path"]):
                continue
            display = record["name"].split(" / ", 1)[1] if selected_type_key and " / " in record["name"] else record["name"]
            if display in display_paths:
                display = f"{display} [{record['group_index'] + 1}]"
            display_paths[display] = record["key"]
            display_sources[display] = record["path"]
        ordered_displays = [
            display
            for display, _key in sorted(
                display_paths.items(),
                key=lambda item: (
                    self.normalized_path(self.territory_group_key_source(item[1])),
                    self.territory_group_key_index(item[1]),
                    item[0].casefold(),
                ),
            )
        ]
        values = ["All groups"] + ordered_displays
        self.territory_group_filter_paths = display_paths
        self.territory_group_filter_sources = display_sources
        if self.current_territory_group_key and self.current_territory_group_key not in set(display_paths.values()):
            self.current_territory_group_key = ""
        combo = self.__dict__.get("territory_group_combo")
        if combo is not None:
            combo.configure(values=values)
        if not self.territory_default_group_applied and len(values) > 1:
            self.territory_group_filter_var.set(values[1])
            self.territory_default_group_applied = True
        elif current not in values:
            self.territory_group_filter_var.set(values[1] if len(values) > 1 else "All groups")
        self.sync_territory_source_filter_to_group()

    def on_territory_type_filter_changed(self, event=None):
        self.territory_group_filter_var.set("All groups")
        self.current_territory_group_key = ""
        self.territory_default_group_applied = False
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()

    def on_territory_group_filter_changed(self, event=None):
        self.sync_territory_source_filter_to_group()
        group_path = self.selected_territory_group_path()
        group_key = self.selected_territory_group_key()
        if group_key:
            self.current_territory_group_key = group_key
            for key, variable in self.territory_layer_vars.items():
                variable.set(key == group_key)
            self.ensure_territory_layer_visible(group_key)
        elif group_path:
            self.ensure_territory_layer_visible(group_path)
        self.refresh_territory_table()
        self.update_territory_icon_control()

    def on_territory_active_filter_changed(self):
        self.territory_default_group_applied = False
        self.current_territory_group_key = ""
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()

    def sync_territory_source_filter_to_group(self):
        group_path = self.selected_territory_group_path()
        self.territory_source_filter_var.set(self.source_display_name(group_path) if group_path else "All sources")

    def selected_territory_group_key(self):
        group_filter = self.territory_group_filter_var.get()
        if not group_filter or group_filter == "All groups":
            return ""
        return self.territory_group_filter_paths.get(group_filter, "")

    def selected_territory_group_path(self):
        group_key = self.selected_territory_group_key()
        if not group_key:
            return ""
        group_filter = self.territory_group_filter_var.get()
        return self.territory_group_filter_sources.get(group_filter, self.territory_group_key_source(group_key))

    def update_territory_sort_headings(self):
        if self.territory_tree is None:
            return
        labels = {
            "name": ("#0", "Zone"),
            "source": ("source", "Source"),
            "x": ("x", "X"),
            "z": ("z", "Z"),
            "r": ("r", "Radius"),
            "dmin": ("dmin", "DMin"),
            "dmax": ("dmax", "DMax"),
            "related": ("related", "Related"),
        }
        arrow = " v" if self.territory_sort_reverse else " ^"
        for column, (tree_column, label) in labels.items():
            text = label + (arrow if self.territory_sort_column == column else "")
            self.territory_tree.heading(tree_column, text=text, command=lambda sort_column=column: self.sort_territory_zones(sort_column))

    def sort_territory_zones(self, column):
        if self.territory_sort_column == column:
            self.territory_sort_reverse = not self.territory_sort_reverse
        else:
            self.territory_sort_column = column
            self.territory_sort_reverse = False
        self.refresh_territory_table()

    def territory_sort_key(self, item):
        index, zone = item
        column = self.territory_sort_column
        if column == "name":
            return (zone.name.casefold(), self.source_display_name(zone.source_path).casefold(), index)
        if column == "source":
            return (self.source_display_name(zone.source_path).casefold(), zone.name.casefold(), index)
        if column == "related":
            return (len(self.events_for_territory_zone(zone)), zone.name.casefold(), index)
        if column in {"x", "z", "r", "dmin", "dmax"}:
            try:
                value = float(zone.attributes.get(column, ""))
            except ValueError:
                value = None
            return (value is None, value if value is not None else 0.0, zone.name.casefold(), index)
        return (zone.name.casefold(), index)

    def visible_territory_zone_items(self):
        search = self.territory_search_var.get().strip().casefold()
        layer_keys = self.visible_territory_layer_keys()
        if self.territory_layer_vars and not layer_keys:
            return []
        visible = []
        for index, zone in enumerate(self.territory_zones):
            if not self.territory_show_inactive_var.get() and not self.territory_zone_is_active(zone):
                continue
            group_key = self.territory_zone_group_key(zone)
            if layer_keys and group_key not in layer_keys:
                continue
            source_name = self.source_display_name(zone.source_path)
            haystack = " ".join(
                [
                    zone.name,
                    getattr(zone, "group_name", ""),
                    self.territory_group_display_name(zone),
                    source_name,
                    zone.coordinate_preview(),
                    " ".join(f"{key}={value}" for key, value in zone.attributes.items()),
                ]
            ).casefold()
            if search and search not in haystack:
                continue
            visible.append((index, zone))
        return sorted(visible, key=self.territory_sort_key, reverse=self.territory_sort_reverse)

    def refresh_territory_table(self):
        self.update_territory_group_filter_values()
        self.update_territory_source_filter_values()
        self.refresh_territory_layers()
        paths = self.territory_source_paths()
        if paths:
            first = self.source_display_name(paths[0])
            suffix = "" if len(paths) == 1 else f" (+{len(paths) - 1} more)"
            self.territory_path_var.set(first + suffix)
        elif self.mission_workspace is not None:
            self.territory_path_var.set("No env/*_territories.xml files found in mission folder")
        else:
            self.territory_path_var.set("No territory XML loaded")

        self.territory_summary_var.set(f"{len(self.territory_zones)} zone(s) from {len(paths)} territory file(s).")
        if self.territory_tree is None:
            self.draw_territory_map()
            return

        self.update_territory_sort_headings()
        self.territory_tree.delete(*self.territory_tree.get_children())
        self.territory_iids = {}
        for index, zone in self.visible_territory_zone_items():
            related = self.events_for_territory_zone(zone)
            iid = f"territory-{index}"
            self.territory_tree.insert(
                "",
                "end",
                iid=iid,
                text=zone.name,
                values=(
                    self.source_display_name(zone.source_path),
                    zone.attributes.get("x", ""),
                    zone.attributes.get("z", ""),
                    zone.attributes.get("r", ""),
                    zone.attributes.get("dmin", ""),
                    zone.attributes.get("dmax", ""),
                    str(len(related)),
                ),
            )
            self.territory_iids[iid] = index
        if self.current_territory_index is not None and f"territory-{self.current_territory_index}" in self.territory_tree.get_children():
            iid = f"territory-{self.current_territory_index}"
            self.territory_tree.selection_set(iid)
            self.territory_tree.see(iid)
        else:
            self.clear_territory_detail()

    def select_territory_zone_index(self, index, preserve_selection=False):
        if index is None or not (0 <= index < len(self.territory_zones)):
            return False
        self.set_active_territory_group_for_zone(self.territory_zones[index])
        self.current_territory_index = index
        if preserve_selection:
            self.selected_territory_indices.add(index)
        else:
            self.selected_territory_indices = {index}
        if self.territory_tree is not None:
            iid = f"territory-{index}"
            if iid in self.territory_tree.get_children():
                self.territory_tree.selection_set(iid)
                self.territory_tree.see(iid)
        self.populate_territory_detail(index)
        self.draw_territory_map()
        self.update_territory_group_tree_tags()
        return True

    def select_territory_source_path(self, source_path):
        self.switch_module("territories")
        self.update_territory_group_filter_values()
        self.set_territory_group_filter_for_path(source_path)
        self.ensure_territory_layer_visible(source_path)
        self.refresh_territory_table()
        return any(self.normalized_path(zone.source_path) == self.normalized_path(source_path) for zone in self.territory_zones)

    def select_territory_zone_by_name(self, name, source_path=""):
        key = str(name or "").casefold()
        source_key = self.normalized_path(source_path) if source_path else ""
        for index, zone in enumerate(self.territory_zones):
            if zone.name.casefold() != key:
                continue
            if source_key and self.normalized_path(zone.source_path) != source_key:
                continue
            self.select_territory_source_path(zone.source_path)
            return self.select_territory_zone_index(index)
        if source_path:
            return self.select_territory_source_path(source_path)
        else:
            self.switch_module("territories")
        return False

    def toggle_territory_zone_selection(self, index):
        if index is None or not (0 <= index < len(self.territory_zones)):
            return
        if index in self.selected_territory_indices:
            self.selected_territory_indices.remove(index)
            if self.current_territory_index == index:
                self.current_territory_index = next(iter(sorted(self.selected_territory_indices)), None)
                if self.current_territory_index is not None:
                    self.set_active_territory_group_for_zone(self.territory_zones[self.current_territory_index])
        else:
            self.selected_territory_indices.add(index)
            self.current_territory_index = index
            self.set_active_territory_group_for_zone(self.territory_zones[index])
        if self.current_territory_index is None:
            self.clear_territory_detail()
        else:
            self.populate_territory_detail(self.current_territory_index)
        self.draw_territory_map()
        self.update_territory_group_tree_tags()

    def select_visible_territory_zones(self):
        visible_indices = [index for index, _zone in self.visible_territory_zone_items()]
        if not visible_indices:
            self.log("No visible territory zones to select.", "muted")
            return
        self.selected_territory_indices = set(visible_indices)
        if self.current_territory_index not in self.selected_territory_indices:
            self.current_territory_index = visible_indices[0]
        self.populate_territory_detail(self.current_territory_index)
        self.draw_territory_map()
        self.update_territory_group_tree_tags()
        self.log(f"Selected {len(visible_indices)} visible territory zones.", "success")

    def territory_map_dimensions_for_current_view(self):
        visible_items = self.territory_map_visible_items()
        zones = [zone for _index, zone, _coord in visible_items] or self.territory_zones
        return self.mission_map_size(zones, self.selected_map_key)

    def canvas_point_inside_territory_map(self, canvas_x, canvas_y):
        base_w, base_h = self.territory_map_base_size()
        state = self.territory_map_state
        map_x1 = state["offset_x"]
        map_y1 = state["offset_y"]
        map_x2 = map_x1 + base_w * state["zoom"]
        map_y2 = map_y1 + base_h * state["zoom"]
        return map_x1 <= canvas_x <= map_x2 and map_y1 <= canvas_y <= map_y2

    def territory_radius_to_canvas(self, radius, map_width):
        try:
            radius_value = float(radius)
        except (TypeError, ValueError):
            radius_value = 0.0
        base_w, _base_h = self.territory_map_base_size()
        return max(0.0, (radius_value / max(map_width, 1.0)) * base_w * self.territory_map_state["zoom"])

    def territory_canvas_radius_to_world(self, center_x, center_y, edge_x, edge_y):
        map_width, map_height, _map_label = self.territory_map_dimensions_for_current_view()
        center = self.territory_canvas_to_world(center_x, center_y, map_width, map_height)
        edge = self.territory_canvas_to_world(edge_x, edge_y, map_width, map_height)
        if center is None or edge is None:
            return None
        return ((edge[0] - center[0]) ** 2 + (edge[1] - center[1]) ** 2) ** 0.5

    def territory_add_radius_value(self):
        try:
            radius = float(self.territory_add_radius_var.get().strip() or "200")
        except ValueError:
            radius = 200.0
        return max(1.0, radius)

    def selected_territory_add_source_path(self):
        group_path = self.selected_territory_group_path()
        if group_path:
            return group_path
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            return self.territory_zones[self.current_territory_index].source_path
        visible_sources = {
            zone.source_path for _index, zone in self.visible_territory_zone_items()
        }
        return next(iter(visible_sources)) if len(visible_sources) == 1 else ""

    def selected_territory_add_group_index(self):
        group_key = self.selected_territory_group_key()
        if group_key:
            return self.territory_group_key_index(group_key)
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            return int(getattr(self.territory_zones[self.current_territory_index], "group_index", 0) or 0)
        return 0

    def default_territory_template(self, source_path):
        source_key = self.normalized_path(source_path)
        group_index = self.selected_territory_add_group_index()
        exemplar = None
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            current_zone = self.territory_zones[self.current_territory_index]
            if self.normalized_path(current_zone.source_path) == source_key and int(getattr(current_zone, "group_index", 0) or 0) == group_index:
                exemplar = current_zone
        if exemplar is None:
            for zone in self.territory_zones:
                if self.normalized_path(zone.source_path) == source_key and int(getattr(zone, "group_index", 0) or 0) == group_index:
                    exemplar = zone
                    break
        radius = self.format_territory_radius(self.territory_add_radius_value())
        if not radius and exemplar is not None:
            radius = exemplar.attributes.get("r", "200")
        template = {
            "name": self.default_territory_zone_name(source_path),
            "r": radius or "200",
            "dmin": "0",
            "dmax": "0",
            "_group_index": str(group_index),
        }
        if exemplar is not None:
            template["_group_name"] = getattr(exemplar, "group_name", "")
            template["_group_attributes"] = dict(getattr(exemplar, "group_attributes", {}) or {})
            for field in ("dmin", "dmax", "smin", "smax"):
                if field in exemplar.attributes:
                    template[field] = exemplar.attributes.get(field, "0")
        return template

    def clear_territory_placement_preview(self):
        if self.territory_map_canvas is not None:
            self.territory_map_canvas.delete("territory-placement-preview")
        self.territory_map_state["placement_preview"] = None

    def set_territory_map_cursor(self):
        if self.territory_map_canvas is None:
            return
        mode = self.territory_map_state.get("edit_mode", "")
        self.territory_map_canvas.configure(cursor="crosshair" if mode else "")

    def cancel_territory_map_edit_mode(self, event=None):
        state = self.territory_map_state
        if not state.get("edit_mode"):
            return "break"
        mode = state.get("edit_mode")
        state["edit_mode"] = ""
        state["placement_source_path"] = ""
        state["placement_template"] = None
        state["placement_duplicate_indices"] = []
        state["placement_duplicate_origin"] = None
        state["drag_mode"] = "idle"
        self.clear_territory_placement_preview()
        self.set_territory_map_cursor()
        self.draw_territory_map()
        self.log(f"Cancelled territory {mode.replace('_', ' ')} mode.", "muted")
        return "break"

    def draw_territory_add_preview(self, canvas_x, canvas_y, radius=None):
        canvas = self.territory_map_canvas
        if canvas is None or not self.selected_map_key:
            return
        canvas.delete("territory-placement-preview")
        if not self.canvas_point_inside_territory_map(canvas_x, canvas_y):
            return
        radius = self.territory_add_radius_value() if radius is None else radius
        map_width, _map_height, _map_label = self.territory_map_dimensions_for_current_view()
        canvas_radius = self.territory_radius_to_canvas(radius, map_width)
        template = self.territory_map_state.get("placement_template") or {}
        name = template.get("name", "Zone")
        canvas.create_oval(
            canvas_x - canvas_radius,
            canvas_y - canvas_radius,
            canvas_x + canvas_radius,
            canvas_y + canvas_radius,
            outline=GRAPHITE_ACCENT_HOVER,
            width=2,
            dash=(5, 3),
            tags=("territory-placement-preview",),
        )
        canvas.create_oval(canvas_x - 5, canvas_y - 5, canvas_x + 5, canvas_y + 5, fill=GRAPHITE_ACCENT_HOVER, outline="#ffffff", tags=("territory-placement-preview",))
        radius_label = self.format_territory_radius(radius)
        canvas.create_text(canvas_x + 10, canvas_y - 10, text=f"Add {name} | r={radius_label}", fill=GRAPHITE_TEXT, anchor="sw", font=("Segoe UI", 9, "bold"), tags=("territory-placement-preview",))

    def draw_territory_duplicate_preview(self, canvas_x, canvas_y):
        canvas = self.territory_map_canvas
        if canvas is None or not self.selected_map_key:
            return
        canvas.delete("territory-placement-preview")
        state = self.territory_map_state
        origin = state.get("placement_duplicate_origin")
        indices = state.get("placement_duplicate_indices") or []
        if origin is None or not indices or not self.canvas_point_inside_territory_map(canvas_x, canvas_y):
            return
        map_width, map_height, _map_label = self.territory_map_dimensions_for_current_view()
        target = self.territory_canvas_to_world(canvas_x, canvas_y, map_width, map_height)
        if target is None:
            return
        dx = target[0] - origin[0]
        dz = target[1] - origin[1]
        for index in indices:
            if not (0 <= index < len(self.territory_zones)):
                continue
            zone = self.territory_zones[index]
            coord = self.spawn_position_xy(zone)
            if coord is None:
                continue
            px, py = self.territory_world_to_canvas(coord[0] + dx, coord[1] + dz, map_width, map_height)
            canvas_radius = self.territory_radius_to_canvas(zone.attributes.get("r", "0"), map_width)
            if canvas_radius > 0:
                canvas.create_oval(px - canvas_radius, py - canvas_radius, px + canvas_radius, py + canvas_radius, outline=GRAPHITE_ACCENT_HOVER, width=2, dash=(5, 3), tags=("territory-placement-preview",))
            canvas.create_oval(px - 5, py - 5, px + 5, py + 5, fill=GRAPHITE_ACCENT_HOVER, outline="#ffffff", tags=("territory-placement-preview",))
        canvas.create_text(canvas_x + 10, canvas_y - 10, text=f"Place {len(indices)} duplicate zone(s)", fill=GRAPHITE_TEXT, anchor="sw", font=("Segoe UI", 9, "bold"), tags=("territory-placement-preview",))

    def clear_territory_resize_preview(self):
        if self.territory_map_canvas is not None:
            self.territory_map_canvas.delete("territory-resize-preview")

    def draw_territory_resize_preview(self):
        canvas = self.territory_map_canvas
        if canvas is None or not self.selected_map_key:
            return
        canvas.delete("territory-resize-preview")
        state = self.territory_map_state
        indices = [
            index for index in state.get("resize_preview_indices", []) or state.get("resize_indices", [])
            if 0 <= index < len(self.territory_zones)
        ]
        if not indices:
            return
        map_width, map_height, _map_label = self.territory_map_dimensions_for_current_view()
        for index in indices:
            zone = self.territory_zones[index]
            coord = self.spawn_position_xy(zone)
            if coord is None:
                continue
            px, py = self.territory_world_to_canvas(coord[0], coord[1], map_width, map_height)
            radius = self.territory_radius_value(zone)
            canvas_radius = self.territory_radius_to_canvas(radius, map_width)
            if canvas_radius <= 0:
                continue
            canvas.create_oval(
                px - canvas_radius,
                py - canvas_radius,
                px + canvas_radius,
                py + canvas_radius,
                outline=GRAPHITE_ACCENT_HOVER,
                width=3,
                dash=(5, 3),
                tags=("territory-resize-preview",),
            )
            canvas.create_text(
                px + canvas_radius + 8,
                py,
                text=f"r={self.format_territory_radius(radius)}",
                fill=GRAPHITE_TEXT,
                anchor="w",
                font=("Segoe UI", 9, "bold"),
                tags=("territory-resize-preview",),
            )

    def on_territory_map_motion(self, event):
        mode = self.territory_map_state.get("edit_mode")
        if mode == "add_zone":
            self.draw_territory_add_preview(event.x, event.y)
        elif mode == "duplicate_zone":
            self.draw_territory_duplicate_preview(event.x, event.y)

    def selected_territory_action_indices(self):
        indices = sorted(
            index
            for index in self.selected_territory_indices
            if 0 <= index < len(self.territory_zones)
        )
        if indices:
            return indices
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            return [self.current_territory_index]
        return []

    def territory_source_index_for_path(self, source_path):
        source_key = self.normalized_path(source_path)
        for index, path in enumerate(self.territory_source_paths()):
            if self.normalized_path(path) == source_key:
                return index
        return 0

    def selected_territory_edit_source_path(self):
        group_path = self.selected_territory_group_path()
        if group_path:
            return group_path
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            return self.territory_zones[self.current_territory_index].source_path
        paths = self.territory_source_paths()
        return paths[0] if paths else ""

    def default_territory_zone_name(self, source_path):
        counts = {}
        source_key = self.normalized_path(source_path)
        for zone in self.territory_zones:
            if self.normalized_path(zone.source_path) != source_key:
                continue
            name = zone.name if not zone.name.startswith("<missing ") else ""
            if name:
                counts[name] = counts.get(name, 0) + 1
        if counts:
            return sorted(counts.items(), key=lambda item: (-item[1], item[0].casefold()))[0][0]
        return self.territory_group_name(source_path) or "Zone"

    def default_territory_zone_position(self):
        if self.territory_map_canvas is not None and self.selected_map_key:
            self.territory_map_canvas.update_idletasks()
            width = max(self.territory_map_canvas.winfo_width(), 400)
            height = max(self.territory_map_canvas.winfo_height(), 400)
            visible_items = self.territory_map_visible_items()
            zones = [zone for _index, zone, _coord in visible_items] or self.territory_zones
            map_width, map_height, _map_label = self.mission_map_size(zones, self.selected_map_key)
            coord = self.territory_canvas_to_world(width / 2, height / 2, map_width, map_height)
            if coord is not None:
                return coord
        if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
            coord = self.spawn_position_xy(self.territory_zones[self.current_territory_index])
            if coord is not None:
                return coord
        return 0.0, 0.0

    def make_territory_zone(self, source_path, name, x, z, radius="200", dmin="0", dmax="0", extra_attributes=None, group_index=0, group_name="", group_attributes=None):
        attributes = {
            "name": str(name).strip() or "Zone",
            "x": self.format_territory_coordinate(x),
            "z": self.format_territory_coordinate(z),
            "r": self.format_territory_radius(radius),
            "dmin": str(dmin).strip() or "0",
            "dmax": str(dmax).strip() or "0",
        }
        for field, value in (extra_attributes or {}).items():
            if field not in attributes and value is not None:
                attributes[field] = str(value).strip()
        element = ET.Element("zone", attributes)
        return TerritoryZone(
            name=attributes["name"],
            attributes=dict(attributes),
            element=element,
            source_path=source_path,
            source_index=self.territory_source_index_for_path(source_path),
            group_index=int(group_index or 0),
            group_name=str(group_name or ""),
            group_attributes=dict(group_attributes or {}),
        )

    def insert_territory_zone_for_source(self, zone, source_path):
        source_key = self.normalized_path(source_path)
        group_index = int(getattr(zone, "group_index", 0) or 0)
        insert_at = len(self.territory_zones)
        for index in range(len(self.territory_zones) - 1, -1, -1):
            existing = self.territory_zones[index]
            if self.normalized_path(existing.source_path) == source_key and int(getattr(existing, "group_index", 0) or 0) == group_index:
                insert_at = index + 1
                break
        else:
            for index in range(len(self.territory_zones) - 1, -1, -1):
                if self.normalized_path(self.territory_zones[index].source_path) == source_key:
                    insert_at = index + 1
                    break
        self.territory_zones.insert(insert_at, zone)
        return insert_at

    def finish_territory_structure_edit(self, source_paths, selected_indices, message, center_selected=True):
        self.selected_territory_indices = {
            index for index in selected_indices if 0 <= index < len(self.territory_zones)
        }
        self.current_territory_index = min(self.selected_territory_indices) if self.selected_territory_indices else None
        for source_path in source_paths:
            self.mark_source_dirty(source_path)
        self.mark_territory_related_event_cache_stale()
        self.schedule_validation_refresh()
        self.refresh_territory_table()
        if self.current_territory_index is not None:
            self.populate_territory_detail(self.current_territory_index)
            if center_selected:
                self.center_selected_territory_on_map()
            else:
                self.draw_territory_map()
        else:
            self.clear_territory_detail()
            self.draw_territory_map()
        self.update_summary()
        self.log(message, "success")

    def add_custom_territory_source(self):
        if self.mission_workspace is None:
            messagebox.showwarning(APP_TITLE, "Open a mission folder before adding custom territories.")
            return
        name = simpledialog.askstring(
            APP_TITLE,
            "Custom territory name:",
            parent=self,
        )
        if name is None:
            return
        source_path = self.custom_territory_source_path_for_name(name)
        if not source_path:
            messagebox.showwarning(APP_TITLE, "Enter a territory name that contains letters or numbers.")
            return
        source_key = self.normalized_path(source_path)
        if any(self.normalized_path(path) == source_key for path in self.territory_source_paths()):
            messagebox.showwarning(APP_TITLE, f"Territory source already exists:\n{self.source_display_name(source_path)}")
            return
        self.add_territory_source_path(source_path)
        self.territory_groups.append(
            TerritoryGroup(
                source_path=source_path,
                source_index=self.territory_source_index_for_path(source_path),
                group_index=0,
            )
        )
        self.custom_territory_source_keys.add(source_key)
        self.remember_custom_territory_source_path(source_path)
        self.mark_source_dirty(source_path)
        self.territory_default_group_applied = True
        self.update_territory_group_filter_values()
        self.set_territory_group_filter_for_path(source_path)
        self.ensure_territory_layer_visible(source_path)
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()
        self.update_summary()
        self.log(f"Added custom territory source: {self.source_display_name(source_path)}. Use Add zone, then Save.", "success")
        if messagebox.askyesno(APP_TITLE, f"Register this territory in cfgenvironment.xml now?\n\n{self.source_display_name(source_path)}"):
            self.register_territory_source_in_environment(source_path)

    def delete_custom_territory_source(self):
        source_path = self.selected_territory_group_path() or self.selected_territory_edit_source_path()
        if not source_path:
            messagebox.showwarning(APP_TITLE, "Choose a custom territory group first.")
            return
        if not self.is_custom_territory_source_path(source_path):
            messagebox.showwarning(APP_TITLE, "Only custom territory sources created in this session can be deleted here. Use Delete to remove zones from existing mission files.")
            return
        source_key = self.normalized_path(source_path)
        zones = self.territory_zones_for_source(self.territory_zones, source_path)
        if not messagebox.askyesno(
            APP_TITLE,
            f"Delete custom territory source?\n\n{self.source_display_name(source_path)}\n\nThis removes {len(zones)} loaded zone(s). If the file was already saved, it will be deleted from disk.",
        ):
            return
        try:
            if Path(source_path).exists():
                Path(source_path).unlink()
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not delete territory source:\n{exc}")
            return
        self.remove_territory_source_path(source_path)
        self.custom_territory_source_keys.discard(source_key)
        self.forget_custom_territory_source_path(source_path)
        self.territory_zones = [
            zone for zone in self.territory_zones
            if self.normalized_path(zone.source_path) != source_key
        ]
        self.territory_groups = [
            group for group in self.territory_groups
            if self.normalized_path(group.source_path) != source_key
        ]
        self.original_territory_zones = [
            zone for zone in self.original_territory_zones
            if self.normalized_path(zone.source_path) != source_key
        ]
        self.original_territory_groups = [
            group for group in self.original_territory_groups
            if self.normalized_path(group.source_path) != source_key
        ]
        self.dirty_source_keys_cache.discard(source_key)
        for key in list(self.territory_layer_vars):
            if key.rsplit("::", 1)[0] == source_key:
                self.territory_layer_vars.pop(key, None)
        self.territory_group_filter_var.set("All groups")
        self.selected_territory_indices.clear()
        self.current_territory_index = None
        self.mark_territory_related_event_cache_stale()
        self.schedule_validation_refresh()
        self.refresh_territory_table()
        self.clear_territory_detail()
        self.draw_territory_map()
        self.update_summary()
        self.set_dirty(bool(self.dirty_source_keys_cache) or self.definitions_dirty)
        self.log(f"Deleted custom territory source: {self.source_display_name(source_path)}.", "success")

    def territory_groups_for_source(self, groups, source_path):
        source_key = self.normalized_path(source_path)
        return [group for group in groups if self.normalized_path(group.source_path) == source_key]

    def selected_territory_group_meta(self):
        group_key = self.selected_territory_group_key()
        if not group_key:
            return None
        return self.territory_group_meta_for_key(group_key)

    def territory_group_meta_for_key(self, group_key):
        source_path = self.territory_group_key_source(group_key)
        group_index = self.territory_group_key_index(group_key)
        for group in self.territory_groups:
            if self.normalized_path(group.source_path) == self.normalized_path(source_path) and int(group.group_index or 0) == group_index:
                return group
        for zone in self.territory_zones:
            if self.normalized_path(zone.source_path) == self.normalized_path(source_path) and int(getattr(zone, "group_index", 0) or 0) == group_index:
                return TerritoryGroup(
                    source_path=source_path,
                    source_index=self.territory_source_index_for_path(source_path),
                    group_index=group_index,
                    name=getattr(zone, "group_name", ""),
                    attributes=dict(getattr(zone, "group_attributes", {}) or {}),
                )
        return TerritoryGroup(source_path=source_path, source_index=self.territory_source_index_for_path(source_path), group_index=group_index)

    def territory_group_choices_for_source(self, source_path):
        source_key = self.normalized_path(source_path)
        choices = []
        seen = set()
        records = self.territory_group_records()
        for record in sorted(records.values(), key=lambda item: (self.normalized_path(item["path"]), item["group_index"])):
            if self.normalized_path(record["path"]) != source_key:
                continue
            key = record["key"]
            if key in seen:
                continue
            seen.add(key)
            group = self.territory_group_meta_for_key(key)
            label = f"{group.display_name()} ({record['total']} zone{'s' if record['total'] != 1 else ''})"
            choices.append((label, key, group))
        return choices

    def ask_territory_group_choice(self, title, source_path, initial_key=""):
        choices = self.territory_group_choices_for_source(source_path)
        if not choices:
            return None
        window = tk.Toplevel(self)
        window.title(title)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        window.grab_set()
        window.resizable(False, False)
        container = ttk.Frame(window, style="Card.TFrame", padding=14)
        container.grid(row=0, column=0, sticky="nsew")
        ttk.Label(container, text=f"Territory-Type: {self.territory_type_name(source_path)}", style="FieldName.TLabel").grid(row=0, column=0, sticky="w", pady=(0, 8))
        selected = tk.StringVar(value=choices[0][0])
        label_by_key = {key: label for label, key, _group in choices}
        if initial_key in label_by_key:
            selected.set(label_by_key[initial_key])
        combo = ttk.Combobox(container, textvariable=selected, values=[label for label, _key, _group in choices], state="readonly", width=38, style="TCombobox")
        combo.grid(row=1, column=0, sticky="ew", pady=(0, 12))
        self.bind_combobox_open_on_click(combo)
        result = {"key": None}

        def submit():
            label = selected.get()
            for choice_label, key, _group in choices:
                if choice_label == label:
                    result["key"] = key
                    break
            window.destroy()

        actions = ttk.Frame(container, style="Card.TFrame")
        actions.grid(row=2, column=0, sticky="e")
        self.make_button(actions, "Cancel", window.destroy)
        self.make_button(actions, "Move", submit, variant="save")
        window.bind("<Return>", lambda _event: submit())
        window.bind("<Escape>", lambda _event: window.destroy())
        center_window(window, self)
        combo.focus_set()
        self.wait_window(window)
        return result["key"]

    def add_territory_group(self):
        source_path = self.selected_territory_type_path() or self.selected_territory_group_path() or self.selected_territory_edit_source_path()
        if not source_path:
            messagebox.showwarning(APP_TITLE, "Choose a territory type first.")
            return
        name = simpledialog.askstring(APP_TITLE, "Group name:", parent=self)
        if name is None:
            return
        clean_name = str(name).strip()
        source_groups = self.territory_groups_for_source(self.territory_groups, source_path)
        group_index = (max((int(group.group_index or 0) for group in source_groups), default=-1) + 1)
        attributes = {"name": clean_name} if clean_name else {}
        old_zones = self.territory_zone_snapshot()
        old_groups = self.territory_group_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        group = TerritoryGroup(
            source_path=source_path,
            source_index=self.territory_source_index_for_path(source_path),
            group_index=group_index,
            name=clean_name,
            attributes=attributes,
            zone_count=0,
        )
        self.territory_groups.append(group)
        self.push_territory_structure_undo(f"add group {group.display_name()}", old_zones, self.territory_zones, [source_path], old_selected, [], old_groups=old_groups, new_groups=self.territory_groups)
        self.mark_source_dirty(source_path)
        self.territory_type_filter_var.set(self.territory_type_name(source_path))
        self.update_territory_group_filter_values()
        self.set_territory_group_filter_for_key(self.territory_group_key_for(source_path, group_index))
        self.ensure_territory_layer_visible(self.territory_group_key_for(source_path, group_index))
        self.clear_territory_selection(announce=False)
        self.refresh_territory_table()
        self.update_summary()
        self.log(f"Added territory group {group.display_name()} in {self.territory_type_name(source_path)}.", "success")

    def update_territory_group_metadata(self, group, name=None, color=None):
        source_key = self.normalized_path(group.source_path)
        group_index = int(group.group_index or 0)
        if not any(self.normalized_path(item.source_path) == source_key and int(item.group_index or 0) == group_index for item in self.territory_groups):
            self.territory_groups.append(group)
        if name is not None:
            group.name = str(name).strip()
            if group.name:
                group.attributes["name"] = group.name
            else:
                group.attributes.pop("name", None)
        if color is not None:
            group.attributes["color"] = str(color)
        for zone in self.territory_zones:
            if self.normalized_path(zone.source_path) == source_key and int(getattr(zone, "group_index", 0) or 0) == group_index:
                zone.group_name = group.name
                zone.group_attributes = dict(group.attributes)

    def rename_territory_group(self):
        group = self.selected_territory_group_meta()
        if group is None:
            messagebox.showwarning(APP_TITLE, "Choose a territory group first.")
            return
        name = simpledialog.askstring(APP_TITLE, "Group name:", initialvalue=group.display_name(), parent=self)
        if name is None:
            return
        old_zones = self.territory_zone_snapshot()
        old_groups = self.territory_group_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        self.update_territory_group_metadata(group, name=name)
        self.push_territory_structure_undo(
            f"rename group {group.display_name()}",
            old_zones,
            self.territory_zones,
            [group.source_path],
            old_selected,
            old_selected,
            old_groups=old_groups,
            new_groups=self.territory_groups,
        )
        self.mark_source_dirty(group.source_path)
        self.update_territory_group_filter_values()
        self.set_territory_group_filter_for_key(self.territory_group_key_for(group.source_path, group.group_index))
        self.refresh_territory_table()
        self.update_summary()
        self.log(f"Renamed territory group to {group.display_name()}.", "success")

    def choose_territory_group_color(self):
        group = self.selected_territory_group_meta()
        if group is None:
            messagebox.showwarning(APP_TITLE, "Choose a territory group first.")
            return
        initial = self.territory_group_color_hex(group.attributes, self.territory_group_key_for(group.source_path, group.group_index))
        _rgb, hex_color = colorchooser.askcolor(color=initial, title="Territory group color", parent=self)
        if not hex_color:
            return
        ce_value = self.territory_color_to_ce_value(hex_color)
        if not ce_value:
            return
        old_zones = self.territory_zone_snapshot()
        old_groups = self.territory_group_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        self.update_territory_group_metadata(group, color=ce_value)
        self.push_territory_structure_undo(
            f"set group color {group.display_name()}",
            old_zones,
            self.territory_zones,
            [group.source_path],
            old_selected,
            old_selected,
            old_groups=old_groups,
            new_groups=self.territory_groups,
        )
        self.mark_source_dirty(group.source_path)
        self.refresh_territory_table()
        self.update_summary()
        self.log(f"Updated territory group color for {group.display_name()}.", "success")

    def move_selected_territory_zones_to_group(self):
        indices = self.selected_territory_action_indices()
        if not indices:
            messagebox.showwarning(APP_TITLE, "Select one or more territory zones first.")
            return
        source_keys = {
            self.normalized_path(self.territory_zones[index].source_path)
            for index in indices
            if 0 <= index < len(self.territory_zones)
        }
        if len(source_keys) != 1:
            messagebox.showwarning(APP_TITLE, "Move zones from one territory type at a time.")
            return
        source_path = self.territory_zones[indices[0]].source_path
        current_key = self.territory_zone_group_key(self.territory_zones[indices[0]]) if len({self.territory_zone_group_key(self.territory_zones[index]) for index in indices}) == 1 else ""
        target_key = self.ask_territory_group_choice("Move zones to group", source_path, current_key)
        if not target_key:
            return
        target_group = self.territory_group_meta_for_key(target_key)
        if target_group is None:
            return
        old_zones = self.territory_zone_snapshot()
        old_groups = self.territory_group_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        moved = 0
        for index in indices:
            if not (0 <= index < len(self.territory_zones)):
                continue
            zone = self.territory_zones[index]
            zone.group_index = int(target_group.group_index or 0)
            zone.group_name = target_group.name
            zone.group_attributes = dict(target_group.attributes or {})
            zone.source_path = target_group.source_path
            zone.source_index = target_group.source_index
            moved += 1
        if not moved:
            return
        self.push_territory_structure_undo(
            f"move {moved} zone(s) to {target_group.display_name()}",
            old_zones,
            self.territory_zones,
            [source_path],
            old_selected,
            indices,
            old_groups=old_groups,
            new_groups=self.territory_groups,
        )
        self.territory_type_filter_var.set(self.territory_type_name(source_path))
        self.update_territory_group_filter_values()
        self.set_territory_group_filter_for_key(target_key)
        for key, variable in self.territory_layer_vars.items():
            variable.set(key == target_key)
        self.finish_territory_structure_edit([source_path], indices, f"Moved {moved} territory zone(s) to {target_group.display_name()}.", center_selected=False)

    def duplicate_territory_group(self):
        group = self.selected_territory_group_meta()
        if group is None:
            messagebox.showwarning(APP_TITLE, "Choose a territory group first.")
            return
        source_path = group.source_path
        source_groups = self.territory_groups_for_source(self.territory_groups, source_path)
        new_index = max((int(item.group_index or 0) for item in source_groups), default=-1) + 1
        new_attributes = dict(group.attributes)
        base_name = group.display_name()
        new_name = f"{base_name} Copy"
        if new_attributes or group.name:
            new_attributes["name"] = new_name
        new_group = TerritoryGroup(source_path=source_path, source_index=group.source_index, group_index=new_index, name=new_name, attributes=new_attributes, zone_count=0)
        old_zones = self.territory_zone_snapshot()
        old_groups = self.territory_group_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        new_indices = []
        insert_after = max(
            [index for index, zone in enumerate(self.territory_zones) if self.territory_zone_group_key(zone) == self.territory_group_key_for(source_path, group.group_index)],
            default=len(self.territory_zones) - 1,
        )
        copied = []
        for zone in self.territory_zones:
            if self.territory_zone_group_key(zone) != self.territory_group_key_for(source_path, group.group_index):
                continue
            clone = zone.clone()
            clone.group_index = new_index
            clone.group_name = new_name
            clone.group_attributes = dict(new_attributes)
            copied.append(clone)
        self.territory_groups.append(new_group)
        for offset, clone in enumerate(copied, start=1):
            self.territory_zones.insert(insert_after + offset, clone)
            new_indices.append(insert_after + offset)
        self.push_territory_structure_undo(f"duplicate group {base_name}", old_zones, self.territory_zones, [source_path], old_selected, new_indices, old_groups=old_groups, new_groups=self.territory_groups)
        self.mark_source_dirty(source_path)
        self.update_territory_group_filter_values()
        self.set_territory_group_filter_for_key(self.territory_group_key_for(source_path, new_index))
        self.finish_territory_structure_edit([source_path], new_indices, f"Duplicated territory group {base_name}.", center_selected=False)

    def delete_territory_group(self):
        group = self.selected_territory_group_meta()
        if group is None:
            messagebox.showwarning(APP_TITLE, "Choose a territory group first.")
            return
        group_key = self.territory_group_key_for(group.source_path, group.group_index)
        zone_count = sum(1 for zone in self.territory_zones if self.territory_zone_group_key(zone) == group_key)
        if not messagebox.askyesno(APP_TITLE, f"Delete territory group?\n\n{group.display_name()}\n\nThis removes {zone_count} zone(s)."):
            return
        old_zones = self.territory_zone_snapshot()
        old_groups = self.territory_group_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        self.territory_zones = [zone for zone in self.territory_zones if self.territory_zone_group_key(zone) != group_key]
        self.territory_groups = [
            item for item in self.territory_groups
            if not (self.normalized_path(item.source_path) == self.normalized_path(group.source_path) and int(item.group_index or 0) == int(group.group_index or 0))
        ]
        self.territory_layer_vars.pop(group_key, None)
        self.push_territory_structure_undo(f"delete group {group.display_name()}", old_zones, self.territory_zones, [group.source_path], old_selected, [], old_groups=old_groups, new_groups=self.territory_groups)
        self.territory_group_filter_var.set("All groups")
        self.finish_territory_structure_edit([group.source_path], [], f"Deleted territory group {group.display_name()}.")

    def add_territory_zone(self):
        if self.territory_map_state.get("edit_mode") == "add_zone":
            self.cancel_territory_map_edit_mode()
            return
        source_path = self.selected_territory_add_source_path()
        if not source_path:
            messagebox.showwarning(APP_TITLE, "Choose a territory group first, or select a zone from the group you want to edit.")
            return
        if not self.selected_map_key:
            messagebox.showwarning(APP_TITLE, "Choose a map before adding territory zones.")
            return
        template = self.default_territory_template(source_path)
        self.territory_add_radius_var.set(template.get("r", "200"))
        self.ensure_territory_layer_visible(self.territory_group_key_for(source_path, template.get("_group_index", 0)))
        state = self.territory_map_state
        state["edit_mode"] = "add_zone"
        state["placement_source_path"] = source_path
        state["placement_template"] = template
        state["placement_duplicate_indices"] = []
        state["placement_duplicate_origin"] = None
        self.set_territory_map_cursor()
        self.territory_map_status_var.set("Add zone: click the map to place, drag while placing to set radius, Esc cancels.")
        self.log(f"Add zone mode: placing into {self.territory_type_name(source_path)} group {int(template.get('_group_index', 0)) + 1}.", "muted")

    def duplicate_selected_territory_zones(self):
        if self.territory_map_state.get("edit_mode") == "duplicate_zone":
            self.cancel_territory_map_edit_mode()
            return
        indices = self.selected_territory_action_indices()
        if not indices:
            messagebox.showwarning(APP_TITLE, "Select one or more territory zones first.")
            return
        if not self.selected_map_key:
            messagebox.showwarning(APP_TITLE, "Choose a map before duplicating territory zones.")
            return
        coords = [
            self.spawn_position_xy(self.territory_zones[index])
            for index in indices
            if 0 <= index < len(self.territory_zones)
        ]
        coords = [coord for coord in coords if coord is not None]
        if not coords:
            messagebox.showwarning(APP_TITLE, "Selected zone(s) have no plottable X/Z coordinates.")
            return
        origin = (
            sum(coord[0] for coord in coords) / len(coords),
            sum(coord[1] for coord in coords) / len(coords),
        )
        state = self.territory_map_state
        state["edit_mode"] = "duplicate_zone"
        state["placement_source_path"] = ""
        state["placement_template"] = None
        state["placement_duplicate_indices"] = indices
        state["placement_duplicate_origin"] = origin
        self.set_territory_map_cursor()
        self.territory_map_status_var.set("Duplicate: click the map to place copied zone(s), Esc cancels.")
        self.log(f"Duplicate mode: placing {len(indices)} selected territory zone(s).", "muted")

    def place_territory_zone_at_canvas(self, canvas_x, canvas_y, radius=None):
        state = self.territory_map_state
        source_path = state.get("placement_source_path")
        template = state.get("placement_template") or {}
        if not source_path or not self.canvas_point_inside_territory_map(canvas_x, canvas_y):
            self.log("Click inside the map image to place a territory zone.", "warning")
            return
        map_width, map_height, _map_label = self.territory_map_dimensions_for_current_view()
        coord = self.territory_canvas_to_world(canvas_x, canvas_y, map_width, map_height)
        if coord is None:
            self.log("Could not resolve map coordinates for the new territory zone.", "warning")
            return
        radius = self.format_territory_radius(radius if radius is not None else self.territory_add_radius_value())
        self.territory_add_radius_var.set(radius)
        extra_attributes = {
            field: template.get(field)
            for field in ("smin", "smax")
            if template.get(field) is not None
        }
        old_zones = self.territory_zone_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        new_zone = self.make_territory_zone(
            source_path,
            template.get("name", self.default_territory_zone_name(source_path)),
            coord[0],
            coord[1],
            radius,
            template.get("dmin", "0"),
            template.get("dmax", "0"),
            extra_attributes=extra_attributes,
            group_index=int(template.get("_group_index", 0) or 0),
            group_name=template.get("_group_name", ""),
            group_attributes=template.get("_group_attributes", {}),
        )
        insert_at = self.insert_territory_zone_for_source(new_zone, source_path)
        self.push_territory_structure_undo(
            f"add zone {new_zone.name}",
            old_zones,
            self.territory_zones,
            [source_path],
            old_selected,
            [insert_at],
        )
        self.finish_territory_structure_edit([source_path], [insert_at], f"Added territory zone {new_zone.name}.", center_selected=False)
        self.territory_map_state["edit_mode"] = "add_zone"
        self.territory_map_state["placement_source_path"] = source_path
        self.territory_map_state["placement_template"] = template
        self.set_territory_map_cursor()
        self.territory_map_status_var.set("Add zone: click again to place another zone, drag to set radius, Esc cancels.")

    def place_duplicate_territory_zones_at_canvas(self, canvas_x, canvas_y):
        state = self.territory_map_state
        indices = [
            index for index in state.get("placement_duplicate_indices", [])
            if 0 <= index < len(self.territory_zones)
        ]
        origin = state.get("placement_duplicate_origin")
        if not indices or origin is None:
            return
        if not self.canvas_point_inside_territory_map(canvas_x, canvas_y):
            self.log("Click inside the map image to place duplicated territory zone(s).", "warning")
            return
        map_width, map_height, _map_label = self.territory_map_dimensions_for_current_view()
        target = self.territory_canvas_to_world(canvas_x, canvas_y, map_width, map_height)
        if target is None:
            self.log("Could not resolve map coordinates for duplicated territory zone(s).", "warning")
            return
        dx = target[0] - origin[0]
        dz = target[1] - origin[1]
        selected = set(indices)
        source_paths = {self.territory_zones[index].source_path for index in indices}
        old_zones = self.territory_zone_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        new_indices = []
        rebuilt = []
        for index, zone in enumerate(self.territory_zones):
            rebuilt.append(zone)
            if index not in selected:
                continue
            clone = zone.clone()
            coord = self.spawn_position_xy(clone)
            if coord is not None:
                clone.set_attribute("x", self.format_territory_coordinate(coord[0] + dx))
                clone.set_attribute("z", self.format_territory_coordinate(coord[1] + dz))
            rebuilt.append(clone)
            new_indices.append(len(rebuilt) - 1)
        self.territory_zones = rebuilt
        self.push_territory_structure_undo(
            f"duplicate {len(new_indices)} zone(s)",
            old_zones,
            self.territory_zones,
            source_paths,
            old_selected,
            new_indices,
        )
        self.finish_territory_structure_edit(source_paths, new_indices, f"Duplicated {len(new_indices)} territory zone(s).", center_selected=False)
        state["edit_mode"] = ""
        state["placement_duplicate_indices"] = []
        state["placement_duplicate_origin"] = None
        state["placement_preview"] = None
        self.clear_territory_placement_preview()
        self.set_territory_map_cursor()
        self.draw_territory_map()

    def delete_selected_territory_zones(self):
        if self.territory_map_state.get("edit_mode"):
            self.cancel_territory_map_edit_mode()
        indices = self.selected_territory_action_indices()
        if not indices:
            messagebox.showwarning(APP_TITLE, "Select one or more territory zones first.")
            return
        if not messagebox.askyesno(APP_TITLE, f"Delete {len(indices)} selected territory zone(s)?"):
            return
        delete_set = set(indices)
        source_paths = {self.territory_zones[index].source_path for index in indices}
        old_zones = self.territory_zone_snapshot()
        old_selected = sorted(self.selected_territory_indices)
        self.territory_zones = [
            zone for index, zone in enumerate(self.territory_zones) if index not in delete_set
        ]
        self.push_territory_structure_undo(
            f"delete {len(indices)} zone(s)",
            old_zones,
            self.territory_zones,
            source_paths,
            old_selected,
            [],
        )
        self.finish_territory_structure_edit(source_paths, [], f"Deleted {len(indices)} territory zone(s).")

    def clear_territory_selection(self, announce=True):
        self.selected_territory_indices.clear()
        self.clear_territory_detail()
        self.draw_territory_map()
        self.update_territory_group_tree_tags()
        if announce:
            self.log("Cleared territory selection.", "muted")

