        tk.Label(shell, text="Mouse actions are optimized for editing territories. Panning is deliberate: hold Alt.", bg=GRAPHITE_CARD, fg=GRAPHITE_MUTED, font=("Segoe UI", 9), wraplength=640, justify="left").pack(anchor="w", pady=(4, 14))

