        canvas.bind("<MouseWheel>", lambda event: canvas.yview_scroll(int(-1 * (event.delta / 120)), "units"))

        rows = [
            ("Click marker", "Select one zone"),
            ("Click empty map", "Clear selection"),
            ("Left-drag empty map", "Box-select visible zones"),
            ("Drag marker", "Move selected zone"),
            ("Ctrl + click marker", "Toggle zone selection"),
            ("Ctrl + drag marker", "Resize selected zone or selected group"),
            ("Drag square handle", "Resize selected zone"),
            ("Alt + drag", "Move the map view"),
            ("Mouse wheel", "Zoom map"),
            ("Add zone", "Enter placement mode; click map to place"),
            ("Add zone + drag", "Place and set radius from the drag distance"),
            ("Duplicate", "Enter placement mode for selected zone copies"),
            ("Esc", "Cancel Add/Duplicate placement mode"),
            ("Ctrl + Z / Ctrl + Y", "Undo / redo map edits"),
        ]
        for shortcut, description in rows:
            row = tk.Frame(rows_frame, bg=GRAPHITE_CARD)
