    def remove_selected_source(self):
        selected = list(self.source_listbox.curselection())
        if not selected:
            return
        for index in reversed(selected):
            del self.loaded_paths[index]
        if self.loaded_paths:
            self.reload_all()
        else:
            self.clear_files()

