    def validate_loaded_entries(self, entries=None, include_duplicates=True):
        return validate_entries(
            self.entries if entries is None else entries,
            include_duplicates=include_duplicates,
            relation_definitions=self.relation_definitions,
        )

    def merge_issue_layers(self):
        self.issues = list(self.validation_issues) + list(self.analysis_issues)

    def dedupe_issues(self, issues):
        seen = set()
        deduped = []
        for issue in issues:
            key = (
                issue.severity,
                issue.name.casefold(),
                issue.message,
                self.normalized_path(issue.source_path),
                issue.line,
                issue.column,
            )
            if key in seen:
                continue
            seen.add(key)
            deduped.append(issue)
        return deduped

    def path_is_in_profile_roots(self, path):
        if not path:
            return False
        for profile_root in self.profile_roots:
            try:
                Path(path).resolve().relative_to(Path(profile_root).resolve())
                return True
            except (OSError, ValueError):
                continue
        return False

    def issue_module_id(self, issue):
        source_path = issue.source_path or ""
        source_key = self.normalized_path(source_path) if source_path else ""
        ce_project = getattr(self, "ce_zones_project", None)
        if ce_project is not None and source_key:
            if self.normalized_path(ce_project.source_path) == source_key:
                return "ce_zones"
            if any(layer.image_path and self.normalized_path(layer.image_path) == source_key for layer in ce_project.layers):
                return "ce_zones"
        if source_key and source_key in {self.normalized_path(path) for path in self.profile_config_paths}:
            return "profiles"
        if source_path and self.path_is_in_profile_roots(source_path):
            return "profiles"
        if source_path:
            name = Path(source_path).name.casefold()
            suffix = Path(source_path).suffix.casefold()
            if self.is_weather_source_path(source_path) or name == "cfgweather.xml":
                return "weather"
            if self.is_economycore_source_path(source_path) or name == "cfgeconomycore.xml":
                return "economy_core"
            if self.is_mapgroupproto_source_path(source_path) or name == "mapgroupproto.xml":
                return "mapgroupproto"
            if name == "cfglimitsdefinition.xml":
                return "definitions"
            if name == "cfgspawnabletypes.xml":
                return "spawnabletypes"
            if name == "cfgrandompresets.xml":
                return "randompresets"
            if name in {"events.xml", "cfgeventspawns.xml", "cfgeventgroups.xml"}:
                return "events"
            if name == "cfgenvironment.xml":
                return "environment"
            if name.endswith("_territories.xml"):
                return "territories"
            if name == "areaflags.map" or suffix == ".tga":
                return "ce_zones"
            if suffix in {".json", ".cfg", ".c"}:
                return "profiles" if self.path_is_in_profile_roots(source_path) else "configs"
        if source_key in {self.normalized_path(path) for path in self.spawnable_source_paths()}:
            return "spawnabletypes"
        if source_key in {self.normalized_path(path) for path in self.random_preset_source_paths()}:
            return "randompresets"
        if source_key in {self.normalized_path(path) for path in self.event_source_paths() + self.event_spawn_source_paths() + self.event_group_source_paths()}:
            return "events"
        if source_key in {self.normalized_path(path) for path in self.territory_source_paths()}:
            return "territories"
        if source_key in {self.normalized_path(path) for path in self.loaded_paths}:
            return "types"
        if source_path and self.is_config_source_path(source_path):
            return "configs"
        if issue.name:
            return "types"
        if source_path:
            name = Path(source_path).name.casefold()
            suffix = Path(source_path).suffix.casefold()
            if suffix == ".xml":
                return "xml"
        return "workspace"

    def issue_module_label(self, issue_or_module):
        module_id = issue_or_module if isinstance(issue_or_module, str) else self.issue_module_id(issue_or_module)
        return {
            "types": "Types",
            "spawnabletypes": "Spawnabletypes",
            "randompresets": "Randompresets",
            "events": "Events",
            "environment": "Environment",
            "territories": "Territories",
            "ce_zones": "CE Zones",
            "mapgroupproto": "Mapgroupproto",
            "configs": "Configs",
            "profiles": "Profiles",
            "weather": "Weather",
            "definitions": "Definitions",
            "economy_core": "Economy Core",
            "xml": "XML syntax",
            "workspace": "Workspace",
        }.get(module_id, "Workspace")

    def issue_module_sort_key(self, module_id):
        order = {
            "types": 0,
            "spawnabletypes": 1,
            "randompresets": 2,
            "events": 3,
            "environment": 4,
            "territories": 5,
            "ce_zones": 6,
            "mapgroupproto": 7,
            "configs": 8,
            "profiles": 9,
            "weather": 10,
            "definitions": 11,
            "economy_core": 12,
            "xml": 13,
            "workspace": 14,
        }
        return order.get(module_id, 99)

    def issue_groups_by_module(self, issues):
        groups = {}
        for issue in issues:
            groups.setdefault(self.issue_module_id(issue), []).append(issue)
        return dict(sorted(groups.items(), key=lambda item: self.issue_module_sort_key(item[0])))

    def issue_counts_by_severity(self, issues):
        return {
            "error": sum(1 for issue in issues if issue.severity == "error"),
            "warning": sum(1 for issue in issues if issue.severity == "warning"),
            "info": sum(1 for issue in issues if issue.severity == "info"),
        }

    def issue_target(self, issue):
        source_path = issue.source_path or ""
        module_id = self.issue_module_id(issue)
        line = issue.line if issue.line is not None else None
        column = issue.column if issue.column is not None else None

        def source_target(kind: str, path: str):
            if line is None:
                return (kind, path)
            return (kind, path, line, column)

        if module_id == "events":
            return ("event", issue.name, source_path) if issue.name else ("event_source", source_path)
        if module_id == "environment":
            return ("module", "environment")
        if module_id == "territories":
            return ("territory_zone", issue.name, source_path) if issue.name and source_path else ("territory_source", source_path) if source_path else ("module", "territories")
        if module_id == "ce_zones":
            return ("ce_zone_layer", issue.name, source_path) if issue.name else ("ce_zones_source", source_path) if source_path else ("module", "ce_zones")
        if module_id == "mapgroupproto":
            return ("mapgroupproto_group", issue.name) if issue.name else ("module", "mapgroupproto")
        if module_id == "spawnabletypes":
            return ("spawnable", issue.name, source_path) if issue.name else ("spawnable_source", source_path)
        if module_id == "randompresets":
            return ("random_preset", issue.name, source_path) if issue.name else ("random_preset_source", source_path)
        if module_id == "configs":
            return source_target("config_source", source_path) if source_path else ("module", "configs")
        if module_id == "profiles":
            return source_target("profile_source", source_path) if source_path else ("module", "profiles")
        if module_id == "weather":
            return ("weather_source", source_path, issue.name) if source_path and issue.name else ("weather_source", source_path) if source_path else ("module", "weather")
        if module_id == "definitions":
            return ("module", "definitions")
        if module_id == "economy_core":
            return ("module", "economy_core")
        if module_id == "types":
            return ("entry", issue.name, source_path) if issue.name else source_target("source", source_path)
        if module_id == "xml" and source_path:
            if self.is_config_source_path(source_path):
                return source_target("config_source", source_path)
            return source_target("source", source_path)
        if module_id == "workspace":
            return ("module", "dashboard")
        if source_path:
            return ("source", source_path)
        return ("module", "dashboard")

    def issue_module_dashboard_target(self, module_id):
        return {
            "types": ("module", "types"),
            "spawnabletypes": ("module", "spawnabletypes"),
            "randompresets": ("module", "randompresets"),
            "events": ("module", "events"),
            "environment": ("module", "environment"),
            "territories": ("module", "territories"),
            "ce_zones": ("module", "ce_zones"),
            "mapgroupproto": ("module", "mapgroupproto"),
            "configs": ("module", "configs"),
            "profiles": ("module", "profiles"),
            "weather": ("module", "weather"),
            "definitions": ("module", "definitions"),
            "economy_core": ("module", "economy_core"),
            "xml": ("module", "dashboard"),
            "workspace": ("module", "dashboard"),
        }.get(module_id, ("module", "dashboard"))

    def set_validation_issues(self, issues, mode="XML validation"):
        self.validation_issues = self.dedupe_issues(issues)
        self.issue_mode = "Validation + economy analysis" if self.analysis_issues else mode
        self.merge_issue_layers()

    def set_analysis_issues(self, issues):
        self.analysis_issues = list(issues)
        self.issue_mode = "Validation + economy analysis" if self.validation_issues else "Economy analysis"
        self.merge_issue_layers()

    def clear_analysis_for_entries(self, names):
        keys = {name.casefold() for name in names if name}
        if not keys:
            return
        self.analysis_issues = [
            issue
            for issue in self.analysis_issues
            if not issue.name or issue.name.casefold() not in keys
        ]
        self.merge_issue_layers()

    def refresh_issues_view(self):
        self.log_issues()
        self.refresh_table()
        self.update_summary()

    def validate_current(self):
        if not self.loaded_paths and self.mission_workspace is None and not self.config_paths and not self.profile_config_paths:
            messagebox.showwarning(APP_TITLE, "Load a mission folder or at least one supported file first.")
            return
        if self.mission_workspace is not None:
            file_issues = validate_mission_workspace_xml(self.mission_workspace.root_path)
        else:
            file_issues = validate_xml_files(self.loaded_paths)
        self.event_issues = self.territory_issues + self.validate_event_relationships()
        self.spawnable_issues = validate_spawnable_type_references(self.spawnable_entries, self.entries)
        self.random_preset_issues = validate_random_preset_references(self.random_preset_entries, self.entries)
        weather_issues = self.current_weather_validation_issues() if self.weather_path else []
        mapgroupproto_issues = []
        if self.ensure_mapgroupproto_loaded():
            self.validate_mapgroupproto_current_text(show_success=False)
            mapgroupproto_issues = list(self.mapgroupproto_issues)
        self.set_validation_issues(file_issues + self.validate_loaded_entries() + self.spawnable_issues + self.random_preset_issues + self.event_issues + weather_issues + mapgroupproto_issues + self.validate_loaded_config_files(), mode="Workspace validation")
        self.last_workspace_validation_at = datetime.now()
        self.workspace_validation_stale = False
        kept = f" Kept {len(self.analysis_issues)} economy hint(s)." if self.analysis_issues else ""
        self.log(f"Workspace validation complete.{kept}", "success")
        self.refresh_spawnable_table()
        self.refresh_random_preset_table()
        self.refresh_event_table()
        self.refresh_issues_view()

    def analyze_current(self):
        if not self.loaded_paths:
            messagebox.showwarning(APP_TITLE, "Load at least one supported file first.")
            return
        if not self.entries:
            self.log("No type entries parsed. Fix XML syntax issues first.", "warning")
            self.log_issues()
            self.update_selected_issue_panel()
            return
        progress = ProgressWindow(self, "Analyzing Economy", "Analyzing economy entries...", maximum=4)
        self.set_status("Analyzing...", "warning")
        try:
            progress.update_progress(1, 4, detail=f"Preparing {len(self.entries)} type entries")
            self.update_idletasks()
            issues = analyze_economy(self.entries)
            progress.update_progress(2, 4, detail=f"Found {len(issues)} economy hint(s)")
            self.set_analysis_issues(issues)
            progress.update_progress(3, 4, detail="Refreshing issue views")
            self.log("Economy analysis complete.", "success")
            self.refresh_issues_view()
            progress.update_progress(4, 4, detail="Complete")
        finally:
            if progress.winfo_exists():
                progress.destroy()

    def log_issues(self):
        if not self.issues:
            self.log("No issues found.", "success")
            self.set_status("Clean", "success")
            return
        errors = sum(1 for issue in self.issues if issue.severity == "error")
        warnings = sum(1 for issue in self.issues if issue.severity == "warning")
        infos = sum(1 for issue in self.issues if issue.severity == "info")
        groups = self.issue_groups_by_module(self.issues)
        self.log("Validation summary by module:", "muted")
        for module_id, issues in groups.items():
            counts = self.issue_counts_by_severity(issues)
            parts = []
            if counts["error"]:
                parts.append(f"{counts['error']} error(s)")
            if counts["warning"]:
                parts.append(f"{counts['warning']} warning(s)")
            if counts["info"]:
                parts.append(f"{counts['info']} hint(s)")
            self.log(f"- {self.issue_module_label(module_id)}: {', '.join(parts) if parts else 'clean'}", "muted")

        rendered_count = 0
        omitted = 0
        for module_id, issues in groups.items():
            if rendered_count >= MAX_RENDERED_LOG_ISSUES:
                omitted += len(issues)
                continue
            self.log(f"{self.issue_module_label(module_id)} issues:", "muted")
            for issue in issues:
                if rendered_count >= MAX_RENDERED_LOG_ISSUES:
                    omitted += 1
                    continue
                tag = issue.severity if issue.severity in {"error", "warning", "info"} else "muted"
                source = f" [{os.path.basename(issue.source_path)}]" if issue.source_path else ""
                name = f"{issue.name}: " if issue.name else ""
                self.log(f"{issue.severity.upper()}: {name}{issue.message}{source}", tag)
                if issue.context:
                    self.log(issue.context, tag)
                rendered_count += 1
        if omitted:
            self.log(f"Omitted {omitted} additional issue log line(s). Select entries in the table to inspect their exact issues and hints.", "muted")
        if errors:
            self.set_status(f"{errors} error(s), {warnings} warning(s), {infos} hint(s)", "error")
        elif warnings:
            self.set_status(f"{warnings} warning(s), {infos} hint(s)", "warning")
        else:
            self.set_status(f"{infos} hint(s)", "success")

    def sort_type_entries(self, column):
        if self.type_sort_column == column:
            self.type_sort_reverse = not self.type_sort_reverse
        else:
            self.type_sort_column = column
            self.type_sort_reverse = False
        self.refresh_table()

    def update_type_sort_headings(self):
        labels = {
            "classname": ("#0", "Classname"),
            "source": ("source", "Source"),
            "nominal": ("nominal", "Nominal"),
            "min": ("min", "Min"),
            "links": ("links", "Links"),
        }
        arrow = " v" if self.type_sort_reverse else " ^"
        for column, (tree_column, label) in labels.items():
            text = label + (arrow if self.type_sort_column == column else "")
            self.tree.heading(tree_column, text=text, command=lambda sort_column=column: self.sort_type_entries(sort_column))

    def type_entry_sort_key(self, item):
        index, entry = item
        column = self.type_sort_column
        if column == "classname":
            return (entry.name.casefold(), index)
        if column == "source":
            return (self.source_display_name(entry.source_path).casefold(), entry.name.casefold(), index)
        if column in {"nominal", "min"}:
            value = parse_sort_int(entry.child_text(column))
            missing = value is None
            return (missing, value if value is not None else 0, entry.name.casefold(), index)
        if column == "links":
            return (self.type_link_label(entry).casefold(), entry.name.casefold(), index)
        return (entry.name.casefold(), index)

    def type_entry_flag_value(self, entry, flag):
        flags = entry.element.find("flags")
        return flags.attrib.get(flag, "") if flags is not None else ""

    def spawnable_entries_for_classname(self, classname, include_item_refs=True):
        key = str(classname or "").casefold()
        result = []
        for entry in self.spawnable_entries:
            if entry.name.casefold() == key:
                result.append(entry)
                continue
            if include_item_refs and key in {name.casefold() for name in entry.referenced_item_names()}:
                result.append(entry)
        return result

    def random_presets_for_classname(self, classname):
        key = str(classname or "").casefold()
        return [entry for entry in self.random_preset_entries if key in {name.casefold() for name in entry.referenced_item_names()}]

    def type_link_label(self, entry, spawnable_link_names=None, random_preset_link_names=None):
        links = []
        name_key = entry.name.casefold()
        if (spawnable_link_names is not None and name_key in spawnable_link_names) or (
            spawnable_link_names is None and self.spawnable_entries_for_classname(entry.name)
        ):
            links.append("Spawnabletype")
        if (random_preset_link_names is not None and name_key in random_preset_link_names) or (
            random_preset_link_names is None and self.random_presets_for_classname(entry.name)
        ):
            links.append("Randompreset")
        return ", ".join(links)

    def type_reference_name_sets(self):
        spawnable_names = set()
        for entry in self.spawnable_entries:
            spawnable_names.add(entry.name.casefold())
            spawnable_names.update(name.casefold() for name in entry.referenced_item_names())
        random_preset_names = set()
        for entry in self.random_preset_entries:
            random_preset_names.update(name.casefold() for name in entry.referenced_item_names())
        return spawnable_names, random_preset_names

    def type_entry_matches_view_filter(self, entry, view, duplicate_names, warning_or_error_names, info_names):
        name_key = entry.name.casefold()
        if view == "All":
            return True
        if view == "Duplicates":
            return name_key in duplicate_names
        if view == "Errors/Warnings":
            return name_key in warning_or_error_names
        if view == "Analysis hints":
            return name_key in info_names
        if view == "Missing category":
            return not entry.relation_names("category")
        if view == "Missing usage":
            return not entry.relation_names("usage")
        if view == "Missing value tier":
            return not entry.relation_names("value")
        if view.startswith("Flag "):
            try:
                flag_expression = view.removeprefix("Flag ")
                flag, expected = flag_expression.split("=", 1)
            except ValueError:
                return True
            return self.type_entry_flag_value(entry, flag) == expected
        return True

    def schedule_type_table_refresh(self, event=None):
        if self.type_search_after_id:
            self.after_cancel(self.type_search_after_id)
        self.type_search_after_id = self.after(120, self.refresh_table)

    def refresh_table(self):
        self.type_search_after_id = None
        self.update_type_sort_headings()
        search = self.search_var.get().strip().casefold()
        view = self.filter_var.get()
        selected_source_key = self.normalized_path(self.selected_source_path) if self.selected_source_path else ""
        usage_filter = self.active_usage_filter
        usage_kind = usage_filter[0] if usage_filter else ""
        usage_value = usage_filter[1].casefold() if usage_filter else ""
        duplicate_names = {name.casefold() for name in get_duplicate_groups(self.entries)}
        warning_or_error_names = {issue.name.casefold() for issue in self.issues if issue.severity in {"error", "warning"} and issue.name}
        error_names = {issue.name.casefold() for issue in self.issues if issue.severity == "error" and issue.name}
        warning_names = {issue.name.casefold() for issue in self.issues if issue.severity == "warning" and issue.name}
        info_names = {issue.name.casefold() for issue in self.issues if issue.severity == "info" and issue.name}
        spawnable_link_names, random_preset_link_names = self.type_reference_name_sets()

        self.rebuilding_table = True
        try:
            self.tree.delete(*self.tree.get_children())
            self.filtered_indices = []
            self.tree_iids = {}

            visible_entries = []
            for index, entry in enumerate(self.entries):
                if selected_source_key and self.normalized_path(entry.source_path) != selected_source_key:
                    continue
                if usage_filter and usage_value not in {name.casefold() for name in entry.relation_names(usage_kind)}:
                    continue
                if search and search not in entry.name.casefold() and search not in ",".join(entry.relation_names("category")).casefold():
                    continue
                if not self.type_entry_matches_view_filter(entry, view, duplicate_names, warning_or_error_names, info_names):
                    continue
                visible_entries.append((index, entry))

            for index, entry in sorted(visible_entries, key=self.type_entry_sort_key, reverse=self.type_sort_reverse):
                tag = ""
                if entry.name.casefold() in error_names:
                    tag = "error"
                elif entry.name.casefold() in warning_names:
                    tag = "warning"
                elif entry.name.casefold() in info_names:
                    tag = "info"
                elif entry.name.casefold() in duplicate_names:
                    tag = "duplicate"
                iid = str(index)
                self.tree.insert(
                    "",
                    "end",
                    iid=iid,
                    text=entry.name,
                    values=(
                        os.path.basename(entry.source_path),
                        entry.child_text("nominal"),
                        entry.child_text("min"),
                        self.type_link_label(entry, spawnable_link_names, random_preset_link_names),
                    ),
                    tags=(tag,) if tag else (),
                )
                self.filtered_indices.append(index)
                self.tree_iids[iid] = index
            if self.current_index is not None and str(self.current_index) in self.tree.get_children():
                self.tree.selection_set(str(self.current_index))
                self.tree.see(str(self.current_index))
        finally:
            self.rebuilding_table = False
        self.update_selected_issue_panel()

    def update_visible_tree_row(self, index):
        iid = str(index)
        if index is None or index >= len(self.entries) or iid not in self.tree.get_children():
            self.refresh_table()
            return
        entry = self.entries[index]
        duplicate_names = {name.casefold() for name in get_duplicate_groups(self.entries)}
        error_names = {issue.name.casefold() for issue in self.issues if issue.severity == "error" and issue.name}
        warning_names = {issue.name.casefold() for issue in self.issues if issue.severity == "warning" and issue.name}
        info_names = {issue.name.casefold() for issue in self.issues if issue.severity == "info" and issue.name}
        tag = ""
        if entry.name.casefold() in error_names:
            tag = "error"
        elif entry.name.casefold() in warning_names:
            tag = "warning"
        elif entry.name.casefold() in info_names:
            tag = "info"
        elif entry.name.casefold() in duplicate_names:
            tag = "duplicate"
        self.tree.item(
            iid,
            text=entry.name,
            values=(
                os.path.basename(entry.source_path),
                entry.child_text("nominal"),
                entry.child_text("min"),
                self.type_link_label(entry),
            ),
            tags=(tag,) if tag else (),
        )
        self.tree.selection_set(iid)
        self.tree.see(iid)
        self.update_selected_issue_panel()

    def on_tree_select(self, event=None):
        if self.rebuilding_table:
            return
        selected = self.tree.selection()
        if not selected:
            self.clear_editor()
            return
        self.current_index = self.tree_iids.get(selected[0])
        if self.current_index is None:
            self.clear_editor()
            return
        self.populate_editor(self.entries[self.current_index])

    def on_source_select(self, event=None):
        if self.rebuilding_sources:
            return
        selected = self.source_listbox.curselection()
        if not selected:
            self.selected_source_path = None
            self.refresh_table()
            self.update_summary()
            return
        self.selected_source_path = self.loaded_paths[selected[0]]
        self.tree.selection_remove(self.tree.selection())
        self.current_index = None
        for variable in self.editor_vars.values():
            variable.set("")
        for variable in self.flag_vars.values():
            variable.set(False)
        self.set_entry_xml_text("")
        self.clear_relation_editor()
        self.refresh_table()
        self.update_summary()
        self.update_selected_issue_panel()

    def populate_editor(self, entry: TypeEntry):
        self.editor_vars["name"].set(entry.name)
        self.editor_vars["source"].set(os.path.basename(entry.source_path))
        self.editor_vars["category"].set(", ".join(entry.relation_names("category")))
        for field in ("nominal", "lifetime", "restock", "min", "quantmin", "quantmax", "cost"):
            self.editor_vars[field].set(entry.child_text(field))
        self.populate_flag_editor(entry)
        self.set_entry_xml_text(format_entry_xml(entry))
        self.populate_relation_editor(entry)
        self.update_type_link_buttons(entry)
        self.update_selected_issue_panel()

    def clear_editor(self):
        self.current_index = None
        for variable in self.editor_vars.values():
            variable.set("")
        for variable in self.flag_vars.values():
            variable.set(False)
        self.set_entry_xml_text("")
        self.clear_relation_editor()
        self.update_type_link_buttons(None)
        self.update_selected_issue_panel()

    def update_type_link_buttons(self, entry):
        if not hasattr(self, "type_spawnable_button"):
            return
        if entry is None:
            self.type_spawnable_button.configure(text="Create spawnable", state="disabled")
            self.type_random_preset_button.configure(text="Create preset", state="disabled")
            return
        self.type_spawnable_button.configure(
            text="Show spawnable" if self.spawnable_entries_for_classname(entry.name) else "Create spawnable",
            state="normal",
        )
        self.type_random_preset_button.configure(
            text="Show preset" if self.random_presets_for_classname(entry.name) else "Create preset",
            state="normal",
        )

    def ensure_spawnable_source_path(self):
        paths = self.spawnable_source_paths()
        if paths:
            return paths[0]
        if self.mission_workspace is None:
            messagebox.showwarning(APP_TITLE, "Open a mission folder before creating cfgspawnabletypes.xml.")
            return ""
        path = str(Path(self.mission_workspace.root_path) / "db" / "cfgspawnabletypes.xml")
        if not self.create_missing_spawnable_source_file(path):
            return ""
        if path not in self.mission_workspace.spawnable_type_paths:
            self.mission_workspace.spawnable_type_paths.append(path)
        self.update_spawnable_summary()
        return path

    def ensure_random_preset_source_path(self):
        paths = self.random_preset_source_paths()
        if paths:
            return paths[0]
        if self.mission_workspace is None:
            messagebox.showwarning(APP_TITLE, "Open a mission folder before creating cfgrandompresets.xml.")
            return ""
        path = str(Path(self.mission_workspace.root_path) / "db" / "cfgrandompresets.xml")
        if not self.create_missing_random_preset_source_file(path):
            return ""
        if path not in self.mission_workspace.random_preset_paths:
            self.mission_workspace.random_preset_paths.append(path)
        self.update_random_preset_summary()
        return path

    def create_missing_spawnable_source_file(self, path):
        target = Path(path)
        if target.is_file():
            return True
        if target.exists():
            messagebox.showerror(APP_TITLE, f"Cannot create cfgspawnabletypes.xml because path exists and is not a file:\n{target}")
            return False
        if not messagebox.askyesno(APP_TITLE, f"No cfgspawnabletypes.xml source is loaded.\n\nCreate this file now?\n{target}"):
            return False
        try:
            target.parent.mkdir(parents=True, exist_ok=True)
            self.ensure_source_writable(target)
            write_spawnable_types_file([], target)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not create cfgspawnabletypes.xml:\n{exc}")
            return False
        self.log(f"Created cfgspawnabletypes.xml: {target}", "success")
        return True

    def create_missing_random_preset_source_file(self, path):
        target = Path(path)
        if target.is_file():
            return True
        if target.exists():
            messagebox.showerror(APP_TITLE, f"Cannot create cfgrandompresets.xml because path exists and is not a file:\n{target}")
            return False
        if not messagebox.askyesno(APP_TITLE, f"No cfgrandompresets.xml source is loaded.\n\nCreate this file now?\n{target}"):
            return False
        try:
            target.parent.mkdir(parents=True, exist_ok=True)
            self.ensure_source_writable(target)
            write_random_presets_file([], target)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not create cfgrandompresets.xml:\n{exc}")
            return False
        self.log(f"Created cfgrandompresets.xml: {target}", "success")
        return True

    def selected_type_entry(self):
        if self.current_index is None or not (0 <= self.current_index < len(self.entries)):
            messagebox.showwarning(APP_TITLE, "Select a type entry first.")
            return None
        return self.entries[self.current_index]

    def default_type_source_path(self):
        if self.selected_source_path:
            return self.selected_source_path
        if self.current_index is not None and 0 <= self.current_index < len(self.entries):
            return self.entries[self.current_index].source_path
        selected = self.source_listbox.curselection() if hasattr(self, "source_listbox") else ()
        if selected:
            return self.loaded_paths[selected[0]]
        if self.loaded_paths:
            return self.loaded_paths[0]
        messagebox.showwarning(APP_TITLE, "Load or select a types.xml source first.")
        return ""

    def type_source_index(self, source_path):
        source_key = self.normalized_path(source_path)
        for index, path in enumerate(self.loaded_paths):
            if self.normalized_path(path) == source_key:
                return index
        return 0

    def add_type_entry(self):
        source_path = self.default_type_source_path()
        if not source_path:
            return
        name = simpledialog.askstring(APP_TITLE, "New type classname:", parent=self)
        name = (name or "").strip()
        if not name:
            return
        element = ET.Element("type", {"name": name})
        for tag, value in (
            ("nominal", "0"),
            ("lifetime", "7200"),
            ("restock", "0"),
            ("min", "0"),
            ("quantmin", "-1"),
            ("quantmax", "-1"),
            ("cost", "100"),
        ):
            ET.SubElement(element, tag).text = value
        ET.SubElement(
            element,
            "flags",
            {
                "count_in_cargo": "0",
                "count_in_hoarder": "0",
                "count_in_map": "1",
                "count_in_player": "0",
                "crafted": "0",
                "deloot": "0",
            },
        )
        order_type_entry_children(element)
        entry = TypeEntry(name=name, element=element, source_path=source_path, source_index=self.type_source_index(source_path))
        self.entries.append(entry)
        self.current_index = len(self.entries) - 1
        self.selected_source_path = source_path
        self.mark_source_dirty(source_path)
        self.refresh_table()
        self.populate_editor(entry)
        self.schedule_validation_refresh(delay=1500)
        self.log(f"Added type entry: {name}", "success")

    def delete_selected_type_entries(self):
        if self.tree is None:
            return
        selected_indices = sorted(
            {
                self.tree_iids[iid]
                for iid in self.tree.selection()
                if iid in self.tree_iids and 0 <= self.tree_iids[iid] < len(self.entries)
            },
            reverse=True,
        )
        if not selected_indices and self.current_index is not None and 0 <= self.current_index < len(self.entries):
            selected_indices = [self.current_index]
        if not selected_indices:
            messagebox.showwarning(APP_TITLE, "Select type entry/entries first.")
            return
        names = [self.entries[index].name for index in selected_indices]
        if not messagebox.askyesno(APP_TITLE, f"Delete {len(selected_indices)} type entr{'y' if len(selected_indices) == 1 else 'ies'}?\n\n" + "\n".join(names[:12]) + ("\n..." if len(names) > 12 else "")):
            return
        dirty_paths = set()
        for index in selected_indices:
            dirty_paths.add(self.entries[index].source_path)
            del self.entries[index]
        for path in dirty_paths:
            self.mark_source_dirty(path)
        self.current_index = None
        self.clear_editor()
        self.refresh_table()
        self.schedule_validation_refresh(delay=1500)
        self.log(f"Deleted {len(selected_indices)} type entr{'y' if len(selected_indices) == 1 else 'ies'}.", "success")

    def create_or_show_spawnable_for_selected_type(self):
        entry = self.selected_type_entry()
        if entry is None:
            return
        linked = self.spawnable_entries_for_classname(entry.name)
        if linked:
            self.select_spawnable_entry(linked[0])
            return
        source_path = self.ensure_spawnable_source_path()
        if not source_path:
            return
        element = ET.Element("type", {"name": entry.name})
        spawnable = SpawnableTypeEntry(name=entry.name, element=element, source_path=source_path, source_index=max(0, len(self.spawnable_source_paths()) - 1))
        self.spawnable_entries.append(spawnable)
        self.mark_source_dirty(source_path)
        self.spawnable_issues = validate_spawnable_type_references(self.spawnable_entries, self.entries)
        file_issues = [issue for issue in self.validation_issues if not issue.name]
        self.set_validation_issues(file_issues + self.validate_loaded_entries() + self.spawnable_issues + self.random_preset_issues + self.event_issues, mode=self.issue_mode)
        self.refresh_spawnable_table()
        self.refresh_table()
        self.update_type_link_buttons(entry)
        self.select_spawnable_entry(spawnable)
        self.log(f"Created spawnabletype entry for {entry.name}.", "success")

    def create_or_show_random_preset_for_selected_type(self):
        entry = self.selected_type_entry()
        if entry is None:
            return
        linked = self.random_presets_for_classname(entry.name)
        if linked:
            self.select_random_preset_entry(linked[0])
            return
        source_path = self.ensure_random_preset_source_path()
        if not source_path:
            return
        element = ET.Element("cargo", {"name": entry.name, "chance": "1.00"})
        ET.SubElement(element, "item", {"name": entry.name, "chance": "1.00"})
        preset = RandomPresetEntry(
            name=entry.name,
            kind="cargo",
            attributes={str(key): str(value) for key, value in element.attrib.items()},
            items=[
                RandomPresetItem(
                    name=entry.name,
                    attributes={"name": entry.name, "chance": "1.00"},
                    element=copy.deepcopy(element.find("item")),
                )
            ],
            element=element,
            source_path=source_path,
            source_index=max(0, len(self.random_preset_source_paths()) - 1),
        )
        self.random_preset_entries.append(preset)
        self.mark_source_dirty(source_path)
        self.random_preset_issues = validate_random_preset_references(self.random_preset_entries, self.entries)
        file_issues = [issue for issue in self.validation_issues if not issue.name]
        self.set_validation_issues(file_issues + self.validate_loaded_entries() + self.spawnable_issues + self.random_preset_issues + self.event_issues, mode=self.issue_mode)
        self.refresh_random_preset_table()
        self.refresh_table()
        self.update_type_link_buttons(entry)
        self.select_random_preset_entry(preset)
        self.log(f"Created randompreset entry for {entry.name}.", "success")

    def references_for_type_name(self, classname):
        key = str(classname or "").casefold()
        references = []
        if not key:
            return references
        for entry in self.spawnable_entries:
            item_names = {name.casefold() for name in entry.referenced_item_names()}
            if entry.name.casefold() == key:
                references.append(("Spawnabletypes", "Parent type", entry.name, entry.source_path, lambda item=entry: self.select_spawnable_entry(item)))
            if key in item_names:
                references.append(("Spawnabletypes", "Cargo/attachment item", entry.name, entry.source_path, lambda item=entry: self.select_spawnable_entry(item)))
        for entry in self.random_preset_entries:
            item_names = {name.casefold() for name in entry.referenced_item_names()}
            if entry.name.casefold() == key:
                references.append(("Randompresets", "Preset name", entry.name, entry.source_path, lambda item=entry: self.select_random_preset_entry(item)))
            if key in item_names:
                references.append(("Randompresets", "Preset item", entry.name, entry.source_path, lambda item=entry: self.select_random_preset_entry(item)))
        return references

    def open_type_references_window(self):
        entry = self.selected_type_entry()
        if entry is None:
            return
        references = self.references_for_type_name(entry.name)
        window = tk.Toplevel(self)
        window.title(f"References: {entry.name}")
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)
        frame = ttk.Frame(window, padding=12)
        frame.pack(fill="both", expand=True)
        ttk.Label(
            frame,
            text=f"{entry.name}: {len(references)} linked reference(s) in loaded Spawnabletypes/Randompresets.",
            style="FieldMuted.TLabel",
        ).grid(row=0, column=0, sticky="w", pady=(0, 8))
        columns = ("module", "relation", "entry", "source")
        tree = ttk.Treeview(frame, columns=columns, show="headings", height=14, style="Economy.Treeview")
        for column, label, width in (
            ("module", "Module", 130),
            ("relation", "Relation", 170),
            ("entry", "Entry", 320),
            ("source", "Source", 420),
        ):
            tree.heading(column, text=label)
            tree.column(column, width=width, anchor="w")
        tree.grid(row=1, column=0, sticky="nsew")
        frame.rowconfigure(1, weight=1)
        frame.columnconfigure(0, weight=1)
        scrollbar = ttk.Scrollbar(frame, command=tree.yview)
        scrollbar.grid(row=1, column=1, sticky="ns")
        x_scrollbar = ttk.Scrollbar(frame, command=tree.xview, orient="horizontal")
        x_scrollbar.grid(row=2, column=0, sticky="ew")
        tree.configure(yscrollcommand=scrollbar.set, xscrollcommand=x_scrollbar.set)
        callbacks = {}
        for index, (module, relation, target_name, source_path, callback) in enumerate(references):
            iid = f"ref-{index}"
            tree.insert("", "end", iid=iid, values=(module, relation, target_name, self.source_display_name(source_path)))
            callbacks[iid] = callback
        if not references:
            tree.insert("", "end", values=("None", "-", "No loaded references found", ""))

        def open_selected():
            selected = tree.selection()
            if not selected:
                return
            callback = callbacks.get(selected[0])
            if callback is None:
                return
            window.destroy()
            callback()

        tree.bind("<Double-Button-1>", lambda _event: open_selected())
        actions = ttk.Frame(frame)
        actions.grid(row=3, column=0, columnspan=2, sticky="e", pady=(10, 0))
        self.make_button(actions, "Close", window.destroy)
        self.make_button(actions, "Open selected", open_selected, variant="action")
        window.geometry("900x430")
        window.after(20, lambda: center_window(window, self))

    def choose_reference_name(self, title, label, names):
        clean_names = sorted({name for name in names if name}, key=str.casefold)
        if not clean_names:
            return ""
        if len(clean_names) == 1:
            return clean_names[0]
        result = self.prompt_name_chance(title, label, clean_names[0], "", include_chance=False, name_values=clean_names, name_readonly=True)
        return result[0] if result else ""

    def open_selected_spawnable_type_reference(self):
        if self.current_spawnable_index is None or not (0 <= self.current_spawnable_index < len(self.spawnable_entries)):
            messagebox.showwarning(APP_TITLE, "Select a spawnabletype entry first.")
            return
        entry = self.spawnable_entries[self.current_spawnable_index]
        block = self.selected_spawnable_block()
        if block is not None:
            names = [item.attrib.get("name", "").strip() for item in block.findall("item")]
            target_name = self.choose_reference_name("Open item type", "Item classname", names)
        else:
            target_name = entry.name
        if not target_name:
            messagebox.showwarning(APP_TITLE, "Selected block has no item reference.")
            return
        self.select_type_entry_by_name(target_name)

    def open_selected_spawnable_preset_reference(self):
        block = self.selected_spawnable_block()
        if block is None:
            messagebox.showwarning(APP_TITLE, "Select a cargo or attachments block first.")
            return
        preset_name = block.attrib.get("preset", "").strip()
        if not preset_name:
            messagebox.showwarning(APP_TITLE, "Selected block has no preset reference.")
            return
        self.select_random_preset_entry_by_name(preset_name)

    def open_selected_random_preset_item_type(self):
        entry = self.selected_random_preset_entry()
        if entry is None:
            messagebox.showwarning(APP_TITLE, "Select a randompreset first.")
            return
        indices = self.selected_random_preset_item_indices()
        items = entry.element.findall("item")
        if not indices and len(items) == 1:
            indices = [0]
        if len(indices) != 1:
            messagebox.showwarning(APP_TITLE, "Select one preset item first.")
            return
        name = items[indices[0]].attrib.get("name", "").strip()
        if not name:
            return
        self.select_type_entry_by_name(name)

    def open_random_preset_usage_reference(self):
        entry = self.selected_random_preset_entry()
        if entry is None:
            messagebox.showwarning(APP_TITLE, "Select a randompreset first.")
            return
        key = entry.name.casefold()
        matches = [spawnable for spawnable in self.spawnable_entries if key in {name.casefold() for name in spawnable.preset_names()}]
        if not matches:
            messagebox.showinfo(APP_TITLE, "No loaded spawnabletype uses this preset.", parent=self)
            return
        self.select_spawnable_entry(matches[0])

    def select_spawnable_entry(self, target):
        try:
            index = self.spawnable_entries.index(target)
        except ValueError:
            target_key = (target.name.casefold(), self.normalized_path(target.source_path))
            index = next(
                (
                    item_index
                    for item_index, entry in enumerate(self.spawnable_entries)
                    if (entry.name.casefold(), self.normalized_path(entry.source_path)) == target_key
                ),
                None,
            )
        if index is None:
            return
        self.switch_module("spawnabletypes")
        self.refresh_spawnable_table()
        iid = f"spawnable-{index}"
        if self.spawnable_tree is not None and iid in self.spawnable_tree.get_children():
            self.spawnable_tree.selection_set(iid)
            self.spawnable_tree.see(iid)
        self.populate_spawnable_detail(index)

    def select_random_preset_entry(self, target):
        try:
            index = self.random_preset_entries.index(target)
        except ValueError:
            target_key = (target.name.casefold(), self.normalized_path(target.source_path))
            index = next(
                (
                    item_index
                    for item_index, entry in enumerate(self.random_preset_entries)
                    if (entry.name.casefold(), self.normalized_path(entry.source_path)) == target_key
                ),
                None,
            )
        if index is None:
            return
        self.switch_module("randompresets")
        self.refresh_random_preset_table()
        iid = f"random-preset-{index}"
        if self.random_preset_tree is not None and iid in self.random_preset_tree.get_children():
            self.random_preset_tree.selection_set(iid)
            self.random_preset_tree.see(iid)
        self.populate_random_preset_detail(index)

    def populate_flag_editor(self, entry):
        flags = entry.element.find("flags")
        for field, variable in self.flag_vars.items():
            variable.set(flags is not None and flags.attrib.get(field) == "1")

    def apply_flag_editor(self, entry):
        flags = entry.element.find("flags")
        if flags is None:
            flags = entry.element.makeelement("flags", {})
            insert_at = 0
            for index, child in enumerate(list(entry.element)):
                if child.tag in {"category", "usage", "value", "tag"}:
                    break
                insert_at = index + 1
            entry.element.insert(insert_at, flags)
        for field, variable in self.flag_vars.items():
            flags.attrib[field] = "1" if variable.get() else "0"
        order_type_entry_children(entry.element)

    def set_entry_xml_text(self, text: str):
        if not hasattr(self, "entry_xml_text"):
            return
        self.entry_xml_text.delete("1.0", "end")
        if text:
            self.entry_xml_text.insert("1.0", text)
        self.apply_xml_highlighting()

    def get_entry_xml_text(self) -> str:
        if not hasattr(self, "entry_xml_text"):
            return ""
        return self.entry_xml_text.get("1.0", "end").strip()

    def raw_xml_editor_changed(self, entry):
        return bool(self.get_entry_xml_text()) and self.get_entry_xml_text() != format_entry_xml(entry).strip()

    def clear_relation_editor(self):
        if not hasattr(self, "relation_tree"):
            return
        self.relation_tree.delete(*self.relation_tree.get_children())
        self.relation_iids = {}
        for variable in self.relation_value_vars.values():
            variable.set("")
        self.update_relation_value_options()

    def populate_relation_editor(self, entry):
        if not hasattr(self, "relation_tree"):
            return
        self.relation_tree.delete(*self.relation_tree.get_children())
        self.relation_iids = {}
        occurrence_counts = {field: 0 for field in RELATION_FIELDS}
        for child_index, child in enumerate(entry.element):
            if child.tag not in RELATION_FIELDS:
                continue
            name = child.attrib.get("name", "").strip()
            if not name:
                continue
            occurrence = occurrence_counts[child.tag]
            occurrence_counts[child.tag] += 1
            iid = f"relation-{child_index}"
            self.relation_tree.insert("", "end", iid=iid, values=(child.tag, name))
            self.relation_iids[iid] = (child.tag, occurrence)
        self.update_relation_value_options(entry)

    def update_relation_value_options(self, entry=None):
        if not hasattr(self, "relation_value_combos"):
            return
        for kind in RELATION_FIELDS:
            values = set(self.relation_definitions.get(kind, []))
            if entry is not None:
                values.update(entry.relation_names(kind))
            options = sorted(values, key=str.casefold)
            combo = self.relation_value_combos.get(kind)
            if combo is not None:
                combo.configure(values=options)
            current = self.relation_value_vars[kind].get().strip()
            if current and current in options:
                continue
            self.relation_value_vars[kind].set(options[0] if options else "")

    def apply_relation_editor_change(self, entry, message):
        entry_key = entry.name.casefold()
        self.clear_analysis_for_entries([entry.name])
        self.validation_issues = [
            issue
            for issue in self.validation_issues
            if not issue.name or issue.name.casefold() != entry_key
        ]
        self.validation_issues.extend(self.validate_loaded_entries([entry], include_duplicates=False))
        self.issue_mode = "Validation + economy analysis" if self.analysis_issues else "XML validation"
        self.merge_issue_layers()
        self.keep_entry_visible_after_apply(entry)
        self.update_visible_tree_row(self.current_index)
        self.populate_editor(entry)
        self.update_summary()
        self.mark_source_dirty(entry.source_path)
        self.log(message, "success")

    def add_relation_from_row(self, kind):
        if self.current_index is None:
            messagebox.showwarning(APP_TITLE, "Select a type entry first.")
            return
        entry = self.entries[self.current_index]
        if self.raw_xml_editor_changed(entry):
            messagebox.showwarning(APP_TITLE, "Apply the full XML changes first, then use relation buttons.")
            return
        if kind not in RELATION_FIELDS:
            return
        value = self.relation_value_vars[kind].get().strip()
        if not value:
            messagebox.showwarning(APP_TITLE, f"Choose or type a {kind} name first.")
            return
        current_names = entry.relation_names(kind)
        if value.casefold() in {name.casefold() for name in current_names}:
            self.log(f"{entry.name} already has {kind} {value}.", "warning")
            return
        entry.set_relation_names_preserve_order(kind, current_names + [value])
        self.apply_relation_editor_change(entry, f"Added {kind} {value} to {entry.name}.")

    def remove_relation_from_row(self, kind):
        if self.current_index is None:
            messagebox.showwarning(APP_TITLE, "Select a type entry first.")
            return
        entry = self.entries[self.current_index]
        if self.raw_xml_editor_changed(entry):
            messagebox.showwarning(APP_TITLE, "Apply the full XML changes first, then use relation buttons.")
            return
        if kind not in RELATION_FIELDS:
            return
        value = self.relation_value_vars[kind].get().strip()
        if not value:
            messagebox.showwarning(APP_TITLE, f"Choose or type a {kind} name to remove.")
            return
        names = entry.relation_names(kind)
        filtered = [name for name in names if name.casefold() != value.casefold()]
        if len(filtered) == len(names):
            self.log(f"{entry.name} does not have {kind} {value}.", "warning")
            return
        entry.set_relation_names_preserve_order(kind, filtered)
        self.apply_relation_editor_change(entry, f"Removed {kind} {value} from {entry.name}.")

    def keep_entry_visible_after_apply(self, entry):
        try:
            self.current_index = self.entries.index(entry)
        except ValueError:
            self.current_index = None

        if self.selected_source_path and self.normalized_path(entry.source_path) != self.normalized_path(self.selected_source_path):
            self.selected_source_path = None
            self.source_listbox.selection_clear(0, "end")

        search = self.search_var.get().strip().casefold()
        categories = ",".join(entry.relation_names("category")).casefold()
        if search and search not in entry.name.casefold() and search not in categories:
            self.search_var.set("")

    def configure_xml_highlighting(self):
        self.configure_xml_tags(self.entry_xml_text)
        self.entry_xml_text.bind("<KeyRelease>", self.schedule_xml_highlighting, add="+")

    def configure_xml_tags(self, widget):
        widget.tag_configure("xml_comment", foreground=GRAPHITE_MUTED)
        widget.tag_configure("xml_tag", foreground=GRAPHITE_ACCENT_HOVER)
        widget.tag_configure("xml_name", foreground=GRAPHITE_TEXT)
        widget.tag_configure("xml_attr", foreground=GRAPHITE_WARNING)
        widget.tag_configure("xml_string", foreground=GRAPHITE_SUCCESS)

    def configure_config_tags(self, widget):
        self.configure_xml_tags(widget)
        widget.tag_configure("cfg_comment", foreground=GRAPHITE_MUTED)
        widget.tag_configure("cfg_keyword", foreground=GRAPHITE_ACCENT_HOVER)
        widget.tag_configure("cfg_name", foreground=GRAPHITE_WARNING)
        widget.tag_configure("cfg_string", foreground=GRAPHITE_SUCCESS)
        widget.tag_configure("cfg_number", foreground=GRAPHITE_PREFLIGHT_HOVER)
        widget.tag_configure("c_preprocessor", foreground=GRAPHITE_WARNING)
        widget.tag_configure("c_function", foreground=GRAPHITE_PREFLIGHT_HOVER)
        widget.tag_configure("json_key", foreground=GRAPHITE_WARNING)
        widget.tag_configure("json_string", foreground=GRAPHITE_SUCCESS)
        widget.tag_configure("json_number", foreground=GRAPHITE_PREFLIGHT_HOVER)
        widget.tag_configure("json_literal", foreground=GRAPHITE_ACCENT_HOVER)

    def config_highlight_tags(self):
        return (
            "xml_comment",
            "xml_tag",
            "xml_name",
            "xml_attr",
            "xml_string",
            "cfg_comment",
            "cfg_keyword",
            "cfg_name",
            "cfg_string",
            "cfg_number",
            "c_preprocessor",
            "c_function",
            "json_key",
            "json_string",
            "json_number",
            "json_literal",
        )

    def clear_config_highlighting(self, widget):
        for tag in self.config_highlight_tags():
            widget.tag_remove(tag, "1.0", "end")

    def schedule_config_highlighting(self, event=None, delay=120):
        if self.config_highlight_after_id:
            try:
                self.after_cancel(self.config_highlight_after_id)
            except tk.TclError:
                pass
        self.config_highlight_after_id = self.after(delay, self.apply_config_highlighting)

    def apply_config_highlighting(self):
        self.config_highlight_after_id = None
        if self.config_editor_text is None:
            return
        path = self.selected_config_path or ""
        self.apply_config_highlighting_to_editor(self.config_editor_text, path, self.set_config_validation_message)

    def schedule_profile_config_highlighting(self, event=None, delay=120):
        if self.profile_config_highlight_after_id:
            try:
                self.after_cancel(self.profile_config_highlight_after_id)
            except tk.TclError:
                pass
        self.profile_config_highlight_after_id = self.after(delay, self.apply_profile_config_highlighting)

    def apply_profile_config_highlighting(self):
        self.profile_config_highlight_after_id = None
        if self.profile_config_editor_text is None:
            return
        path = self.selected_profile_config_path or ""
        self.apply_config_highlighting_to_editor(self.profile_config_editor_text, path, self.set_profile_config_validation_message)

    def apply_config_highlighting_to_editor(self, widget, path, message_callback):
        suffix = Path(path).suffix.casefold()
        self.clear_config_highlighting(widget)
        text_length = len(widget.get("1.0", "end-1c"))
        if text_length > CONFIG_HIGHLIGHT_MAX_CHARS:
            message_callback("Large file loaded. Syntax highlighting is skipped for responsiveness; use Validate to check syntax.", "muted")
            return
        if suffix == ".xml":
            self.apply_xml_highlighting_to_widget(widget)
        elif suffix == ".json":
            self.apply_json_highlighting_to_widget(widget)
        elif suffix == ".c":
            self.apply_c_highlighting_to_widget(widget)
        else:
            self.apply_cfg_highlighting_to_widget(widget)

    def add_text_tag_by_offsets(self, widget, tag, start, end):
        widget.tag_add(tag, f"1.0+{start}c", f"1.0+{end}c")

    def apply_json_highlighting_to_widget(self, widget):
        text = widget.get("1.0", "end-1c")
        string_pattern = r'"(?:\\.|[^"\\])*"'
        for match in re.finditer(string_pattern, text):
            after = text[match.end() : match.end() + 32]
            tag = "json_key" if re.match(r"\s*:", after) else "json_string"
            self.add_text_tag_by_offsets(widget, tag, match.start(), match.end())
        for match in re.finditer(r"(?<![\w.])-?(?:0|[1-9]\d*)(?:\.\d+)?(?:[eE][+-]?\d+)?(?![\w.])", text):
            self.add_text_tag_by_offsets(widget, "json_number", match.start(), match.end())
        for match in re.finditer(r"\b(?:true|false|null)\b", text):
            self.add_text_tag_by_offsets(widget, "json_literal", match.start(), match.end())
        for tag in ("json_key", "json_string", "json_number", "json_literal"):
            widget.tag_raise(tag)

    def apply_cfg_highlighting_to_widget(self, widget):
        text = widget.get("1.0", "end-1c")
        comment_spans = []
        for pattern, flags in (
            (r"//.*?$", re.MULTILINE),
            (r"#.*?$", re.MULTILINE),
            (r"/\*.*?\*/", re.MULTILINE | re.DOTALL),
        ):
            for match in re.finditer(pattern, text, flags):
                comment_spans.append((match.start(), match.end()))
                self.add_text_tag_by_offsets(widget, "cfg_comment", match.start(), match.end())

        def in_comment(start, end):
            return any(start >= comment_start and end <= comment_end for comment_start, comment_end in comment_spans)

        for match in re.finditer(r'"(?:\\.|[^"\\])*"|\'(?:\\.|[^\'\\])*\'', text):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "cfg_string", match.start(), match.end())
        for match in re.finditer(r"\b(?:class|enum|modded|static|private|protected|public|override|const|true|false)\b", text):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "cfg_keyword", match.start(), match.end())
        for match in re.finditer(r"\b([A-Za-z_][\w]*)\s*(?==)", text):
            if not in_comment(match.start(1), match.end(1)):
                self.add_text_tag_by_offsets(widget, "cfg_name", match.start(1), match.end(1))
        for match in re.finditer(r"(?<![\w.])-?(?:0x[0-9A-Fa-f]+|\d+(?:\.\d+)?)(?![\w.])", text):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "cfg_number", match.start(), match.end())
        for tag in ("cfg_keyword", "cfg_name", "cfg_string", "cfg_number", "cfg_comment"):
            widget.tag_raise(tag)

    def apply_c_highlighting_to_widget(self, widget):
        text = widget.get("1.0", "end-1c")
        comment_spans = []
        for pattern, flags in (
            (r"//.*?$", re.MULTILINE),
            (r"/\*.*?\*/", re.MULTILINE | re.DOTALL),
        ):
            for match in re.finditer(pattern, text, flags):
                comment_spans.append((match.start(), match.end()))
                self.add_text_tag_by_offsets(widget, "cfg_comment", match.start(), match.end())

        def in_comment(start, end):
            return any(start >= comment_start and end <= comment_end for comment_start, comment_end in comment_spans)

        for match in re.finditer(r"^\s*#\s*[A-Za-z_]\w*", text, re.MULTILINE):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "c_preprocessor", match.start(), match.end())
        for match in re.finditer(r'"(?:\\.|[^"\\])*"|\'(?:\\.|[^\'\\])*\'', text):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "cfg_string", match.start(), match.end())
        for match in re.finditer(r"\b(?:auto|bool|break|case|class|const|continue|default|delete|do|else|enum|extern|false|float|for|if|int|long|modded|new|null|override|private|protected|public|return|static|string|struct|switch|true|typedef|typename|void|while)\b", text):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "cfg_keyword", match.start(), match.end())
        for match in re.finditer(r"\b([A-Za-z_]\w*)\s*(?=\()", text):
            if not in_comment(match.start(1), match.end(1)):
                self.add_text_tag_by_offsets(widget, "c_function", match.start(1), match.end(1))
        for match in re.finditer(r"(?<![\w.])-?(?:0x[0-9A-Fa-f]+|\d+(?:\.\d+)?f?)(?![\w.])", text):
            if not in_comment(match.start(), match.end()):
                self.add_text_tag_by_offsets(widget, "cfg_number", match.start(), match.end())
        for tag in ("cfg_keyword", "c_function", "cfg_string", "cfg_number", "c_preprocessor", "cfg_comment"):
            widget.tag_raise(tag)

    def schedule_xml_highlighting(self, event=None):
        if self.xml_highlight_after_id:
            try:
                self.after_cancel(self.xml_highlight_after_id)
            except tk.TclError:
                pass
        self.xml_highlight_after_id = self.after(120, self.apply_xml_highlighting)

    def apply_xml_highlighting(self):
        if not hasattr(self, "entry_xml_text"):
            return
        self.xml_highlight_after_id = None
        self.apply_xml_highlighting_to_widget(self.entry_xml_text)

    def apply_xml_highlighting_to_widget(self, widget):
        text = widget.get("1.0", "end-1c")
        for tag in ("xml_comment", "xml_tag", "xml_name", "xml_attr", "xml_string"):
            widget.tag_remove(tag, "1.0", "end")

        def index(offset):
            return f"1.0+{offset}c"

        def add_tag(tag, start, end):
            widget.tag_add(tag, index(start), index(end))

        comment_spans = [(match.start(), match.end()) for match in re.finditer(r"<!--.*?-->", text, re.DOTALL)]
        for start, end in comment_spans:
            add_tag("xml_comment", start, end)

        def inside_comment(start, end):
            return any(start >= comment_start and end <= comment_end for comment_start, comment_end in comment_spans)

        for match in re.finditer(r"<[^>]+>", text):
            if inside_comment(match.start(), match.end()):
                continue
            tag_text = match.group(0)
            base = match.start()
            add_tag("xml_tag", match.start(), match.end())

            name_match = re.match(r"</?\s*([A-Za-z_][\w:.-]*)", tag_text)
            if name_match:
                add_tag("xml_name", base + name_match.start(1), base + name_match.end(1))

            for attr_match in re.finditer(r"\s([A-Za-z_][\w:.-]*)\s*=", tag_text):
                add_tag("xml_attr", base + attr_match.start(1), base + attr_match.end(1))
            for string_match in re.finditer(r'"[^"]*"|\'[^\']*\'', tag_text):
                add_tag("xml_string", base + string_match.start(), base + string_match.end())

        for tag in ("xml_tag", "xml_name", "xml_attr", "xml_string", "xml_comment"):
            widget.tag_raise(tag)

    def get_selected_issues(self):
        if self.current_index is None or self.current_index >= len(self.entries):
            return []
        name = self.entries[self.current_index].name.casefold()
        return [issue for issue in self.issues if issue.name.casefold() == name]

    def get_selected_source_issues(self):
        selected = self.source_listbox.curselection()
        if not selected:
            return []
        source_path = self.loaded_paths[selected[0]]
        source_key = self.normalized_path(source_path)
        return [
            issue
            for issue in self.issues
            if issue.source_path and self.normalized_path(issue.source_path) == source_key and not issue.name
        ]

    def render_issue_panel(self, issues, empty_message):
        if not issues:
            self.selected_issue_text.insert("end", empty_message, "success")
            return

        for index, issue in enumerate(issues):
            if index:
                self.selected_issue_text.insert("end", "\n\n")
            label = issue.severity.upper()
            tag = issue.severity if issue.severity in {"error", "warning", "info"} else "muted"
            self.selected_issue_text.insert("end", f"{label}: ", tag)
            self.selected_issue_text.insert("end", issue.message)
            if issue.line is not None:
                self.selected_issue_text.insert("end", f"\nLocation: line {issue.line}, column {issue.column if issue.column is not None else '-'}", "muted")
            if issue.context:
                self.selected_issue_text.insert("end", "\n\n")
                self.selected_issue_text.insert("end", issue.context, tag)
            if issue.suggestion:
                self.selected_issue_text.insert("end", "\nFix / hint: ", "suggestion")
                self.selected_issue_text.insert("end", issue.suggestion)

    def update_selected_issue_panel(self):
        if not hasattr(self, "selected_issue_text"):
            return
        self.selected_issue_text.configure(state="normal")
        self.selected_issue_text.delete("1.0", "end")

        if self.current_index is None or self.current_index >= len(self.entries):
            source_issues = self.get_selected_source_issues()
            if source_issues:
                self.render_issue_panel(source_issues, "")
            else:
                self.selected_issue_text.insert("end", "Select a source file or type entry to see validation issues, economy hints, and suggested fixes.", "muted")
            self.selected_issue_text.configure(state="disabled")
            return

        issues = self.get_selected_issues()
        self.render_issue_panel(issues, f"No issues for this entry in {self.issue_mode}.")
        self.selected_issue_text.configure(state="disabled")

    def save_selected_entry(self):
        if self.current_index is None:
            return
        entry = self.entries[self.current_index]
        raw_xml = self.get_entry_xml_text()
        original_xml = format_entry_xml(entry).strip()
        if raw_xml and raw_xml != original_xml:
            old_name = entry.name
            try:
                updated = parse_type_entry_xml(raw_xml, entry.source_path, entry.source_index)
            except ET.ParseError as exc:
                line, column = getattr(exc, "position", (None, None))
                location = f" at line {line}, column {column}" if line is not None and column is not None else ""
                messagebox.showerror(APP_TITLE, f"Selected type XML has a syntax error{location}:\n\n{exc}")
                return
            except ValueError as exc:
                messagebox.showerror(APP_TITLE, str(exc))
                return
            entry.name = updated.name
            entry.element = updated.element
            self.populate_flag_editor(entry)
            self.clear_analysis_for_entries([old_name, entry.name])
            order_type_entry_children(entry.element)
            self.schedule_validation_refresh()
            self.keep_entry_visible_after_apply(entry)
            self.update_visible_tree_row(self.current_index)
            self.populate_editor(entry)
            self.update_summary()
            self.mark_source_dirty(entry.source_path)
            self.log(f"Updated {entry.name} from full XML.", "success")
            return

        try:
            for field in ("nominal", "lifetime", "restock", "min", "quantmin", "quantmax", "cost"):
                value = self.editor_vars[field].get().strip()
                if value:
                    int(value)
                entry.set_child_text(field, value)
        except ValueError:
            messagebox.showerror(APP_TITLE, "Numeric fields must contain integers.")
            return

        category = self.editor_vars["category"].get().strip()
        entry.set_relation_names_preserve_order("category", [item.strip() for item in category.split(",")])
        self.apply_flag_editor(entry)
        order_type_entry_children(entry.element)

        self.clear_analysis_for_entries([entry.name])
        self.schedule_validation_refresh()
        self.keep_entry_visible_after_apply(entry)
        self.update_visible_tree_row(self.current_index)
        self.populate_editor(entry)
        self.update_summary()
        self.mark_source_dirty(entry.source_path)
        self.log(f"Updated {entry.name}.", "success")

    def select_next_duplicate(self):
        duplicates = get_duplicate_groups(self.entries)
        duplicate_indices = [index for index, entry in enumerate(self.entries) if any(entry.name.casefold() == name.casefold() for name in duplicates)]
        if not duplicate_indices:
            self.log("No duplicate classnames found.", "success")
            return
        start = self.current_index if self.current_index is not None else -1
        target = next((index for index in duplicate_indices if index > start), duplicate_indices[0])
        self.search_var.set("")
        self.filter_var.set("Duplicates")
        self.refresh_table()
        if str(target) in self.tree.get_children():
            self.tree.selection_set(str(target))
            self.tree.see(str(target))

    def open_duplicate_resolver(self):
        duplicates = get_duplicate_groups(self.entries)
        if not duplicates:
            messagebox.showinfo(APP_TITLE, "No duplicate classnames found.")
            return

        start_name = ""
        if self.current_index is not None:
            selected_name = self.entries[self.current_index].name
            if selected_name in duplicates:
                start_name = selected_name

        dialog = DuplicateResolverDialog(self, start_name=start_name)
        self.wait_window(dialog)
        if not dialog.result_indices:
            return

        kept_labels = [f"{self.entries[index].name} ({os.path.basename(self.entries[index].source_path)})" for index in dialog.result_indices]
        affected_names = sorted({self.entries[index].name for index in dialog.result_indices}, key=str.casefold)
        try:
            removed = resolve_duplicates_by_indices(self.entries, dialog.result_indices)
        except (IndexError, ValueError) as exc:
            messagebox.showerror(APP_TITLE, str(exc))
            return
        self.clear_analysis_for_entries(affected_names)
        self.set_validation_issues(self.validate_loaded_entries())
        self.filter_var.set("Duplicates" if get_duplicate_groups(self.entries) else "All")
        self.refresh_table()
        self.clear_editor()
        self.update_summary()
        self.recompute_dirty_sources()
        self.log(f"Resolved {len(dialog.result_indices)} duplicate classname(s); removed {removed} duplicate entr{'y' if removed == 1 else 'ies'}.", "success")
        for label in kept_labels:
            self.log(f"Kept {label}", "success")
        self.log_issues()

    def open_bulk_edit(self):
        if not self.entries:
            messagebox.showwarning(APP_TITLE, "Load at least one supported file first.")
            return
        dialog = BulkEditDialog(self)
        self.wait_window(dialog)
        if not dialog.result:
            return
        result = dialog.result
        scoped_entries = self.bulk_scope_entries(result["scope"])
        if not scoped_entries:
            messagebox.showinfo(APP_TITLE, f"No type entries match the '{result['scope']}' scope.")
            return
        try:
            preview_changes, preview_counts = self.preview_bulk_type_changes(scoped_entries, result)
        except (ET.ParseError, ValueError) as exc:
            messagebox.showerror(APP_TITLE, str(exc))
            return
        if not preview_changes:
            messagebox.showinfo(APP_TITLE, "Bulk edit preview found no actual changes.")
            return
        if not self.confirm_bulk_type_preview(preview_changes, preview_counts, result):
            return
        try:
            exact_count = apply_bulk_edit(
                [entry for _index, entry in scoped_entries],
                result["values"],
                category_filter=result["category_filter"],
                name_filter=result["name_filter"],
            )
            mult_count = 0
            if result["multiplier"] is not None:
                mult_count = multiply_numeric_field(
                    [entry for _index, entry in scoped_entries],
                    result["multiplier_field"],
                    result["multiplier"],
                    category_filter=result["category_filter"],
                    name_filter=result["name_filter"],
                )
            replace_count = replace_text_in_entries(
                [entry for _index, entry in scoped_entries],
                result["replace_find"],
                result["replace_with"],
                category_filter=result["category_filter"],
                name_filter=result["name_filter"],
            )
        except (ET.ParseError, ValueError) as exc:
            messagebox.showerror(APP_TITLE, str(exc))
            return
        if exact_count or mult_count or replace_count:
            self.analysis_issues = []
        self.set_validation_issues(self.validate_loaded_entries())
        self.refresh_table()
        self.update_summary()
        if exact_count or mult_count or replace_count:
            self.recompute_dirty_sources()
        self.log(f"Bulk edit complete. Exact edits: {exact_count}. Multiplied rows: {mult_count}. Text replacements: {replace_count}.", "success")

    def bulk_scope_options(self):
        options = ["filtered"]
        if self.bulk_scope_entries("selected"):
            options.append("selected")
        if self.bulk_scope_entries("current source"):
            options.append("current source")
        options.append("all loaded")
        return options

    def bulk_scope_description(self, scope):
        scope = (scope or "filtered").casefold()
        entries = self.bulk_scope_entries(scope)
        count = len(entries)
        if scope == "selected":
            if count:
                names = ", ".join(self.entries[index].name for index, _entry in entries[:5])
                suffix = f" First: {names}" + (f" (+{count - 5} more)." if count > 5 else ".")
                return f"Selected: {count} type entr{'y' if count == 1 else 'ies'} selected in the Types table before opening this dialog.{suffix}"
            return "Selected: unavailable. Select one or more rows in the Types table before opening this dialog."
        if scope == "current source":
            source_path = self.bulk_current_source_path()
            if source_path:
                return f"Current source: {self.source_display_name(source_path)}, {count} type entr{'y' if count == 1 else 'ies'}."
            return "Current source: unavailable. Select a source or a type row before opening this dialog."
        if scope == "all loaded":
            return f"All loaded: {count} type entr{'y' if count == 1 else 'ies'} across every loaded types.xml source."
        return f"Filtered: {count} currently visible type entr{'y' if count == 1 else 'ies'} from the Types table. This uses the active search, source filter, usage filter, and View dropdown."

    def bulk_current_source_path(self):
        if self.selected_source_path:
            return self.selected_source_path
        if self.current_index is not None and 0 <= self.current_index < len(self.entries):
            return self.entries[self.current_index].source_path
        return ""

    def bulk_scope_entries(self, scope):
        scope = (scope or "filtered").casefold()
        if scope == "selected":
            selected_indices = []
            if self.tree is not None:
                selected_indices = [
                    self.tree_iids[iid]
                    for iid in self.tree.selection()
                    if iid in self.tree_iids
            ]
            return [(index, self.entries[index]) for index in selected_indices if 0 <= index < len(self.entries)]
        if scope == "current source":
            source_path = self.bulk_current_source_path()
            if not source_path:
                return []
            source_key = self.normalized_path(source_path)
            return [
                (index, entry)
                for index, entry in enumerate(self.entries)
                if self.normalized_path(entry.source_path) == source_key
            ]
        if scope == "all loaded":
            return list(enumerate(self.entries))
        return [(index, self.entries[index]) for index in self.filtered_indices if 0 <= index < len(self.entries)]

    def type_entry_matches_bulk_filters(self, entry, result):
        category_filter = result["category_filter"].strip().casefold()
        name_filter = result["name_filter"].strip().casefold()
        if category_filter and category_filter not in ",".join(entry.relation_names("category")).casefold():
            return False
        if name_filter and name_filter not in entry.name.casefold():
            return False
        return True

    def preview_bulk_type_changes(self, scoped_entries, result):
        preview_entries = [entry.clone() for _index, entry in scoped_entries]
        exact_count = apply_bulk_edit(
            preview_entries,
            result["values"],
            category_filter=result["category_filter"],
            name_filter=result["name_filter"],
        )
        mult_count = 0
        if result["multiplier"] is not None:
            mult_count = multiply_numeric_field(
                preview_entries,
                result["multiplier_field"],
                result["multiplier"],
                category_filter=result["category_filter"],
                name_filter=result["name_filter"],
            )
        replace_count = replace_text_in_entries(
            preview_entries,
            result["replace_find"],
            result["replace_with"],
            category_filter=result["category_filter"],
            name_filter=result["name_filter"],
        )
        changes = []
        for (index, original), updated in zip(scoped_entries, preview_entries):
            if not self.type_entry_matches_bulk_filters(original, result):
                continue
            original_xml = format_entry_xml(original).strip()
            updated_xml = format_entry_xml(updated).strip()
            if original_xml == updated_xml:
                continue
            field_changes = []
            if original.name != updated.name:
                field_changes.append(f"name: {original.name} -> {updated.name}")
            for field in BULK_FIELDS:
                old_value = original.child_text(field)
                new_value = updated.child_text(field)
                if old_value != new_value:
                    field_changes.append(f"{field}: {old_value or '-'} -> {new_value or '-'}")
            if not field_changes:
                field_changes.append("XML text changed")
            changes.append(
                {
                    "index": index,
                    "before": original,
                    "after": updated,
                    "fields": field_changes,
                    "before_xml": original_xml,
                    "after_xml": updated_xml,
                }
            )
        return changes, {"exact": exact_count, "multiplied": mult_count, "replaced": replace_count}

    def confirm_bulk_type_preview(self, changes, counts, result):
        window = tk.Toplevel(self)
        window.title("Bulk Edit Preview")
        window.geometry("980x620")
        window.minsize(760, 460)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)
        accepted = {"value": False}

        shell = ttk.Frame(window, padding=12)
        shell.pack(fill="both", expand=True)
        shell.rowconfigure(1, weight=1)
        shell.columnconfigure(0, weight=1)
        summary = (
            f"{len(changes)} entr{'y' if len(changes) == 1 else 'ies'} will change. "
            f"Scope: {result['scope']}. Exact rows: {counts['exact']}. "
            f"Multiplied rows: {counts['multiplied']}. Text replacements: {counts['replaced']}."
        )
        ttk.Label(shell, text=summary, style="FieldMuted.TLabel", wraplength=930, justify="left").grid(row=0, column=0, sticky="ew", pady=(0, 10))

        panes = ttk.PanedWindow(shell, orient="vertical")
        panes.grid(row=1, column=0, sticky="nsew")
        table_frame = ttk.Frame(panes)
        detail_frame = ttk.Frame(panes)
        panes.add(table_frame, weight=2)
        panes.add(detail_frame, weight=3)
        table_frame.rowconfigure(0, weight=1)
        table_frame.columnconfigure(0, weight=1)
        columns = ("source", "changes")
        tree = ttk.Treeview(table_frame, columns=columns, show="tree headings", selectmode="browse", style="Economy.Treeview")
        tree.heading("#0", text="Classname")
        tree.heading("source", text="Source")
        tree.heading("changes", text="Changes")
        tree.column("#0", width=240, anchor="w", stretch=True)
        tree.column("source", width=160, anchor="w", stretch=False)
        tree.column("changes", width=520, anchor="w", stretch=True)
        tree.grid(row=0, column=0, sticky="nsew")
        y_scroll = ttk.Scrollbar(table_frame, command=tree.yview)
        y_scroll.grid(row=0, column=1, sticky="ns")
        x_scroll = ttk.Scrollbar(table_frame, command=tree.xview, orient="horizontal")
        x_scroll.grid(row=1, column=0, sticky="ew")
        tree.configure(yscrollcommand=y_scroll.set, xscrollcommand=x_scroll.set)

        detail_frame.rowconfigure(0, weight=1)
        detail_frame.columnconfigure(0, weight=1)
        detail = tk.Text(
            detail_frame,
            wrap="none",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            insertbackground=GRAPHITE_TEXT,
            selectbackground=GRAPHITE_ACCENT_DARK,
            selectforeground="#ffffff",
            relief="flat",
            borderwidth=0,
            highlightthickness=1,
            highlightbackground=GRAPHITE_BORDER,
            highlightcolor=GRAPHITE_ACCENT,
            font=("Consolas", 9),
        )
        detail.grid(row=0, column=0, sticky="nsew")
        self.configure_xml_tags(detail)
        detail_y = ttk.Scrollbar(detail_frame, command=detail.yview)
        detail_y.grid(row=0, column=1, sticky="ns")
        detail_x = ttk.Scrollbar(detail_frame, command=detail.xview, orient="horizontal")
        detail_x.grid(row=1, column=0, sticky="ew")
        detail.configure(yscrollcommand=detail_y.set, xscrollcommand=detail_x.set)

        change_by_iid = {}
        for row, change in enumerate(changes):
            iid = f"bulk-preview-{row}"
            change_by_iid[iid] = change
            tree.insert(
                "",
                "end",
                iid=iid,
                text=change["before"].name,
                values=(
                    self.source_display_name(change["before"].source_path),
                    "; ".join(change["fields"]),
                ),
            )

        def show_change(_event=None):
            selected = tree.selection()
            detail.configure(state="normal")
            detail.delete("1.0", "end")
            if selected:
                change = change_by_iid.get(selected[0])
                if change:
                    detail.insert("end", "Before:\n")
                    detail.insert("end", change["before_xml"])
                    detail.insert("end", "\n\nAfter:\n")
                    detail.insert("end", change["after_xml"])
                    self.apply_xml_highlighting_to_widget(detail)
            detail.configure(state="disabled")

        tree.bind("<<TreeviewSelect>>", show_change)
        first = tree.get_children()
        if first:
            tree.selection_set(first[0])
            show_change()

        actions = ttk.Frame(shell)
        actions.grid(row=2, column=0, sticky="e", pady=(12, 0))

        def apply_and_close():
            accepted["value"] = True
            window.destroy()

        self.make_button(actions, "Apply changes", apply_and_close, variant="save")
        self.make_button(actions, "Cancel", window.destroy)
        window.bind("<Escape>", lambda _event: window.destroy())
        window.after(20, lambda: center_window(window, self))
        window.grab_set()
        self.wait_window(window)
        return accepted["value"]

    def open_config_types_generator(self):
        ConfigTypesGeneratorDialog(self)

    def open_type_splitter(self):
        if not self.loaded_paths:
            messagebox.showwarning(APP_TITLE, "Load a mission folder or at least one types.xml source first.")
            return
        TypeSplitterDialog(self)

    def compare_files(self):
        old_path = filedialog.askopenfilename(title="Choose old DayZ XML file", filetypes=[("XML files", "*.xml"), ("All files", "*.*")], initialdir=self.saved_settings.get("last_dir", str(Path.home())))
        if not old_path:
            return
        new_path = filedialog.askopenfilename(title="Choose new DayZ XML file", filetypes=[("XML files", "*.xml"), ("All files", "*.*")], initialdir=os.path.dirname(old_path))
        if not new_path:
            return
        old_entries, old_issues = parse_types_file(old_path, 0)
        new_entries, new_issues = parse_types_file(new_path, 1)
        if old_issues or new_issues:
            self.log("Compare loaded files with validation issues:", "warning")
            for issue in old_issues + new_issues:
                self.log(f"{issue.severity.upper()}: {issue.message} [{os.path.basename(issue.source_path)}]", issue.severity)
        changes = compare_entries(old_entries, new_entries)
        self.log(f"Compare: {os.path.basename(old_path)} -> {os.path.basename(new_path)}", "success")
        if not changes:
            self.log("No economy changes found.", "success")
            return
        for change in changes:
            fields = f" ({', '.join(change.fields)})" if change.fields else ""
            tag = "warning" if change.change_type == "changed" else "muted"
            self.log(f"{change.change_type.upper()}: {change.name}{fields}", tag)
        self.set_status(f"{len(changes)} compare change(s)", "warning")

    def find_mission_file(self, filename):
        name_key = filename.casefold()
        if self.mission_workspace is not None:
            root = Path(self.mission_workspace.root_path)
            direct = root / filename
            if direct.is_file():
                return str(direct)
            db_path = root / "db" / filename
            if db_path.is_file():
                return str(db_path)
        for path in self.config_paths + self.loaded_paths:
            if Path(path).name.casefold() == name_key and Path(path).is_file():
                return path
        return ""

    def find_mission_root_neighbor_file(self, filename):
        name_key = filename.casefold()
        candidates: list[Path] = []

        def add_dir(value):
            try:
                path = Path(value)
            except (TypeError, ValueError):
                return
            if path.is_file():
                path = path.parent
            candidates.append(path)
            if path.name.casefold() == "db":
                candidates.append(path.parent)
            parent = path.parent
            if parent.name.casefold() == "db":
                candidates.append(parent.parent)

        if self.mission_workspace is not None and getattr(self.mission_workspace, "root_path", ""):
            add_dir(self.mission_workspace.root_path)
        for path in self.loaded_paths + self.config_paths:
            add_dir(path)

        seen: set[str] = set()
        for directory in candidates:
            key = self.normalized_path(str(directory))
            if key in seen:
                continue
            seen.add(key)
            direct = directory / filename
            if direct.is_file() and direct.name.casefold() == name_key:
                return str(direct)
        return ""

    def open_loot_distribution_report(self):
        if not self.entries:
            messagebox.showwarning(APP_TITLE, "Load a mission folder or Types files first.")
            return
        mapgroupproto_path = self.find_mission_file("mapgroupproto.xml")
        mapgrouppos_path = self.find_mission_file("mapgrouppos.xml")
        missing = []
        if not mapgroupproto_path:
            missing.append("mapgroupproto.xml")
        if not mapgrouppos_path:
            missing.append("mapgrouppos.xml")
        if missing:
            messagebox.showwarning(
                APP_TITLE,
                "Loot distribution needs mapgroup files from the mission root or loaded configs:\n\n"
                + "\n".join(f"- {item}" for item in missing),
            )
            return
        try:
            report = analyze_loot_distribution(
                self.entries,
                mapgroupproto_path,
                mapgrouppos_path,
                spawnable_entries=self.spawnable_entries,
                random_presets=self.random_preset_entries,
                events=self.event_entries,
                event_spawn_positions=self.event_spawn_positions,
            )
        except (OSError, ET.ParseError) as exc:
            messagebox.showerror(APP_TITLE, f"Could not analyze loot distribution:\n{exc}")
            return
        self.open_loot_distribution_table_window(report)
        self.log(
            f"Loot distribution report: nominal {report.total_nominal}, capacity {report.total_capacity}, "
            f"{len(report.item_rows)} item row(s), {len(report.relation_summaries)} relation row(s), {len(report.unmatched_items)} unmatched item(s).",
            "success" if not report.warnings else "warning",
        )

    def open_loot_distribution_table_window(self, report):
        window = tk.Toplevel(self)
        window.title("Economy Health / Loot Balance")
        window.geometry("1280x760")
        window.minsize(980, 600)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)
        item_rows = list(report.item_rows)
        dead_rows = loot_distribution_dead_loot_rows(report)
        overloaded_rows = loot_distribution_overloaded_rows(report)
        no_capacity_relations = [row for row in report.relation_summaries if row.status == "no capacity" and row.nominal > 0]
        over_target_relations = [row for row in report.relation_summaries if row.status == "over target"]
        tight_relations = [row for row in report.relation_summaries if row.status == "tight"]
        action_count = len(dead_rows) + len(overloaded_rows)
        if dead_rows or no_capacity_relations:
            overall_state, overall_color = "Red", GRAPHITE_ERROR_DARK
            overall_note = "Spawn blockers found"
        elif overloaded_rows or over_target_relations or tight_relations or report.warnings:
            overall_state, overall_color = "Orange", GRAPHITE_WARNING
            overall_note = "Review balance pressure"
        else:
            overall_state, overall_color = "Green", GRAPHITE_SUCCESS_DARK
            overall_note = "No major blockers"
        if overloaded_rows or over_target_relations:
            balance_state, balance_color = "Orange", GRAPHITE_WARNING
            balance_note = "Nominal pressure high"
        elif tight_relations:
            balance_state, balance_color = "Yellow", GRAPHITE_WARNING
            balance_note = "Some relations tight"
        else:
            balance_state, balance_color = "Green", GRAPHITE_SUCCESS_DARK
            balance_note = "Demand fits capacity"

        shell = ttk.Frame(window, padding=12)
        shell.pack(fill="both", expand=True)
        shell.columnconfigure(0, weight=1)
        shell.rowconfigure(2, weight=1)

        header = ttk.LabelFrame(shell, text="Overview", padding=12)
        header.grid(row=0, column=0, sticky="ew", pady=(0, 10))
        for column in range(5):
            header.columnconfigure(column, weight=1)
        summary_items = (
            ("Overall Economy Health", overall_state, overall_note, overall_color),
            ("Loot Balance", balance_state, balance_note, balance_color),
            ("Change first", action_count, "red/orange action rows", GRAPHITE_CARD_SOFT),
            ("Dead loot", len(dead_rows), "nominal with no source", GRAPHITE_CARD_SOFT),
            ("Overloaded", len(overloaded_rows), "nominal > matching points", GRAPHITE_CARD_SOFT),
        )
        for column, (label, value, note, color) in enumerate(summary_items):
            text_fg = "#1f2126" if color == GRAPHITE_WARNING else GRAPHITE_TEXT
            muted_fg = "#2f3238" if color == GRAPHITE_WARNING else GRAPHITE_MUTED
            box = tk.Frame(header, bg=color, padx=12, pady=8)
            box.grid(row=0, column=column, sticky="ew", padx=(0 if column == 0 else 8, 0))
            tk.Label(box, text=label, bg=color, fg=muted_fg, font=("Segoe UI", 9)).pack(anchor="w")
            tk.Label(box, text=str(value), bg=color, fg=text_fg, font=("Segoe UI", 14, "bold")).pack(anchor="w", pady=(2, 0))
