        issue_tree.tag_configure("overloaded", foreground=GRAPHITE_WARNING)
        issue_tree.tag_configure("ok", foreground=GRAPHITE_SUCCESS)

        detail = ttk.LabelFrame(shell, text="Selected item", padding=10)
        detail.grid(row=3, column=0, sticky="ew", pady=(10, 0))
        detail.columnconfigure(0, weight=1)
        detail_var = tk.StringVar(value="Select an item to see why it is rated that way.")
        ttk.Label(detail, textvariable=detail_var, style="FieldMuted.TLabel", wraplength=980, justify="left").grid(row=0, column=0, sticky="w")

        sort_state = {"column": "rarity_view", "reverse": True}
        label_weight = {
            "Unique / Extremely Rare": 0,
            "Very Rare": 1,
            "Rare": 2,
            "Uncommon": 3,
            "Common": 4,
            "Very Common": 5,
            "Not configured to spawn": 6,
        }

        def relation_values(rows, attribute_name):
            values = sorted({value for row in rows for value in getattr(row, attribute_name)}, key=str.casefold)
            return ("All",) + tuple(values)

        category_combo, usage_combo, value_combo, tag_combo = relation_combos
        category_combo.configure(values=relation_values(item_rows, "categories"))
        usage_combo.configure(values=relation_values(item_rows, "usages"))
        value_combo.configure(values=relation_values(item_rows, "values"))
        tag_combo.configure(values=relation_values(item_rows, "tags"))

        def row_has_relation(row, attribute_name, selected_value):
            return selected_value == "All" or selected_value in getattr(row, attribute_name)

        def source_bucket(row):
            return loot_item_source_bucket(row)

        def refresh_health_tables():
            relation_tree.delete(*relation_tree.get_children())
            relation_rows = sorted(
                report.relation_summaries,
                key=lambda row: (
                    row.status != "no capacity",
                    row.status != "over target",
                    row.status != "tight",
                    -(row.ratio or 0),
                    row.kind,
                    row.name.casefold(),
                ),
            )
            for index, row in enumerate(relation_rows):
                ratio = "n/a" if row.ratio is None else f"{row.ratio:.2f}"
                relation_tree.insert(
                    "",
                    "end",
                    iid=f"relation:{index}",
                    text=f"{row.kind}: {row.name}",
                    values=(row.status, row.nominal, row.capacity, ratio, row.item_count, row.building_count, row.spawnpoints),
                    tags=(row.status,),
                )

            source_tree.delete(*source_tree.get_children())
            source_notes = {
                "World": "Normal map loot through mapgroupproto/mapgrouppos relations.",
                "Dispatch proxy": "Exact mapgroupproto dispatch proxies multiplied by matching mapgrouppos placements.",
                "Cargo/Attachment": "Derived from cfgspawnabletypes cargo/attachments and random presets.",
                "Event": "Derived from enabled events.xml children and cfgeventspawns positions.",
                "Crafted": "Marked crafted in types flags.",
                "Deloot": "Marked deloot in types flags.",
                "No matched source": "Configured item has no matched world, event, cargo, crafted, or deloot source.",
            }
            for bucket in loot_distribution_source_summary(report):
                name = str(bucket["Source"])
                tag = "error" if name == "No matched source" and int(bucket["Nominal"]) > 0 else "warning" if name in {"Crafted", "Deloot"} else "ok"
                source_tree.insert(
                    "",
                    "end",
                    text=name,
                    values=(bucket["Items"], bucket["Nominal"], bucket["Min"], f"{float(bucket['AverageFindabilityPercent']):.4f}%", source_notes.get(name, "")),
                    tags=(tag,),
                )

            issue_tree.delete(*issue_tree.get_children())
            issue_index = 0
            for row in dead_rows:
                issue_tree.insert(
                    "",
                    "end",
                    iid=f"issue:{issue_index}:{row.class_name}",
                    text=row.class_name,
                    values=(
                        "Red",
                        "Nominal item has no matched spawn source.",
                        "Add a valid world/event/cargo source, fix relations, or set nominal to 0.",
                        row.nominal,
                        row.eligible_spawn_points,
                        row.spawn_source_text,
                    ),
                    tags=("dead",),
                )
                issue_index += 1
            for row in overloaded_rows:
                issue_tree.insert(
                    "",
                    "end",
                    iid=f"issue:{issue_index}:{row.class_name}",
                    text=row.class_name,
                    values=(
                        "Orange",
                        f"Nominal is {row.location_density:.2f} per matching point.",
                        "Lower nominal/restock pressure or add more matching map opportunities.",
                        row.nominal,
                        row.eligible_spawn_points,
                        row.spawn_source_text,
                    ),
                    tags=("overloaded",),
                )
                issue_index += 1
            if issue_index <= 0:
                issue_tree.insert(
                    "",
                    "end",
                    iid="issue:ok",
                    text="No critical item changes",
                    values=("Green", "No dead or overloaded item rows found.", "Use Items tab only for fine tuning.", "", "", ""),
                    tags=("ok",),
                )

        def row_sort_value(row, column):
            if column == "#0":
                return row.class_name.casefold()
            if column == "label":
                return label_weight.get(row.estimated_rarity_label, 99)
            if column == "findability":
                return row.findability_score
            if column == "rarity_view":
                return row.rarity_index
            if column == "eligible":
                return row.eligible_spawn_points
            if column == "nominal":
                return row.nominal
            if column == "sources":
                return row.spawn_source_text.casefold()
            if column == "min":
                return row.minimum
            if column == "lifetime":
                return row.lifetime
            if column == "restock":
                return row.restock
            if column == "cost":
                return row.cost
            if column == "category":
                return row.category_text.casefold()
            if column == "usage":
                return row.usage_text.casefold()
            if column == "tier":
                return row.value_text.casefold()
            if column == "tags":
                return row.tag_text.casefold()
            if column == "hoarding":
                return row.hoarding_sensitivity
            if column == "density":
                return row.location_density
            if column == "effective":
                return row.effective_rarity_score
            return ""

        def current_filtered_rows():
            label_filter = label_var.get()
            source_filter = source_var.get()
            search_text = search_var.get().strip().casefold()
            rows = []
            for row in item_rows:
                if label_filter != "All" and row.estimated_rarity_label != label_filter:
                    continue
                if source_filter != "All":
                    if source_bucket(row) != source_filter:
                        continue
                if not row_has_relation(row, "categories", category_var.get()):
                    continue
                if not row_has_relation(row, "usages", usage_var.get()):
                    continue
                if not row_has_relation(row, "values", value_var.get()):
                    continue
                if not row_has_relation(row, "tags", tag_var.get()):
                    continue
                if search_text and search_text not in row.class_name.casefold():
                    continue
                rows.append(row)
            return sorted(rows, key=lambda item: row_sort_value(item, sort_state["column"]), reverse=sort_state["reverse"])

        def set_display_columns():
            compact = ("label", "findability", "rarity_view", "eligible", "nominal", "sources")
            full = (
                "label",
                "findability",
                "rarity_view",
                "eligible",
                "nominal",
                "sources",
                "min",
                "lifetime",
                "restock",
                "cost",
                "category",
                "usage",
                "tier",
                "tags",
                "hoarding",
                "density",
                "effective",
            )
            tree.configure(displaycolumns=full if show_details_var.get() else compact)

        def refresh_rows(*_args):
            set_display_columns()
            tree.delete(*tree.get_children())
            for index, row in enumerate(current_filtered_rows()):
                iid = f"item:{index}:{row.class_name}"
                tree.insert(
                    "",
                    "end",
                    iid=iid,
                    text=row.class_name,
                    values=(
                        row.estimated_rarity_label,
                        f"{row.findability_score * 100:.4f}%",
                        f"1 per {row.rarity_index:,.0f}",
                        f"{row.eligible_spawn_points:,}",
                        row.nominal,
                        row.spawn_source_text,
                        row.minimum,
                        row.lifetime,
                        row.restock,
                        row.cost,
                        row.category_text,
                        row.usage_text,
                        row.value_text,
                        row.tag_text,
                        row.hoarding_sensitivity,
                        f"{row.location_density:.6f}",
                        f"{row.effective_rarity_score:.6f}",
                    ),
                    tags=(row.estimated_rarity_label,),
                )
            count = len(tree.get_children())
            detail_var.set(f"{count} item row(s) shown. Select one for details.")

        def sort_by(column):
            if sort_state["column"] == column:
                sort_state["reverse"] = not sort_state["reverse"]
            else:
                sort_state["column"] = column
                sort_state["reverse"] = column in {"findability", "rarity_view", "eligible", "nominal", "min", "lifetime", "restock", "cost", "hoarding", "density", "effective"}
            refresh_rows()

        tree.heading("#0", text="ClassName", command=lambda: sort_by("#0"))
        for column, label in headings.items():
            tree.heading(column, text=label, command=lambda selected=column: sort_by(selected))

        def selected_row():
            selection = tree.selection()
            if not selection:
                return None
            class_name = selection[0].split(":", 2)[-1]
            for row in item_rows:
                if row.class_name == class_name:
                    return row
            return None

        def selected_action_type_name():
            selection = issue_tree.selection()
            if not selection:
                return ""
            iid = selection[0]
            if iid == "issue:ok":
                return ""
            return str(issue_tree.item(iid, "text") or "").strip()

        def open_selected_type_entry():
            if notebook.select() == str(action_tab):
                class_name = selected_action_type_name()
            else:
                row = selected_row()
                class_name = row.class_name if row is not None else selected_action_type_name()
            if not class_name:
                messagebox.showwarning(APP_TITLE, "Select a loot item first.", parent=window)
                return
            if self.select_type_entry_by_name(class_name):
                return
            messagebox.showwarning(APP_TITLE, f"Could not find loaded Types entry:\n{class_name}", parent=window)

        def update_detail(_event=None):
            row = selected_row()
            if row is None:
                detail_var.set("Select an item to see why it is rated that way.")
                return
            detail_var.set(
                f"{row.class_name}: {row.estimated_rarity_label}. Nominal {row.nominal}, matching points {row.eligible_spawn_points:,}. "
                f"Findability is about {row.findability_score * 100:.4f}% (1 per {row.rarity_index:,.0f}). "
                f"This is configured target share across matching opportunities, not a guaranteed live spawn chance. "
                f"Sources: {row.spawn_source_text}. Usage distribution: {format_distribution_map(row.distribution_by_usage) or '-'}; "
                f"tier distribution: {format_distribution_map(row.distribution_by_tier) or '-'}."
            )

        tree.bind("<<TreeviewSelect>>", update_detail)
        tree.bind("<Double-Button-1>", lambda _event: open_selected_type_entry())
        tree.bind("<Return>", lambda _event: open_selected_type_entry())
        issue_tree.bind("<Double-Button-1>", lambda _event: open_selected_type_entry())
        issue_tree.bind("<Return>", lambda _event: open_selected_type_entry())
        label_combo.bind("<<ComboboxSelected>>", refresh_rows, add="+")
        source_combo.bind("<<ComboboxSelected>>", refresh_rows, add="+")
        for combo in relation_combos:
            combo.bind("<<ComboboxSelected>>", refresh_rows, add="+")
        search.bind("<KeyRelease>", refresh_rows, add="+")
        details_check.configure(command=refresh_rows)

        def save_text_file(title, extension, text_factory):
            path = filedialog.asksaveasfilename(
                title=title,
                defaultextension=extension,
                filetypes=((extension.upper().lstrip(".") + " files", f"*{extension}"), ("All files", "*.*")),
            )
            if not path:
                return
            try:
                Path(path).write_text(text_factory(), encoding="utf-8")
            except OSError as exc:
                messagebox.showerror(APP_TITLE, f"Could not export report:\n{exc}")
                return
            self.log(f"Exported loot distribution report: {path}", "success")

        actions = ttk.Frame(shell, style="Card.TFrame")
        actions.grid(row=4, column=0, sticky="e", pady=(10, 0))
        self.make_button(actions, "Open Type", open_selected_type_entry, variant="action")
        self.make_button(actions, "Export CSV", lambda: save_text_file("Export Loot Distribution CSV", ".csv", lambda: format_loot_distribution_csv(report)), variant="report")
        self.make_button(actions, "Export JSON", lambda: save_text_file("Export Loot Distribution JSON", ".json", lambda: format_loot_distribution_json(report)), variant="report")
        self.make_button(actions, "Full report", lambda: self.open_text_report_window("Economy Health / Loot Balance Report", format_loot_distribution_report(report)), variant="report")
        self.make_button(actions, "Close", window.destroy, variant="primary")

        refresh_rows()
        refresh_health_tables()
        window.after(20, lambda: center_window(window))

