    def refresh_validation_for_mission_report(self):
        if self.mission_workspace is not None:
            file_issues = validate_mission_workspace_xml(self.mission_workspace.root_path)
        else:
            file_issues = validate_xml_files(self.loaded_paths)
        self.event_issues = self.territory_issues + self.validate_event_relationships()
        self.spawnable_issues = validate_spawnable_type_references(self.spawnable_entries, self.entries)
        self.random_preset_issues = validate_random_preset_references(self.random_preset_entries, self.entries)
        weather_issues = self.current_weather_validation_issues() if self.weather_path else []
        mapgroupproto_issues = []
        if self.ensure_mapgroupproto_loaded():
            self.validate_mapgroupproto_current_text(show_success=False)
            mapgroupproto_issues = list(self.mapgroupproto_issues)
        self.set_validation_issues(
            file_issues
            + self.validate_loaded_entries()
            + self.spawnable_issues
            + self.random_preset_issues
            + self.event_issues
            + weather_issues
            + mapgroupproto_issues
            + self.validate_loaded_config_files(),
            mode="Workspace validation",
        )
        self.last_workspace_validation_at = datetime.now()
        self.workspace_validation_stale = False
        self.refresh_dashboard()

    def mission_validation_report_data(self):
        issues = list(getattr(self, "issues", []))
        issue_counts = self.issue_counts_by_severity(issues)
        issue_groups = self.issue_groups_by_module(issues)
        duplicates = get_duplicate_groups(self.entries)
        all_sources = self.all_save_source_paths()
        dirty_keys = set(getattr(self, "dirty_source_keys_cache", set()))
        source_rows = []
        for source_path in all_sources:
            source_key = self.normalized_path(source_path)
            source_rows.append({
                "module": self.source_module_label(source_path),
                "file_type": self.source_file_type_label(source_path),
                "path": source_path,
                "dirty": source_key in dirty_keys,
                "exists": Path(source_path).is_file(),
            })
        issue_rows = []
        for issue in issues:
            module_id = self.issue_module_id(issue)
            issue_rows.append({
                "severity": issue.severity,
                "module": self.issue_module_label(module_id),
                "module_id": module_id,
                "name": issue.name,
                "message": issue.message,
                "source_path": issue.source_path,
                "source": self.source_display_name(issue.source_path) if issue.source_path else "",
                "target": list(self.issue_target(issue)),
                "line": issue.line,
                "column": issue.column,
                "suggestion": issue.suggestion,
                "context": issue.context,
            })
        module_issue_counts = {}
        for module_id, module_issues in issue_groups.items():
            counts = self.issue_counts_by_severity(module_issues)
            module_issue_counts[module_id] = {
                "label": self.issue_module_label(module_id),
                "errors": counts["error"],
                "warnings": counts["warning"],
                "infos": counts["info"],
                "total": len(module_issues),
            }
        workspace = self.mission_workspace.root_path if self.mission_workspace is not None else "Loose files" if all_sources else "No workspace loaded"
        return {
            "app": APP_TITLE,
            "version": APP_VERSION,
            "created_at": datetime.now().isoformat(timespec="seconds"),
            "workspace": workspace,
            "selected_map_key": getattr(self, "selected_map_key", ""),
            "summary": {
                "types": len(self.entries),
                "spawnabletypes": len(self.spawnable_entries),
                "randompresets": len(self.random_preset_entries),
                "events": len(self.event_entries),
                "territories": len(self.territory_zones),
                "sources": len(source_rows),
                "dirty_sources": sum(1 for row in source_rows if row["dirty"]),
                "definitions_dirty": bool(getattr(self, "definitions_dirty", False)),
                "duplicate_classnames": len(duplicates),
                "errors": issue_counts["error"],
                "warnings": issue_counts["warning"],
                "infos": issue_counts["info"],
            },
            "sources": source_rows,
            "module_issue_counts": module_issue_counts,
            "issues": issue_rows,
        }

    def mission_validation_report_text(self, data):
        summary = data.get("summary", {})
        lines = [
            "RaG Economy Manager mission-wide validation report",
            "",
            f"Created: {data.get('created_at', '')}",
            f"Version: {data.get('version', '')}",
            f"Workspace: {data.get('workspace', '')}",
            f"Selected map: {data.get('selected_map_key') or 'not selected'}",
            "",
            "Summary:",
            f"- Types: {summary.get('types', 0)}",
            f"- Spawnabletypes: {summary.get('spawnabletypes', 0)}",
            f"- Randompresets: {summary.get('randompresets', 0)}",
            f"- Events: {summary.get('events', 0)}",
            f"- Territories: {summary.get('territories', 0)}",
            f"- Sources: {summary.get('sources', 0)}",
            f"- Dirty sources: {summary.get('dirty_sources', 0)}",
            f"- Definitions dirty: {'yes' if summary.get('definitions_dirty') else 'no'}",
            f"- Duplicate classnames: {summary.get('duplicate_classnames', 0)}",
            f"- Errors: {summary.get('errors', 0)}",
            f"- Warnings: {summary.get('warnings', 0)}",
            f"- Info: {summary.get('infos', 0)}",
            "",
            "Module issue counts:",
        ]
        module_counts = data.get("module_issue_counts", {})
        if module_counts:
            for counts in module_counts.values():
                lines.append(f"- {counts['label']}: {counts['errors']} error(s), {counts['warnings']} warning(s), {counts['infos']} info")
        else:
            lines.append("- No validation issues recorded.")
        lines.append("")
        lines.append("Dirty / missing sources:")
        source_notes = [row for row in data.get("sources", []) if row.get("dirty") or not row.get("exists")]
        if source_notes:
            for row in source_notes:
                flags = []
                if row.get("dirty"):
                    flags.append("dirty")
                if not row.get("exists"):
                    flags.append("missing")
                lines.append(f"- {row['module']} [{', '.join(flags)}]: {row['path']}")
        else:
            lines.append("- No dirty or missing loaded sources.")
        lines.append("")
        lines.append("Issues:")
        if data.get("issues"):
            for issue in data["issues"]:
                location = issue.get("source_path") or "workspace"
                if issue.get("line"):
                    location += f": line {issue['line']}"
                    if issue.get("column"):
                        location += f", column {issue['column']}"
                name = f" [{issue['name']}]" if issue.get("name") else ""
                lines.append(f"- {issue['severity'].upper()} {issue['module']}{name}: {issue['message']}")
                lines.append(f"  Source: {location}")
                if issue.get("suggestion"):
                    lines.append(f"  Fix: {issue['suggestion']}")
                if issue.get("context"):
                    lines.append("  Context:")
                    for context_line in str(issue["context"]).splitlines()[:6]:
                        lines.append(f"    {context_line}")
        else:
            lines.append("- No validation issues recorded.")
        return "\n".join(lines).rstrip() + "\n"

    def export_mission_validation_report_interactive(self):
        if not self.all_save_source_paths() and self.mission_workspace is None:
            messagebox.showwarning(APP_TITLE, "Load a mission folder or supported files before exporting a validation report.")
            return
        self.refresh_validation_for_mission_report()
        data = self.mission_validation_report_data()
        report = self.mission_validation_report_text(data)
        default_name = f"RaG_Economy_Manager_validation_report_{datetime.now().strftime('%Y%m%d_%H%M%S')}.txt"
        output_path = filedialog.asksaveasfilename(
            title="Save validation report",
            defaultextension=".txt",
            initialfile=default_name,
            filetypes=[("Text report", "*.txt"), ("All files", "*.*")],
        )
        if not output_path:
            return
        json_path = str(Path(output_path).with_suffix(".json"))
        try:
            Path(output_path).write_text(report, encoding="utf-8")
            Path(json_path).write_text(json.dumps(data, indent=2), encoding="utf-8")
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not write validation report:\n{exc}")
            return
        self.log(f"Wrote validation report: {output_path}", "success")
        self.log(f"Wrote validation report JSON: {json_path}", "success")
        self.set_status("Validation report saved", "success")
        self.refresh_spawnable_table()
        self.refresh_random_preset_table()
        self.refresh_event_table()
        self.refresh_issues_view()
    def get_change_report_path(self, output_path):
        base, ext = os.path.splitext(output_path)
        return f"{base}.change_report.txt"

    def changed_source_paths(self):
        paths = []
        economycore_paths = [self.economycore_path] if self.economycore_path else []
        for path in self.loaded_paths + self.spawnable_source_paths() + self.random_preset_source_paths() + self.event_source_paths() + self.territory_source_paths() + economycore_paths:
            if self.normalized_path(path) in {self.normalized_path(existing) for existing in paths}:
                continue
            if self.source_has_changes(path):
                paths.append(path)
        return paths

    def local_change_report_dir(self):
        path = app_data_dir() / "change_reports"
        path.mkdir(parents=True, exist_ok=True)
        return path

    def load_backup_manifest(self):
        path = source_backup_manifest_path()
        if not path.is_file():
            return {}
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
        except (OSError, json.JSONDecodeError):
            return {}
        return data if isinstance(data, dict) else {}

    def save_backup_manifest(self, manifest):
        path = source_backup_manifest_path()
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(manifest, indent=2, sort_keys=True), encoding="utf-8")

    def create_pre_save_backup(self, source_path):
        if is_ignored_storage_path(source_path):
            raise OSError("Access blocked: storage_1 is always ignored.")
        source = Path(source_path)
        if not source.is_file():
            return ""
        backup_path = source_backup_dir() / safe_backup_name(source)
        backup_path.write_bytes(source.read_bytes())
        manifest = self.load_backup_manifest()
        source_key = self.normalized_path(source)
        manifest[source_key] = {
            "source_path": str(source),
            "backup_path": str(backup_path),
            "created_at": datetime.now().isoformat(timespec="seconds"),
            "size": backup_path.stat().st_size,
            "module": self.source_module_label(source),
            "file_type": self.source_file_type_label(source),
        }
        self.save_backup_manifest(manifest)
        self.log(f"Updated rolling backup: {backup_path}", "muted")
        return str(backup_path)

    def source_file_type_label(self, source_path):
        suffix = Path(source_path).suffix.lower()
        if suffix == ".xml":
            return "XML"
        if suffix == ".json":
            return "JSON"
        if suffix == ".c":
            return "C script"
        if suffix == ".cfg":
            return "CFG"
        return suffix[1:].upper() if suffix else "File"

    def source_module_label(self, source_path):
        source_key = self.normalized_path(source_path)
        if self.is_environment_source_path(source_path):
            return "Environment"
        if source_key in {self.normalized_path(path) for path in self.loaded_paths}:
            return "Types"
        if source_key in {self.normalized_path(path) for path in self.spawnable_source_paths()}:
            return "Spawnabletypes"
        if source_key in {self.normalized_path(path) for path in self.random_preset_source_paths()}:
            return "Randompresets"
        if source_key in {self.normalized_path(path) for path in self.event_source_paths()}:
            return "Events"
        if source_key in {self.normalized_path(path) for path in self.territory_source_paths()}:
            return "Territories"
        if self.is_economycore_source_path(source_path):
            return "Economy Core"
        if self.is_mapgroupproto_source_path(source_path):
            return "Mapgroupproto"
        if self.is_weather_source_path(source_path):
            return "Weather"
        if self.is_config_source_path(source_path):
            return "Configs"
        name = Path(source_path).name.lower()
        suffix = Path(source_path).suffix.lower()
        if name == "cfgspawnabletypes.xml":
            return "Spawnabletypes"
        if name == "cfgrandompresets.xml":
            return "Randompresets"
        if name == "cfgeconomycore.xml":
            return "Economy Core"
        if name == "cfgenvironment.xml":
            return "Environment"
        if name == "mapgroupproto.xml":
            return "Mapgroupproto"
        if name in {"cfgeventspawns.xml", "cfgeventgroups.xml"}:
            return "Events"
        if name == "events.xml":
            return "Events"
        if name.endswith("_territories.xml"):
            return "Territories"
        if suffix in {".json", ".c", ".cfg"}:
            return "Configs"
        return "Types" if suffix == ".xml" else "File"

    def backup_preview_text(self, backup_path, limit=200_000):
        if is_ignored_storage_path(backup_path):
            return "storage_1 is always ignored."
        path = Path(backup_path)
        try:
            data = path.read_bytes()
        except OSError as exc:
            return f"Could not read backup preview: {exc}"
        if b"\x00" in data[:4096]:
            return f"Binary backup preview is not available.\n\nFile: {path}\nSize: {len(data)} bytes"
        truncated = len(data) > limit
        data = data[:limit]
        for encoding in ("utf-8-sig", "utf-8", "latin-1"):
            try:
                text = data.decode(encoding)
                break
            except UnicodeDecodeError:
                continue
        else:
            return f"Could not decode backup preview.\n\nFile: {path}\nSize: {path.stat().st_size} bytes"
        if truncated:
            text += f"\n\n--- Preview truncated at {limit:,} bytes ---"
        return text

    def restore_source_backup_interactive(self):
        manifest = self.load_backup_manifest()
        rows = []
        for source_key, info in manifest.items():
            if not isinstance(info, dict):
                continue
            source_path = info.get("source_path", source_key)
            backup_path = info.get("backup_path", "")
            if is_ignored_storage_path(source_path) or is_ignored_storage_path(backup_path):
                continue
            if not source_path or not backup_path or not Path(backup_path).is_file():
                continue
            rows.append(
                {
                    "source_key": source_key,
                    "source_path": source_path,
                    "backup_path": backup_path,
                    "created_at": info.get("created_at", ""),
                    "size": str(info.get("size", Path(backup_path).stat().st_size)),
                    "module": info.get("module") or self.source_module_label(source_path),
                    "file_type": info.get("file_type") or self.source_file_type_label(source_path),
                }
            )
        rows.sort(key=lambda item: (item["created_at"], item["source_path"]), reverse=True)
        if not rows:
            messagebox.showinfo(APP_TITLE, "No source backups are available yet.")
            return

        window = tk.Toplevel(self)
        window.title("Restore Source Backup")
        window.geometry("1120x720")
        window.minsize(860, 560)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)

        shell = ttk.Frame(window, padding=12)
        shell.pack(fill="both", expand=True)
        shell.rowconfigure(1, weight=1)
        shell.columnconfigure(0, weight=1)
        ttk.Label(
            shell,
            text="Restore replaces the source file on disk with its latest pre-save backup. Reload the mission or file after restoring if it is currently open.",
            style="FieldMuted.TLabel",
            wraplength=900,
            justify="left",
        ).grid(row=0, column=0, sticky="ew", pady=(0, 10))

        panes = ttk.PanedWindow(shell, orient="vertical")
        panes.grid(row=1, column=0, sticky="nsew")
        list_frame = ttk.Frame(panes)
        preview_frame = ttk.LabelFrame(panes, text="Backup preview", padding=8)
        panes.add(list_frame, weight=2)
        panes.add(preview_frame, weight=3)
        list_frame.rowconfigure(0, weight=1)
        list_frame.columnconfigure(0, weight=1)

        columns = ("module", "type", "created", "size", "backup")
        tree = ttk.Treeview(list_frame, columns=columns, show="tree headings", selectmode="browse", style="Economy.Treeview")
        tree.heading("#0", text="Source")
        tree.heading("module", text="Module")
        tree.heading("type", text="Type")
        tree.heading("created", text="Backup time")
        tree.heading("size", text="Bytes")
        tree.heading("backup", text="Backup file")
        tree.column("#0", width=340, anchor="w", stretch=True)
        tree.column("module", width=100, anchor="w", stretch=False)
        tree.column("type", width=90, anchor="w", stretch=False)
        tree.column("created", width=160, anchor="w", stretch=False)
        tree.column("size", width=90, anchor="e", stretch=False)
        tree.column("backup", width=300, anchor="w", stretch=True)
        tree.grid(row=0, column=0, sticky="nsew")
        scroll_y = ttk.Scrollbar(list_frame, command=tree.yview)
        scroll_y.grid(row=0, column=1, sticky="ns")
        scroll_x = ttk.Scrollbar(list_frame, command=tree.xview, orient="horizontal")
        scroll_x.grid(row=1, column=0, sticky="ew")
        tree.configure(yscrollcommand=scroll_y.set, xscrollcommand=scroll_x.set)

        preview_frame.rowconfigure(0, weight=1)
        preview_frame.columnconfigure(0, weight=1)
        preview_text = tk.Text(
            preview_frame,
            wrap="none",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            insertbackground=GRAPHITE_TEXT,
            selectbackground=GRAPHITE_ACCENT_DARK,
            selectforeground="#ffffff",
            relief="flat",
            borderwidth=0,
            highlightthickness=1,
            highlightbackground=GRAPHITE_BORDER,
            highlightcolor=GRAPHITE_ACCENT,
            font=("Consolas", 9),
        )
        preview_text.grid(row=0, column=0, sticky="nsew")
        preview_y = ttk.Scrollbar(preview_frame, command=preview_text.yview)
        preview_y.grid(row=0, column=1, sticky="ns")
        preview_x = ttk.Scrollbar(preview_frame, command=preview_text.xview, orient="horizontal")
        preview_x.grid(row=1, column=0, sticky="ew")
        preview_text.configure(yscrollcommand=preview_y.set, xscrollcommand=preview_x.set, state="disabled")

        row_by_iid = {}
        for index, row in enumerate(rows):
            iid = f"backup-{index}"
            row_by_iid[iid] = row
            tree.insert(
                "",
                "end",
                iid=iid,
                text=row["source_path"],
                values=(row["module"], row["file_type"], row["created_at"], row["size"], row["backup_path"]),
            )

        def selected_backup_row():
            selected = tree.selection()
            if not selected:
                return None
            return row_by_iid.get(selected[0])

        def refresh_preview(_event=None):
            row = selected_backup_row()
            preview_text.configure(state="normal")
            preview_text.delete("1.0", "end")
            if row:
                preview_text.insert("end", self.backup_preview_text(row["backup_path"]))
            else:
                preview_text.insert("end", "Select a backup to preview it.")
            preview_text.configure(state="disabled")

        def restore_selected():
            row = selected_backup_row()
            if not row:
                messagebox.showwarning(APP_TITLE, "Select a backup to restore.", parent=window)
                return
            source_path = row["source_path"]
            backup_path = row["backup_path"]
            if is_ignored_storage_path(source_path) or is_ignored_storage_path(backup_path):
                messagebox.showwarning(APP_TITLE, "storage_1 is always ignored and cannot be restored.", parent=window)
                return
            if not messagebox.askyesno(
                APP_TITLE,
                f"This will overwrite:\n{source_path}\n\nwith backup:\n{backup_path}\n\nContinue?",
                parent=window,
            ):
                return
            try:
                Path(source_path).parent.mkdir(parents=True, exist_ok=True)
                Path(source_path).write_bytes(Path(backup_path).read_bytes())
            except OSError as exc:
                messagebox.showerror(APP_TITLE, f"Restore failed:\n{exc}", parent=window)
                return
            self.log(f"Restored backup to source: {source_path}", "success")
            self.set_status("Backup restored; reload the affected file or mission", "success")
            window.destroy()

        def open_backup_folder():
            row = selected_backup_row()
            folder = Path(row["backup_path"]).parent if row else source_backup_dir()
            try:
                os.startfile(str(folder))
            except OSError as exc:
                messagebox.showerror(APP_TITLE, f"Could not open backup folder:\n{exc}", parent=window)

        actions = ttk.Frame(shell)
        actions.grid(row=3, column=0, columnspan=2, sticky="e", pady=(12, 0))
        self.make_button(actions, "Restore selected", restore_selected, variant="save")
        self.make_button(actions, "Open backup folder", open_backup_folder, variant="action")
        self.make_button(actions, "Close", window.destroy)
        tree.bind("<<TreeviewSelect>>", refresh_preview)
        tree.bind("<Double-Button-1>", lambda _event: restore_selected())
        window.bind("<Escape>", lambda _event: window.destroy())
        first = tree.get_children()
        if first:
            tree.selection_set(first[0])
            refresh_preview()
        window.after(20, lambda: center_window(window, self))
        window.grab_set()
        self.wait_window(window)

    def update_auto_change_report_setting(self):
        self.saved_settings["auto_change_reports"] = bool(self.auto_change_reports_var.get())
        save_settings(self.saved_settings)
        state = "enabled" if self.auto_change_reports_var.get() else "disabled"
        self.log(f"Automatic local change reports {state}.", "muted")

    def entries_for_sources(self, entries, source_paths):
        source_keys = {self.normalized_path(path) for path in source_paths}
        return [entry for entry in entries if self.normalized_path(entry.source_path) in source_keys]

    def create_change_report_interactive(self, source_path=None, use_current_context=True):
        if not self.entries and not self.event_entries and not self.territory_zones and not self.config_paths and not self.profile_config_paths:
            messagebox.showwarning(APP_TITLE, "Load at least one supported file first.")
            return False

        target_source = source_path or (self.current_save_source_path() if use_current_context else "")
        if target_source and (self.is_config_source_path(target_source) or self.is_economycore_source_path(target_source)):
            messagebox.showinfo(APP_TITLE, "This source does not have a structured economy change report yet.")
            return False
        if target_source:
            source_paths = [target_source] if self.source_has_changes(target_source) else []
        else:
            source_paths = self.changed_source_paths()

        if not source_paths:
            messagebox.showinfo(APP_TITLE, "No changes to report.")
            return False

        report = self.change_report_for_sources(source_paths)
        if not self.report_has_changes(report):
            messagebox.showinfo(APP_TITLE, "No changes to report.")
            return False

        if len(source_paths) == 1:
            initialdir = os.path.dirname(source_paths[0])
            initialfile = os.path.basename(self.get_change_report_path(source_paths[0]))
        else:
            initialdir = self.saved_settings.get("last_dir", str(Path.home()))
            initialfile = "RaG_Economy_Manager.change_report.txt"
        output_path = filedialog.asksaveasfilename(
            title="Save change report",
            initialdir=initialdir,
            initialfile=initialfile,
            defaultextension=".txt",
            filetypes=[("Text files", "*.txt"), ("All files", "*.*")],
        )
        if not output_path:
            return False
        try:
            Path(output_path).parent.mkdir(parents=True, exist_ok=True)
            Path(output_path).write_text(report, encoding="utf-8")
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Could not write change report:\n{exc}")
            return False

        self.saved_settings["last_dir"] = os.path.dirname(output_path)
        self.log(f"Wrote change report: {output_path}", "success")
        self.set_status("Change report saved", "success")
        return True

    def confirm_export_with_errors(self):
        errors = [issue for issue in self.issues if issue.severity == "error"]
        if not errors:
            return True
        return messagebox.askyesno(APP_TITLE, f"There are {len(errors)} validation error(s). Save anyway?")

    def source_write_permission_message(self, source_path, exc=None):
        path = Path(source_path)
        path_text = str(path)
        lower_path = path_text.casefold()
        lines = [
            "Cannot write source file.",
            "",
            f"File: {path_text}",
        ]
        if exc is not None:
            lines.append(f"Windows error: {exc}")
        lines.extend(
            [
                "",
                "Likely causes:",
                "- File or folder is read-only.",
                "- DayZ server, Steam, editor, or sync tool has the file locked.",
                "- Current Windows user has no write permission for this folder.",
            ]
        )
        if "program files" in lower_path or "steamapps" in lower_path:
            lines.append("- Mission is under Program Files / Steam. Windows can block normal apps from writing there.")
        if f"{os.sep}db{os.sep}" in lower_path or "/db/" in lower_path.replace("\\", "/"):
            lines.append("- File is inside mission db folder; check write access on the whole mission folder, not only the file.")
        lines.extend(
            [
                "",
                "Fix:",
                "- Stop the server and close other editors using the mission files.",
                "- Remove read-only from the mission folder and files.",
                "- Move/copy the mission to a writable folder, edit it there, then copy it back.",
                "- Or run RaG Economy Manager as Administrator if you insist on editing under Steam/Program Files.",
            ]
        )
        return "\n".join(lines)

    def ensure_source_writable(self, source_path):
        if is_ignored_storage_path(source_path):
            raise OSError("Access blocked: storage_1 is always ignored.")
        path = Path(source_path)
        parent = path.parent
        try:
            if path.exists():
                if not path.is_file():
                    raise OSError(f"Source path is not a file: {source_path}")
                with path.open("r+b"):
                    pass
                return
            if not parent.exists():
                raise OSError(f"Parent folder does not exist: {parent}")
            temp_path = ""
            try:
                with tempfile.NamedTemporaryFile(prefix=".rag_write_test_", dir=str(parent), delete=False) as handle:
                    temp_path = handle.name
                    handle.write(b"")
            finally:
                if temp_path:
                    try:
                        Path(temp_path).unlink(missing_ok=True)
                    except OSError:
                        pass
        except PermissionError as exc:
            raise OSError(self.source_write_permission_message(source_path, exc)) from exc
        except OSError as exc:
            winerror = getattr(exc, "winerror", None)
            if winerror in {5, 32, 33}:
                raise OSError(self.source_write_permission_message(source_path, exc)) from exc
            raise

    def normalized_path(self, path):
        return os.path.normcase(os.path.abspath(path))

    def is_dedicated_module_source_path(self, path):
        source_key = self.normalized_path(path)
        if self.is_environment_source_path(path):
            return True
        if self.is_weather_source_path(path):
            return True
        if self.is_economycore_source_path(path):
            return True
        if self.is_mapgroupproto_source_path(path):
            return True
        if source_key in {self.normalized_path(type_path) for type_path in self.loaded_paths}:
            return True
        if source_key in {self.normalized_path(spawnable_path) for spawnable_path in self.spawnable_source_paths()}:
            return True
        if source_key in {self.normalized_path(random_path) for random_path in self.random_preset_source_paths()}:
            return True
        if source_key in {self.normalized_path(event_path) for event_path in self.event_source_paths() + self.event_spawn_source_paths() + self.event_group_source_paths()}:
            return True
        if source_key in {self.normalized_path(territory_path) for territory_path in self.territory_source_paths()}:
            return True
        if Path(path).name.casefold() == "cfglimitsdefinition.xml":
            return True
        return False

    def is_config_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(config_path) for config_path in self.config_paths + self.profile_config_paths} and not self.is_dedicated_module_source_path(path)

    def is_weather_source_path(self, path):
        weather_path = self.__dict__.get("weather_path", "")
        return bool(weather_path) and self.normalized_path(path) == self.normalized_path(weather_path)

    def is_economycore_source_path(self, path):
        economycore_path = self.__dict__.get("economycore_path", "")
        return bool(economycore_path) and self.normalized_path(path) == self.normalized_path(economycore_path)

    def is_environment_source_path(self, path):
        environment_path = self.__dict__.get("environment_path", "")
        return bool(environment_path) and self.normalized_path(path) == self.normalized_path(environment_path)

    def is_mapgroupproto_source_path(self, path):
        mapgroupproto_path = self.__dict__.get("mapgroupproto_path", "")
        if not mapgroupproto_path and getattr(self.__dict__.get("mission_workspace", None), "root_path", ""):
            mapgroupproto_path = self.find_mapgroupproto_path()
        return bool(mapgroupproto_path) and self.normalized_path(path) == self.normalized_path(mapgroupproto_path)

    def is_profile_config_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(config_path) for config_path in self.profile_config_paths}

    def is_type_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(type_path) for type_path in self.loaded_paths}

    def is_spawnable_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(spawnable_path) for spawnable_path in self.spawnable_source_paths()}

    def is_random_preset_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(random_path) for random_path in self.random_preset_source_paths()}

    def is_event_spawn_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(spawn_path) for spawn_path in self.event_spawn_source_paths()}

    def is_event_group_source_path(self, path):
        source_key = self.normalized_path(path)
        return source_key in {self.normalized_path(group_path) for group_path in self.event_group_source_paths()}

    def all_save_source_paths(self):
        paths = []
        seen = set()
        weather_paths = [self.weather_path] if self.weather_path else []
        economycore_paths = [self.economycore_path] if self.economycore_path else []
        environment_path = self.__dict__.get("environment_path", "")
        environment_root = self.__dict__.get("environment_root")
        environment_paths = [environment_path] if environment_path and environment_root is not None else []
        mapgroupproto_path = self.__dict__.get("mapgroupproto_path", "")
        if not mapgroupproto_path and getattr(self.__dict__.get("mission_workspace", None), "root_path", ""):
            mapgroupproto_path = self.find_mapgroupproto_path()
        mapgroupproto_paths = [mapgroupproto_path] if mapgroupproto_path else []
        for path in self.loaded_paths + self.spawnable_source_paths() + self.random_preset_source_paths() + self.event_source_paths() + self.event_spawn_source_paths() + self.event_group_source_paths() + self.territory_source_paths() + environment_paths + weather_paths + economycore_paths + mapgroupproto_paths + self.config_paths + self.profile_config_paths:
            if is_ignored_storage_path(path):
                continue
            key = self.normalized_path(path)
            if key in seen:
                continue
            seen.add(key)
            paths.append(path)
        return paths

    def entries_for_source(self, entries, source_path):
        source_key = self.normalized_path(source_path)
        return [entry for entry in entries if self.normalized_path(entry.source_path) == source_key]

    def spawnable_entries_for_source(self, entries, source_path):
        source_key = self.normalized_path(source_path)
        return [entry for entry in entries if self.normalized_path(entry.source_path) == source_key]

    def random_preset_entries_for_source(self, entries, source_path):
        source_key = self.normalized_path(source_path)
        return [entry for entry in entries if self.normalized_path(entry.source_path) == source_key]

    def event_entries_for_source(self, entries, source_path):
        source_key = self.normalized_path(source_path)
        return [entry for entry in entries if self.normalized_path(entry.source_path) == source_key]

    def event_spawn_groups_for_source(self, groups, source_path):
        source_key = self.normalized_path(source_path)
        return [group for group in groups if self.normalized_path(group.source_path) == source_key]

    def event_group_definitions_for_source(self, groups, source_path):
        source_key = self.normalized_path(source_path)
        return [group for group in groups if self.normalized_path(group.source_path) == source_key]

    def territory_zones_for_source(self, zones, source_path):
        source_key = self.normalized_path(source_path)
        return [zone for zone in zones if self.normalized_path(zone.source_path) == source_key]

    def territory_group_signature_for_source(self, groups, source_path):
        return [
            (int(group.group_index or 0), dict(group.attributes or {}), str(group.name or ""))
            for group in self.territory_groups_for_source(groups, source_path)
        ]

    def change_report_for_source(self, source_path):
        if self.is_spawnable_source_path(source_path):
            return create_spawnable_type_change_report(
                self.spawnable_entries_for_source(self.original_spawnable_entries, source_path),
                self.spawnable_entries_for_source(self.spawnable_entries, source_path),
            )
        if self.is_random_preset_source_path(source_path):
            return create_random_preset_change_report(
                self.random_preset_entries_for_source(self.original_random_preset_entries, source_path),
                self.random_preset_entries_for_source(self.random_preset_entries, source_path),
            )
        if self.normalized_path(source_path) in {self.normalized_path(path) for path in self.event_source_paths()}:
            return create_event_change_report(
                self.event_entries_for_source(self.original_event_entries, source_path),
                self.event_entries_for_source(self.event_entries, source_path),
            )
        if self.is_event_spawn_source_path(source_path):
            before = [format_event_spawn_group_xml(group).strip() for group in self.event_spawn_groups_for_source(self.original_event_spawn_groups, source_path)]
            after = [format_event_spawn_group_xml(group).strip() for group in self.event_spawn_groups_for_source(self.event_spawn_groups, source_path)]
            return "No changes detected.\n" if before == after else f"CHANGED: cfgeventspawns.xml\nDefinitions: {len(before)} -> {len(after)}\n"
        if self.is_event_group_source_path(source_path):
            before = [format_event_group_definition_xml(group).strip() for group in self.event_group_definitions_for_source(self.original_event_group_definitions, source_path)]
            after = [format_event_group_definition_xml(group).strip() for group in self.event_group_definitions_for_source(self.event_group_definitions, source_path)]
            return "No changes detected.\n" if before == after else f"CHANGED: cfgeventgroups.xml\nGroups: {len(before)} -> {len(after)}\n"
        if self.normalized_path(source_path) in {self.normalized_path(path) for path in self.territory_source_paths()}:
            return create_territory_change_report(
                self.territory_zones_for_source(self.original_territory_zones, source_path),
                self.territory_zones_for_source(self.territory_zones, source_path),
            )
        return create_change_report(
            self.entries_for_source(self.original_entries, source_path),
            self.entries_for_source(self.entries, source_path),
        )

    def report_has_changes(self, report):
        return any(
            line.startswith(("ADDED:", "REMOVED:", "COUNT CHANGED:", "CHANGED:"))
            for line in str(report or "").splitlines()
        )

    def source_has_changes(self, source_path):
        source_key = self.normalized_path(source_path)
        if self.is_environment_source_path(source_path):
            return self.environment_root is not None and format_cfgenvironment_xml(self.environment_root) != self.environment_original_text
        if self.is_economycore_source_path(source_path):
            return self.economycore_current_text != self.economycore_original_text
        if self.is_mapgroupproto_source_path(source_path):
            return self.mapgroupproto_current_text != self.mapgroupproto_original_text
        if self.is_weather_source_path(source_path):
            return self.weather_values_from_vars() != self.original_weather_values
        if self.is_config_source_path(source_path):
            if source_key not in self.config_current_texts:
                return False
            self.capture_config_editor_text_for_path(source_path)
            return self.config_current_texts.get(source_key, "") != self.config_original_texts.get(source_key, "")
        if source_key in {self.normalized_path(path) for path in self.event_source_paths()}:
            return [format_event_xml(entry).strip() for entry in self.event_entries_for_source(self.original_event_entries, source_path)] != [format_event_xml(entry).strip() for entry in self.event_entries_for_source(self.event_entries, source_path)]
        if self.is_event_spawn_source_path(source_path):
            return [format_event_spawn_group_xml(group).strip() for group in self.event_spawn_groups_for_source(self.original_event_spawn_groups, source_path)] != [format_event_spawn_group_xml(group).strip() for group in self.event_spawn_groups_for_source(self.event_spawn_groups, source_path)]
        if self.is_event_group_source_path(source_path):
            return [format_event_group_definition_xml(group).strip() for group in self.event_group_definitions_for_source(self.original_event_group_definitions, source_path)] != [format_event_group_definition_xml(group).strip() for group in self.event_group_definitions_for_source(self.event_group_definitions, source_path)]
        if self.is_spawnable_source_path(source_path):
            return [format_spawnable_type_xml(entry).strip() for entry in self.spawnable_entries_for_source(self.original_spawnable_entries, source_path)] != [format_spawnable_type_xml(entry).strip() for entry in self.spawnable_entries_for_source(self.spawnable_entries, source_path)]
        if self.is_random_preset_source_path(source_path):
            return [format_random_preset_xml(entry).strip() for entry in self.random_preset_entries_for_source(self.original_random_preset_entries, source_path)] != [format_random_preset_xml(entry).strip() for entry in self.random_preset_entries_for_source(self.random_preset_entries, source_path)]
        if source_key in {self.normalized_path(path) for path in self.territory_source_paths()}:
            return (
                [format_territory_xml(zone).strip() for zone in self.territory_zones_for_source(self.original_territory_zones, source_path)]
                != [format_territory_xml(zone).strip() for zone in self.territory_zones_for_source(self.territory_zones, source_path)]
                or self.territory_group_signature_for_source(self.original_territory_groups, source_path)
                != self.territory_group_signature_for_source(self.territory_groups, source_path)
            )
        return self.report_has_changes(self.change_report_for_source(source_path))

    def source_save_sanity_warnings(self, source_path):
        source_key = self.normalized_path(source_path)
        if self.is_environment_source_path(source_path):
            if self.environment_root is None:
                return ["environment XML is not loaded"]
            warnings = []
            if self.environment_root.tag != "env":
                warnings.append(f"environment XML root is <{self.environment_root.tag}>")
            if self.environment_root.find("territories") is None:
                warnings.append("environment XML has no territories section")
            return warnings
        if self.is_weather_source_path(source_path):
            return []
        if self.is_economycore_source_path(source_path):
            warnings = []
            text = self.economycore_current_text or ""
            if not text.strip():
                warnings.append("economy core XML is empty")
            else:
                try:
                    self.parse_economycore_root_from_text(text)
                except (ET.ParseError, ValueError) as exc:
                    warnings.append(f"economy core XML is invalid: {exc}")
            return warnings
        if self.is_mapgroupproto_source_path(source_path):
            warnings = []
            text = self.mapgroupproto_current_text or ""
            if not text.strip():
                warnings.append("mapgroupproto XML is empty")
            else:
                try:
                    root = ET.fromstring(text)
                    if root.tag.casefold() not in {"prototype", "mapgroupproto"}:
                        warnings.append(f"mapgroupproto XML root is <{root.tag}>")
                except ET.ParseError as exc:
                    warnings.append(f"mapgroupproto XML is invalid: {exc}")
            return warnings
        warnings = []
        if self.is_config_source_path(source_path):
            self.capture_config_editor_text_for_path(source_path)
            text = self.config_current_texts.get(source_key)
            if text is None:
                warnings.append("config source is not loaded in the editor")
            elif text.strip() == "":
                warnings.append("config output is empty")
            elif looks_like_empty_types_xml(text):
                warnings.append("config output looks like an empty types.xml file")
            return warnings
        if source_key in {self.normalized_path(path) for path in self.event_source_paths()}:
            if not self.event_entries_for_source(self.event_entries, source_path):
                warnings.append("event output contains no event entries")
            return warnings
        if self.is_event_spawn_source_path(source_path):
            return warnings
        if self.is_event_group_source_path(source_path):
            return warnings
        if self.is_spawnable_source_path(source_path):
            if not self.spawnable_entries_for_source(self.spawnable_entries, source_path):
                warnings.append("spawnabletypes output contains no type entries")
            return warnings
        if self.is_random_preset_source_path(source_path):
            if not self.random_preset_entries_for_source(self.random_preset_entries, source_path):
                warnings.append("randompresets output contains no preset entries")
            return warnings
        if source_key in {self.normalized_path(path) for path in self.territory_source_paths()}:
            if not self.territory_zones_for_source(self.territory_zones, source_path):
                warnings.append("territory output contains no zones")
            return warnings
        if self.is_type_source_path(source_path):
            if not self.entries_for_source(self.entries, source_path):
                warnings.append("type output would be empty <types />")
            return warnings
        warnings.append("source type is unknown")
        return warnings

    def confirm_source_save_sanity(self, source_paths):
        problems = []
        for source_path in source_paths:
            warnings = self.source_save_sanity_warnings(source_path)
            if warnings:
                problems.append((source_path, warnings))
        if not problems:
            return True
        lines = []
        for source_path, warnings in problems[:12]:
            lines.append(f"{source_path}")
            for warning in warnings:
                lines.append(f"  - {warning}")
        if len(problems) > 12:
            lines.append(f"... and {len(problems) - 12} more source file(s).")
        message = (
            "Some source files would save suspicious or empty output.\n\n"
            + "\n".join(lines)
            + "\n\nContinue anyway?"
        )
        return messagebox.askyesno(APP_TITLE, message)

    def dirty_source_keys(self):
        return set(self.dirty_source_keys_cache)

    def has_unsaved_changes(self):
        return bool(self.dirty_source_keys_cache)

    def mark_source_dirty(self, source_path):
        if not source_path:
            return
        self.dirty_source_keys_cache.add(self.normalized_path(source_path))
        self.workspace_validation_stale = True
        self.set_dirty(True)

    def recompute_dirty_sources(self):
        self.dirty_source_keys_cache = {self.normalized_path(path) for path in self.all_save_source_paths() if self.source_has_changes(path)}
        self.set_dirty(bool(self.dirty_source_keys_cache))

    def cached_source_has_changes(self, source_path):
        if self.is_config_source_path(source_path):
            self.capture_config_editor_text_for_path(source_path)
            key = self.normalized_path(source_path)
            if self.config_current_texts.get(key, "") != self.config_original_texts.get(key, ""):
                self.dirty_source_keys_cache.add(key)
            else:
                self.dirty_source_keys_cache.discard(key)
                self.set_dirty(True)
        return self.normalized_path(source_path) in self.dirty_source_keys_cache

    def current_save_source_path(self):
        if self.active_module == "environment":
            return self.environment_source_path()
        if self.active_module == "weather":
            return self.weather_path
        if self.active_module == "economy_core":
            return self.economycore_path
        if self.active_module == "mapgroupproto":
            return self.mapgroupproto_path
        if self.active_module == "configs":
            return self.selected_config_path
        if self.active_module == "profiles":
            return self.selected_profile_config_path
        if self.active_module == "spawnabletypes":
            if self.current_spawnable_index is not None and 0 <= self.current_spawnable_index < len(self.spawnable_entries):
                return self.spawnable_entries[self.current_spawnable_index].source_path
            spawnable_paths = self.spawnable_source_paths()
            if len(spawnable_paths) == 1:
                return spawnable_paths[0]
        if self.active_module == "randompresets":
            if self.current_random_preset_index is not None and 0 <= self.current_random_preset_index < len(self.random_preset_entries):
                return self.random_preset_entries[self.current_random_preset_index].source_path
            random_paths = self.random_preset_source_paths()
            if len(random_paths) == 1:
                return random_paths[0]
        if self.active_module == "territories":
            if self.current_territory_index is not None and 0 <= self.current_territory_index < len(self.territory_zones):
                return self.territory_zones[self.current_territory_index].source_path
            territory_paths = self.territory_source_paths()
            if len(territory_paths) == 1:
                return territory_paths[0]
        if self.active_module == "events":
            if self.current_event_index is not None and 0 <= self.current_event_index < len(self.event_entries):
                return self.event_entries[self.current_event_index].source_path
            event_paths = self.event_source_paths()
            if len(event_paths) == 1:
                return event_paths[0]
        if self.selected_source_path:
            return self.selected_source_path
        if self.current_index is not None and 0 <= self.current_index < len(self.entries):
            return self.entries[self.current_index].source_path
        selected = self.source_listbox.curselection() if hasattr(self, "source_listbox") else ()
        if selected:
            return self.loaded_paths[selected[0]]
        if len(self.loaded_paths) == 1:
            return self.loaded_paths[0]
        return ""

    def save_source_file(self, source_path, allow_suspicious=False):
        if is_ignored_storage_path(source_path):
            raise OSError("Access blocked: storage_1 is always ignored.")
        source_key = self.normalized_path(source_path)
        if not allow_suspicious:
            warnings = self.source_save_sanity_warnings(source_path)
            if warnings:
                raise OSError(f"Suspicious save refused for {source_path}: {'; '.join(warnings)}")
        self.ensure_source_writable(source_path)
        if self.is_environment_source_path(source_path):
            if self.environment_root is None:
                raise OSError("Environment XML is not loaded, save blocked.")
            if Path(source_path).is_file():
                self.create_pre_save_backup(source_path)
            count = write_cfgenvironment_file(self.environment_root, source_path)
            self.sync_environment_workspace_links()
            return count
        if self.is_economycore_source_path(source_path):
            try:
                self.parse_economycore_root_from_text(self.economycore_current_text)
            except (ET.ParseError, ValueError) as exc:
                raise OSError(f"Economy Core XML is invalid, save blocked: {exc}") from exc
            if Path(source_path).is_file():
                self.create_pre_save_backup(source_path)
            Path(source_path).parent.mkdir(parents=True, exist_ok=True)
            Path(source_path).write_text(self.economycore_current_text, encoding="utf-8")
            return len(self.economycore_current_text.splitlines())
        if self.is_mapgroupproto_source_path(source_path):
            ET.fromstring(self.mapgroupproto_current_text)
            self.create_pre_save_backup(source_path)
            Path(source_path).write_text(self.mapgroupproto_current_text, encoding="utf-8")
            return len(self.mapgroupproto_current_text.splitlines())
        if self.is_weather_source_path(source_path):
            values = self.weather_values_from_vars()
            self.create_pre_save_backup(source_path)
            write_weather_config_file(values, source_path)
            return len(values)
        if self.is_config_source_path(source_path):
            if source_key not in self.config_current_texts:
                raise OSError(f"Config file is not loaded for editing, refusing to overwrite: {source_path}")
            self.capture_config_editor_text_for_path(source_path)
            if looks_like_empty_types_xml(self.config_current_texts.get(source_key, "")):
                raise OSError(f"Refusing to write empty types.xml content to config file: {source_path}")
            self.create_pre_save_backup(source_path)
            Path(source_path).write_text(self.config_current_texts.get(source_key, ""), encoding="utf-8")
            return len(self.config_current_texts.get(source_key, "").splitlines())
        if self.is_event_spawn_source_path(source_path):
            current_groups = self.event_spawn_groups_for_source(self.event_spawn_groups, source_path)
            self.create_pre_save_backup(source_path)
            write_event_spawns_file(current_groups, source_path)
            return len(current_groups)
        if self.is_event_group_source_path(source_path):
            current_groups = self.event_group_definitions_for_source(self.event_group_definitions, source_path)
            self.create_pre_save_backup(source_path)
            write_event_groups_file(current_groups, source_path)
            return len(current_groups)
        if self.normalized_path(source_path) in {self.normalized_path(path) for path in self.event_source_paths()}:
            current_events = self.event_entries_for_source(self.event_entries, source_path)
            self.create_pre_save_backup(source_path)
            write_events_file(current_events, source_path)
            return len(current_events)
        if self.is_spawnable_source_path(source_path):
            current_entries = self.spawnable_entries_for_source(self.spawnable_entries, source_path)
            self.create_pre_save_backup(source_path)
            write_spawnable_types_file(current_entries, source_path)
            return len(current_entries)
        if self.is_random_preset_source_path(source_path):
            current_entries = self.random_preset_entries_for_source(self.random_preset_entries, source_path)
            self.create_pre_save_backup(source_path)
            write_random_presets_file(current_entries, source_path)
            return len(current_entries)
        if self.normalized_path(source_path) in {self.normalized_path(path) for path in self.territory_source_paths()}:
            current_zones = self.territory_zones_for_source(self.territory_zones, source_path)
            current_groups = self.territory_groups_for_source(self.territory_groups, source_path)
            self.create_pre_save_backup(source_path)
            write_territory_file(current_zones, source_path, current_groups)
            return len(current_zones)
        if not self.is_type_source_path(source_path):
            raise OSError(f"Unknown source type, refusing to overwrite: {source_path}")
        current_entries = self.entries_for_source(self.entries, source_path)
        self.create_pre_save_backup(source_path)
        write_types_file(current_entries, source_path, keep_duplicates=True)
        return len(current_entries)

    def mark_source_saved(self, source_path):
        source_key = self.normalized_path(source_path)
        if self.is_environment_source_path(source_path):
            self.environment_original_text = format_cfgenvironment_xml(self.environment_root) if self.environment_root is not None else ""
            if self.mission_workspace and source_path not in self.mission_workspace.cfgenvironment_paths:
                self.mission_workspace.cfgenvironment_paths.append(source_path)
        elif self.is_economycore_source_path(source_path):
            self.economycore_original_text = self.economycore_current_text
            if self.mission_workspace and source_path not in self.mission_workspace.cfgeconomycore_paths:
                self.mission_workspace.cfgeconomycore_paths.append(source_path)
        elif self.is_mapgroupproto_source_path(source_path):
            self.mapgroupproto_original_text = self.mapgroupproto_current_text
        elif self.is_weather_source_path(source_path):
            self.weather_values = self.weather_values_from_vars()
            self.original_weather_values = dict(self.weather_values)
        elif self.is_config_source_path(source_path):
            if source_key in self.config_current_texts:
                self.config_original_texts[source_key] = self.config_current_texts.get(source_key, "")
        elif self.is_event_spawn_source_path(source_path):
            self.original_event_spawn_groups = [
                group for group in self.original_event_spawn_groups
                if self.normalized_path(group.source_path) != source_key
            ]
            self.original_event_spawn_groups.extend(group.clone() for group in self.event_spawn_groups_for_source(self.event_spawn_groups, source_path))
        elif self.is_event_group_source_path(source_path):
            self.original_event_group_definitions = [
                group for group in self.original_event_group_definitions
                if self.normalized_path(group.source_path) != source_key
            ]
            self.original_event_group_definitions.extend(group.clone() for group in self.event_group_definitions_for_source(self.event_group_definitions, source_path))
        elif source_key in {self.normalized_path(path) for path in self.event_source_paths()}:
            self.original_event_entries = [
                entry
                for entry in self.original_event_entries
                if self.normalized_path(entry.source_path) != source_key
            ]
            self.original_event_entries.extend(entry.clone() for entry in self.event_entries_for_source(self.event_entries, source_path))
        elif self.is_spawnable_source_path(source_path):
            self.original_spawnable_entries = [
                entry
                for entry in self.original_spawnable_entries
                if self.normalized_path(entry.source_path) != source_key
            ]
            self.original_spawnable_entries.extend(entry.clone() for entry in self.spawnable_entries_for_source(self.spawnable_entries, source_path))
        elif self.is_random_preset_source_path(source_path):
            self.original_random_preset_entries = [
                entry
                for entry in self.original_random_preset_entries
                if self.normalized_path(entry.source_path) != source_key
            ]
            self.original_random_preset_entries.extend(entry.clone() for entry in self.random_preset_entries_for_source(self.random_preset_entries, source_path))
        elif source_key in {self.normalized_path(path) for path in self.territory_source_paths()}:
            self.original_territory_zones = [
                zone
                for zone in self.original_territory_zones
                if self.normalized_path(zone.source_path) != source_key
            ]
            self.original_territory_zones.extend(zone.clone() for zone in self.territory_zones_for_source(self.territory_zones, source_path))
            self.original_territory_groups = [
                group
                for group in self.original_territory_groups
                if self.normalized_path(group.source_path) != source_key
            ]
            self.original_territory_groups.extend(group.clone() for group in self.territory_groups_for_source(self.territory_groups, source_path))
        else:
            self.original_entries = [
                entry
                for entry in self.original_entries
                if self.normalized_path(entry.source_path) != source_key
            ]
            self.original_entries.extend(entry.clone() for entry in self.entries_for_source(self.entries, source_path))
        self.dirty_source_keys_cache.discard(source_key)
        self.set_dirty(True)

    def mark_all_saved(self):
        self.original_entries = [entry.clone() for entry in self.entries]
        self.original_spawnable_entries = [entry.clone() for entry in self.spawnable_entries]
        self.original_random_preset_entries = [entry.clone() for entry in self.random_preset_entries]
        self.original_event_entries = [entry.clone() for entry in self.event_entries]
        self.original_event_spawn_groups = [group.clone() for group in self.event_spawn_groups]
        self.original_event_group_definitions = [group.clone() for group in self.event_group_definitions]
        self.original_territory_zones = [zone.clone() for zone in self.territory_zones]
        self.original_territory_groups = [group.clone() for group in self.territory_groups]
        self.original_territory_groups = [group.clone() for group in self.territory_groups]
        environment_root = self.__dict__.get("environment_root")
        self.environment_original_text = format_cfgenvironment_xml(environment_root) if environment_root is not None else ""
        self.original_weather_values = dict(self.weather_values_from_vars())
        self.economycore_original_text = self.economycore_current_text
        self.config_original_texts = dict(self.config_current_texts)
        self.dirty_source_keys_cache = set()
        self.set_dirty(False)

    def change_report_for_sources(self, source_paths):
        type_paths = [path for path in source_paths if self.normalized_path(path) in {self.normalized_path(type_path) for type_path in self.loaded_paths}]
        spawnable_paths = [path for path in source_paths if self.is_spawnable_source_path(path)]
        random_preset_paths = [path for path in source_paths if self.is_random_preset_source_path(path)]
        event_paths = [path for path in source_paths if self.normalized_path(path) in {self.normalized_path(event_path) for event_path in self.event_source_paths()}]
        event_spawn_paths = [path for path in source_paths if self.is_event_spawn_source_path(path)]
        event_group_paths = [path for path in source_paths if self.is_event_group_source_path(path)]
        territory_paths = [path for path in source_paths if self.normalized_path(path) in {self.normalized_path(territory_path) for territory_path in self.territory_source_paths()}]
        reports = []
        if type_paths:
            reports.append(create_change_report(
                self.entries_for_sources(self.original_entries, type_paths),
                self.entries_for_sources(self.entries, type_paths),
            ))
        if spawnable_paths:
            reports.append(create_spawnable_type_change_report(
                self.entries_for_sources(self.original_spawnable_entries, spawnable_paths),
                self.entries_for_sources(self.spawnable_entries, spawnable_paths),
            ))
        if random_preset_paths:
            reports.append(create_random_preset_change_report(
                self.entries_for_sources(self.original_random_preset_entries, random_preset_paths),
                self.entries_for_sources(self.random_preset_entries, random_preset_paths),
            ))
        if event_paths:
            reports.append(create_event_change_report(
                self.entries_for_sources(self.original_event_entries, event_paths),
                self.entries_for_sources(self.event_entries, event_paths),
            ))
        reports.extend(self.change_report_for_source(path) for path in event_spawn_paths + event_group_paths)
        if territory_paths:
            reports.append(create_territory_change_report(
                self.entries_for_sources(self.original_territory_zones, territory_paths),
                self.entries_for_sources(self.territory_zones, territory_paths),
            ))
        return "\n".join(report.strip() for report in reports if report.strip()) + ("\n" if reports else "")

    def auto_save_change_report(self, source_paths):
        if not self.auto_change_reports_var.get():
            return ""
        changed_paths = [path for path in source_paths if self.source_has_changes(path)]
        if not changed_paths:
            return ""
        report = self.change_report_for_sources(changed_paths)
        if not self.report_has_changes(report):
            return ""
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        if len(changed_paths) == 1:
            base_name = Path(changed_paths[0]).stem
        else:
            base_name = "multiple_sources"
        safe_name = re.sub(r"[^A-Za-z0-9_.-]+", "_", base_name).strip("._") or "change_report"
        output_path = self.local_change_report_dir() / f"{timestamp}_{safe_name}.change_report.txt"
        try:
            output_path.write_text(report, encoding="utf-8")
        except OSError as exc:
            self.log(f"Could not save local change report: {exc}", "warning")
            return ""
        self.log(f"Saved local change report: {output_path}", "success")
        return str(output_path)

    def show_change_report_preview(self, report, title="Change report"):
        window = tk.Toplevel(self)
        window.title(title)
        window.geometry("920x620")
        window.minsize(720, 460)
        window.configure(bg=GRAPHITE_BG)
        window.transient(self)
        apply_app_icon(window)
        frame = ttk.Frame(window, padding=12)
        frame.pack(fill="both", expand=True)
        frame.rowconfigure(0, weight=1)
        frame.columnconfigure(0, weight=1)
        text = tk.Text(
            frame,
            wrap="none",
            bg=GRAPHITE_FIELD,
            fg=GRAPHITE_TEXT,
            insertbackground=GRAPHITE_TEXT,
            selectbackground=GRAPHITE_ACCENT_DARK,
            selectforeground="#ffffff",
            relief="flat",
            borderwidth=0,
            highlightthickness=1,
            highlightbackground=GRAPHITE_BORDER,
            highlightcolor=GRAPHITE_ACCENT,
            font=("Consolas", 9),
        )
        text.grid(row=0, column=0, sticky="nsew")
        text.insert("1.0", report)
        text.configure(state="disabled")
        y_scroll = ttk.Scrollbar(frame, command=text.yview)
        y_scroll.grid(row=0, column=1, sticky="ns")
        x_scroll = ttk.Scrollbar(frame, command=text.xview, orient="horizontal")
        x_scroll.grid(row=1, column=0, sticky="ew")
        text.configure(yscrollcommand=y_scroll.set, xscrollcommand=x_scroll.set)
        actions = ttk.Frame(frame)
        actions.grid(row=2, column=0, columnspan=2, sticky="e", pady=(10, 0))
        self.make_button(actions, "Close", window.destroy, primary=True)
        window.grab_set()
        window.after(20, lambda: center_window(window, self))
        self.wait_window(window)

    def prompt_change_report_preview(self, source_paths):
        source_paths = [path for path in source_paths if self.source_has_changes(path) and not self.is_config_source_path(path)]
        if not source_paths:
            return
        report = self.change_report_for_sources(source_paths)
        if not self.report_has_changes(report):
            return
        if messagebox.askyesno(APP_TITLE, "Show change report before saving?"):
            self.show_change_report_preview(report)

    def save_original(self):
        if not self.entries and not self.spawnable_entries and not self.random_preset_entries and not self.event_entries and not self.territory_zones and not self.economycore_path and self.environment_root is None and not self.config_paths and not self.profile_config_paths:
            messagebox.showwarning(APP_TITLE, "Load one supported file first.")
            return
        source_path = self.current_save_source_path()
        if not source_path:
            messagebox.showwarning(APP_TITLE, "Select a source file or type entry first, or use Save All.")
            return
        if not self.confirm_export_with_errors():
            return

        changed = self.cached_source_has_changes(source_path)
        proceed = messagebox.askyesno(APP_TITLE, f"This will save the selected source file:\n{source_path}\n\nContinue?")
        if not proceed:
            return
        if not self.confirm_source_save_sanity([source_path]):
            return
        if changed and not self.is_config_source_path(source_path) and not self.is_economycore_source_path(source_path) and not self.is_environment_source_path(source_path):
            self.auto_save_change_report([source_path])

        try:
            entry_count = self.save_source_file(source_path, allow_suspicious=True)
        except OSError as exc:
            messagebox.showerror(APP_TITLE, f"Save failed:\n{exc}")
            return

        self.mark_source_saved(source_path)
        unit = "line(s)" if self.is_config_source_path(source_path) or self.is_economycore_source_path(source_path) else "entries"
        if changed:
            self.log(f"Saved {entry_count} {unit} to selected source: {source_path}", "success")
        else:
            self.log(f"Saved selected source with no content changes: {source_path}", "success")
        self.set_status("Save complete", "success")

    def save_all_sources(self):
        dirty_keys = set(self.dirty_source_keys_cache)
        if self.selected_config_path:
            self.cached_source_has_changes(self.selected_config_path)
            dirty_keys = set(self.dirty_source_keys_cache)
        if self.selected_profile_config_path:
            self.cached_source_has_changes(self.selected_profile_config_path)
            dirty_keys = set(self.dirty_source_keys_cache)
        save_paths = [path for path in self.all_save_source_paths() if self.normalized_path(path) in dirty_keys]
        if not save_paths:
            messagebox.showinfo(APP_TITLE, "No unsaved source files to save.")
            return
        if not self.confirm_export_with_errors():
            return

        proceed = messagebox.askyesno(APP_TITLE, f"This will save {len(save_paths)} changed source file(s).\n\nContinue?")
        if not proceed:
            return
        if not self.confirm_source_save_sanity(save_paths):
            return
        report_paths = [path for path in save_paths if not self.is_config_source_path(path) and not self.is_economycore_source_path(path) and not self.is_environment_source_path(path)]
        if report_paths:
            self.auto_save_change_report(report_paths)

        saved = []
        try:
            for source_path in save_paths:
                entry_count = self.save_source_file(source_path, allow_suspicious=True)
                saved.append((source_path, entry_count))
        except (OSError, ValueError, ET.ParseError) as exc:
            messagebox.showerror(APP_TITLE, f"Save All failed:\n{exc}")
            return

        self.mark_all_saved()
        for source_path, entry_count in saved:
            unit = "line(s)" if self.is_config_source_path(source_path) or self.is_economycore_source_path(source_path) else "entries"
            self.log(f"Saved {entry_count} {unit} to: {source_path}", "success")
        self.set_status("Save All complete", "success")

    def refresh_dashboard(self):
        if not self.dashboard_vars:
            return
        map_issues = self.dashboard_map_issues()
        dashboard_issues = list(self.issues) + map_issues
        errors = [issue for issue in dashboard_issues if issue.severity == "error"]
        warnings = [issue for issue in dashboard_issues if issue.severity == "warning"]
        infos = [issue for issue in dashboard_issues if issue.severity == "info"]
        event_paths = self.event_source_paths()
        event_spawn_paths = self.event_spawn_source_paths()
        event_group_paths = self.event_group_source_paths()
        spawnable_paths = self.spawnable_source_paths()
        random_preset_paths = self.random_preset_source_paths()
        territory_paths = self.territory_source_paths()
        economycore_paths = [self.economycore_path] if self.economycore_path else []
        environment_path = self.__dict__.get("environment_path", "")
        environment_root = self.__dict__.get("environment_root")
        environment_paths = [environment_path] if environment_path and environment_root is not None else []
        mapgroupproto_paths = [self.mapgroupproto_path] if self.mapgroupproto_path else []
        mapgrouppos_paths = [self.mapgrouppos_path] if self.mapgrouppos_path else []
        weather_paths = [self.weather_path] if self.weather_path else []
        definition_paths = list(getattr(self.mission_workspace, "cfglimits_paths", [])) if self.mission_workspace is not None else []
        ce_project = self.ce_zones_project
        ce_zone_paths = [ce_project.source_path] if ce_project is not None else []
        definition_count = sum(len(values) for values in self.relation_definitions.values())
        if self.mission_workspace is not None:
            workspace = self.mission_workspace.root_path
        elif self.loaded_paths:
            workspace = "Loose files"
        else:
            workspace = "No workspace loaded"
        dirty_keys = set(self.dirty_source_keys_cache)

        def dirty_paths(paths):
            return [path for path in paths if self.normalized_path(path) in dirty_keys]

        unsaved_records = []
        seen_unsaved = set()

        def add_unsaved(module, path, target):
            key = (module, self.normalized_path(path) if path else str(target))
            if key in seen_unsaved:
                return
            seen_unsaved.add(key)
            unsaved_records.append((module, self.source_display_name(path) if path else module, target))

        for path in dirty_paths(self.loaded_paths):
            add_unsaved("Types", path, ("source", path))
        for path in dirty_paths(spawnable_paths):
            add_unsaved("Spawnabletypes", path, ("spawnable_source", path))
        for path in dirty_paths(random_preset_paths):
            add_unsaved("Randompresets", path, ("random_preset_source", path))
        for path in dirty_paths(event_paths):
            add_unsaved("Events", path, ("event_source", path))
        for path in dirty_paths(event_spawn_paths + event_group_paths):
            add_unsaved("Event System", path, ("module", "events"))
        for path in dirty_paths(environment_paths):
            add_unsaved("Environment", path, ("module", "environment"))
        for path in dirty_paths(territory_paths):
            add_unsaved("Territories", path, ("territory_source", path))
        for path in dirty_paths(economycore_paths):
            add_unsaved("Economy Core", path, ("module", "economy_core"))
        for path in dirty_paths(mapgroupproto_paths):
            add_unsaved("Mapgroupproto", path, ("module", "mapgroupproto"))
        for path in dirty_paths(weather_paths):
            add_unsaved("Weather", path, ("weather_source", path))
        for path in dirty_paths(self.config_paths):
            add_unsaved("Configs", path, ("config_source", path))
        for path in dirty_paths(self.profile_config_paths):
            add_unsaved("Profiles", path, ("profile_source", path))
        if self.definitions_dirty:
            add_unsaved("Definitions", self.definition_output_path(), ("module", "definitions"))
        for layer_name in sorted(self.ce_zones_dirty_layers, key=str.casefold):
            add_unsaved("CE Zones", layer_name, ("ce_zone_layer", layer_name, ce_project.source_path if ce_project is not None else ""))

        map_info = self.map_info_summary()
        map_text = map_info["text"] if map_info["selected"] else "Not selected"
        has_loaded_data = bool(self.mission_workspace is not None or self.loaded_paths or self.config_paths or self.profile_config_paths)
        if not has_loaded_data:
            validation_text = "Not available"
        elif self.last_workspace_validation_at is None:
            validation_text = "Not validated"
        else:
            stamp = self.last_workspace_validation_at.strftime("%H:%M") if self.last_workspace_validation_at.date() == datetime.now().date() else self.last_workspace_validation_at.strftime("%Y-%m-%d %H:%M")
            validation_text = f"Stale - last {stamp}" if self.workspace_validation_stale else f"Validated {stamp}"
        self.dashboard_vars["workspace"].set(workspace)
        self.dashboard_vars["map"].set(map_text or "Not selected")
        self.dashboard_vars["validation"].set(validation_text)
        self.dashboard_vars["unsaved_summary"].set(f"{len(unsaved_records)} source(s)" if unsaved_records else "Clean")

        issue_groups = self.issue_groups_by_module(dashboard_issues)

        def coverage_issues(module_id, paths):
            path_keys = {self.normalized_path(path) for path in paths if path}
            return [
                issue
                for issue in self.issues
                if self.issue_module_id(issue) == module_id
                and (not path_keys or not issue.source_path or self.normalized_path(issue.source_path) in path_keys)
            ]

        coverage_groups = (
            ("Economy", (
                ("types", "Types", self.loaded_paths, len(self.entries), "types", True, ("module", "types"), False),
                ("spawnabletypes", "Spawnabletypes", spawnable_paths, len(self.spawnable_entries), "spawnabletypes", False, ("module", "spawnabletypes"), False),
                ("randompresets", "Randompresets", random_preset_paths, len(self.random_preset_entries), "randompresets", False, ("module", "randompresets"), False),
                ("definitions", "Definitions", definition_paths, definition_count, "definitions", True, ("module", "definitions"), self.definitions_dirty),
                ("economy_core", "Economy Core", economycore_paths, "-", "economy_core", True, ("module", "economy_core"), False),
            )),
            ("Events", (
                ("events", "Events", event_paths, len(self.event_entries), "events", True, ("module", "events"), False),
                ("event_spawns", "Event Spawns", event_spawn_paths, sum(len(group.positions) for group in self.event_spawn_groups), "events", False, ("module", "events"), False),
                ("event_groups", "Event Groups", event_group_paths, len(self.event_group_definitions), "events", False, ("module", "events"), False),
                ("environment", "Environment", environment_paths, sum(1 for element in environment_root.iter() if isinstance(element.tag, str)) if environment_root is not None else 0, "environment", False, ("module", "environment"), False),
                ("territories", "Territories", territory_paths, len(self.territory_zones), "territories", False, ("module", "territories"), False),
            )),
            ("World", (
                ("mapgroupproto", "Mapgroupproto", mapgroupproto_paths, len(self.mapgroupproto_groups), "mapgroupproto", False, ("module", "mapgroupproto"), False),
                ("mapgrouppos", "Mapgrouppos", mapgrouppos_paths, sum(group.placed_count for group in self.mapgroupproto_groups), "mapgroupproto", False, ("module", "mapgroupproto"), False),
                ("ce_zones", "CE Zones", ce_zone_paths, len(ce_project.layers) if ce_project is not None else 0, "ce_zones", False, ("module", "ce_zones"), bool(self.ce_zones_dirty_layers)),
                ("weather", "Weather", weather_paths, len(self.weather_values) if self.weather_path else 0, "weather", False, ("module", "weather"), False),
            )),
            ("Server", (
                ("configs", "Configs", self.config_paths, "-", "configs", False, ("module", "configs"), False),
                ("profiles", "Profiles", self.profile_config_paths, "-", "profiles", False, ("module", "profiles"), False),
            )),
        )

        coverage_tree = self.dashboard_coverage_tree
        self.dashboard_targets = {}
        self.dashboard_missing_iids = []
        missing_required_count = 0
        if coverage_tree is not None:
            children = coverage_tree.get_children()
            if children:
                coverage_tree.delete(*children)
            state_rank = {"Errors": 0, "Missing required": 1, "Unsaved": 2, "Warnings": 3, "Ready": 4, "Optional": 5, "Not loaded": 6}
            tag_by_state = {"Errors": "error", "Missing required": "missing", "Unsaved": "dirty", "Warnings": "warning", "Ready": "ready", "Optional": "optional", "Not loaded": "optional"}
            for group_index, (group_label, rows) in enumerate(coverage_groups):
                prepared = []
                for row_id, label, paths, entry_count, module_id, required, target, special_dirty in rows:
                    row_issues = coverage_issues(module_id, paths)
                    counts = self.issue_counts_by_severity(row_issues)
                    is_dirty = special_dirty or bool(dirty_paths(paths))
                    available_paths = [path for path in paths if Path(path).is_file()]
                    if not available_paths and is_dirty:
                        state = "Unsaved"
                    elif not available_paths:
                        state = "Missing required" if required and self.mission_workspace is not None else "Optional" if self.mission_workspace is not None else "Not loaded"
                    elif counts["error"]:
                        state = "Errors"
                    elif is_dirty:
                        state = "Unsaved"
                    elif counts["warning"]:
                        state = "Warnings"
                    else:
                        state = "Ready"
                    issue_text = "None" if not sum(counts.values()) else f"{counts['error']}E {counts['warning']}W {counts['info']}H"
                    prepared.append((row_id, label, available_paths, entry_count, counts, state, target))
                group_files = sum(len(row[2]) for row in prepared)
                group_entries = sum(row[3] for row in prepared if isinstance(row[3], int))
                group_counts = {severity: sum(row[4][severity] for row in prepared) for severity in ("error", "warning", "info")}
                group_state = min((row[5] for row in prepared), key=lambda value: state_rank[value])
                group_issue_text = "None" if not sum(group_counts.values()) else f"{group_counts['error']}E {group_counts['warning']}W {group_counts['info']}H"
                group_iid = f"coverage-group-{group_index}"
                coverage_tree.insert("", "end", iid=group_iid, text=group_label, values=(group_files, group_entries, group_issue_text, group_state), tags=(tag_by_state[group_state],), open=True)
                for row_id, label, paths, entry_count, _counts, state, target in prepared:
                    iid = f"coverage-{row_id}"
                    coverage_tree.insert(group_iid, "end", iid=iid, text=label, values=(len(paths), entry_count, "None" if not sum(_counts.values()) else f"{_counts['error']}E {_counts['warning']}W {_counts['info']}H", state), tags=(tag_by_state[state],))
                    self.dashboard_targets[iid] = target
                    if state == "Missing required":
                        self.dashboard_missing_iids.append(iid)
                        missing_required_count += 1

        health_values = {
            "errors": ("Errors", len(errors), GRAPHITE_ERROR_DARK),
            "warnings": ("Warnings", len(warnings), "#7f5f3a"),
            "hints": ("Hints", len(infos), GRAPHITE_CARD_SOFT),
            "dirty": ("Dirty files", len(unsaved_records), GRAPHITE_PREFLIGHT),
            "missing": ("Missing required", missing_required_count, GRAPHITE_ERROR_DARK),
        }
        for key, (label, count, active_color) in health_values.items():
            button = self.dashboard_health_buttons.get(key)
            if button is not None:
                color = active_color if count else GRAPHITE_CARD_SOFT
                foreground = "#ffffff" if count and key in {"errors", "warnings", "dirty", "missing"} else GRAPHITE_TEXT
                button.configure(text=f"{label}\n{count}", bg=color, fg=foreground, activebackground=color, activeforeground=foreground)

        attention_tree = self.dashboard_attention_tree
        if attention_tree is not None:
            children = attention_tree.get_children()
            if children:
                attention_tree.delete(*children)
            ordered_issues = sorted(dashboard_issues, key=lambda issue: ({"error": 0, "warning": 1, "info": 2}.get(issue.severity, 3), self.issue_module_sort_key(self.issue_module_id(issue)), issue.name.casefold(), issue.message.casefold()))
            visible_issues = ordered_issues[:8]
            grouped_visible = self.issue_groups_by_module(visible_issues)
            issue_index = 0
            for group_index, (module_id, module_issues) in enumerate(grouped_visible.items()):
                parent_iid = f"attention-group-{group_index}"
                highest = min(module_issues, key=lambda issue: {"error": 0, "warning": 1, "info": 2}.get(issue.severity, 3)).severity
                attention_tree.insert("", "end", iid=parent_iid, text=self.issue_module_label(module_id), values=("", f"{len(module_issues)} shown"), tags=(highest,), open=True)
                self.dashboard_targets[parent_iid] = self.issue_module_dashboard_target(module_id)
                for issue in module_issues:
                    iid = f"attention-{issue_index}"
                    item = issue.name or (self.source_display_name(issue.source_path) if issue.source_path else "Workspace")
                    attention_tree.insert(parent_iid, "end", iid=iid, text=item, values=(issue.severity.title(), issue.message), tags=(issue.severity,))
                    self.dashboard_targets[iid] = self.issue_target(issue)
                    issue_index += 1
            if len(ordered_issues) > len(visible_issues):
                attention_tree.insert("", "end", iid="attention-more", text="More issues", values=("", f"{len(ordered_issues) - len(visible_issues)} additional issue(s)"), tags=("info",))
            if not ordered_issues:
                message = "No issues found in current validation." if has_loaded_data else "Load a mission or supported files to begin."
                attention_tree.insert("", "end", iid="attention-empty", text="Workspace", values=("Ready" if has_loaded_data else "Idle", message), tags=("info",))

        unsaved_tree = self.dashboard_unsaved_tree
        if unsaved_tree is not None:
            children = unsaved_tree.get_children()
            if children:
                unsaved_tree.delete(*children)
            for index, (module, source, target) in enumerate(unsaved_records):
                iid = f"unsaved-{index}"
                unsaved_tree.insert("", "end", iid=iid, values=(module, source))
                self.dashboard_targets[iid] = target
            if not unsaved_records:
                unsaved_tree.insert("", "end", iid="unsaved-clean", values=("Clean", "No unsaved changes"))

    def update_summary(self):
        duplicates = get_duplicate_groups(self.entries)
        errors = sum(1 for issue in self.issues if issue.severity == "error")
        warnings = sum(1 for issue in self.issues if issue.severity == "warning")
        infos = sum(1 for issue in self.issues if issue.severity == "info")
        mission = " | mission workspace" if self.mission_workspace is not None else ""
        source_filter = ""
        if self.selected_source_path:
            source_entries = sum(1 for entry in self.entries if self.normalized_path(entry.source_path) == self.normalized_path(self.selected_source_path))
            source_filter = f" | showing {source_entries} from {self.source_display_name(self.selected_source_path)}"
        usage_filter = ""
        if self.active_usage_filter:
            kind, value = self.active_usage_filter
            usage_count = sum(1 for entry in self.entries if value.casefold() in {name.casefold() for name in entry.relation_names(kind)})
            usage_filter = f" | showing {usage_count} using {kind} {value}"
        config_total = len(self.config_paths) + len(self.profile_config_paths)
        config_summary = f" | {len(self.config_paths)} mission config file(s), {len(self.profile_config_paths)} profile config file(s)" if config_total else ""
        spawnable_summary = f" | {len(self.spawnable_entries)} spawnabletype(s)" if self.spawnable_entries else ""
        random_summary = f" | {len(self.random_preset_entries)} randompreset(s)" if self.random_preset_entries else ""
        self.summary_var.set(f"{len(self.entries)} entries | {len(self.loaded_paths)} source file(s){spawnable_summary}{random_summary}{config_summary}{mission}{source_filter}{usage_filter} | {len(duplicates)} duplicate classname(s) | {errors} error(s) | {warnings} warning(s) | {infos} hint(s)")
        self.refresh_dashboard()

    def register_file_drop(self):
        if not TKDND_AVAILABLE:
            return
        for widget in [self, self.tree, self.source_listbox]:
            try:
                widget.drop_target_register(DND_FILES)
                widget.dnd_bind("<<Drop>>", self.on_drop_files)
                self.drop_registered_widgets.append(widget)
            except Exception:
                pass

    def on_drop_files(self, event):
        raw_paths = self.tk.splitlist(event.data)
        folders = [path for path in raw_paths if os.path.isdir(path)]
        if folders:
            self.open_mission_folder(folders[0])
            return COPY
        paths = [path for path in raw_paths if str(path).lower().endswith(".xml")]
        if paths:
            self.add_paths(paths)
        return COPY

